INSERT INTO diagnosis_quizzes (question, choice_1, choice_2, choice_3, choice_4, correct_answer) VALUES
  ('トレードで退場する人のほとんどの原因は何ですか？', '手法が悪かったから', '1回の負けが大きすぎたから', '運が悪かったから', '証券会社が悪いから', 2),
  ('1回のトレードで失っていい金額は総資金の何%までですか？', '10%', '5%', '2%', '1%', 3),
  ('損切り後に最初にやるべきことは何ですか？', 'すぐに次のトレードに入る', '少なくとも30分チャートから離れる', 'SNSで愚痴を書く', 'ロットを上げて取り返す', 2),
  ('STRADAとは何を意味する言葉ですか？', '日本語で「勝利」', 'イタリア語で「道」', '英語で「戦略」', 'ドイツ語で「分析」', 2),
  ('相場の7割はどんな状態ですか？', '上昇トレンド', '下降トレンド', 'レンジ', 'ブレイクアウト', 3);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(1, 'レバレッジをフルに使い、資金の大部分を1回のトレードに投入するのが習慣のトレーダーがいる。このトレードスタイルが退場につながりやすい最大の理由はどれですか？', '1回の読み違いで資金の大半を失うと、元に戻すのに数倍のリターンが必要になるから', 'レバレッジをかけすぎると証券会社から警告が来ることがあるから', '集中投資は分析の客観性が失われ、判断ミスが増えるから', 'ポジションサイズが大きいと感情が乱れ、判断力が低下するから', 1, '資金の大部分を1回に賭けるスタイルは、読み違いの1回で取り返しのつかないダメージを受ける。資金の50%を失えば元に戻すには100%のリターンが必要になる。「確実に見える」相場でも、1回のリスクを資金の数%以内に制限することが退場しないための前提条件。', false, 1),
(1, '相場が急変した日、Aは資金の3%でポジションを持っていたため、想定外の方向に動いても損切りして冷静に次を考えられた。Bは「絶対来る」と確信して資金の50%でエントリーし、口座が壊滅的なダメージを受けた。AとBの本質的な差は何ですか？', 'Aはテクニカル分析の精度が高く、相場の急変を事前に察知できていたから', 'Aは1回のリスクを小さく抑えていたため、予測が外れても致命傷にならなかったから', 'Bは経験が浅く、確信を持てる場面の見極め方を習得していなかったから', 'ポジションサイズが違うだけで、手法の精度という本質的な差はないから', 2, '「絶対来る」と感じても相場には不確実性がある。Aが生き残ったのは予測が正確だったからではなく、外れても致命傷にならないロットを選んでいたから。1回のリスクを制限することが、予測精度より先に身につけるべき技術。', false, 2),
(1, '含み損がどんどん拡大しているのに「まだ戻るかも」と損切りできず、損失が膨らみ続けている。この行動の根本的な原因として最も正しいのはどれですか？', '損切りのタイミングを計算する技術が不足しているため', '損失を確定させることへの恐怖から、脳が「先延ばし」を選んでいるため', '証拠金維持率が高すぎて、損切りしても意味がないと判断しているため', 'ロットが小さすぎて、損切りしても心理的に大きな痛みを感じないため', 2, '人間の脳は損失の痛みを利益の喜びより約2倍強く感じる。だから「まだ戻るかも」という先延ばしで痛みを回避しようとする。この衝動に対抗する唯一の方法は、エントリー時点で損切りラインを決め、感情に関係なく機械的に実行すること。', false, 3),
(1, 'あるトレーダーが「含み益が出るとすぐ利確したくなるが、含み損が出ると「まだ戻る」と持ち続けてしまう」と悩んでいます。この行動パターンが生まれる理由として最も正しいのはどれですか？', '利確の技術は高いが、損切りの技術だけが身についていないため', '人間は損失の痛みを利益の喜びより約2倍強く感じるため、損失の確定を避け利益を早く確保しようとするため', 'トレード経験が浅いため、ポジション管理が難しく感じられるから', '急変動を恐れるあまり、利益を早めに確定する習慣がついているから', 2, '損失の痛みは利益の喜びの約2倍強く感じる。含み益は「失いたくない」と早めに確定し、含み損は「戻るかも」と先延ばしするのはその結果。防ぐにはエントリー前に利確・損切りラインをルールとして固め、感情に関係なく守ること。', false, 4),
(1, 'あるトレーダーが「絶対に来る」と感じた場面に全力でエントリーし、ドカンと大きな損失を受けた。それ以来チャートが開けなくなり、3ヶ月経った今も資金が残ったまま動けていない。この退場の根本的な原因は何ですか？', 'エントリー根拠が甘く、分析力を高めれば防げたから', '精神的に耐えられないロットサイズでギャンブルのようなトレードをしていたから', '3ヶ月の休止で相場感覚が失われてしまったから', '「絶対に来る」という強い確信を持ってしまったこと自体が間違いだったから', 2, 'どんな確信があっても、1回の損失で「チャートを開けなくなる」ほどのダメージを受けるロットはサイズが大きすぎる。精神的に耐えられるロットなら大きな損失の後も冷静に次を判断できる。次のトレードを続けられる余裕を残すことが、技術より先に身につけるべきロット管理の目的。', false, 5),
(1, 'あるトレーダーが3ヶ月間「1回の損失は小さいし、たまに大きく勝てる」と感じていた。だが気づいたら口座残高が半分になっていた。このトレーダーに起きていたことは何ですか？', '気づかないうちに1回の大きな損失が積み重なり、資金が半分になった', '毎回の損失は小さく見えたが、負けトレードの損失が勝ちトレードの利益を上回り続けていた', '精神的なストレスから無意識に取引頻度が落ち、機会損失が積み重なっていた', '根拠なくエントリーを繰り返した結果、回数に比例して損失が増えていた', 2, '1回1回の損失が小さくても、負けトレードの損失額が勝ちトレードの利益額を上回る状態が続けば、口座は着実に減り続ける。「大きな負けはない」と安心しているうちに進行するため、発見が遅れやすい。毎週の損益を記録して傾向を確認する習慣が早期発見の鍵になる。', false, 6),
(1, '損切りラインに達したとき「もう少し待てば戻るかも」という感情が湧き、ラインを無視した。結果、損失は当初の3倍に膨らんだ。このトレーダーの問題の本質は何ですか？', '損切りラインの設定が甘すぎたこと', '感情に動かされてルールを破ったこと', '感情を全く感じないように自分を鍛えていなかったこと', '経験が浅いため、損切りタイミングの判断精度が低かったこと', 2, 'メンタルの強さとは「感情をゼロにすること」ではなく、「感情があってもルール通りに実行できること」。「戻るかも」と感じること自体は問題ない。問題は感情に動かされてルールを破ることで、損失は際限なく膨らむ。損切りラインを決めたら感情に関係なく実行する習慣が解決策。', false, 7),
(1, '「損切りの重要性は誰より知っている」と言うトレーダーが、いざ含み損を抱えると毎回「もう少し待てば戻るかも」と先延ばしにし続けた。この「わかっているのにできない」状態の最大の原因はどれですか？', '理論をさらに深く学べば、感情に関係なく実行できるようになるから', '知識を「知っている」段階で止まり、実際の失敗と振り返りで「できる」に変えていないから', '損切りはメンタルの問題なので、強い意志を持つことで解決できるから', 'トレード回数を増やして経験を積めば、自然と判断が変わっていくから', 2, '「知っている」と「できる」は別もの。学んだことをアウトプットし、実際のトレードで失敗し、振り返るサイクルを回してはじめて「できる」に変わる。「わかっているのにできない」は知識を増やすサインではなく、行動と振り返りが足りていないサイン。', false, 8),
(1, '「損切りルールを作るべきとわかっている。でも今はポジションがないし、決めると逆に動けなくなりそう」と感じ、1ヶ月先延ばしにしているトレーダーがいる。この先に起きやすいことはどれですか？', 'ルールのないまま損失が出ると、基準がなく感情で動いて損失が限界まで拡大する', '柔軟に動ける分、相場への対応力が自然と上がっていく', 'ポジションのない期間が長く続き、機会損失が増えていく', '先延ばしの習慣が、エントリーへの躊躇に変わっていく', 1, '「何もしない方が安全」という感覚がルール作りを先延ばしさせる。だがルールなしで相場に入ると、損失が出たとき頼れる基準がなく感情で動く。損失は限界まで膨らむ。「今はポジションがないから後でいい」と思った瞬間こそ、作るタイミング。', false, 9),
(1, 'あるトレーダーは長期間勉強しても成績が変わらなかった。転機となったのは「大きな負けをなくし、小さな負けだけにした」ことだった。このエピソードが示す教訓として最も正しいのはどれですか？', 'テクニカル分析の知識を増やすことが、勝率向上の最も直接的な手段だから', '損失の上限を守り続けることで、勝ちトレードの利益が積み上がるようになるから', '感情をコントロールして損失を一切なくすことが、上達のための正しい目標だから', '勝てる手法を見つけることより、師匠やメンターを探すことが先決だから', 2, '「大きな負けをなくす」とは損失の上限を決めて守ること。損失を小さく抑えることで、勝ちトレードの利益が積み上がるようになり収支が改善する。勉強量を増やすだけでは変わらなかった。「負け方を制御すること」こそが突破口になるという教訓。', false, 10),
(1, 'あるトレーダーが2年かけて高い勝率のエントリー手法を習得した。しかしある日の急変で1回のトレードに資金の大半を賭けていたため、口座が半分以下になった。手法を磨く前に、やっておくべきだったことは何ですか？', '複数の手法を組み合わせて、1つの手法への依存を下げること', 'どの手法でも1回の損失を小さく抑えるロット管理と損切りルールを先に固めること', 'バックテストで十分な検証を積んでから本番に移行すること', 'デモトレードで安定した利益が出るまで本番では取引しないこと', 2, '手法がどれだけ優れていても、1回のトレードで大半を失うリスク管理なしでは手法ごと退場する。正しい順序は「負けないトレーダー」の土台を先に固め、その上に手法を積み上げること。手法は後からでも学べるが、退場後には学べない。', false, 11),
(1, '含み損が出たとき「損切りすべきとわかっているが、何かするより待つ方が安全」と感じ、損切りを先送りした。結果、損失が当初の4倍に膨らんだ。この「何もしない方が安全」という感覚の何が危険ですか？', 'この感覚が過剰な取引頻度をもたらし、損失機会を増やすから', 'この感覚がルール通りの行動（損切り）を先延ばしさせ、損失を雪だるま式に膨らませるから', '経験不足から生まれる感覚で、取引回数を増やせば自然に消えるから', '市場の動きを静観することで、次の判断の精度が下がっていくから', 2, '「何もしない方が安全」という感覚（現状維持バイアス）は脳の自然な反応。だが損切り場面では「正しい行動をしない」ことが損失を膨らませる。この感覚が湧いた瞬間こそ、感情ではなく事前に決めたルールに従って動くタイミング。', false, 12),
(1, 'あるプロトレーダーの勝率は52%だった。つまり約2回に1回は負ける。それでも毎月安定して利益を出している。この理由として最も正しいのはどれですか？', '勝率が50%を超えれば、長期的に自動的に利益が積み上がるから', '勝ちトレードの利益が負けトレードの損失を常に上回るよう損益比を管理しているから', '勝率52%のプロは優れた手法を持ち、負けは偶然の例外に過ぎないから', '取引回数を増やすことで確率の法則により少しずつ利益が積み上がるから', 2, '勝率50%でも「勝ちの利益が負けの損失より大きい」状態を維持できれば、トータルで利益が残る。大切なのは何回勝つかではなく「負けの大きさを制限すること」。小さく負ける能力が、損益比を守る土台になる。', false, 13),
(1, '「1回の損失は30%以内に抑えれば大丈夫」というルールを自分に課しているトレーダーがいる。このルールが危険な理由として最も正しいのはどれですか？', '30%の損失でも回復には約42.9%のリターンが必要で、すでに「非常に困難」な水準に達しているから', '30%というラインは一般的に「許容範囲内」とされており、このルール自体は問題ない', '30%の損失からは長期保有すれば必ず自然に回復できるから', '損失を%で管理することは意味がなく、絶対額で管理すべきだから', 1, '30%の損失は回復に約42.9%のリターンが必要で、「非常に困難」な水準。5〜10%の損失なら回復は現実的だが、20%を超えると急激に困難になる。「30%まで許容」では既に危険域に入っている。適切なのは1回のトレードで資金の2%まで、という単位でのリスク管理。', false, 14),
(1, '「今回のエントリーは完璧に確信が持てる場面だ」と感じ、これまでより大きなロットでエントリーした。直後の急落で想定外の大損を被った。この経験が示す最も重要な教訓は何ですか？', '強い確信を持てるほど感情的なエントリーになっており、冷静な分析が必要だったから', '確信の強さにかかわらず、1回で口座が壊滅しないロット制限が唯一の防衛策だから', 'エントリー前に損切りラインを決め、急落時に即座に損切りする反射神経が必要だったから', '分割買いでリスクを分散すれば、急落時のダメージを抑えられたから', 2, '「絶対来る」という確信は、脳が作り出す感覚で相場を保証しない。予測が外れることを前提として、1回のリスクを制限するルールが必要。確信が強いほど、むしろロットを守るルールの重要性が増す。', false, 15),
(1, 'トレーダーAは先月10回負けたが1回の損失は常に資金の2%以内だった。トレーダーBは3回しか負けなかったが1回の負けで資金の35%を失った。どちらが「正しい負け方」をしていますか？', 'Aが正しい。10回負けても1回の損失を小さく抑え、口座へのダメージを最小化しているから', 'Bが正しい。負け回数が少ないほどトレーダーとしての実力が高いから', 'どちらも間違い。負け=失敗であり、どちらも改善が必要だから', 'Bが正しい。3回の負けなら回数が少ない分、心理的ダメージも小さいから', 1, 'Aは10回負けても口座へのダメージは最大20%程度、回復も現実的。Bは1回で35%を失い、回復に約54%のリターンが必要になる。負け回数より「1回の負けが口座に与えるダメージを小さく抑えること」が、退場しないための本質的な技術。', false, 16),
(1, '「損切りはしっかりできている。今週も大きな損失はなかった」と感じていたトレーダーが、2ヶ月後に口座を確認すると30%近く減っていた。このトレーダーに起きていたことの原因として最も正しいのは？', '「損切りできている」という認識が正確でなく、大きな損失を見落としていたから', '毎回の損切りは小さくても、1回の損失が利益を常に上回り続けていたから', '取引頻度が高すぎて、手数料の積み重ねで口座が削られていたから', '損切りはできているが、タイミングが遅すぎて損失が大きくなっていたから', 2, '「損切りできている」だけでは不十分。1回の損失が1回の利益より大きい状態が続けば、口座は確実に減る。毎週のトレード記録で「平均利益」と「平均損失」を比較する習慣が、この状態の早期発見につながる唯一の手段。', false, 17),
(1, '「損切りの重要性はわかった。でも良いシナリオが浮かばない日が続くから、また明日から実践しよう」と1ヶ月先延ばしにした結果、ルールなしで大きな損失を出した。1ヶ月前にやるべきだったことは何ですか？', 'さらに多くの教材を読んで、損切り方法論を完全に理解してから実践する', '学んだことを今日のトレードで一つ試し、結果を記録して翌日振り返ること', 'デモトレードで100回連続利益を出してから本番に移行すること', 'プロトレーダーにトレードをチェックしてもらえる環境を用意すること', 2, '「明日から」は永遠に来ない。「わかっている」が「できる」に変わるのは、今日学んだことを一つ試し、失敗を記録して振り返り、また学ぶサイクルを回したとき。まず今日1回、損切りラインを事前に決めてエントリーしてみることが最初の一歩。', false, 18),
(1, '2年間で7つの手法を使い捨てにしながら資金が半分になったトレーダーがいる。毎回「もっと高い勝率の手法があるはず」と探し続けた結果だ。この失敗の根本原因はどれですか？', '相場と相性の良い手法を引き当てる運がなかったから', '「勝てるトレーダー」を目指して手法を追い続け、「負けないトレーダー」になる段階を飛ばしたから', '2年間という期間が短すぎて、どの手法も正当に評価できなかったから', '師匠やメンターがいないまま独学で学び続けたから', 2, '正しい成長の順序は「負けトレーダー → 負けないトレーダー → 勝てるトレーダー」。高勝率手法を探すのは「勝てるトレーダー」段階の話。損失を一定以内に抑える技術なしに手法を変え続けると、どの手法でも同じように資金が減り続ける。まず「小さく負ける能力」を身につけることが最優先。', false, 19),
(1, 'ある投資初心者が「まずエントリー手法とインジケーターを半年で完璧にしてから、資金管理は次のフェーズで学ぼう」と考えています。この学習順序の何が問題ですか？', 'インジケーターよりも先に経済指標の読み方を学ぶべきだから', 'エントリー手法がどれだけ優れていても、損切りとロット管理が身についていなければ1回の大負けで退場する可能性があるから', '半年という期間が短すぎて、手法を習得するには不十分だから', 'インジケーターは上級者向けのツールなので、初心者はまず基礎知識を学ぶべきだから', 2, '勝ち方より先に「負け方」を学ぶことが最優先です。どれだけ優れたエントリー手法を持っていても、1回のトレードで口座の大部分を失うリスクを管理できなければ退場します。資金管理と損切りは手法より先に身につけるべき土台です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(2, 'あるトレーダーは先月1万円の利益が出たとき「まあまあ嬉しい」と感じた。今月、同じ1万円の損失が出ると、先月の喜びより何倍も強い苦しさに押しつぶされそうになった。この心理的な非対称性を説明しているのはどれですか？', '損失の痛みは同額の利益の喜びより約2倍強く感じる', '保有効果により、失うものを実際より高く評価してしまう', 'サンクコストへの執着が損失の感情を増幅させる', '損失の記憶だけが強く残る選択的な認知が起きる', 1, '損失の痛みは同額の利益の喜びの約2倍強く感じる。この非対称性が「利益は早めに確定・損失は先延ばし」という利小損大パターンを生み出す。脳の仕組みを理解することが、感情に振り回されず行動するための出発点。', false, 1),
(2, '含み損を抱えたトレーダーが「損切りしたいが、まだ戻るかもしれない」と損切りを先延ばし続けている。この「まだ戻るかも」という思考を生み出している根本の仕組みはどれですか？', '損失を確定させる痛みが、含み損を放置するコストより強く感じられるから', '過去のトレードで回復した経験があるため、今回も戻ると学習しているから', 'チャートを見続けることで上昇の根拠を見つけようとしているから', 'エントリーに自信があるため、自分の判断を信じ続けているから', 1, '損失を確定させる痛みが、含み損を放置し続けるコストより強く感じる。だから脳は「まだ戻るかも」という先延ばしを選ぶ。対抗するにはエントリー時点で損切りラインを決め、この感覚が湧いた瞬間を「ラインを実行するタイミング」と認識すること。', false, 2),
(2, '「利益が出るとすぐ確定したい、でも損失は戻るまで待ちたい」という感覚でトレードを繰り返すと、長期的にどのような結果に陥りやすいですか？', '利確が早く損切りが遅いため、利益より損失が大きくなる', '損失への耐性が鍛えられ、大きな利益が増えてくる', 'リスクを取らないため、小さな利益と小さな損失が続く', '感情が安定しているため、安定したパフォーマンスになる', 1, '損失の痛みが利益の喜びより強く感じられると、利益は早めに確定し、損失は「戻るはず」と先延ばしします。結果として利益は小さく損失は大きい「利小損大」パターンが定着します。', false, 3),
(2, '含み益+8,000円のポジションを持っているトレーダーが、利確ラインはまだ先なのに「この利益が消えたら怖い」という感覚が強まり、予定外のタイミングで利確した。この行動を繰り返すと、口座にどんな影響が出ますか？', '小さな利益を積み重ねることで、長期的に安定した収益が得られる', '利確は早く損失は大きい「利小損大」パターンが定着し、口座が減り続ける', '利確のタイミングが洗練され、勝率が自然と向上していく', '小さなリスクを取り続けることで、感情的な安定が生まれる', 2, '「利益が消えたら怖い」という感覚は、脳がすでに含み益を「自分のもの」と感じ、失う痛みを恐れているから。この感覚で利確を繰り返すと利益は小さく、損失は「戻るかも」と大きくなる「利小損大」が定着して口座が減り続ける。', false, 4),
(2, '勝率65%で取引しているトレーダーが毎月口座を減らし続けている。振り返ると平均利益+3,000円・平均損失−12,000円だった。この矛盾の根本原因はどれですか？', '利益を早めに確定し損失を先延ばしにする習慣が、損益比をマイナスにし続けるから', '勝率65%は不十分で、安定した利益には最低70%以上が必要だから', 'エントリー根拠が毎回異なり、一貫した戦略が機能していないから', '取引回数が多すぎてリスク管理が機能していないから', 1, '勝率が高くても損益比がマイナスなら口座は減り続ける。「利益は早く確定したい・損失はまだ戻るかも」というプロスペクト理論の非対称性が、この矛盾を生み出している。', false, 5),
(2, 'トレーダーBは「ドル円が上がる」と予測してから分析を始めた。すると買いシグナルばかりが目につき確信を強めたが、その後大きく下落した。この判断ミスの直接の原因はどれですか？', 'テクニカル指標が不足しており分析の精度が低かった', '「上がる」と先に決めたことで支持する情報だけが目に入った', '下落シグナルを無視する損失回避性が働いた', '相場の急変を予測するスキルが不足していた', 2, '先に結論を持つと確証バイアスが働き、その結論を支持する情報だけが目に入ります。「チャートが何を語っているか」から分析を始めることで、この歪みを防ぐことができます。', false, 6),
(2, 'トレーダーFはSNSで「今週ドル円は上昇する」という投稿を見てからチャートを開き、「確かに上がりそう」と感じてロングした。直後に下落した。このミスを防ぐために最初に変えるべき習慣はどれですか？', 'SNSを見る前に「チャートが何を語っているか」だけを先に確認する', 'SNSを複数比較して多数意見が一致した方向にのみエントリーする', 'SNSとテクニカル指標の両方が一致したときのみエントリーする', 'SNSを見た後は同方向のテクニカル根拠を最低3つ集めてから判断する', 1, '他者の見方を先に受け取ると確証バイアスが強まり、その方向を支持するサインだけが目に入る。分析は必ず「チャートが何を語っているか」から始め、他者の意見は後から参考にする。', false, 7),
(2, '「もうここまで耐えたのだから、ここで損切りしたらこれまでの我慢が無駄になる」と考えているトレーダーがいる。この思考の何が危険ですか？', '取り返せない過去の我慢に縛られ損切りタイミングを見逃し続けることで、損失が際限なく膨らむから', '過去の経験から学ぼうとしない姿勢が、成長を妨げているから', '「我慢」という感情が冷静な分析を妨げ、勝率を下げているから', '損切りを嫌がる性格がトレードに向いていないことを示しているから', 1, '今すべき判断は「このレートから上がるか」だけ。過去の我慢は取り戻せない埋没費用であり、その判断と無関係なのに、それに引きずられると損切りタイミングを永遠に失い続け、損失が膨らみます。', false, 8),
(2, '含み損−10万円でポジションを保有3日目のトレーダーCが「ここまで耐えたのだから今さら損切りできない」と考えた。正しい判断軸として最も適切なものはどれですか？', '過去の損失は関係なく「今このレートでエントリーするか？」だけを基準にする', '損失を取り戻すためポジションを追加して平均単価を下げる', 'ここまで損失が拡大した以上、今は回復を待つしかない', '感情が高ぶっているため、24時間後に改めて判断する', 1, 'サンクコストは過去に失われたものであり、これからの判断に関係ありません。「今このレートでエントリーするか？」という問いだけが正しい判断軸になります。', false, 9),
(2, '「損切りラインは相場を見ながら柔軟に決めよう」とエントリーしたトレーダーが、含み損が膨らむたびに先延ばしを繰り返し、当初想定の5倍の損失を出した。この失敗を防ぐために、エントリー前に必ずやっておくべきことは？', 'エントリー根拠を最低3つ以上揃えてから発注する', '損切りラインと利確ラインを、感情が入る前の冷静な状態で決めておく', 'エントリー後に複数の相場変化シナリオを書き出して対策を考える', '信頼できるトレーダーに分析を確認してもらってから発注する', 2, 'ポジションを持った後の判断は「自分のもの」として過大評価する歪みが入る。「柔軟に決める」という考え方自体が、この歪みに乗っ取られる入口。エントリー前の冷静な状態で決めたラインだけが、唯一歪みを受けていない判断基準になる。', false, 10),
(2, 'エントリー前は「根拠が弱ければすぐ切る」と決めていたトレーダーが、実際にポジションを持つと「絶対上がる、手放せない」と感じて損切りできなくなった。なぜエントリー前後でこれほど判断が変わったのですか？', '保有した瞬間から「自分のもの」として実際より高く評価するようになるから', 'エントリー後はチャートを見る時間が増え、根拠が積み上がっていくから', '損切りの決断は精神的に消耗するため、先延ばしするのが自然だから', 'エントリー後は相場の動きに集中するため、事前の計画を忘れがちになるから', 1, 'ポジションを持った瞬間に「自分のもの」として実際より高く評価するようになります。事前のルールを守れないのはメンタルの弱さではなく、この認知の歪みが原因です。', false, 11),
(2, '含み損が拡大中のトレーダーEは「ここまで耐えたから」と損切りを先延ばした。やがて損失が膨らむと「取り返さないと」と大きなポジションを建て始めた。この連鎖を止める最初のタイミングはどれですか？', '「取り返したい」と感じ始めた時点', '「ここまで耐えたから」とサンクコストを感じた最初の時点', '大きなポジションを実際に建ててしまった後', '損切りラインを超えてさらに損失が拡大し始めた時点', 2, '「ここまで耐えたから」というサンクコストに気づいた瞬間が連鎖を断ち切る最初のチャンスです。この感情を無視すると保有効果・損失拡大・リベンジ心理という破滅的な連鎖が始まります。', false, 12),
(2, '急騰する相場を見て「乗り遅れたくない」と飛び乗りエントリーした後、反落で含み損が出ると「今日の損を取り返さないと」と大きなポジションを建てた。この2つのミスに共通する根本原因は何ですか？', 'どちらも感情が冷静な判断を上書きし「今すぐ行動しなければ」と動かしているから', '相場の分析力が不足しており、エントリータイミングを見極められていないから', '損失が出ると感情が不安定になるため、大きなポジションは自然と避けるべきだから', '下降相場での飛び乗りは禁物であり、トレンド確認が不足していたから', 1, '感情が先に動いているとき、マーケットではなく自分が最大の敵になります。「乗り遅れたくない」「取り返したい」と感じたら一度止まり、エントリー条件をゼロから確認し直す。', false, 13),
(2, '損切りタイミングで「今切ったら損する」という恐怖を感じたトレーダーが、「今、怖さを感じているな」と自分の状態に気づいた。この気づきの後に取るべき行動として正しいものはどれですか？', '恐怖を感じている間は判断を下すべきでないため、相場から離れる', '感情は一時的な脳の反応と理解し、恐怖を感じながらも事前のルール通りに実行する', '恐怖の原因を分析して、次のエントリーに活かす', '「恐怖を感じた」という事実をトレード日誌に記録し、後で振り返る', 2, 'メタ認知の目的は感情を消すことではなく「気づいて距離を置く」こと。「怖いな」と観察できた時点で感情と距離ができている。そのまま事前に決めたルール通りに動くことが、感情を行動の主導権から外す唯一の方法。', false, 14),
(2, '急騰する相場を見て「乗り遅れたくない」という焦りを感じたトレーダーHが、メタ認知で冷静さを取り戻すために最初にすべき行動として正しいものはどれですか？', '深呼吸してモニターから目を離し感情が収まるのを待つ', '「今、焦り（FOMO）を感じているな」と感情を言語化する', '事前に決めたトレードルールに従いエントリー条件を確認する', '感情を無視してチャート分析に集中する', 2, 'メタ認知の第一歩は「気づく」ことです。「焦りを感じているな」と感情を言語化することで感情と距離を置き、ルールに沿った行動に戻る準備が整います。', false, 15),
(2, '含み損が拡大中のトレーダーが「もうここまで損が拡大したのだから、さらにポジションを追加して平均単価を下げよう」と考えた。この行動が危険な理由として最も正しいものはどれですか？', '拡大した損失という取り返せない過去が、さらに傷口を広げる行動を正当化しているから', '平均単価を下げると損切りラインが複雑になり、管理できなくなるから', 'ナンピンは上昇相場では有効だが、下降相場では機能しないから', 'ポジションを追加すると感情的になりやすく、冷静な判断ができなくなるから', 1, '「ここまで損が拡大した」という取り返せない過去が悪手を正当化します。ナンピンを考え始めた瞬間がサンクコストのサイン—そのポジションを手放し、冷静になってから再エントリー条件を確認する。', false, 16),
(2, '含み損−5万円のポジションを持っているトレーダーが、保有効果とサンクコストの影響を排除して判断をリセットしたい。最も有効な問い直し方はどれですか？', '「この銘柄の今後の見通しは強気か弱気か？」と大局的に判断する', '「含み損がさらに拡大したら自分はどう感じるか？」と最悪ケースを想像する', '「今ポジションがなければ、このレートでエントリーするか？」と問い直す', '「損切り後に相場が反転したらどうするか？」と次のシナリオを考える', 3, '「今ポジションがなければ入るか？」という問いかけで、保有効果（手放したくない）とサンクコスト（ここまで耐えた）の影響を同時に排除できる。答えが「いいえ」なら、今保有しているという事実に関係なく、手放すべき根拠が揃っている。', false, 17),
(2, '損切りした直後に相場が反転して上昇し始めた。「切らなければよかった」と強い後悔を感じたトレーダーが、次のトレードで損切りをためらうようになった。この後悔が引き起こす問題の本質は何ですか？', '損切りの精度が低いため、損切りラインの設定を見直すサインだから', '過去1回の結果が次の判断に影響し、損切りという正しい行動を「悪手」と学習してしまうから', '後悔という感情が積み重なると、長期的にトレード自体への意欲を失わせるから', '反転を予測できなかったことが、テクニカルスキル不足を示しているから', 2, '損切り後の反転は「正しい行動が悪い結果を生んだ」という誤った学習を脳に与える。これを次の判断に持ち込むと次の損切りが遅れ、損失が膨らむ。損切りは「正しいプロセス」、結果は「確率」という軸を崩さないことが、後悔を次に持ち込まない唯一の方法。', false, 18),
(2, 'ドル円が急騰するチャートを見たトレーダーHは「乗り遅れる」と焦り、高値圏でロングエントリーした。直後に反落して含み損が拡大した。このエントリーを引き起こした感情の仕組みとして正しいものはどれですか？', '「乗り遅れる恐怖」が冷静な判断を上書きし、エントリー条件より先に行動させたから', '上昇チャートを確認してトレンドに乗ろうとした、合理的な判断の結果だから', '損失回避性が機会損失を防ごうとする行動として現れたから', 'テクニカルスキル不足による高値掴みで、分析精度を上げれば防げるから', 1, '急騰を見て「乗り遅れたくない」と感じた瞬間がFOMOのサイン。相場がすでに動ききった後で生まれやすく、この焦りを感じたときこそエントリー条件をゼロから確認し直す。', false, 19),
(2, 'チャート分析を行う際に「この銘柄を買いたい」という先入観を持った状態で分析を始めると、どのような結果になりやすいですか？', '買いの根拠と売りの根拠を同等に見つけ、判断に迷う', 'チャートパターンの認識精度が向上し、エントリーポイントが良くなる', '売りの根拠に敏感になり、エントリーを見送る可能性が高まる', '買いの根拠ばかりが目に入り、リスクを見落とした判断をする', 4, '先に「買いたい」という結論を持つと確証バイアスが働き、リスクを見落とします。分析は必ず「チャートが何を語っているか」から始め、エントリーしたい気持ちは後回しにする。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(3, '資金200万円のトレーダーAが「この取引では最大20万円まで負けてもいい」と決めている。2%ルールの観点から、このトレーダーの行動をどう評価できますか？', '20万円は総資金の10%であり、2%ルールを大きく超えている', '20万円は適正で、2%ルールの2倍の余裕があるため安全圏内にある', '20万円は総資金に対して少額なので、特に問題はない', '2%ルールは証券会社が定めた規則であり、個人の裁量は関係ない', 1, '2%ルールでは1回の最大損失を総資金の2%までに抑えます。200万円の2%は4万円。20万円（10%）は許容範囲の5倍であり、1回の負けで壊滅的なダメージを受けるリスクがあります。', false, 1),
(3, '勝率60%で運用していたトレーダーAが8連敗した。「もう2%ルールを守っても意味がない」と感じ始めた。この感覚が誤っている理由として正しいものはどれですか？', '8連敗は統計的に異常なため、手法を見直すべき段階に来ているから', '2%ルールでは8連敗後も資金の約85%が残っており、トレードを続ける力が保たれているから', '連敗中こそロットを上げて早期回復を図ることが2%ルールの本来の使い方だから', '8連敗はメンタル管理の失敗が原因なので、手法ではなく心理面を見直すべきだから', 2, '2%ルールでは1回負けても98%が残る。8連敗後でも約85%が残っており、これがルールを守り続けるだけで得られる生き残り力。「意味がない」と感じた瞬間こそ、ルールを守り続けなければならない局面。', false, 2),
(3, '資金が思うように増えず焦ったトレーダーBが、リスク率を2%から5%に引き上げた。この変更が最も危険な理由はどれですか？', '勝率60%の手法はリスク率2%専用であり、5%では機能しなくなる', 'リスク率5%では連敗時の損失が2%と比べて劇的に大きくなる', '5%ルールは金融庁により推奨されていない運用方法である', 'リスク率を上げると1回の利益も増え、過度な期待を生む', 2, 'リスク率2%→5%は小さく見えても、20連敗時の残資金は約67%から約36%に急落します。わずか3%の差が連敗時の耐久力を半分以下にするため、リスク率の変更は軽視できません。', false, 3),
(3, 'トレーダーBが「損切りラインを決めた後、もう少しロットを増やしたいから損切り幅を狭めた」と話している。この行動が危険な理由として正しいものはどれですか？', '損切り幅を狭めると損切りに引っかかりやすくなり、負けが増えるため', 'ロットは損切り幅を先に決め、そこから逆算するものであり、順序が逆になっているため', '損切り幅を変えると2%ルールの計算式が使えなくなるため', 'ロット数を増やすと心理的プレッシャーが高まり、判断が歪むため', 2, '正しい手順は「エントリー根拠から損切り幅を決める → ロット＝最大リスク額÷損切り幅」です。ロットに合わせて損切り幅を変えるのは本末転倒であり、2%ルールの意味がなくなります。', false, 4),
(3, 'トレーダーBは「1,000株エントリーしたいから損切り幅は50円にしよう」と決めた。総資金100万円で2%ルールを使う場合、このロット決定の何が問題ですか？', '1,000株は100万円には多すぎるため、まず500株以下にすべきだから', 'ロットを先に決め損切り幅を後から合わせると、2%ルールのリスク管理が形骸化するから', '損切り幅50円は狭すぎて、自然な値動きで引っかかりやすくなるから', 'エントリー前にロット数を決めると、相場の状況を見落としやすくなるから', 2, '正しい順序は「根拠から損切り幅を決める→最大リスク額÷損切り幅でロットを出す」。ロット先決めでは損切り幅の根拠がなく、2%ルールは計算だけの形骸になる。', false, 5),
(3, '2%ルールで計算した適正ロットが出たのに、「少なすぎる気がする」とトレーダーCが感覚で2倍に増やしてエントリーした。この行動の問題点として最も正しいものはどれですか？', '2%ルールはあくまで目安であり、感覚で調整することは認められている', '計算で出た適正ロットを感覚で変えた瞬間、2%ルールによる資金管理が機能しなくなる', 'ロットを2倍にすれば利益も2倍になる可能性があり、合理的な判断である', '2%ルールは初心者向けであり、慣れたら感覚でロットを決めてよい', 2, '計算で出た適正ロットを感覚で変えることは、2%ルールを自ら破る行為です。「多すぎる・少なすぎる」という感覚こそ、感情がリスク管理を歪めているサインです。', false, 6),
(3, 'トレーダーCが「損切り幅が大きい銘柄ほど1株あたりのリスクが高いのに、ロット数は変えないでいい」と考えている。2%ルールに基づくと、この考えはどう評価されますか？', '正しい。損切り幅に関わらず、同じ資金なら適正ロット数は同じ', '誤り。損切り幅が大きいほど1株のリスクが増すため、ロット数を減らす必要がある', '正しい。損切り幅が大きい銘柄の方がリスクが少ないため増やせる', '誤り。損切り幅が大きい銘柄は取引してはいけない', 2, 'ロット＝最大リスク額÷損切り幅のため、損切り幅が2倍になれば適正ロットは半分になります。同じ2%ルールでも損切り幅に応じてポジションサイズを調整することが正しい資金管理です。', false, 7),
(3, 'トレード中に「心臓がバクバクする」「仕事が手につかない」「夜スマホでチャートを見てしまう」ような状態になった場合、最も考えられる原因はどれですか？', 'ロットが大きすぎる', '分析手法が間違っている', 'メンタルが弱い', '銘柄選びが悪い', 1, 'トレード中に強い不安やストレスを感じるのは、分析やメンタルの問題ではなく、単にロットが大きすぎることが原因です。適正ロットであれば感情的な動揺は大幅に軽減されます。', false, 8),
(3, '普段は問題なくトレードできていたトレーダーDがロットを2倍にした途端、夜眠れなくなりチャートが気になり始めた。この状態が示すこととして最も正しいものはどれですか？', '分析能力が追いついていないため、より多くの勉強が必要', '2倍のロットは自分のリスク許容度を超えており、適正ロットではない', 'ロットが大きいほど集中力が増し、良い判断ができるようになる', '眠れなくなるのは初心者だけに起きる一時的な現象である', 2, '「夜ぐっすり眠れるかどうか」はロットが自分のリスク許容度に合っているかのシグナルです。眠れなくなった時点で適正ロットを超えており、元のロットに戻すべきサインです。', false, 9),
(3, 'トレーダーEはリスク率1%、トレーダーFはリスク率2%で同じ手法で運用している。どちらも20連敗した場合、2人の残資金とトレード継続力について正しい説明はどれですか？', 'リスク率が違うだけで連敗後の残資金は同じになる', '1%の方が残資金は多く残るが、勝ち続けた場合の資金成長は遅い', '1%の方が残資金も多く残り、資金成長速度も速くなる', '20連敗は統計上起こらないため、リスク率の違いは実質的に無意味', 2, '20連敗後の残資金は1%で約82%、2%で約67%。1%の方が連敗耐性は高いですが、利益の積み上がりも遅くなります。リスク率は連敗耐性と資金効率のトレードオフです。', false, 10),
(3, '2%ルールで毎回リスクを限定しているトレーダーEが「損切りするたびに無駄なコストを払っている気がする」と感じ始めた。この感覚を放置すると何が起きますか？', '損切りをコストとして嫌がることで先延ばしが増え、1回の損失が壊滅的な規模になるから', 'コスト意識が高まると利益を急ぐようになり、損益比が自然に改善されるから', '損切り回数が減ってトレード頻度が下がるため、資金管理上は有利になるから', '2%ルールは初心者期間だけのルールで、コストを嫌がる段階では卒業してよいから', 1, '損切りは「保険料」として小さな損失を払い、口座破綻を防ぐ仕組み。この感覚が薄れると損切りが後回しになり、1回の損失で取り返せないダメージを受ける。コストに感じたとき、それが損切り回避の始まりのサイン。', false, 11),
(3, '5連敗中のトレーダーFが「自分だけこんな連敗をしている。手法が壊れているに違いない」と焦り始めた。勝率60%の手法でこの判断が誤りである理由として正しいものはどれですか？', '5連敗は勝率60%でも約1%の確率で起こる、統計的に正常な範囲内の現象だから', '5連敗は手法ではなくメンタルの問題が引き起こしているから', '5連敗中はエントリーを止めて相場から完全に離れるべきだから', '勝率60%なら5連敗は理論上起こらないため、エントリー基準の見直しが必要だから', 1, '勝率60%でも5連敗の確率は約1%（100回に1回）。「壊れている」と感じるのは感情であって統計ではない。連敗中こそ手法変更を急がず、ルールを守ってトレードを続けることが重要。', false, 12),
(3, '7連敗中のトレーダーGは「このまま負け続けるわけにはいかない」と焦り、ロットを通常の1.5倍にしてエントリーした。この判断の何が危険ですか？', '連敗中のロット増加は損失拡大を加速させ、2%ルールが持つ連敗耐性を自ら崩すから', '1.5倍のロットでも2%ルールの許容範囲内なら問題ない', '連敗中はエントリーせず待つことが最善で、ロット変更以前の問題だから', '連敗が続いているため手法を変えることが先決で、ロットは関係ないから', 1, '連敗中にロットを上げると損失の拡大スピードが増す。2%ルールの「連敗耐性」はルールを守り続けることでのみ機能する。「取り返したい」という衝動こそが最大の危険信号であり、その瞬間こそロットを下げる理由になる。', false, 13),
(3, '「もっと早く稼ぎたい」と考えたトレーダーGがリスク率を2%から10%に引き上げた。20連敗という状況に置かれた場合、どのような現実に直面しますか？', '資金の約50%を失い、回復は難しいが継続は可能な水準になる', '資金の約88%を失い、100万円の資金が約12万円になる', '資金の約33%を失うが、2%ルールとの差は小さい', '連敗中に損切り幅が自動調整されるため、実際の損失は計算より少なくなる', 2, 'リスク率10%で20連敗すると残資金は約12%。100万円なら約12万円しか残りません。「早く稼ぎたい」という気持ちで上げた10%という数字が、退場寸前の現実を生み出します。', false, 14),
(3, '「2%ルールを守ると利益が少なくてもどかしい。5%にすれば早く増やせる」と考えたトレーダーHがリスク率を引き上げた。この行動が長期的に危険な理由として正しいものはどれですか？', '2%は連敗耐性と資金効率を両立させるバランス点で、5%では20連敗後の残資金が約67%から約36%に急落するから', '2%ルールは規則であり、勝手に変更すると証券会社から警告が来るから', '5%ルールは上級者向けであり、初心者が適用すると判断が歪むから', 'リスク率を上げると利益への期待が増し、感情的なエントリーが増えるから', 1, '2%は「我慢の数値」ではなく、連敗耐性と成長効率を両立させる数学的なバランス点。5%に変えると連敗時の損失スピードが大幅に上がり、「早く増やしたい」という一歩が退場への近道になる。', false, 15),
(3, '2%ルールを学んだトレーダーHが「計算が面倒だから毎回100株で固定する」と決めた。この運用方法の問題点として正しいものはどれですか？', '固定ロットは感情的なミスを防ぐため、合理的な管理方法である', '銘柄ごとに損切り幅が違うため、固定ロットでは実際の損失額が毎回バラバラになる', '100株は少なすぎるため、最低500株以上で運用しなければならない', '固定ロットでも損切り幅を統一すれば2%ルールと同等の効果がある', 2, '2%ルールの本質は「1回のリスク額を総資金の2%に固定すること」です。固定ロットでは銘柄の損切り幅によって実際の損失額が変わるため、リスク管理になっていません。', false, 16),
(3, 'トレードで連敗したとき「手法が悪いのかもしれない」と不安になるのは自然な反応ですが、その不安に対して最初に確認すべきことはどれですか？', '最新の投資書籍で新しい手法を学び直す', '連敗を取り返すためにロットを増やすべきか検討する', '直近の勝率を計算して、手法を別のものに変えるか決める', '連敗は統計的に正常な範囲内かどうかを確認する', 4, '勝率60%のトレーダーでも5連敗する確率は約1%あり、連敗は統計的に正常な範囲で起こり得ます。連敗中こそ冷静に統計的な観点から「今の連敗は異常かどうか」を確認し、感情的に手法を変えたりロットを調整したりしないことが重要です。', false, 17),
(3, '2%ルールで運用した場合、20連敗した後に残っている資金の割合は約何%ですか？', '約50%', '約57%', '約67%', '約82%', 3, '2%ルールでは1回の負けで資金の98%が残るため、20連敗後は0.98の20乗で約66.8%が残ります。20連敗という極端な状況でも資金の3分の2以上が残るため、トレードを続ける土台が保たれます。', false, 18),
(3, '「最近、損切りするたびに自信を失い、エントリーが怖くなってきた」と悩むトレーダーIがいる。この心理的苦痛の根本原因として最も可能性が高いものはどれですか？', '手法の勝率が低すぎるため、より精度の高い手法を見つける必要がある', 'メンタルが弱いため、精神的なトレーニングが必要である', 'ロットが大きすぎるため、毎回の損失が心理的な許容範囲を超えている', 'トレード経験が浅いため、場数を踏んで慣れるしかない', 3, '精神的な苦痛の原因の多くはロットの大きさにあります。適正ロットに下げるだけで損失の痛みが和らぎ、冷静なエントリーが戻ってきます。手法やメンタルを疑う前にロットを確認すべきです。', false, 19),
(3, '連敗中に「ルールを守れるかどうか」が分かれ目になる理由として最も適切な説明はどれですか？', '連敗中は冷静に分析できるため、ここでルールを見直す最大のチャンスだから', '連敗中こそ感情的になりやすく、ルールを破ってロットを上げたくなる衝動が強まるから', '連敗中は市場のルールが変わるため、自分のルールも適応させる必要があるから', '連敗中は勝率が上がる直前のサインであり、ルールを守れば必ず反転するから', 2, '連敗が続くと「取り返したい」という感情が強まり、ロットを上げたりルールを無視したエントリーをしがちです。この感情的な圧力に抗えるかどうかが、生き残るトレーダーと退場するトレーダーの分かれ目になります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(4, '2%ルールを守りながら10連敗したトレーダーAと、ルールを守らず1回に大きく賭けたトレーダーBの結果として最も正確なものはどれですか？', 'Aは資金の約82%が残り次月も取引できた。Bは1回の大きな負けで致命的な損失を被った', 'Aは損切り回数が多く手数料負けした。Bはリスクを取って大きな利益を得る可能性があった', '10連敗する確率は極めて低いため、AとBの結果に有意な差はない', 'Aは損失を繰り返し心理的に消耗した。Bは1回の決断で決着がついた', 1, '2%ルールで10連敗しても資金の約82%が残る。毎回の小さな損失（保険料）が、口座崩壊という壊滅的なリスクを防ぐ仕組みです。損切りは「損した」ではなく「続けるための保険料」として捉えることが重要です。', false, 1),
(4, '含み損が少し出た直後「大丈夫、すぐ戻る」と感じて損切りラインを確認しなかった。数日後「ここまで耐えた、報われるはず」とラインを広げた。さらに悪化した時、損切りボタンを押す気力すらなかった。最初に行動すべきだったのはいつか？', '「大丈夫、すぐ戻る」と感じた最初の段階で、損切りラインを確認して実行する', '「ここまで耐えた」と感じた段階で、追加ポジションで平均単価を下げる', '気力がなくなった段階で、一旦離れてから損切りする', 'ラインを広げた時点で、より長期足のシナリオを再考する', 1, '否認→期待→麻痺の3段階で、行動できる唯一の機会は「否認」の段階。余裕があるうちに「大丈夫」という思い込みを疑い実行することが、後の麻痺状態を防ぐ唯一の出口です。', false, 2),
(4, '含み損を3週間保有しているトレーダーが「ここまで耐えたのだから絶対に報われる」と確信している。この心理の何が危険か？', '3週間という保有期間は長期投資として適切であり、危険な心理ではないから', '損失額が2%ルールを超えているため、心理よりもルール違反が問題だから', '過去の耐えた時間・損失に縛られて合理的な判断ができず、損失がさらに膨らむ可能性が高いから', '「報われるはず」という期待は分析的判断であり、問題となる心理ではないから', 3, '「ここまで耐えたから」は過去のコストに縛られるサンクコスト効果。過去の耐えた時間は現在の判断と無関係。この執着が損切りを先延ばしにし続け、損失を取り返しのつかない水準まで膨らませる。', false, 3),
(4, 'エントリー後に含み損が膨らみ「やっぱり損切りラインをもう少し下に広げよう」と変更した。この行動が特に危険な理由は？', '損切りラインを動かすと、証券会社のシステムが注文を強制キャンセルするから', 'ラインを広げると次のエントリーの計算が複雑になり、ミスが起きやすいから', '損切りラインは一度設定したら変更できない仕組みになっているから', 'エントリー前の冷静な自分が決めたラインを動かすと、根拠のない「祈りのトレード」に変わるから', 4, '損切りラインはエントリー前の冷静な判断。含み損の中にいる自分は感情で歪んでいる。動かした瞬間に2%ルールが崩壊し、根拠のない「待てば戻るかも」という祈りだけのトレードになる。', false, 4),
(4, '「計画的ナンピン」と「感情的ナンピン」を見分ける最も重要な基準はどれですか？', '追加エントリーの回数が3回以内かどうか', 'ナンピンした時の含み損が資金の5%以内かどうか', 'エントリーする前に「ここで追加する」と決めていたかどうか', '追加エントリーの間隔が1時間以上あいているかどうか', 3, '計画か感情かの分かれ目は「事前に決めていたか」。エントリー前にシナリオに組み込んでいれば戦略、含み損が出てから「助かりたい」と追加すれば祈り。事前決定がなければ感情的ナンピンと判断する。', false, 5),
(4, 'あるトレーダーがチャートを見て「上がりそう！」という直感でエントリーした後、損切り幅を決めてロット計算をした。この手順の何が問題か？', '感情でエントリーすると損切りラインが「根拠が崩れる場所」ではなく「これ以上は嫌だ」という感情的な値になるから', '直感によるエントリーは証券会社の規定で無効になるから', 'ロットをエントリー後に計算すると注文が成立しないから', '損切り幅をエントリー後に設定すると手数料が増加するから', 1, '正しい順番は「根拠→損切りライン→ロット計算→エントリー」。先に入ると損切りラインが感情で決まり、根拠が崩れた場所に置けない。エントリー根拠と損切りラインはセットで考えるのが原則。', false, 6),
(4, 'ある初心者が「損切りはエントリー価格から-2%の場所に固定する」というルールを使っている。このルールの問題点は？', '-2%の損切り幅は2%ルールの計算と矛盾するから', '損切り位置が市場の構造と無関係になり、エントリー根拠が崩れる場所と一致しないことが多いから', '損切り位置を固定すると他の市場参加者に狙われやすくなるから', 'エントリー価格からの距離で損切りを決めると証券会社が注文を受け付けないから', 2, '損切りラインは「エントリー根拠が崩れる場所」に置くのが正解。価格やパーセンテージで機械的に決めると、有効な根拠があるのに損切りされる、または根拠が崩れても残り続けるという事態が起きる。', false, 7),
(4, '含み損が少し出た直後「まだ大丈夫、ちょっと待てば戻るよ」と感じて損切りラインを確認しなかった。この初期段階で行動しなかった場合、その後最も起きやすい展開は？', '「まだ大丈夫」という段階から始まり、損失拡大で「耐えた報い」への期待、最終的に損切りの気力すら失う麻痺状態へ進む', '損失が一定水準を超えたところで冷静さを取り戻し、自然に損切りできるようになる', '時間が経つほど相場が戻る可能性が統計的に高まるため、保有継続が正解になる', '含み損が大きくなるほど損切りへの抵抗感が薄れ、むしろ実行しやすくなる', 1, '「まだ大丈夫」は否認の段階。余裕があるように見えるこの段階で行動しないと、期待→麻痺へと深みにはまる。麻痺状態では損切りボタンすら押せなくなるため、初期段階の行動が唯一の出口になる。', false, 8),
(4, '損切りが「否認→期待→麻痺」と進んでしまう心理の連鎖を、そもそも起こさないための最も確実な対策はどれですか？', '損切りの3段階を毎日ノートに書いて、自分の状態をセルフチェックする', 'エントリーと同時に逆指値注文を設定し、感情が介在する前に自動で損切りを執行させる', '含み損が出たらすぐにポジションサイズを半分にして心理的な圧力を下げる', 'チャートの確認頻度を下げて、含み損の変動に敏感にならないようにする', 2, '逆指値注文を使えば、否認・期待・麻痺のどの段階でも感情に関係なく機械的に損切りが執行される。人間の意志に頼らず「仕組みで守る」のが最も確実。含み損を抱えてから考えても遅い。', false, 9),
(4, 'エントリー前に「ここまで下がったら追加で買い増す」と計画し、追加も含めた全リスクが資金の2%以内に収まるよう計算してからトレードした。このナンピンは戦略的と言えるか？', 'はい。事前シナリオ・根拠・リスク管理の3条件が揃っているから', 'いいえ。ナンピン自体は戦略的かどうかに関わらず禁止だから', 'はい。ロットを倍にして平均単価を下げているなら合理的だから', 'いいえ。相場は予測不能なため、事前に決めた追加ポイントに根拠は持てないから', 1, '計画的ナンピンの3条件は「事前のシナリオ」「各ポイントの根拠」「全体リスクの2%以内」。ロットを倍にして平均単価を下げる（マーチンゲール）は別物で、リスクを指数関数的に増大させるため推奨されない。', false, 10),
(4, '感情的ナンピンをしてしまう人の根拠として、実際に動いている心理として最も近いものはどれですか？', '「ここが底値だから反転する可能性が高い」という分析的判断', '「平均単価を下げれば小さな反発で損益が戻る」という計算', '「過去のチャートで同じパターンは反転している」という統計的根拠', '「今の含み損をどうにかして減らしたい、助かりたい」という切迫感', 4, '感情的ナンピンを動かしているのは「助かりたい」という切迫感だけ。分析でも計算でもない。この切迫感のまま追加エントリーすると損失はさらに拡大し、最終的に逃げ場を失う。', false, 11),
(4, '損切りラインに達するたびに「もう少し待てば戻るかも」と感じ、実行できないトレーダーがいる。人間の意志に頼らず損切りを確実に実行させる方法として正しいのはどれか？', '損切りラインに近づいたらチャートを閉じて、気持ちが落ち着くまで待つ', '損切り幅を広めにとって、精神的に耐えられる余裕を作っておく', 'エントリーと同時に逆指値注文を設定し、価格到達で自動執行されるようにする', '損切りの判断を支える根拠をノートに書いて、毎朝読み返す習慣をつける', 3, '「もう少し待てば」という感情は、損切りラインに達するたびに必ず現れる。逆指値注文なら迷いや感情が介在する前に自動執行される。人間の意志に頼らず仕組みで解決するのが最も確実な対策。', false, 12),
(4, '損切りが執行された5分後、「今すぐ取り返さないと」という焦りを感じてチャートを凝視し、根拠のないままエントリーしてさらに負けた。最初にすべき行動は？', '逆方向にエントリーして、トレンドに乗り直す', '損切り後すぐにチャートを閉じ、最低30分は離れる', 'ロットを増やして1回で損失を取り戻せる設定にする', '勝率の高いシグナルが出るまでチャートを分析し続ける', 2, '損切り直後は「取り返したい」感情が強く、判断が歪んでいる。この状態でのエントリーは根拠のない衝動的な行動になる。チャートから30分物理的に離れて感情をリセットすることが、負の連鎖を断ち切る唯一の方法。', false, 13),
(4, '5連勝中のトレーダーが「今は絶好調だから」と通常の3倍のロットでエントリーした。その1回で5連勝分の利益がほぼ消えた。この失敗の根本的な原因は？', '連勝の勢いでロットを感覚的に決め、2%ルールが崩壊していたから', '5連勝後は統計的に負ける確率が高まるため、エントリー自体が間違っていたから', 'ロットが大きいと市場に影響が出て、相場の方向が変わるから', '連勝中は慢心から分析が甘くなり、エントリー根拠が不十分だったから', 1, '連勝しても、ロットは常に2%ルールの計算で決める。感覚でロットを3倍にした瞬間、1回の負けが3回分の損失になる。「調子が良いから」という感覚がリスク管理を崩壊させる典型パターン。', false, 14),
(4, 'チャートを分析していたとき「今日だけは特別だ。このトレードはルールの例外にしよう」と思いついた。次にすべき行動は？', '「今日だけ特別」と思った時点でそのトレードを見送る', '特別だと感じた根拠を確認し、客観的な正当性があれば実行する', '直感が正しいことも多いので、小さなロットで試してみる', 'いつもより損切り幅を広げて、特別な値動きに対応できるようにする', 1, '「今日だけ特別」と思った瞬間は、感情がルールを上書きしようとしているサイン。理由がどれだけ正当に見えても、この思考が現れた時点でそのトレードを見送る。ルールに例外を作るたびにリスク管理は崩壊していく。', false, 15),
(4, 'チャートを見て「この形、なんかいける気がする！」と感じてエントリーしようとした。このとき最も有効な自問は？', '「このエントリーは事前のシナリオに基づいているか、それとも今感じた直感か？」', '「このチャートパターンは過去に何回成功しているか？」', '「今の市場の方向は日足・週足のトレンドと一致しているか？」', '「このエントリーで最大いくら利益になるか？」', 1, '「いける気がする」はすべて感情エントリーのサイン。「これは計画か、感情か？」と一言自問するだけで衝動的なエントリーの多くを防げる。計画に基づかないエントリーは根拠なき祈りと同じで、長期的に負け続ける原因になる。', false, 16),
(4, 'ルール通りに損切りを実行した直後、すぐに次のトレードに入ろうとしているトレーダーがいる。なぜこの行動が危険か？', '連続してエントリーすると証券会社から不審な取引とみなされるから', '損切り後にすぐエントリーすると手数料が二重にかかるから', '損切り後はまだ感情的な揺れがあり、「損を取り返したい」という心理が無意識に判断を歪めるから', '損切り直後は市場の流動性が下がりスプレッドが広がるから', 3, 'ルール通りに損切りできても感情はまだ揺れている。すぐ次に入ると「損失を取り戻そう」という心理が無意識に働き、リベンジトレードに変わる。最低30分〜1時間離れて感情をリセットするのが正しい手順。', false, 17),
(4, 'ルール通りに損切りしたが5分後に相場が反転し、「切らなければよかった」という悔しさを感じた。この感情にどう向き合うべきか？', 'ルール通りに実行できた行動そのものを評価する。反転は結果であり、プロセスの正しさは変わらないから', '反転した相場のエントリーチャンスを探し、悔しさをエネルギーに変えて取り返す', '損切り後の反転は頻繁に起きるため、損切りラインの設定を見直す材料として記録する', '悔しさは向上心の表れなので、次回はより精度の高い分析をしてから損切りする', 1, '「切らなければよかった」は次回の損切りをためらわせる最も危険な感情。「ルール通りに動いた自分を褒める」習慣が、この歪んだ学習を上書きし、長期的に損切りを実行できる心理を育てる。', false, 18),
(4, 'エントリーしてから含み損が膨らんだ状態で損切りラインを考えているトレーダーがいる。この進め方の最大の問題は？', 'エントリー後に設定した損切りラインは証券会社のシステムが受け付けないから', 'エントリー後に損切りラインを考えると計算が複雑になりロットを間違えやすいから', '含み損のストレスで分析力が一時的に向上するため、エントリー後の設定の方が精度が高い', '含み損を抱えた状態では感情で判断が歪み、冷静な損切りラインを設定できないから', 4, 'エントリー前は冷静に「根拠が崩れる場所」を判断できる。ポジションを持った後は「少し待てば戻るかも」という感情が介入し、損切りラインが感情的な値になる。冷静な自分が決めた事前のラインに従うのが原則。', false, 19),
(4, '勝率80%の手法を持つトレーダーAと、勝率50%だが損切りルールと資金管理を確立しているトレーダーBがいた。1年後、Bの口座の方が大きくなっていた。なぜか？', '損切りルールにより1回の負けを小さく抑えたBは、20連敗しても資金の約67%が残り生き続けられたから', '勝率50%でも取引回数を増やせば統計的に利益が積み上がるから', '勝率80%の手法は長期的に必ず崩れるため、Aの成績が悪化したから', '個人投資家は勝率より損益比を重視した方が必ず有利になるから', 1, '勝率が高くても1回の負けが大きければ口座は崩壊する。2%ルールで損切りを守れば20連敗しても約67%の資金が残る。Week1〜4の核心は「勝ち方より先に負け方を学ぶ」こと。口座が続く限りチャンスはある。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(5, 'トレードで含み損を抱えた際、「損失を確定させたくない」という心理を引き起こす4つの暴走感情のうちどれに該当しますか？', '焦り', '恐怖', '欲', '後悔', 2, '恐怖は「損を認めたくない」という心理から損切りの実行を阻害します。脳が「失うこと」を極端に嫌うため、損失の確定を避けようとしてポジションを持ち続けてしまいます。', false, 1),
(5, 'トレードにおける「欲」の暴走として典型的な行動はどれですか？', '利確目標に達しても「もっと伸びるかも」と持ち続けること', '含み損が出た瞬間に損切りすること', 'チャートが動き始めた瞬間に飛び乗ること', '損切り直後の反転を気にして次の損切りを遅らせること', 1, '欲の暴走は「もっと欲しい」という心理で、利確目標に達しても利益を伸ばそうとして持ち続ける行動に現れます。事前に決めた目標を超えても満足できず、結果的に利益を取りこぼす原因になります。', false, 2),
(5, 'FOMO（Fear Of Missing Out）がトレードに与える影響として最も典型的なものはどれですか？', '利確を早めすぎて利益を伸ばせないこと', '損切りラインを必要以上に広げてしまうこと', 'チャートが動き始めた瞬間に飛び乗り、高値掴みになること', '連勝後にロットを下げて保守的になりすぎること', 3, 'FOMOは「乗り遅れたくない」という焦りから、チャートが動き始めた瞬間にエントリーしてしまう心理です。エントリーの根拠がないタイミングで飛び乗るため、高値掴みになりやすい特徴があります。', false, 3),
(5, '損切り直後にレートが反転したのを見て「切らなければよかった」と思い、次の損切りを遅らせる原因となる感情はどれですか？', '恐怖', '焦り', '欲', '後悔', 4, '後悔は「あのとき、ああしていれば」と過去の行動を悔やむ感情です。損切り直後の反転を見ると「損切りしなければよかった」と後悔し、その体験が次の損切りを躊躇させる原因になります。', false, 4),
(5, '感情の暴走を防ぐための「メタ認知の3ステップ」として正しい順番はどれですか？', 'ルールに戻る → 気づく → 距離を置く', '距離を置く → ルールに戻る → 気づく', '気づく → 距離を置く → ルールに戻る', '距離を置く → 気づく → ルールに戻る', 3, 'メタ認知のステップは、まず「今、自分は何を感じているか」に気づき、次に「感情は一時的な脳の反応」と距離を置き、最後に「感情ではなくルールで動く」ように戻る、の順番です。', false, 5),
(5, '含み益が出ているにもかかわらず「逆行したらどうしよう」と利確を早めてしまう心理の背景にある感情はどれですか？', '恐怖', '欲', '焦り', '後悔', 1, '含み益がある場面でも「せっかくの利益が消えてしまうかもしれない」という恐怖が働き、計画通りの利確ポイントを待てずに早めに確定させてしまいます。恐怖は含み損だけでなく含み益の場面でも損失回避を引き起こします。', false, 6),
(5, '連勝後に「今がチャンスだ」とロットを上げたくなる心理を、4つの暴走感情のどれで説明できますか？', '恐怖', '焦り', '後悔', '欲', 4, '連勝による高揚感が「もっと稼げるかもしれない」という欲を刺激します。調子がいいときほど「今がチャンス」とロットを上げたくなりますが、これが欲の暴走による危険なサインです。', false, 7),
(5, '4つの暴走感情が連鎖して大損に至る典型的なパターンとして正しいものはどれですか？', '焦りで飛び乗る → 含み損 → 後悔 → 欲が暴走 → 恐怖で損切りできない', '焦りで飛び乗る → 含み損 → 恐怖で損切りできない → 損失拡大 → 後悔 → 欲が暴走 → リベンジトレード', '恐怖で損切りできない → 後悔 → 焦りで飛び乗る → 欲が暴走 → 大損', '欲が暴走 → 高値掴み → 焦り → 恐怖で利確 → 後悔 → ナンピン', 2, '感情の連鎖は「焦り（FOMO）で根拠なく飛び乗る」ことを起点に、含み損→恐怖で損切りできず→損失拡大→後悔→「取り返したい」欲が暴走→リベンジトレード→さらに負ける、という悪循環に陥ります。', false, 8),
(5, 'トレード前の「10秒チェック」で行うべきことは何ですか？', '「今、冷静か？」と自問し、Noならその日はトレードしない', '直近の経済指標発表のスケジュールを確認する', '過去の類似チャートパターンを確認する', '今の資金残高と許容損失額を計算する', 1, 'トレード前の10秒チェックは「今、冷静か？」と自分に問いかける行動です。答えがNoであれば、その日はトレードを見送ることが大きな損失を防ぐ最も確実な方法です。', false, 9),
(5, 'SNSで他者の「爆益」投稿を見て「自分も乗らなければ」と焦ってエントリーする行動の根本にある感情はどれですか？', '焦り', '恐怖', '欲', '後悔', 1, '他人の成果を見て「自分だけ取り残されている」と感じるのは焦りの典型的なパターンです。SNSの情報は結果の一部だけを切り取ったものであり、それに反応してエントリーするのは根拠のない感情トレードになります。', false, 10),
(5, '「今回だけ」と思ったときの心理状態について正しい説明はどれですか？', '「今回だけ」と思ったとき、それは欲が暴走しているサインである', '「今回だけ」は損切りタイミングを見極めた慎重な行動の表れである', '「今回だけ」は過去の検証に基づく例外的なエントリーの合図である', '「今回だけ」は冷静にリスクを評価した上での合理的な判断である', 1, '「今回だけ特別」「今回だけはルールを逸脱してもいい」という思考は、欲が理性を上回っている状態です。ルールを破る言い訳を自分に許している時点で、すでに感情が判断を支配しています。', false, 11),
(5, '恐怖に対する有効な対処法として提示されている問いかけはどれですか？', '「このポジションの含み損は資金の何%にあたるか？」', '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」', '「過去に同じチャートパターンで勝ったことはあるか？」', '「損切りした後にレートが反転する確率は何%か？」', 2, '「もし今ポジションを持っていなかったら、このレートで新規にエントリーするか？」と自問し、答えがNoであれば即座に損切りするのが恐怖への対処法です。保有している事実から離れて純粋に相場を評価することで、恐怖による判断の歪みを修正できます。', false, 12),
(5, '焦り（FOMO）に対する対処法として提示されている問いかけと、その答えの正しい組み合わせはどれですか？', '「このエントリーの根拠は何か？」→「チャートの勢い」', '「このトレードを見送ったら何を失うか？」→「大きな利益を失う」', '「このトレードを見送ったら何を失うか？」→「何も失わない」', '「今エントリーしないとどうなるか？」→「二度とチャンスが来ない」', 3, '焦りへの対処は「このトレードを見送ったら何を失うか？」と自問することです。答えは「何も失わない」であり、1回のトレードを見送っても口座の資金は減りません。この事実を思い出すことで焦りを冷静に処理できます。', false, 13),
(5, '後悔の感情に対する正しい対処法はどれですか？', '次は損切りしないという方針に切り替える', '「結果」ではなく「プロセス」で評価し、ルール通りなら正しい行動とみなす', '過去のトレードを詳細に振り返り、最適なタイミングを探る', '反転の確率が高い場面では損切りを見送る戦略に変更する', 2, '後悔への対処は、結果ではなくプロセスで自分を評価することです。ルール通りに損切りを実行したのであれば、その後レートがどう動いたかにかかわらず正しい行動でしたと評価すべきです。', false, 14),
(5, '欲の暴走を防ぐための対処法として正しいものはどれですか？', '利確目標に達したら、さらに上値を狙えるか1分だけ検討する', '連勝時はロットを段階的に上げて勢いに乗る', '利確目標とロットを事前に決め、機械的に実行する', '利確目標は相場の動きに合わせて毎回柔軟に変更する', 3, '欲への対処は、利確目標とロットをトレード前に決めておき、機械的に実行することです。トレード中の判断は感情に左右されるため、事前の冷静な状態で決めた数値に忠実に従うことが重要です。', false, 15),
(5, 'トレードにおける「感情」について正しい考え方はどれですか？', '感情はトレードの敵であり、感情を完全に排除して初めて勝てるようになる', '感情をゼロにする必要はない。大切なのは「自分が感情的になっている」と気づくことである', '感情は無視すべきで、気づく必要もなくただルールに従えばよい', '感情は初心者だけの問題であり、経験を積めば自然に消えるものである', 2, '感情は敵ではなく「気づくべきシグナル」です。怖くてもいい、悔しくてもいい。感情をゼロにする必要はなく、大切なのは「今、自分が感情的になっている」と自覚し、感情にコントロールされないことです。', false, 16),
(5, 'メタ認知の3ステップのうち、「感情は一時的な脳の反応である」と認識するステップはどれですか？', '気づく', '振り返る', 'ルールに戻る', '距離を置く', 4, '「距離を置く」ステップでは、自分の感情を客観視し、「これは一時的な脳の反応にすぎない」と認識します。感情そのものを否定せず、感情と自分を切り離して俯瞰することで冷静さを取り戻します。', false, 17),
(5, '「今、自分は何を感じているか？」と自問するのは、メタ認知の3ステップのうちどれに該当しますか？', '距離を置く', 'ルールに戻る', '気づく', '振り返る', 3, '「今、自分は何を感じているか？」に気づくことがメタ認知の最初のステップです。自分の感情状態を言語化することで、感情に飲まれるのではなく感情を客体として認識できるようになります。', false, 18),
(5, '損切りした後にレートが反転した経験が、次のトレード行動に与える悪影響として最も典型的なものはどれですか？', '次のトレードで利確を早めすぎて利益を取りこぼすこと', '次のトレードで過剰にロットを上げて一発逆転を狙うこと', '次のエントリーを見送り続けてトレード機会を失うこと', '次の損切りを遅らせて、結果的に大損すること', 4, '損切り直後の反転を見ると「切らなければよかった」と後悔し、その経験から次の損切りを躊躇するようになります。損切りのタイミングを遅らせることで小さな損失が大きな損失に育つのが最も典型的な悪影響です。', false, 19),
(5, '感情の連鎖パターンにおいて、大損後に「取り返したい」という欲が暴走して起こる行動はどれですか？', '損切りラインを厳しくしてリスクを減らすこと', 'しばらくトレードを休んで冷静になること', 'ロットを下げて慎重に取り戻そうとすること', 'リベンジトレードをしてさらに負けること', 4, '感情の連鎖では、大損による後悔が「取り返したい」という欲を暴走させ、リベンジトレードを引き起こします。感情的な状態でのエントリーは根拠が乏しく、さらに負ける確率が高くなる悪循環を生みます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(6, 'あるトレーダーが損切りで3万円を失い、「取り返したい」という気持ちが頭を占領している。このまま次のトレードに進んだ場合、最も起きやすいことはどれですか？', '焦りで根拠のないエントリーをし、さらにロットを上げて損失が拡大していく', '悔しさがモチベーションになり、より慎重な分析でエントリー精度が高まる', '一度負けたことで冷静になり、次のエントリーでは感情が排除できる', '損失の原因を振り返りながら再エントリーすることで、損失を回収できる', 1, '「取り返したい」という感情が支配すると、根拠より衝動が先に動く。ロットを上げてさらに負けるという悪循環が始まり、止まれなくなる。このサインを感じたとき、即座に30分ルールを発動するのが正しい行動。', false, 1),
(6, 'リベンジトレードに陥るプロセスの最終的な帰結として最も適切なものはどれですか？', '一時的な含み損を抱えるが、相場が戻れば回復できる状態', '悪循環を繰り返し、退場への片道切符となる状態', '精神的な疲労は増すが、資金管理さえ守れば退場は免れる状態', 'メンタルが鍛えられ、結果的に冷静なトレードができるようになる状態', 2, 'リベンジトレードは負け→感情→無謀な行動→さらに負けるのサイクルが繰り返され、最終的には退場に直結します。', false, 2),
(6, 'あるトレーダーが3万円の損切りをした直後、「この3万円を取り戻すまでやめられない」と感じ、根拠のないエントリーを繰り返している。この行動を引き起こしている仕組みとして最も正確なものはどれですか？', 'すでに失った損失が現在の判断を歪め、回収を目的としたトレードが止まらなくなっている', '損失を出した原因を分析し、同じミスを繰り返さないよう学習している', '新しいシナリオを立て直し、市場の変化に対応しようとしている', '損失分を上回る利益目標を設定し、リスク計算をしたうえで再エントリーしている', 1, 'すでに失ったお金への執着が現在の判断を歪め、「取り戻すこと」が目的になると根拠のないトレードが止まらなくなる。過去の損失は今の相場とは無関係であるべきで、それに気づくことがリベンジを断ち切る第一歩。', false, 3),
(6, '含み損が出ているのに「一度持ったポジションを手放すのは負けを認めるようで切れない」と感じてズルズル保有している。この思考の何が危険ですか？', 'ポジションへの愛着が損切りの判断を遅らせ、含み損が際限なく拡大してしまう', 'ポジションを持ち続けることで、相場が反転した時に利益を確保できる可能性がある', '決断を先延ばしにすることで、より多くの市場情報を収集できる', '損切りを急ぐと反転のチャンスを逃すため、慎重な姿勢は合理的な判断である', 1, '自分のポジションへの愛着が「手放す＝損失の確定」と感じさせ、損切りを阻む。この心理に引きずられると含み損が膨らみ続け、最終的に取り返しのつかない大損につながる。', false, 4),
(6, '損切りした直後、「このモヤモヤを早く消したい」という感情が押し寄せ、何も考えずにエントリーボタンを押してしまった。この衝動の根本にある仕組みとして最も適切なものはどれですか？', '不快な感情を素早く上書きしようとする脳の働きが、即座の行動へと駆り立てているから', '損切りが間違いだったと潜在的に気づいており、その証明をしたくなるから', '相場の流れが変わるタイミングを本能的に察知し、再エントリーのシグナルが出ているから', '損切り後は判断力が上がるため、むしろ冷静にエントリーできる状態だから', 1, '損失の不快感を素早く解消しようとする脳の反応が、怒りと結びついて衝動的なエントリーを引き起こす。「モヤモヤを消したい」と感じた瞬間がリベンジトレードに入るサイン。その感情に気づいたら、30分ルールを発動するタイミング。', false, 5),
(6, '損切りで2万円を失ったトレーダーが、「取り返さないと」と焦りながら損失ポジションを手放せず、さらに怒りのままエントリーを繰り返している。この一連の行動で3つの心理がそれぞれ担っている役割として最も正確な説明はどれですか？', '「取り返したい」＝失った損失への執着 / 「手放せない」＝ポジションへの愛着 / 「繰り返す」＝不快感を解消したい衝動', '「取り返したい」＝利益への欲望 / 「手放せない」＝相場分析への確信 / 「繰り返す」＝勝率改善の努力', '「取り返したい」＝後悔の感情 / 「手放せない」＝確証バイアス / 「繰り返す」＝FOMO', '「取り返したい」＝恐怖 / 「手放せない」＝損失回避 / 「繰り返す」＝現状維持バイアス', 1, 'リベンジトレードには3つの心理が複合する。失った損失への執着が「取り返したい」を生み、ポジションへの愛着が「手放せない」を、不快感を解消したい衝動が「繰り返す」を引き起こす。3つが重なることで悪循環が止まらなくなる。', false, 6),
(6, 'サンクコストの考え方がトレードにおいて危険な理由として最も適切なものはどれですか？', '過去の利益に固執して利益確定が遅くなるため', '取引手数料が増えてコストパフォーマンスが悪化するため', '失った金額を取り戻そうと、本来見送るべきエントリーをしてしまうため', '過去の成功体験に縛られて新しい手法を試せなくなるため', 3, 'サンクコストは「すでに失った金額」に執着し、その回収を目的とした根拠のないトレードをしてしまう点が危険です。過去の損失は現在の判断には無関係であるべきです。', false, 7),
(6, '保有効果がトレードに与える悪影響として最も典型的なものはどれですか？', '損失が拡大しているポジションを損切りできず、含み損が膨らむ', '利益確定を急ぎすぎて、本来得られたはずの利益を取りこぼす', 'エントリータイミングが遅くなり、良い価格で入れない', '他の銘柄に目移りして、ポジションを頻繁に乗り換えてしまう', 1, '保有効果によって「自分の持っているポジション」に愛着が生まれ、損切りの判断が遅れて含み損が拡大してしまいます。', false, 8),
(6, '損切り後に怒りが生じるメカニズムとして最も正しい説明はどれですか？', '自己評価が下がったことに対する防衛機制として怒りが生まれる', '市場の不公平さに対する正当な怒りであり、合理的な感情反応である', '脳が損失を物理的な脅威として認識し、闘争反応を引き起こす', '損切りそのものが間違いだったと無意識に認識している証拠である', 3, '脳は損失を物理的な脅威と同様に処理し、不快感を素早く解消しようとする報酬系の反応が怒りとして表れます。これが衝動的なリベンジエントリーを引き起こします。', false, 9),
(6, '【30分ルール】の目的として最も重要なものはどれですか？', '相場の変動が落ち着くのを待つため', '次のトレードチャンスを冷静に探すための時間を確保するため', '他のトレーダーの動きを観察してからエントリーするため', '感情の高ぶりが自然に収まる物理的なクーリングタイムを設けるため', 4, '30分ルールは、損切り後の感情的な高ぶりが収まるまで物理的にチャートから離れることで、衝動的なリベンジトレードを防ぐことが目的です。', false, 10),
(6, 'あるトレーダーが今日すでに2連敗している。感情的には「次こそ取り返せる」と感じているが、このまま3回目のトレードに入った場合、最も起きやすいことはどれですか？', '感情が乱れたまま判断するため、リベンジトレードの連鎖に入り損失がさらに拡大する', '2連敗は相場の流れが変わったサインで、逆方向にエントリーすれば回収できる', '連敗中は集中力が高まっているため、次のトレードは精度が上がる', '2連敗程度では感情への影響は小さく、冷静な判断が維持できている', 1, '2連敗後は感情が乱れており、「次こそ」という気持ちは冷静な判断ではなく感情の暴走サイン。だから損失上限ルール（2連敗→ロット半分、3連敗→その日終了）が必要で、自力で止められないから事前に仕組みで止める。', false, 11),
(6, '損切り後に感情メモを書く意義として最も重要なものはどれですか？', '自分の感情を客観視することで、リベンジトレードの衝動を弱めるため', 'トレード日記として後から振り返る記録を残すため', '他のトレーダーと感情を共有して共感を得るため', '感情のパターンを分析して、負けやすい時間帯を特定するため', 1, '「悔しい」「焦っている」「取り返したい」など感情を一言書き出すことで、自分の状態を客観視でき、衝動的な行動へのブレーキがかかりやすくなります。', false, 12),
(6, '損失上限ルールにおいて「2連敗でロットを半分にする」理由として最も適切なものはどれですか？', '連敗中は判断力が低下しており、3連敗目以降の損失を小さく抑えるため', '2連敗した時点で市場の環境が悪化している可能性が高いため', 'ロットを半分にすることで利益幅が広がり、損失を早く回復できるため', '資金の3%ルールと連動しており、自動的にロットを調整するため', 1, '連敗中は感情が乱れており、さらなる判断ミスのリスクが高い状態です。事前にロットを減らすことで、仮に3連敗目が来ても被害を最小限に抑えられます。', false, 13),
(6, 'リベンジトレードが最も危険な理由として、最も本質をついているものはどれですか？', '感情的な状態で判断が続くため根拠のないエントリーが繰り返され、自力では悪循環から抜け出せなくなるから', '取引回数が増えることで手数料コストが積み上がり、長期的に負の影響が出るから', '相場の方向性を無視してエントリーするため、ポジションの偏りが生じるから', '1日の取引時間が長くなることで集中力が落ち、判断の質が下がるから', 1, 'リベンジトレードの本質は「感情→根拠なしエントリー→さらに負ける→さらに感情的」という悪循環にある。感情が理性を上回っているため自力では止まらない。だから30分ルール・損失上限ルールという仕組みが必要になる。', false, 14),
(6, '損切りをした直後に取るべき行動として最も適切なものはどれですか？', 'すぐにチャートを分析して、同じ銘柄の再エントリーポイントを探す', '損失を取り戻すため、ロットを上げて別のエントリーチャンスを探す', '損切りの判断が正しかったか検証するため、すぐにトレード履歴を見直す', '30分間チャートを閉じて物理的に離れ、感情メモを書く', 4, '損切り直後は感情が高ぶっているため、30分ルールで物理的に離れ、感情メモを書くことで冷静さを取り戻すことが最適な行動です。', false, 15),
(6, '損切り後30分が経過し、次のトレードを検討しているトレーダーがいる。「ゼロから組み直す」を正しく実践できているものはどれですか？', '前回の損益を一切考慮せず、今この瞬間の相場状況だけを根拠にエントリーを組み立てている', '前回と同じ銘柄は避け、まったく別の銘柄で損失分を回収しようとしている', '前回の損失金額を今回の目標利益に設定し、取り返すシナリオを立てている', '前回使ったテクニカル指標を変更して、新しい分析手法でエントリーを探している', 1, '「ゼロから組み直す」とは前回の損益を完全に切り離し、今の相場だけを根拠に判断すること。「取り返す」「同じ銘柄を避ける」「手法を変える」はいずれも前回のトレードに引きずられており、ゼロには戻せていない。', false, 16),
(6, 'あるトレーダーが1回目のトレードで2万円の損失を出した直後、「取り返すぞ」と言いながらロットを1.5倍に増やして再エントリーしようとしている。この行動を止めるために最も効果的な対応はどれですか？', '損切り直後はチャートをすべて閉じ、30分間は物理的にトレードできない状態にする', 'ロット増加分が2%ルール内であれば問題なく、損失を合理的に回収する方法として有効', '損切り直後こそ集中力が高まっているため、すぐに次の分析を始めるべき', '2回目は1回目より慎重に分析し、精度の高いエントリーポイントを探す', 1, '「取り返すぞ」＋ロット増加は、感情（失った損失への執着と不快感を消したい衝動）が暴走しているサイン。このサインを認識した瞬間に30分ルールを発動し、物理的にチャートから離れることが唯一の有効策。', false, 17),
(6, '30分ルールを実践する際、最も効果的な具体的な行動はどれですか？', 'スマホのアプリも含めてすべての取引ツールを閉じ、別の部屋に行く', 'チャート画面は開いたままにして、別の銘柄の分析だけをする', 'デモトレードで練習してから、本番に戻る', '取引履歴を確認しながら、次の作戦を頭のなかで組み立てる', 1, '30分ルールの効果は「物理的にチャートから離れる」ことにあります。アプリも含めてツールを閉じ、別の部屋に行くなど、視覚的な刺激を完全に遮断することが最も効果的です。', false, 18),
(6, '次のうち、リベンジトレードを予防するルールとして機能しないものはどれですか？', '連敗3回でその日のトレードを終了する', '損失を出した直後に、損失分を回復できる銘柄をすぐに探す', '1日の損失が総資金の3%に達したらトレードを終了する', '2連敗した時点でロットを半分にする', 2, '損失直後に「回復できる銘柄を探す」行為は、まさにリベンジトレードそのものです。感情的なエントリーを促すだけで予防になりません。', false, 19),
(6, '連敗中に「今は調子が悪い」と自覚しながらもエントリーを止められないトレーダーに対して、最も有効な対策はどれですか？', 'メンタルを強化するために、あえて連敗を続けて耐性をつける', 'エントリー前に自分に「本当に根拠があるか」を問いかける習慣をつける', '連敗の原因をテクニカル分析の不足だと割り切り、勉強時間を増やす', 'あらかじめ損失上限ルールを自動的に执行できる仕組みを用意しておく', 4, '連敗中は感情が理性を上回り、自力でのコントロールが困難です。損失上限ルールを事前に決めておき、ルール通りの行動を仕組み化することが最も確実な予防策です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(7, 'あるトレーダーが「根拠が薄い」と感じながらもエントリーボタンを押すことが止められない。勝負の瞬間に得られる快感がこの行動を繰り返させている。この「止められない」仕組みの正体は何ですか？', 'エントリーの瞬間に脳内でドーパミンが放出され、結果に関わらず報酬回路が活性化するから', 'ポジションを持つことで相場への集中力が高まり、良い判断ができるようになるから', '取引回数が多いほど統計的に勝率が安定していくという期待があるから', 'エントリーしないと相場の流れに乗り遅れるという正当な危機感があるから', 1, 'エントリーの瞬間にドーパミンが放出され、結果に関係なく「報酬を得た感覚」が生まれます。この快感回路が根拠のないエントリーを繰り返させます。「押したい衝動」を感じたとき、それ自体が警戒のサインです。', false, 1),
(7, 'あるトレーダーは明確なセットアップがないのに「何かしなければ」と焦りを感じてエントリーしてしまう。翌日振り返ると「なぜ入ったのか分からない」という状況が毎週続いている。この行動の根本原因は何ですか？', 'チャートを長時間見ることで、実際にはないパターンが見えるようになるから', '常にポジションを持っていないと不安になる心理が、根拠のないトレードを駆り立てているから', 'エントリーしないと資金が時間とともに目減りするという誤った認識があるから', '集中力が高まると根拠が薄くても直感的に正しいエントリーができると思っているから', 2, '「ポジションがないと落ち着かない」感覚はFOMOとドーパミン報酬系が組み合わさって生じます。この衝動に気づかずエントリーを繰り返すと手数料が積み重なり口座を削ります。「焦り」を感じたらまずチャートから離れることが最初の対策です。', false, 2),
(7, '月20回トレードして勝率50%、リスクリワード比1:1の場合、手数料を含めた最終的な損益はどうなりますか？', '勝率50%なのでプラマイゼロで終わる', 'トレード回数が多いほどスプレッドが優遇されてプラスになる', '手数料は利益からのみ引かれるので、損失は増えない', '勝敗が同数でも手数料分だけマイナスになる', 4, '勝率50%・RR1:1では利益と損失が相殺され、全取引にかかる手数料だけが確実に差し引かれます。回数が多いほど手数料負担が膨らみ、結果的にマイナスになります。', false, 3),
(7, 'あるトレーダーが「今度こそ当たる」という期待が止まらず、負けても翌日また根拠の薄いエントリーをしてしまう。この「止められない」感覚を生み出している仕組みは何ですか？', '損失が続くと次は当たるという確率論的な期待が正当化されるから', '不確実な結果に対してドーパミンが放出される脳の仕組みが、繰り返しを促しているから', '相場に参加し続けることで統計的に勝率が収束していくという誤解があるから', 'ポジションを持つことで市場の動きが体感的に把握しやすくなると感じているから', 2, '「当たるかもしれない」という不確実性こそがドーパミンを放出させ、快感を生みます。スロットと同じ原理です。この仕組みを知ることで、衝動的なエントリーに「待て」をかける理由が腹落ちします。', false, 4),
(7, '月5回・勝率60%・RR1:2のトレードが月20回・勝率50%・RR1:1より成績が良い最大の理由は何ですか？', 'トレード回数が少ないほどブローカーのスプレッドが狭くなるから', 'エントリー基準を厳しくすることで低確率のトレードを排除できるから', '勝率60%を維持すれば回数に関係なく常にプラスになるから', '月5回以下なら手数料が無料になる仕組みがあるから', 2, '回数を絞ることで「本当に良いセットアップ」だけを厳選するようになり、勝率とリスクリワード比が同時に向上します。質の低いトレードを削り切ることが成績向上の鍵です。', false, 5),
(7, '「待つこと」に経済的価値がある理由として正しいものはどれですか？', 'トレードしない期間が長いほどブローカーから特別なレートが提供されるから', '待てば待つほどエントリーポイントの精度が上がるから', '余計な損失を防ぎ、次のチャンスにフルの資金で臨める状態を保てるから', '待っている間に相場のトレンドが自動的に予測できるようになるから', 3, '無駄なトレードで資金を削らずに済むことで、本当に良いチャンスが来たときに最大限のポジションサイズで臨めます。資金を温存すること自体が戦略的な行動です。', false, 6),
(7, 'あるトレーダーがSNSで他のトレーダーの大きな利益を見た瞬間、「このチャンスを逃すわけにいかない」と感じてルール外のエントリーをしてしまいました。この感情が繰り返しトレードを誤らせる理由は何ですか？', 'SNSの利益報告は実績データなので、同じ方向に乗らないと機会損失になるから', '相場は多くのトレーダーが同じ方向を向いたときに動くため、追従することが有効だから', '「見逃すことへの恐怖」が冷静な判断より強く働き、根拠のないエントリーを引き起こすから', 'チャンスを見逃すと次のセットアップが来るまで長く待つことになるから', 3, '「見逃すことへの恐怖」は実際のリスクより「チャンスを逃す痛み」を大きく感じさせます。この感情に従うと根拠のないエントリーになり損失を重ねます。SNSを見て焦りを感じたとき、それ自体がトレードを止めるサインです。', false, 7),
(7, '重要な経済指標の発表前にトレードを見送るべき理由として正しいものはどれですか？', 'ボラティリティが急拡大し、予測不能な値動きになるため', '指標発表前はブローカーが注文を制限するため', '指標発表前にエントリーするとスプレッドが3倍になるため', '指標の結果がすでに価格に織り込まれており動きがないため', 1, '重要指標の発表前後はボラティリティが急拡大し、スプレッドも広がりやすくなります。予測不能な値動きの中では技術的な根拠が通用しないため、見送るのが安全です。', false, 8),
(7, '連敗3回した状態でさらにトレードを続けると陥りやすい危険な行動はどれですか？', 'トレードルールを厳格にしてエントリー基準を高くする', 'ポジションサイズを半分にして慎重にトレードする', 'エントリーする銘柄を変えて気分を切り替える', '損失を取り返そうとルールを無視したエントリーに走る', 4, '連敗が続くと損失を取り返そうとする心理が強く働き、冷静さを失ってルールを無視したトレードに走りやすくなります。この「傾斜」に気づいて手を引くことが重要です。', false, 9),
(7, '損切り直後30分以内にトレードすべきではない理由は何ですか？', '損切りの執行に手数料が二重にかかるため', '損切りの痛みから「すぐ取り返したい」という衝動に駆られやすいため', 'ブローカーのシステムが30分間注文を制限するため', '損切りした銘柄は30分以内に必ず反発するため、二度負ける確率が高い', 2, '損切りの直後は損失の痛みが最も強く、「すぐに取り返したい」という衝動に駆られます。この感情は冷静な判断を奪うため、最低30分は距離を置くことが推奨されます。', false, 10),
(7, '「取り返したい」と感じている状態でトレードすると、どのような結果になりやすいですか？', '過去の損失に執着した根拠のないエントリーになり、さらに損失が膨らむ', '怒りが原動力になるため、かえって集中力が上がって良い結果が出る', '損失を取り返す目的があるため、自然的に慎重なトレードになる', '無意識に損切りラインが厳しくなり、小さな負けで済む', 1, '「取り返したい」という感情はサンクコスト効果の表れで、過去の損失に執着した根拠のないトレードを誘発します。冷静な判断が失われ、損失がさらに拡大しやすくなります。', false, 11),
(7, '体調不良や寝不足の日にトレードを見送るべき本質的な理由は何ですか？', '体調が悪いとチャートの色が見分けにくくなるから', 'ブローカーが体調不良時の取引を推奨していないから', '寝不足だとエントリーのタイミングが遅れて約定価格がずれるから', '認知機能と感情制御が低下し、冷静な判断とルールの遵守が難しくなるから', 4, '体調不良や寝不足は認知機能と感情制御を低下させます。トレードに必要な冷静な判断力とルール遵守が難しくなることが、見送るべき本質的な理由です。', false, 12),
(7, 'SNSで他のトレーダーの利益画像を見て焦りを感じたとき、最も適切な対応はどれですか？', '自分もすぐにエントリーして同じように利益を出す', 'そのトレーダーの銘柄をコピーして同じポジションを取る', 'トレードを見送り、SNSから離れて冷静になる', '小額のポジションで気分を落ち着かせてから本番に戻る', 3, 'SNSでの焦りはFOMOの典型的な引き金です。他人の結果は自分のトレードとは無関係であり、焦ってエントリーすると根拠のないトレードになるため、まずは画面から離れるべきです。', false, 13),
(7, '「やらない日」の過ごし方として最も効果的なものはどれですか？', 'デモトレードでエントリーの感覚を維持する', '小額のリアルトレードで感覚を衰えさせない', '過去トレードの振り返りやパターン観察の練習をする', 'SNSでトレーダーの意見を収集して次の戦略を練る', 3, 'トレードしない日は過去の振り返り、パターン観察、日誌の見返し、来週の計画などに使うのが最も効果的です。相場から離れつつも学習を深める有意義な時間になります。', false, 14),
(7, '自分のトレードルールに合うセットアップが見つからない日があります。このとき取るべき行動はどれですか？', 'エントリーせず、ルールに合うセットアップが現れるのを待つ', 'チャートの形が良さそうならルール外でもエントリーする', 'ルールをその場で少し緩めてエントリーの機会を作る', '新しいテクニカル指標を試すために小額でエントリーする', 1, '自分のルールに合うセットアップがない日は堂々とトレードしない日です。ルールを妥協してまでエントリーすることが、長期的な成績を悪化させる最大の要因になります。', false, 15),
(7, '月20回トレードしていたトレーダーが月5回に絞ったところ、勝率が50%から60%に上がり口座の減少が止まりました。トレード回数を減らしただけで成績が改善した主な理由は何ですか？', '取引回数が少ないとブローカーのスプレッドが優遇されるから', '回数を絞ることで各トレードへの集中力が増し、技術的な精度が上がるから', '根拠の薄いエントリーが排除され、手数料負担と低質なトレードが同時に消えたから', '月5回以下のトレーダーは参加者が少ない有利な時間帯を自然に選べるから', 3, '回数を絞ると「本当に良いセットアップだけ」に自然に絞られ、根拠の薄いエントリーが消えます。同時に毎回かかる手数料も激減します。「やらない判断」は消極的ではなく、成績を改善する積極的な戦略です。', false, 16),
(7, '「待つこと」の経済的価値のうち、「感情がニュートラルな状態で判断できる」とはどういう意味ですか？', '前のトレードの勝敗に影響されず、冷静に次のエントリー根拠を組み立てられるということ', '待っている間に感情的な記憶が消去されるということ', 'トレードしない期間が長いほど感情が麻痺して何も感じなくなるということ', '待つことで相場に対する恐怖心が完全に消滅するということ', 1, '前回のトレードで勝っても負けても感情が揺さぶられます。適切に待つことで感情がリセットされ、次のトレードを独立した冷静な判断で臨めるようになります。', false, 17),
(7, '「連敗が3回続いている」「体調が悪い」「相場の方向感がない」の3条件が重なっているとき、このトレーダーが取るべき判断はどれですか？', '体調不良だけでは理由として弱いので、方向感が出るのを待ってエントリーする', '連敗が続いているため、損失を取り返すために早めにエントリーする', '3条件すべてが「やらない」基準に該当するため、今日は完全にトレードを見送る', '小額のポジションならリスクが低いため入っても問題ない', 3, '方向感のなさ・連敗3回・体調不良はいずれもトレードを見送るべきサインです。複数の条件が重なっている日は判断力・冷静さ・相場環境のすべてが整っていません。「やらない」がこの日の最善のトレードです。', false, 18),
(7, 'あなたが損切りした直後、SNSで他のトレーダーの利益画像を見て焦りを感じました。この状況で取るべき最善の判断はどれですか？', '損切りの直後なので30分待ってから、SNSの銘柄を参考にエントリーする', 'SNSの利益画像は信用できないので、自分の分析ですぐに別の銘柄を探す', '焦りを感じているうちはエントリーせず、翌日までトレードを休む', '損切り後の30分ルールを守りつつSNSから離れ、感情が落ち着くまで待つ', 4, '損切り直後は「取り返したい」衝動、SNSはFOMOの引き金という二重の感情リスクがあります。30分ルールを守りSNSから離れることで、両方の感情に対応できます。', false, 19),
(7, 'トレード回数を月20回から月5回に減らしたトレーダーが、勝率50%から60%に向上しました。この変化が起きた理由として最も説明できるものはどれですか？', '手数料が減った分が利益に反映され、勝率の計算結果が上がっただけだから', '月5回しかエントリーできないという制約がプレッシャーになり、集中力が上がるから', '厳しい基準を満たすセットアップだけに絞ることで、低確率の見送り案件を排除できたから', 'トレード回数が少ないほど運が良くなる傾向があるから', 3, '回数を絞ることで「本当に良いセットアップ」だけを厳選するようになり、根拠の薄いトレードを排除できます。選択と集中によって勝率が向上するのが本質的な理由です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(8, '急激に上昇しているのを見て「乗り遅れたくない」とエントリーしたが、直後に急落して損切りになった。この失敗の本質的な原因は何か？', '急騰後は参入した勢力の利確売りが始まる天井付近になりやすく、その後の買い圧力が枯れて反落しやすいから', '急騰時はスプレッドが拡大してエントリーコストが跳ね上がるから', 'ブローカーが急騰中の約定を意図的に遅らせているから', 'エントリーボタンを押すのが遅くてベストな価格に入れなかったから', 1, '「乗り遅れ感」でのエントリーは、すでに参入した勢力の利確売りが始まる天井付近になりやすい。大きく動いた後こそ「待つべき場所で待つ」ことが連続損失を防ぐ。', false, 1),
(8, '逆張り病の本質的な問題として正しいものはどれですか？', 'トレンドの転換点を正確に予測することが技術的に不可能だから', '逆張りは常にトレンド追随よりもリスクが高いと数学的に証明されているから', '逆張りエントリーはブローカーの約定システムに不利なスリッページが発生するから', 'トレンドは想像よりも長く続くため、「そろそろ反転するだろう」という予想が外れやすいから', 4, '逆張り病は「そろそろ反転するだろう」という主観的な予想に基づきますが、トレンドは想像より長く続くのが相場の性質であり、逆張りは損失を膨らませやすい手法です。', false, 2),
(8, 'サポートラインに価格が到達したのを確認して即座にエントリーしたが、そのままラインを割り込んで損切りになった。何が足りなかったか？', '上位足でのトレンド方向を確認していなかった', '価格到達だけでなく、反発の兆候（確定ローソク足など）を確認するエントリー条件が欠けていた', '損切りラインを十分に広く設定していなかった', '複数のサポートラインを引いて精度を高めていなかった', 2, '価格がラインに到達しただけでは「トリガー」にならない。反発の兆候（確定ローソク足・出来高など）を確認するステップを飛ばすと、フェイクに引っかかり損失が重なる。', false, 3),
(8, '感情エントリーの対策として提示されている「5秒ルール」とは具体的にどのような方法ですか？', 'エントリー後に5秒待って損失が拡大しないか確認する', '5秒間チャートを見つめ続けてエントリー根拠を探す', 'エントリーボタンを押す前に5秒止まり、「今、冷静か？」と自分に問う', '5秒以内にエントリーを完了させないとチャンスが消えるという認識を持つ', 3, '5秒ルールはエントリー前に5秒止まって冷静さを確認する方法です。「ワクワクする」だけで飛び込む感情エントリーを防止する具体的な歯止めです。', false, 4),
(8, 'エントリーしたいが使っているインジケーターが矛盾するシグナルを出していて決断できない。情報を増やすほど判断が難しくなっている。この状態が続くとどうなるか？', 'データが増えるほど精度が上がり、やがて確実な場面だけ取れるようになる', '矛盾するシグナルに迷い続け、良い場面でもエントリーできないまま機会を損失し続ける', '全てのインジケーターが一致した瞬間だけ取れる高精度トレードができる', '分析力が磨かれてシンプルな根拠だけで判断できるようになる', 2, '情報を集めすぎると「矛盾するシグナル」が増えて判断が止まる。使う指標を絞り「条件が揃わないなら見送り」と事前に決めることが、この状態から抜け出す方法だ。', false, 5),
(8, '含み損−8万円のポジションを持つトレーダーが「ここまで持ったんだから損切りするのはもったいない」と感じて手放せない。この判断の何が問題か？', '過去に投じたコストへの執着が現在の相場判断を歪め、損失がさらに拡大するリスクを見えなくしている', '損切りすると次のトレードに使える資金が不足するから', '長期保有すれば相場は必ず回復するという認識が欠けているから', '損切り後に相場が反転するケースが多いため、保有継続が正しいから', 1, '過去に払ったコストは取り戻せない。「ここまで持ったから」という感情は相場の現状と無関係で、それに縛られると損失が膨らみ続ける。「今ノーポジなら入るか？」と問い直すことで感情を切り離せる。', false, 6),
(8, '損切りできない病に対する対策として提示されている「今ノーポジなら入るか？」という問いかけが効果的な理由はどれですか？', '現在のポジションを一旦決済してエントリーし直すことで心理がリセットされるから', '含み損のサンクコスト感情を排除し、純粋にエントリー根拠だけを客観的に評価できるから', 'ノーポジ状態で考えると常にエントリーしない方がよいという結論になるから', '問いかけることで時間が経過し、自然と相場が好転する確率が上がるから', 2, '「今ノーポジなら入るか？」と問うことで、含み損のサンクコスト感情を排除し、純粋にエントリー根拠の有無だけを客観的に評価できます。', false, 7),
(8, '大きな損失を出した直後、「今すぐ取り返さなければ」という衝動でルールを無視して連続エントリーを続けた。なぜこれが特に危険か？', '連続エントリーはスプレッドコストが積み重なって損益が悪化するから', '損失への怒りと焦りがすべての判断基準を感情に書き換えてしまい、損失が連鎖して拡大するから', '短時間に多くのトレードをするとブローカーに制限がかかることがあるから', '損失直後は集中力が低下してエントリータイミングがずれるから', 2, '「取り返したい」衝動はすべてのルールを無効にする。この状態でのトレードは感情が判断を全支配し、損失の連鎖を招く。気づいた瞬間に30分チャートを閉じることが唯一の歯止めになる。', false, 8),
(8, 'エントリー後に含み損が拡大し始めたとき、「やはり反転するかもしれない」と損切りラインを下方修正した。この行動の最も大きなリスクは？', '損切りラインを変えると証拠金維持率が下がって強制決済されやすくなるから', '含み損の不安に動かされてルールを書き換えると、小さな損が取り返せない大損に育つから', '損切りラインを動かすと取引コストが余分にかかるから', 'ラインを変えることで他のトレーダーにポジションが見えてしまうから', 2, 'エントリー後のシナリオ変更はほぼ100%感情によるもの。「含み損が怖い」という気持ちが計画を書き換えるたびに損失の上限が際限なく広がる。計画はエントリー前に固定し、後から変えないことが鉄則だ。', false, 9),
(8, '連勝後のロット上げが危険な理由として最も的確なものはどれですか？', '連勝後はブローカーが約定レートを不利に操作する仕組みになっているため', '連勝中は相場の環境が良いだけで技術が向上しているわけではないため、次の1敗でそれまでの利益を全て消し去る可能性がある', 'ロットを上げると強制決済のリスクが高まる仕組みになっているため', '連勝後のエントリーは勝率が統計的に下がることが証明されているため', 2, '連勝中は「ついてる！」と勢いに乗りやすく、ロットを上げた状態で1回負けるとそれまでの利益を全て消し去るリスクがあります。ロットは事前計画で固定すべきです。', false, 10),
(8, '3連敗した後、「このまま負けっぱなしは許せない」という気持ちで次のトレードのロットを2倍に上げた。このとき最も起きやすいことは？', '大きなロットで勝てれば損失を一気に取り戻せる', '焦りで判断が乱れた状態でリスクを倍増させるため、さらに損失が重なって口座が大きく削られる', 'ロットが上がると気合いが入り、集中力が増して勝率が上がる', 'ロットが大きいほど利幅も増えるため、損益がプラスに転じやすい', 2, '連敗後のロット増は「取り返したい」感情が動かすリベンジ行動だ。ただでさえ判断が乱れているときにリスクを増やすと、一度の負けで口座が大きく削られる。連敗後はむしろロットを半分に落とすことが推奨される。', false, 11),
(8, '5分足で上昇トレンドを確認して買いエントリーしたが、日足では大きな下降トレンドの最中だった。損切り後に気づいた。何が根本的な原因か？', '5分足の分析精度が不十分だったから', '短い時間足の局所的な動きだけを見てエントリーし、大きなトレンドの方向を確認しなかったから', '上昇トレンドへの買いエントリーはリスクが高いから', 'エントリー根拠が揃う前に急いで入ったから', 2, '短い時間足の「上昇」は上位足の下降トレンド内の一時的な反発に過ぎない。エントリー前に上位足でトレンド方向を確認する習慣がないと、大きな流れに逆らったポジションを繰り返し取ることになる。', false, 12),
(8, '確証バイアスのトレードにおける典型的な現れ方として正しいものはどれですか？', '自分のポジション方向に有利な情報だけを集め、不利な情報を無視する', '複数の時間足を確認せずに一つのチャートだけで判断する', 'エントリー後に損切りラインを何度も下方修正する', '他人のトレード結果を見て自分の判断を変える', 1, '確証バイアスは「自分が信じたいこと」を裏付ける情報だけを集め、矛盾する情報を無視する認知バイアスです。買いポジションを持っていれば上昇の根拠ばかり探してしまいます。', false, 13),
(8, 'フェイクブレイクに引っかかるトレーダーの典型的な行動として正しいものはどれですか？', '一瞬だけラインを抜けたのを見て飛び込むが、すぐに戻されて損切りになる', 'レンジ相場ではエントリーせず、明確にブレイクした後だけエントリーする', 'ブレイクした後に数本ローソク足を待ってからエントリーする', '複数の時間足でブレイクを確認してから慎重にエントリーする', 1, 'フェイクブレイクは一瞬だけラインを抜ける現象で、これに飛び込むとすぐに戻されて損切りになります。ブレイクの確認にはローソク足の確定や再テストを待つことが重要です。', false, 14),
(8, '利確早すぎ病の対策として提示されているものはどれですか？', '利確後にすぐ次のエントリーをして利益を積み重ねる', '含み益が減る不安をなくすために常に両建てにする', '利確目標を事前に設定し、そこに到達するまでポジションを維持する', '利確のタイミングは直感に頼り、含み益が出たらすぐに手放す', 3, '利確早すぎ病は少しの含み益で焦えて確定してしまう癖です。対策は利確目標を事前に設定し、目標に到達するまでポジションを維持するルールを守ることです。', false, 15),
(8, '「今日だけ特別」症候群について、「今日だけ」と思った瞬間に何が最も危険だと言われていますか？', 'その瞬間がその日の最もエントリーに適したタイミングである可能性が高いから', '「今日だけ」と思った瞬間こそが最も危険な状態であり、ルールを破る入口だから', '「今日だけ」と考えたトレードは勝率が統計的に低いことが分かっているから', '特別な日は相場のボラティリティが高くなり予測不能になるから', 2, '「今日だけルールを少し緩めてもいい」「今日だけロットを上げてもいい」と思った瞬間が最も危険です。この思考がルール崩壊の入口であり、一度崩すと戻りにくくなります。', false, 16),
(8, '半年間トレードを続けているが、同じ失敗を繰り返していることに自分では気づいていない。この状況が続く最大の原因として考えられることは？', '半年は実力をつけるには短すぎるから', '取引記録をつけておらず、自分のパターンを客観的に振り返る材料がないから', 'デモトレードから本番に移行するのが早すぎたから', '感情的なトレードが癖になっていて自力では直せないから', 2, '記録がなければ失敗の原因に気づけず、同じパターンを無限に繰り返す。「エントリー理由・結果・反省」を3行書くだけでも自分のクセが見え始め、成長の土台になる。', false, 17),
(8, 'チャートを開いて「なんとなくいけそう」と感じてエントリーしたが、根拠が曖昧で損切りになった。何が欠けていたか？', '毎日決まった手順（上位足確認→エントリー条件確認→シナリオ設定）を踏んでからエントリーする習慣', '相場環境の把握に役立つインジケーターの追加', '過去チャートを使った徹底的な検証', 'エントリー後に素早く利確するスキル', 1, '「なんとなく」は分析手順を飛ばしたサインだ。毎日のルーティン（上位足確認→エントリー条件確認→シナリオ設定）を守ることが、感情ではなく根拠に基づくトレードの土台になる。', false, 18),
(8, 'トレンド終盤に参入したトレーダーが巻き込まれやすい現象はどれですか？', 'スプレッドが極端に狭くなり利益が出にくくなる', '大口の売り抜けに巻き込まれて天井で掴まされる', '相場のボラティリティが低下してポジションが膠着する', 'ブローカーのシステムトラブルで決済できなくなる', 2, 'トレンド終盤への参入は、すでに利益を確保した大口投資家の売り抜けに巻き込まれるリスクが高いです。長く続いたトレンドの最後に飛び乗るのは典型的な負けパターンです。', false, 19),
(8, '「追いかけエントリー＋損切りできない＋リベンジ」の複合パターンが引き起こす結果として最も正しいものはどれですか？', '手数料負けしてコツコツ損失が積み重なる', '一つのトレードで大きな損失を出すが、そこで止まる', '感情的なエントリーになるが、損切りで最小限の損失に抑えられる', '連鎖的な大損に繋がる', 4, '追いかけエントリーで天井を掴み、損切りできずに含み損を抱え、最後にリベンジトレードでさらに損失を拡大する連鎖は、最も破壊的な負けパターンの組み合わせです。一つの失敗が次の失敗を呼ぶ連鎖的大損に繋がります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(9, 'あるトレーダーがエントリーボタンを押した直後に「あ、今焦って計画外のトレードをしてしまった」と気づき、すぐにポジションを手仕舞った。この行動を可能にした能力として最も正しいものはどれですか？', '過去のトレード統計を瞬時に思い出す記憶力', '自分の思考を客観的に観察する「もう一人の自分」を持つメタ認知', 'エントリー後の損失を最小化するストップロスの設定技術', 'チャートパターンを高速認識するテクニカル分析能力', 2, '「今焦っている自分に気づく」のがメタ認知。感情を消すのではなく観察する視点を持つことで、衝動的な行動の直後でも修正できる。気づきがなければ損失はそのまま拡大し続ける。', false, 1),
(9, 'トレード中に「含み損が怖くて早く決済したい」という感情が出てきたとき、メタ認知を活用できているトレーダーの反応として最も適切なものはどれですか？', '感情を意識から切り離し、チャートだけに集中する', '「今、恐怖を感じている自分がいる」と気づき、その感情を客観的に観察する', 'ポジティブな思考に切り替えて恐怖感を打ち消す', '感情が出てくること自体がトレーダーとして未熟なサインである', 2, 'メタ認知は感情を消すのではなく「感情を感じている自分に気づく」こと。恐怖に気づければ「これは計画外の判断か？」と確認でき、損切りルールに従う行動が取れる。気づきがなければ感情に流されて決済してしまう。', false, 2),
(9, 'お腹が空いている状態でスーパーに買い物に行くと、必要のないものまで買ってしまいがちです。この日常例が示すメタ認知の効果として最も適切なものはどれですか？', '「今お腹が空いているから判断が狂っている」と気づけば、カゴの中を見直すことができる', 'お腹が空いている時はスーパーに行ってはいけないという絶対ルールを示している', '買い物リストを事前に作っていれば空腹の影響は完全に防げる', '空腹時の買い物は精神的に問題がある行動で、自己制御力の欠如を示している', 1, '「今お腹が空いているから判断が狂っているな」と気づくことがメタ認知です。気づきがあれば行動を修正でき、トレードでも同じ原理が働きます。', false, 3),
(9, 'エントリーボタンを押そうとした瞬間、「これ計画外かもしれない」と感じた。5秒ルールを正しく実践するとき、次にすべき行動として正しいのはどれですか？', 'チャートを再分析してエントリー根拠を強化する', '5秒止まり、声に出して「今、冷静か？」と自分に問う', 'ロット数を半分にしてリスクを下げてからエントリーする', '5秒カウントダウンが終わったらそのままボタンを押す', 2, '5秒ルールはボタンを押す前に5秒止まり、「今、冷静か？」と声に出して問うこと。答えがNoならその日はトレードしない。物理的に一瞬止まる仕組みが、衝動的なエントリーを防ぐ唯一の歯止めになる。', false, 4),
(9, '5秒ルールを実践した結果、「今、冷静か？」という問いに対する答えがNoだった場合、取るべき行動として正しいものはどれですか？', '深呼吸を3回行った後、必ずエントリーする', 'エントリーサイズを半分にして冷静さを取り戻してから実行する', 'その日はトレードしない', 'デモトレードに切り替えてエントリーの感覚を確かめる', 3, '「今、冷静か？」への答えがNoなら、その日はトレードしません。無理にトレードする必要はなく、感情が高ぶっている時のトレードはリスクが高くなります。', false, 5),
(9, '「今すぐ入らないとチャンスを逃す！」と焦りを感じ、5秒ルールをスキップしてエントリーしたトレーダーがいる。この判断について最も適切な評価はどれですか？', '素早い決断力があるトレーダーの行動で、むしろ良い判断だ', '5秒立ち止まるだけで逃すような機会は、そもそも自分の戦略に合わないトレードだった可能性が高い', '短期トレードでは5秒ルールを使わない方が結果が出やすい', 'エントリー後にすぐ損切りラインを設定すれば問題ない', 2, '冷静に5秒止まるだけで逃してしまうチャンスは、計画に基づくトレードではない。焦りからのエントリーは感情的判断のサインで、そのまま進めると損失リスクが高くなる。逃したように見えても、それが正しい判断だ。', false, 6),
(9, '損切りをして「なんでこうなるんだ」と怒りを感じた。この後、メタ認知の3ステップを正しく実践したのはどれですか？', 'まず日記に記録し、それから感情の名前を考え、最終的に気づきを得た', '「怒りがある」と気づき、「損切りが悔しくて取り返したい焦り」と名前をつけ、日記に記録した', 'まず感情を深く分析し、次に記録し、最後に気づくプロセスを踏んだ', '「怒り」と名前をつけ、次に自分の感情に気づき、最後に記録した', 2, 'メタ認知は「①気づく→②名前をつける→③記録する」の順。気づかずに名前はつけられず、名前をつけずに記録しても効果が薄い。怒りに気づき、言葉にして書き残すことで、同じパターンを繰り返すリスクが下がる。', false, 7),
(9, 'トレードを始めたばかりのトレーダーが「チャート中は集中していて感情に気づけないが、終わった後に振り返ると焦っていたと分かる」と言っている。この状態について最も適切な評価はどれですか？', 'リアルタイムで気づけない時点でメタ認知の練習は意味がない', 'トレード後に気づけるだけで、メタ認知の第一歩として十分だ', '感情に気づくには瞑想を先に1ヶ月続けて精神を鍛える必要がある', 'トレード中に気づけないなら、感情日記だけ書けば問題ない', 2, '最初はトレード後の振り返りで気づくだけでOK。リアルタイムで気づく力は練習で育つ。事後の気づきを繰り返すことで、徐々に「今、焦っている」とトレード中に自覚できるようになっていく。', false, 8),
(9, '損切り後に「もう最悪だ」と漠然と感じながらトレードを続けるより、「損切りが悔しくて取り返したい焦りを感じている」と言葉にした方が感情の暴走を防ぎやすい理由として、最も正しいものはどれですか？', '長い文章で考えることで、感情が複雑に処理されて弱くなるから', '感情に具体的な名前をつけることで、脳の扁桃体の活動が抑制されるから', '言葉にすると記憶として固定され、次回から同じ感情が湧かなくなるから', '長く考えることで時間が経過し、感情が自然と落ち着くから', 2, '感情に具体的な名前をつける（ラベリング）と扁桃体の活動が抑制される。「イライラ」より「損切りが悔しくて取り返したい」の方が具体的で効果が高く、衝動的なリベンジトレードに踏み出す前に自分を止めやすくなる。', false, 9),
(9, '「イライラしている」という感情をラベリングする際、より効果的な表現として適切なものはどれですか？', '「ネガティブな感情がある」と抽象的に表現する', '「感情スコア3」と数値だけを記録して感情の内容は書かない', '「損切りが悔しくて取り返したいと思っている」と具体的な原因まで含めて表現する', '「イライラしている」とだけ一言で表現する', 3, 'ラベリングは具体的に行うほど効果的です。「イライラ」だけでなく「何に対して」「どうしたいのか」まで言葉にすることで、扁桃体の抑制効果が高まります。', false, 10),
(9, '「なぜあの時あんな判断をしたのか、毎回振り返っても同じミスを繰り返す」と悩むトレーダーがいる。頭の中では「焦っていた」と分かっているのに改善しない。最も効果的な対策はどれですか？', 'テクニカル分析の精度を上げることで、そもそも迷わない状況を作る', 'トレード前後の感情を毎回日記に書き出して記録し、パターンを可視化する', '失敗の原因は運なので、新しい手法に切り替える方が早い', '同じミスが減るまでポジションサイズを小さくして練習する', 2, '「分かっているつもり」は変わらない。書く行為自体が客観性を生み、頭の中だけでは見えなかった自分のパターンを可視化する。記録が積み重なることで「自分はどんな状況で焦るのか」が初めて見えてくる。', false, 11),
(9, '毎日の損益は記録しているのに「なぜあの時あんな判断をしたか」が月末になっても分からないトレーダーが、再発防止のために追加すべき記録として最も効果的なのはどれですか？', 'エントリーした価格・根拠・チャートのスクリーンショット', 'トレード前の感情・トレード中の変化・トレード後の感情とスコア（1〜5）', 'その日の市場環境・使ったインジケーター・利益率の目標達成度', '取引した時間帯・使ったロット数・スプレッドのコスト', 2, '損益だけでは「なぜその判断をしたか」は分からない。感情の流れ（前・中・後）を記録することで、自分がどんな感情状態のときに判断を誤るかが初めて見えてくる。これが再発防止の根拠になる。', false, 12),
(9, '感情日記をつけているトレーダーが「今日は感情スコア5だった。たくさん取引できて充実感がある」と記録した。このスコアについて最も適切な評価はどれですか？', 'スコア5は最もよい状態を示すので、充実感があるのは正しい', 'スコア5は感情的になってトレードした日を意味し、判断の質が低かった可能性が高い', 'スコアの高さと充実感は比例しないが、トレード回数が多い日は問題ない', '感情スコアは気分の良さを記録するものなので、高い方が望ましい', 2, '感情スコアは1（完全に冷静）〜5（感情的だった）を示す指標。スコアが高い日は感情的にトレードしており、損失につながるリスクが高い。「充実感」を感じるときほど、実は感情に流されているサインかもしれない。', false, 13),
(9, 'メタ認知が最も難しくなる瞬間について、適切な説明はどれですか？', '感情が暴走している最中にメタ認知を発動するのが最も難しい', '大きな利益が出て自信に満ちている時にメタ認知が最も難しくなる', 'トレードを始めたばかりの初心者期間だけメタ認知が難しい', 'トレードをしていない休場日にメタ認知が最も難しくなる', 1, '感情が暴走している最中は、メタ認知を発動する余裕がなく最も難しい瞬間です。だからこそ、感情が暴走する「前」に物理的な歯止めを作っておくことが重要です。', false, 14),
(9, '「損切り後、冷静になるつもりでもすぐ次のエントリーをしてしまい、さらに損失を拡大させてしまう」と繰り返すトレーダーへの、メタ認知の観点から最も効果的なアドバイスはどれですか？', '損切り後は深呼吸を3回して気持ちを整えてから判断する', '「損切り後30分はチャートを閉じる」という事前ルールを設定し、必ず守る', '損切りの直後にその原因を分析して次のエントリーで活かす', '損切りの痛みに慣れるため、同じ手法で続けてエントリーし続ける', 2, '感情が暴走している最中にメタ認知を発動するのは難しい。冷静なときに「損切り後30分は閉じる」と決めておくことで、感情的になった自分でもルールが機能する。事前の仕組みが、意志力に頼らずに行動を変える唯一の方法だ。', false, 15),
(9, '「自分はメンタルが強いからセーフティネット（連敗ストップなどのルール）は不要だ」と考えているトレーダーがいる。この考え方の何が危険ですか？', 'セーフティネットを使わないと証券会社から口座停止される可能性がある', '感情の暴走は意志の強さに関わらず誰にでも起こり得るため、仕組みで防ぐ必要がある', '強いメンタルを持つ人は少数なので、ほとんどのトレーダーには当てはまらない前提だ', 'セーフティネットは義務ではないが、使わないと利益が出にくくなる', 2, '感情の暴走はメンタルの強さや意志力の問題ではなく、誰にでも起こる。「自分は大丈夫」という過信がセーフティネットを外す最大のリスク。冷静に判断できる時こそ、仕組みを設計しておく必要がある。', false, 16),
(9, '連敗が続いている日のトレードに対する適切な対応として、メタ認知の観点から最も望ましいものはどれですか？', '連敗を取り返すために次のエントリーでロットを増やす', '連敗3回を超えた時点でその日のトレードを終了する事前ルールを守る', '連敗中は時間足を短くしてエントリー回数を増やし確率を上げる', '連敗は運が悪いだけと考えて、同じやり方でエントリーを続ける', 2, '「連敗3回で終了」という事前ルールは、連敗による焦りや取り返し心理が暴走する前に物理的にストップをかけるセーフティネットです。ルールを守ることが長期的な生存につながります。', false, 17),
(9, '損切り直後に最も起こりやすい心理状態と、それに対する適切な対応の組み合わせとして正しいものはどれですか？', '好奇心 → 損切りの原因をすぐに分析して次のトレードに活かす', '悔しさと取り返し心理 → 30分間チャートを閉じて冷静さを取り戻す', '安心感 → すぐに次のエントリーをして流れに乗る', '無関心 → 感情がないのでそのままエントリーを続けて問題ない', 2, '損切り直後は「悔しさ」や「取り返したい」という心理が強く働きやすく、この状態でのエントリーは更なる損失の原因になります。30分間チャートを閉じるなど物理的な距離を取ることが有効です。', false, 18),
(9, 'あるトレーダーが「損切り後すぐにエントリーして更に損失を拡大させてしまった」という経験をしています。次回から同じ過ちを繰り返さないために、メタ認知の3ステップを踏まえて最も効果的な対策はどれですか？', '損切りのたびにトレード日記に反省文を3行以上書く', '損切りの上限額を1日あたりの利益目標額と同じ額に設定する', '損切りをした時だけエントリーのロット数を減らす運用ルールを追加する', '「損切り後は取り返したくなる」と気づき、「焦り」とラベリングし、「損切り後30分はチャートを見ない」と記録して徹底する', 4, 'メタ認知の3ステップ（気づく→名前をつける→記録する）を適用すれば、「損切り後の焦り」というパターンに気づき、それを言葉にし、具体的な行動ルールとして記録することで再発防止につながります。', false, 19),
(9, 'トレード前に「早くエントリーしないとチャンスを逃す」と焦りを感じている時、メタ認知を活用した対応として最も適切なものはどれですか？', '焦りは行動の原動力になるので、そのままエントリーして勢いに乗る', '焦りを感じたら必ず1時間待ってからエントリーを判断する', '焦りを感じた時は逆張りエントリーが有効なので、皆と逆の方向にエントリーする', '「今、焦っている。これはFOMO（見逃し恐怖）だ」とラベリングし、5秒ルールで冷静さを確認する', 4, '焦りに気づいて「これはFOMOだ」とラベリングし、5秒ルールで冷静かどうかを確認するのがメタ認知を活用した対応です。感情に名前をつけることで客観視でき、5秒止まることで衝動的なエントリーを防げます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(10, '人間がトレード結果を振り返る際、最も起こしやすい認知の偏りとして当てはまるものはどれですか？', '勝った時は「実力」、負けた時は「運が悪い」と処理してしまう', '勝った時も負けた時も等しく「運」のせいにしてしまう', '勝った時は「たまたま」、負けた時は「自分の実力不足」と分析してしまう', '勝敗に関わらず常に自分の判断プロセスを正確に記憶できる', 1, '人間は勝った時は「自分の実力」、負けた時は「運が悪い」と正当化する傾向があります。この自己肯定的な記憶の偏りがあるため、日誌による客観的な記録が必要です。', false, 1),
(10, '毎週の損益は確認しているが「なぜ勝ったのか、なぜ負けたのか」の原因が毎回分からない。トレード日誌をつけることで、この問題はどう改善されるか？', '他のトレーダーと損益を比較し、競争心を養える', '感情や思い込みを排除し、データで自分の行動パターンを把握できる', '自動的に新しいテクニカル指標を開発できるようになる', '毎日の損益を税務申告用に正確に記録できる', 2, '人間の記憶は「勝ちは実力、負けは運」と歪みやすい。日誌はその歪みを排除し、データで自分を見るツール。繰り返す負けパターンを発見して行動を変えるきっかけになる。', false, 2),
(10, '日誌を始めて3日目に「量が多くて面倒」と感じ、辞めそうになっている。継続するための最善策はどれか？', 'エントリー価格・決済価格・損益額の3項目に絞る', '根拠・結果・感情の3項目だけに絞る', 'テクニカル指標・チャートパターン・時間足の3項目にする', '市場環境・経済指標・ニュースの3項目にする', 2, '面倒の原因は記録量の多さ。根拠（なぜ入ったか）・結果・感情の3項目は振り返りに必要な最小単位で、これだけ継続すれば自己パターンが見えてくる。', false, 3),
(10, 'トレード日誌を始めたばかりの人が「何を書けばいいかわからない」という悩みに対する解決策として適切なものはどれですか？', 'プロのトレーダーの日誌をそのままコピーして使う', '毎回異なるフォーマットを試して最適なものを探す', '書く内容を毎日の気分で自由に決める', 'テンプレートに従って書く', 4, '「何を書けばいいかわからない」という悩みには、テンプレートに従って書くことが対策として提示されています。決まった枠組みがあれば迷わず記録できます。', false, 4),
(10, 'トレード日誌をつける際の「完璧主義」を克服する考え方として正しいものはどれですか？', '毎回必ず5行以上書かないと意味がない', '1行でもいいから書くことが大切', '週に1回まとめて書く方が効率的である', '項目を全て埋められなかった日は記録しない', 2, '完璧主義による挫折を防ぐため、「1行でもいい」という考え方が提示されています。書かない日を作るより、短くても継続することに価値があります。', false, 5),
(10, '日誌を2週間続けたが成績に変化がなく「もう意味がないかも」と感じている。このトレーダーへの正しいアドバイスはどれか？', '1週間で効果がなければ方法を変えるべきだ', '1か月続けると変化が現れ、3か月で確実に変わってくる', '半年経たないと一切効果は出ない', '成績が変わらないのは書き方が間違っているサインだ', 2, '日誌の効果は1か月で変化が現れ、3か月で確実に変わる。2週間で辞めてしまうと、自分のパターンが見えてくる前に断念することになる。', false, 6),
(10, 'トレードの評価を「勝ち負け」ではなく「ルール遵守度」で行う理由として最も適切なものはどれですか？', 'ルールを守っていれば必ず毎回利益が出るから', '勝率を気にすると精神的に負担がかかるから', '結果ではなく過程を評価することで、長期的に安定したトレードができるから', 'プロのトレーダーは全員ルール遵守度で評価しているから', 3, 'トレードの結果（勝ち負け）は短期的には運の要素も含みますが、ルールを守る過程を評価することで、長期的に利益を出す確率を高めることができます。', false, 7),
(10, 'ルール通りに損切りをして損失が出たトレードについて、正しい評価はどれですか？', '損失が出たのだから「悪いトレード」である', 'ルールを守れなかった証拠であり、損切りルール自体を見直すべきである', 'ルール通りに損切りできたのだから「良いトレード」である', '損切りのタイミングが遅かった可能性が高く、改善が必要である', 3, 'ルール通りに損切りできた場合は、結果が損失であっても「良いトレード」と評価します。ルールを守ること自体が長期的な生存に直結するからです。', false, 8),
(10, 'ルールを破って利益が出たトレードについて、なぜ「悪いトレード」と評価すべきですか？', '利益が出ても手数料で消えてしまうから', 'ルールを破った利益は税金が高くなるから', '一度ルールを破ると二度とルールに戻れなくなるから', '間違った成功体験を脳に刻み、次回もルールを破る原因になるから', 4, 'ルールを破って利益が出た場合、「ルールを破っても勝てた」という間違った成功体験が脳に刻まれます。これが次回以降もルール違反を繰り返す原因になります。', false, 9),
(10, 'ルール遵守度と長期的なトレード成績の関係について、正しい記述はどれですか？', 'ルール遵守度50%以下では、どんな手法でも資金を減らす可能性が高い', 'ルール遵守度80%以上ならどんな手法でも利益が出る', 'ルール遵守度が低くても、勝率が高ければ長期的に利益を出せる', 'ルール遵守度は最初の1か月だけ意識すれば、あとは自然に維持できる', 1, 'ルール遵守度が50%以下の場合、どんな手法を使っていても資金を減らすとされています。一貫性のない実行は、手法の良し悪しに関わらず成績を悪化させます。', false, 10),
(10, '週末に振り返りをしようとしたが、何から始めればいいか迷っている。最初にすべきことはどれか？', '来週の改善点を1つ決める', 'ルールを守れなかった場面を探す', '最良と最悪のトレードを比べる', '今週の全トレードを数える', 4, 'まず全トレードを数えることで、回数が多すぎないか（焦りや暇つぶしのエントリーが混入していないか）を確認する。実態把握が振り返りの出発点になる。', false, 11),
(10, '週次振り返りの最初のステップ「今週のトレードを数える」の目的として最も適切なものはどれですか？', '週間の損益合計を正確に計算するため', '最も利益が出たトレードを表彰するため', 'トレード回数が多すぎないか、自分の適正ペースか確認するため', '他のトレーダーと回数を比較するため', 3, 'トレード数を数える目的は、回数が多すぎないかを確認することです。トレードが増えすぎている場合は、焦りや暇つぶしでのエントリーが混ざっている可能性があります。', false, 12),
(10, '週次振り返りの第2ステップ「ルールを守れなかった場面を探す」で重要なのは、守れなかった「理由」を探ることです。その理由として最も多い典型的なパターンはどれですか？', 'ルール自体が複雑すぎて理解できていなかった', '感情的な衝動（焦り・過信・取り返し心理）が原因だった', 'チャートのテクニカル指標が誤っていた', '市場が想定外の動きをしてルールが適用できなかった', 2, 'ルールを守れなかった場面の多くは、感情的な要因（焦り・過信・取り返し心理など）が原因です。「なぜ守れなかったか」を突き詰めると、感情のパターンが見えてきます。', false, 13),
(10, '週次振り返りで「最良と最悪のトレードを比べる」目的として正しいものはどれですか？', '自分なりのパターンを発見するため', '最良のトレードの利益で最悪のトレードの損失を相殺できるか確認するため', '最悪のトレードをした日の市場環境を二度と同じ条件でトレードしないため', '最良のトレードの手法を他の銘柄にも応用するため', 1, '最良のトレードと最悪のトレードを比較することで、自分の勝ちパターンと負けパターンが見つかります。このパターン発見が今後のトレード改善に直結します。', false, 14),
(10, '週次振り返りの最終ステップで「来週の改善点を1つだけ決める」理由として最も適切なものはどれですか？', '1つしか改善できないほどトレードのスキルが低いから', '毎週異なる改善点に取り組むことで、全ての課題をローテーションで克服できるから', '1つの改善点をクリアすれば他の問題は自動的に解決するから', '複数の改善点に取り組むと焦点がぼやけて結局何も変わらないから', 4, '改善点を1つに絞るのは、複数同時に取り組むと焦点がぼやけて挫折しやすくなるからです。1つずつ確実に改善していく方が結果的に大きな変化につながります。', false, 15),
(10, 'トレード日誌のデータ分析から「金曜午後は負けやすい」という傾向が見つかりました。この傾向の原因として最も可能性が高いものはどれですか？', '金曜午後は経済指標の発表が集中しているから', '週末の疲れが蓄積している、または値動きが荒れやすいため', '金曜は流動性が最も高すぎて約定がうまくいかないから', '金曜午後はプロのトレーダーだけが参加しているから', 2, '「金曜午後は負けやすい」というデータは、週末の疲れの蓄積や、金曜午後特有の値動きの荒さが原因の可能性があります。このパターンに気づけば、金曜午後のトレードを避けるなどの対策が取れます。', false, 16),
(10, 'トレード日誌のデータから「連勝翌日にロットを上げて大負けしている」というパターンが見つかりました。この根本的な心理的原因はどれですか？', '連勝後は市場の方向性が読みやすくなるという錯覚', '連勝後は必ず反落するという市場の法則が働いている', '連勝による過信でリスク管理が疎かになっている', '連勝翌日の流動性が低下してスプレッドが広がっている', 3, '連勝翌日の大負けは「過信」が原因です。連勝で自信が高まった状態ではロットを上げたくなり、リスク管理がおろそかになります。データがこの危険なパターンを教えてくれます。', false, 17),
(10, 'トレード日誌の記録から「焦りの日は全て負けている」という傾向が判明しました。このデータに基づく最も合理的な対策はどれですか？', '焦りを感じた日はエントリーしないというルールを追加する', '焦りを感じた時はエントリー方向を反転させる', '焦りを感じたらロットサイズを半分にする', '焦りを感じなくなるまでエントリーを10分遅らせる', 1, '「焦りの日は全部負け」というデータがあるなら、焦りを感じた日はエントリーしないという明確なルールが最も合理的な対策です。データに基づくルール作りこそが日誌の最大の価値です。', false, 18),
(10, 'あるトレーダーの1週間の記録が以下の通りです。月曜：ルール通りエントリーして+15pips、火曜：ルールを無視してエントリーして+30pips、水曜：ルール通りエントリーして-10pips、木曜：ルール通りエントリーして-8pips。この週のルール遵守度は何％ですか？', '25%', '50%', '75%', '100%', 3, '4回のトレードのうちルールを守ったのは月・水・木の3回です。ルール遵守度は3/4＝75%となります。火曜は利益が出ていますが、ルールを破っているため「悪いトレード」と評価されます。', false, 19),
(10, 'トレード日誌を3か月続けた結果、自分のデータから以下の傾向が見つかりました。（1）午前中のトレードは勝率65%、午後は勝率38%、（2）連敗後のエントリーは平均損失が2倍、（3）ルール遵守度90%の週は全て黒字。このデータに基づいて最優先で実施すべき改善策はどれですか？', '午後のトレード手法を新しく開発する', '勝率の低い午後の時間を勉強時間にあてて新しい指標を学ぶ', '午後のトレードのロットサイズを午前の半分にして継続する', '連敗後のエントリー制限ルールを作り、午後のトレードを縮小または中止する', 4, '午後の低勝率と連敗後の損失2倍が最大の課題。連敗後のエントリー制限ルールを作り、午後のトレードを縮小または中止することがデータに基づく最善策。ルール遵守度90%の週が全て黒字というデータも、遵守度が利益の鍵であることを示している。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(11, 'ルールブックが「冷静な自分から暴走中の自分への手紙」である理由として最も適切なものはどれですか？', '暴走中は感情的になり、その場で正しい判断を下す力を失っているから', 'ルールブックは他人に見せるものではなく、自分だけの秘密の文書だから', '暴走中の自分は他人のアドバイスしか受け付けない状態になっているから', '冷静な自分と暴走中の自分では好むトレード手法が変わるから', 1, 'トレード中に感情が暴走している最中は、自力で正しい判断を下すことができません。だからこそ、冷静な状態の自分が事前にルールを書き残しておく必要があります。', false, 1),
(11, 'ルールブック7項目のうち、「トレードする市場と時間軸」を1つに絞る理由は何ですか？', '複数の市場を同時に監視すると手数料が増えるから', '焦点を絞ることでその市場のクセや特徴を深く理解できるから', '証券会社の口座が1つの市場しか対応していない場合が多いから', '複数市場のトレードは法律で制限されているから', 2, '市場と時間軸を1つに絞ることで、その環境特有の値動きのパターンやリズムを体感として蓄積でき、判断の精度が向上します。', false, 2),
(11, 'エントリー条件を「具体的に」書くべき理由として正しいものはどれですか？', '曖昧な条件は感情に「今回だけは特別」という言い訳を与えてしまうから', '具体的であれば他のトレーダーと条件を共有しやすくなるから', '証券会社の注文画面には数値で入力する必要があるから', 'エントリー条件は過去データと照合するために数式化が必要だから', 1, 'エントリー条件に曖昧さが残っていると、感情が「これも条件を満たしている」と勝手に解釈し、ルールを曲げる言い訳を生んでしまいます。', false, 3),
(11, '損切りルールの正しい位置として最も適切な記述はどれですか？', '含み損が資金の5%に達した時点で損切りする', 'エントリーの根拠が崩れる場所で、最大でも資金の2%以内に設定する', 'チャートのサポートラインより少し下で、余裕を持って幅広く設定する', '損切り幅は利益目標の3分の1以内に収まるように設定する', 2, '損切りは「根拠が崩れる場所」に設定し、1回の損失を資金の2%以内に抑えます。損切りラインは一度決めたら動かしてはいけません。', false, 4),
(11, '資金管理において、1回のトレードで許容すべきリスクの目安は資金の何%ですか？', '0.1%〜0.5%', '1%〜2%', '5%〜10%', '10%〜20%', 2, '1回のトレードで失う金額を資金の1〜2%に抑えることで、連敗が続いても口座を壊滅させることなく続けられます。', false, 5),
(11, 'ルールブックの6項目目「トレードしない条件」を客観的な数字で区切る理由は何ですか？', '主観的な判断では、手が震えているときでもエントリーしてしまう可能性が高いから', '数字で区切ることで自動売買システムにルールを組み込みやすくなるから', 'トレードしない条件は法律で数値基準を定めることが義務付けられているから', '数字で区切ると他のトレーダーのトレード頻度と比較しやすくなるから', 1, '「今日は調子が悪いからやめておこう」という感覚頼りの判断は、感情に左右されます。「過去10トレードの勝率が〇%以下ならエントリーしない」のように数字で客観的に線を引くことで、感情の介入を防ぎます。', false, 6),
(11, '振り返りルールで「曜日と時間を決める」ことが重要な理由はどれですか？', '市場が開いている時間帯に振り返るとリアルタイムのデータが使えるから', '週末はチャートデータが更新されないため、平日に振り返る必要があるから', 'トレード日記を書くために最低2時間の連続した時間が必要だから', '曜日と時間を固定することで、振り返りを習慣化しサボれなくなるから', 4, '振り返りは「気が向いたときにやる」では続きません。「毎週日曜の朝10時」のように日時を決めることで、振り返りがルーティンになり継続できます。', false, 7),
(11, 'トレード中に「今回だけは特別だ」という考えが浮かんだとき、何が起きていると考えるべきですか？', '直感が研ぎ澄まされており、例外的なチャンスを見つけた状態', 'ほぼ確実に感情が判断を歪めているサイン', 'ルールが不完全で、この状況に対応する条件が抜けている証拠', '市場がいつもと違う動きをしており、柔軟な対応が求められている合図', 2, '「今回だけは特別」という考えが浮かんだ時点で、感情が理性を上回っています。この言葉が出たときは原則としてルールを守るべき警告シグナルです。', false, 8),
(11, '含み損を抱えている最中に「この状況はルールに当てはまらない」と考えたときの正しい対応はどれですか？', '自分の判断を信じて、状況に応じて臨機応変に対応する', 'ルールを一時的に見直して、現在の状況に合った新しい基準を適用する', '含み損の中の自分を信用せず、事前に決めたルール通りに損切りを実行する', '少し待って含み損が縮まるのを見てから、改めて判断し直す', 3, '含み損を抱えているときの自分は「まだ大丈夫」と根拠なく信じ込みやすくなります。損失を抱えている状態での判断は信用せず、冷静な自分が決めたルールに従います。', false, 9),
(11, '「ルールを破って勝つ」ことと「ルールに従って負ける」ことのうち、なぜ後者の方が価値があると言われるのですか？', 'ルールを守って負ければ、損失の金額が必ず小さくなるから', 'ルールを破って勝つと税金が高くなり、結果的に利益が減るから', 'ルールに従って負ける経験は再現性のあるプロセスを示しており、改善できるから', 'ルールを破って勝つと、次のトレードで必ず大きな損失が出る統計があるから', 3, 'ルールを破って勝ってもそれは運であり再現性がありません。ルールに従って負けた場合は「プロセスは正しかったか」を検証でき、改善の材料になります。', false, 10),
(11, 'ルールブックの見直しは何ヶ月ごとに行うことが推奨されていますか？', '1ヶ月ごと', '3ヶ月ごと', '6ヶ月ごと', '1年ごと', 2, '3ヶ月に一度の頻度で見直しを行います。短すぎるとデータが足らず、長すぎると悪い癖が定着してしまうため、3ヶ月が適切な間隔です。', false, 11),
(11, 'ルールの見直し手順として正しい順番はどれですか？', '修正を3つ加える → 検証する → 共通パターンを探す', 'ルール通りのトレードで勝ったものを集める → 勝因を分析する → 新しいルールを追加する', 'ルール通りにやって負けたトレードを集める → 共通パターンを探す → 修正を1つだけ加える', '全トレードの損益を計算する → 利益の大きいトレードを再現する → エントリー条件を増やす', 3, '見直しでは「ルールを守って負けたトレード」に焦点を当て、共通の負けパターンを見つけ、修正は一度に1つだけ加えます。複数同時に変えると何が効果あったか分からなくなります。', false, 12),
(11, 'トレーダーAは「1回の損失を資金の5%まで許容」し、トレーダーBは「1回の損失を資金の1%に制限」しています。両者が5連敗した場合、資金への影響として正しいものはどれですか？', 'トレーダーAは約22%減、トレーダーBは約5%減になる', 'トレーダーAは25%減、トレーダーBは5%減になる', 'トレーダーAは約35%減、トレーダーBは約10%減になる', '両者ともに損失率は同じで、回数が増えるほど差が出るわけではない', 1, '5%リスクで5連敗すると (0.95)^5 ≒ 0.774、約22.6%の減少です。1%リスクなら (0.99)^5 ≒ 0.951、約4.9%の減少です。資金管理の1〜2%ルールは、連敗時の被害を最小限に抑えるためにあります。', false, 13),
(11, '利確ルールを事前に決めておくべき理由として最も適切なものはどれですか？', '利確ルールを決めておけば、利益が必ず最大化されるから', '利確は損切りより重要であり、エントリーよりも先に決めるべきだから', '税金対策のために利確のタイミングを年度末に合わせる必要があるから', '含み益を見ると「まだ伸びるかも」と欲張ったり「今のうちに確定させよう」と焦ったりするから', 4, '含み益がある状態では感情が揺れ動きやすく、冷静な判断ができません。利確ポイントを事前に決めておくことで、感情に判断を委ねず機械的に実行できます。', false, 14),
(11, '次のルールブックの記述のうち、最も改善が必要なものはどれですか？', '「ダウ理論で明確な上昇トレンドを確認後、押し目でエントリーする」', '「1回の損失は口座資金の2%以内に抑え、損切りラインはエントリー後に動かさない」', '「なんとなく上がりそうな気配を感じたらエントリーする」', '「直近5トレードの勝率が30%を下回った日は、それ以上エントリーしない」', 3, '「なんとなく上がりそうな気配」は曖昧すぎる条件です。エントリー条件は具体的で客観的でなければならず、曖昧さは感情の言い訳を許してしまいます。', false, 15),
(11, '損切りラインを「動かさない」ことが重要な理由はどれですか？', '損切りラインを動かすと手数料が発生するから', '損切りラインは計算で求めたものだから、途中で変更すると計算が合わなくなるから', '損切りラインを動かすと、自動売買のプログラムがエラーを起こすから', '一度動かし始めると「もう少し待てば戻る」と期待して、最終的に被害が拡大するから', 4, '損切りラインを少し下にずらすと、さらに下にずらしたくなります。この「損切りの先延ばし」が口座を壊滅させる最大の原因の一つです。', false, 16),
(11, 'ルールの見直しで「修正を1つだけ加える」とされている理由はどれですか？', '1回の見直しで複数の修正を加えると時間がかかりすぎるから', '複数同時に変えると、どの修正が結果に影響したか特定できなくなるから', 'ルールブックの項目は最大7つまでと決まっているから', '1度に2つ以上変更すると、証券会社のシステムに反映されないから', 2, '一度に複数の条件を変えると、勝率が上がっても「どの変更が効いたのか」が分かりません。1つずつ変更・検証を繰り返すことで、精度の高いルールを構築できます。', false, 17),
(11, 'あなたはルールブックを作成しました。ある日、エントリー条件を満たしてポジションを持ったものの、想定と逆に動き始めました。損切りラインまであと少しのところで、「ここで損切りするより、もう少し様子を見よう」と考えました。この状況で取るべき行動はどれですか？', '損切りラインに到達する前に、より安全な位置にラインを引き下げてから待つ', 'チャートパターンを確認し、反転の兆しがあれば損切りを見送る', '事前に決めた損切りラインに到達した時点で、理由に関わらず損切りを実行する', '同じ方向のポジションを追加して平均取得価格を改善する', 3, '損切りラインは「根拠が崩れる場所」です。到達した時点でエントリーの前提が崩れているため、感情的理由で見送らず機械的に実行します。', false, 18),
(11, 'ルールブックを作る「タイミング」として最も適切なものはどれですか？', 'トレード中に気がついたことをその都度メモして、後で整理する', '大きな損失を出した直後に、反省を込めて一気に書き上げる', 'ポジションを持たず冷静な状態のときに、時間をかけて作成する', 'セミナーに参加した直後に、教わった内容をそのまま書き写す', 3, 'ルールブックは感情が介在しない冷静な状態で作成する必要があります。ポジションを持っている最中や損失直後は感情が高ぶっており、適切なルールを作れません。', false, 19),
(11, '次のうち、ルールブックに含めるべき「トレードしない条件」として最も適切なものはどれですか？', '「利益目標に到達するまでは絶対にエントリーしない」', '「その日の最初のトレードが損失だった場合、午後のセッションはトレードしない」', '「ルールに従って損切りした日は、翌日までエントリーしない」', '「勝っている日は調子に乗らないよう、全くトレードしない」', 2, '「1回負けたら午後はやらない」のような客観的な数字による条件は、負けが連鎖するのを防ぎます。トレードしない条件は感情に左右されない明確な基準で設定します。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(12, '毎日チャートを見ようと意気込んで始めたトレーダーが1週間で挫折した。継続できている人との本当の違いは何か？', '生まれつきの継続力に差がある', '続けるための仕組みを持っているかどうかで決まる', '一日にかける時間の長さが違う', '投資への情熱の強さが異なる', 2, '続けられない原因は意志力不足ではなく仕組みの欠如。「気合いは3日、仕組みは3年」— 仕組みを作ることで意志力に頼らない長期継続が可能になる。', false, 1),
(12, 'ルーティンを始めて2週間。毎日こなしてはいるが「面倒くさい」と感じる日が多い。この状態をどう解釈するべきか？', '習慣化の最もつらい初期段階にあり、完璧を求めず小さく続けることが正解', '向いていない証拠なので、やり方を根本から変えるサイン', '66日が過ぎれば自動的に楽になるので、今は強制的にこなすべき', '面倒に感じるのは負荷が大きすぎるサインで、一旦休むべき', 1, '最初の21日間は習慣化で最もつらい時期。面倒くさいのは失敗ではなく正常なプロセス。完璧を求めず小さく続けることが突破口になる。', false, 2),
(12, 'ルーティンを3ヶ月続けてきたトレーダーが「最近はやらないと落ち着かない」と話している。この状態が示すのは？', '習慣への依存が強くなりすぎているサイン', '慣れ始めの段階を抜け出し、自動化が完成した', '意志力が尽きて惰性で続いている状態', '定着の段階に到達し、仕組みが機能している状態', 4, '90日以降の「定着」段階では、やらないと落ち着かなくなる。意志力に頼らず習慣が維持されるこの状態が、仕組み化の最終的なゴール。', false, 3),
(12, 'ルーティンを2ヶ月続けているトレーダーが「最近は考えなくても自然にできる」と感じている。次にこのトレーダーが目指す段階は？', '慣れ始めに戻り、別の習慣も同時に加える', '振り返りを強化して、習慣の内容を一から見直す', '自動化が完了したので習慣の量を一気に増やす', '定着の段階へ。やらないと気持ち悪くなるレベルまで積み上げる', 4, '習慣化は「慣れ始め→自動化（66日）→定着（90日）」の順で進む。2ヶ月は自動化に近い段階。次は90日以降の「定着」を目指して焦らず続ける。', false, 4),
(12, '2ヶ月（60日）続けていたルーティンを旅行中の1週間サボり「もうダメだ」と諦めた。このトレーダーの判断で問題なのは？', '旅行中も何らかの形で続けるべきだった点', '60日積み上げた習慣は自動化に近く、再開すれば戻れたのに諦めた点', '1週間のサボりで習慣化レベルはゼロに戻るので、一から始め直す判断は正しい', '旅行前にルーティンを終わらせておくべきだった点', 2, '60日積み上げた習慣は「自動化」に近く、1週間のブランクで全てが消えるわけではない。「また今日から始める」感覚で再開する方が、長期継続への正しい対応になる。', false, 5),
(12, 'トレードの習慣を作りたいが「毎日1時間の分析は負担で続かない」という悩みを持つトレーダーへの最善のアドバイスは？', '毎朝ニュースサイトを5つ巡回することから始める', '毎日30分のチャート分析から段階的に始める', '今日の感情を一言メモするだけ（10秒）から始める', '毎日のトレード日誌をA4用紙1枚分書くことを習慣化する', 3, '「感情を一言メモ（10秒）」は負担ゼロで始められる行動。小さすぎるくらいから始めることで習慣化の初期段階を乗り越えやすくなり、完璧を求めない姿勢が継続の土台になる。', false, 6),
(12, '習慣化の過程で3日間サボってしまった場合、最も適切な対応はどれですか？', '最初からやり直すため、カレンダーのチェックをリセットする', 'サボったことを深く反省し、ペナルティを自分に課す', '習慣化に失敗した証拠なので、別のアプローチに切り替える', '3日サボっても4日目にまた始めればよく、気にしすぎない', 4, '完璧を目指さないことが習慣化のコツです。3日サボっても4日目にまた始めればよく、途切れたことを理由に諦める必要はありません。', false, 7),
(12, '習慣が続いているか実感が持てないトレーダーが、継続をモチベーションにつなげたい。最も手間が少なく続けやすい方法は？', 'カレンダーにチェックを付けるだけにする', 'スプレッドシートに毎日詳細なデータを入力する', 'SNSに毎日の成果を投稿して記録する', '月に一度まとめて振り返りレポートを作成する', 1, 'カレンダーにチェックを付けるだけのシンプルな見える化が推奨されている。手間が少なく続けやすく、積み重なったチェックが目で見えることが次のモチベーションにつながる。', false, 8),
(12, '「朝のルーティンが時間がかかりすぎて続かない」という悩みに対し、推奨される朝のルーティン全体の所要時間はどれか？', '1〜2分。起床直後に素早くチェックするだけ', '30〜60分。じっくり分析して1日の準備を万全にする', '10〜15分。指標確認・市場把握・シナリオ作成を効率よく行う', '2時間以上。朝に全ての準備を終わらせてから臨む', 3, '推奨ルーティンは「指標確認（2分）→ 市場の流れ確認（5分）→ シナリオ作成（5分）」で合計10〜15分。時間を短く区切ることで毎朝継続しやすくなる。', false, 9),
(12, 'エントリーチャンスを逃したくないトレーダーが日中もずっとチャートに張り付いている。このトレーダーが抱えるリスクは？', '感情が刺激され続け、ルールを外れた衝動的エントリーをしやすくなる', 'リスクはなく、むしろ好機を早く捉えられる利点がある', 'チャートを見過ぎると相場の大きな流れが読めなくなる', '張り付くと疲れるが、慣れれば判断の精度が上がる', 1, '日中はアラートを設定してチャートから離れることが推奨されている。張り付きすぎは感情を常に刺激し、計画外のエントリーや損切り遅れを招く原因になる。', false, 10),
(12, '今日はトレードをしなかった。何も書くことがないと感じて日誌をスキップしてしまった。本来どうすべきだったか？', 'トレードをしていなければ日誌は不要で、スキップは正しい', '次の日のエントリーポイントを詳細に分析して書き残す', '「やらなかった理由」を一言書き留めるだけでよかった', 'チャートを見直して見逃したチャンスを確認して記録する', 3, 'トレードしなかった日こそ「やらなかった理由」を一言残す。記録が積み重なると自分の傾向が見えてくる。何もしない日をそのまま流すのは貴重なデータを捨てることと同じ。', false, 11),
(12, 'トレードをした日の夜、日誌を書こうとしたが何をどれくらい書けばよいか分からない。負担にならず続けるための記録量は？', '感情・判断・結果の3行', '最低500文字の詳細な振り返りを書く', '1ページ分（400字程度）の記録を習慣にする', '感じたことを思いつくまま10行以上書く', 1, 'トレードをした日は3行で十分。負担を最小にすることで継続しやすく、3行の記録でも積み重なれば豊富なデータになる。記録は完璧さより継続が価値を生む。', false, 12),
(12, 'あるトレード手法を10回検証したところ好結果だった。「これなら使える」と判断して実戦投入しようとしている。何が問題か？', '10回ではたまたまの可能性が高く、傾向すら見えていない段階での実戦は根拠のない賭けになる', '10回は少ない。最低30〜50回まで延ばしてから判断すべきだった', '10回で十分な統計的信頼性があるので、問題はない', '検証回数より勝率の方が重要なので、回数は気にしなくてよい', 1, '10回ではたまたまの可能性が高く、傾向が見え始めるのは30回以上。パターン確認に50回、統計的信頼性に100回が目安。早すぎる実戦投入は根拠のない判断になる。', false, 13),
(12, 'あるトレード手法の検証を50回行いました。この時点で期待できることはどれですか？', 'パターンを確認できる段階に達している', 'たまたまの可能性が高く、まだ何も判断できない', '統計的に完全に信頼できる結論が出る', '検証は不要になり、すぐに実戦投入できる', 1, '50回の検証でパターンの確認ができる段階です。ただし統計的な信頼性を高めるには100回が目安であり、50回は中間的な確認地点と捉えます。', false, 14),
(12, '理解していない通貨ペアでトレードして利益が出た。「この手法は合う」と感じてポジションを増やした。何が危険か？', '通貨ペアを絞ることで他の利益機会を逃すリスクがある', '理解していない場面で得た利益は、同じ理解不足のまま同じ場所で返す可能性が高い', 'ポジションを増やすと手数料コストが増えて非効率になる', '感情的な判断があるが、利益が出ているなら大きな問題ではない', 2, '理解していないトレードで得た利益は、同じ理解不足のまま同じ場所で失うことになる。「わかる範囲で、わかることをやる」が長期的な安定の土台になる。', false, 15),
(12, '複数の手法を同時に試しているトレーダーが一向に結果を出せずにいる。「1つを確実にできる人の方が強い」と言われる理由は？', '複数の手法を並行すると混乱して判断が遅くなるから', '手法の数が多いと記録と管理が複雑になりすぎるから', '1つの手法を繰り返すことで検証数が積み上がり、確信を持ってエントリーできるから', 'トレードは直感が重要で、多くの手法を覚えると直感が鈍るから', 3, '手法を絞ることで検証が積み上がり、統計的な根拠を持った取引ができるようになる。拡散より確実な積み上げの方が、長期的に強いトレーダーにつながる。', false, 16),
(12, 'SNSで「この通貨ペアは今週上がる」という情報を見た。根拠は書いていないが多くの人が支持していた。どう対応するのが正しいか？', '多数が支持しているなら信頼できる情報と判断してよい', 'SNSの雰囲気に流されず、自分の分析で根拠を確認してから判断する', 'SNSの情報を完全に無視して、自分のルールだけで判断する', '発信者のフォロワー数を確認してから信頼性を判断する', 2, '「自分の頭で考える」とはSNSに振り回されず自分の基準で判断すること。根拠のない情報を鵜呑みにすると、感情トレードと同じリスクを抱えることになる。', false, 17),
(12, 'あなたはトレードを始めて3週間が経ちました。最初の習慣化の段階が一番つらいと知った今、どのように取り組むのが最も適切ですか？', '毎日必ず完璧なルーティンをこなすと決めて、どんなに忙しくても時間を作る', 'この時期はつらいのが当然なので、完璧を求めず小さく続ける', '3週間が一番つらいなら、つらさが減る21日目まで一気に集中して乗り切る', 'つらい期間を短縮するため、複数の習慣を同時に始めて一気に慣れる', 2, '最初の21日間は「慣れ始める」段階で最もつらい時期です。この時期は完璧を求めず小さく続けることが推奨されており、無理な目標設定は挫折の原因になります。', false, 18),
(12, 'あなたはあるトレード手法を20回検証しました。結果は悪くありませんが、実戦で使うべきか迷っています。正しい判断はどれですか？', '20回でも結果が良ければ統計的に十分であり、すぐに実戦投入してよい', 'まだ傾向が見え始める段階なので、少なくとも50回までは検証を続ける', '10回でたまたまの可能性があるため、あと10回追加して判断する', '検証回数に関わらず、自分が納得すればいつでも実戦投入してよい', 2, '20回ではまだ傾向が見え始める段階（30回）にも達していません。パターンを確認するには50回、統計的な信頼性には100回が目安なので、焦らず検証を続けることが重要です。', false, 19),
(12, '朝のルーティンで「シナリオを最初に考えてから指標を確認する」順番でやっているトレーダーがいる。なぜこの順番は推奨されないのか？', 'シナリオは夜に考えるべきで、朝は確認だけにするのが正しいから', 'まず事実（指標・市場の流れ）を把握してからシナリオを作るのが正しい順序だから', '朝は時間がないため、指標確認は省略してシナリオだけでよいから', '順番より3つのステップをこなすことの方が大切で、順序は問題ではないから', 2, '朝のルーティンは「指標確認→市場の流れ確認→シナリオ作成」の順が推奨。事実の把握なしにシナリオを先に作ると、思い込みに基づく計画になり正確性が落ちる。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(13, 'STRADAという言葉の語源とその意味として正しいものはどれですか？', 'イタリア語で「道」— 大口投資家の注文痕跡を読む技術体系', 'ラテン語で「構造」— テクニカル指標を統合した分析フレームワーク', '英語で「戦略」— 勝率を最大化するための売買アルゴリズム', 'スペイン語で「波」— 相場の波動パターンを分類する理論', 1, 'STRADAはイタリア語で「道」を意味し、チャートに残る大口投資家の注文痕跡を読み取る技術体系を指します。目的地に着くことだけが価値ではなく、道を歩き続けること自体が成長だという思想が込められています。', true, 1),
(13, '大口投資家が大量の買い注文を一度に出せない根本的な理由は何ですか？', '取引所のシステムが大口注文を自動的に分割処理する仕様になっているため', '金融規制上、1回の注文サイズに上限が設けられているため', '一度に大量買いすると価格が急騰し、自身の平均取得単価が悪化するため', '監督官庁への事前報告義務があり、承認を待つ必要があるため', 3, '大口は資金量が膨大なため、一度に大量買いを入れると価格が跳ね上がり、自分自身の平均取得価格を押し上げてしまいます。そのため価格への影響を最小限に抑えながら少しずつ買い集める必要があります。', true, 2),
(13, 'チャートの値動きの正体について、最も正確な表現はどれですか？', 'テクニカル指標のシグナルが蓄積・合成された結果', '買い手と売り手の力関係であり、注文の「数」ではなく「資金量」で決まる', 'トレーダーの心理的サイクルが可視化されたもの', '経済指標に対する市場参加者の理性的な価格発見のプロセス', 2, 'チャートの裏側では常に買い注文と売り注文が飛び交っていますが、相場を動かすのは注文の数ではなく資金量です。個人100人の買いよりも、機関1社の売りの方が相場に与える影響は圧倒的に大きくなります。', true, 3),
(13, '大口投資家と個人投資家の間に存在する「3つの格差」として正しい組み合わせはどれですか？', '資金量・スキル・テクノロジー', '情報・時間・テクノロジー', '資金量・情報・時間', '資金量・情報・スキル', 3, '大口と個人の間には「資金量」「情報」「時間」の3つの格差があります。大口は桁違いの資金と専門チームによる独自データを持ちますが、個人には「時間の自由」という逆転の武器があります。', true, 4),
(13, '個人投資家にだけ与えられた「3つの武器」について、空欄に入る正しい組み合わせを選んでください。  「① ＿＿：大口にはパフォーマンス期限があるが、個人にはない」 「② ＿＿：個人の注文は市場を動かさない。大口にはそれができない」 「③ ＿＿：四半期報告も上司もない。自分のペースで判断できる」', '① 時間の自由　② ステルス性能　③ 待つ権利', '① ステルス性能　② 待つ権利　③ 時間の自由', '① 待つ権利　② 時間の自由　③ ステルス性能', '① 待つ権利　② ステルス性能　③ 時間の自由', 4, '個人の3つの武器は「待つ権利」「ステルス性能」「時間の自由」です。大口には四半期報告やリスク管理規則という制約がありますが、個人は最高の場面だけを選び、気づかれずにエントリーし、自分のペースで動くことができます。', true, 5),
(13, '資金管理の三原則として正しい組み合わせはどれですか？', '1回2%ルール／利益確定を先に決める／証拠金維持率100%以上', '1回5%ルール／損切りはエントリー後に感覚で決める／証拠金維持率200%以上', '1回10%ルール／損切りはエントリー前に決める／証拠金維持率150%以上', '1回2%ルール／損切りはエントリー前に決める／証拠金維持率200%以上', 4, '資金管理の三原則は「1回のトレードで口座の2%以上を賭けない」「損切りはエントリー前に決める（逆指値を入れてからエントリー）」「証拠金維持率を200%以上に保つ」です。この3つを守ることで生存確率が劇的に上がります。', true, 6),
(13, '証拠金維持率について、最低ラインと理想水準の正しい組み合わせはどれですか？', '最低200%／理想300〜500%', '最低100%／理想200%', '最低150%／理想300%', '最低200%／理想500%以上', 1, '証拠金維持率は200%以上を最低ラインとし、理想は300〜500%です。維持率が高ければ、急激な相場変動でも強制ロスカットのリスクを回避でき、冷静な判断を保つことができます。', true, 7),
(13, 'STRADAが「手法ではなく構造を読む力」を重視する理由として最も適切なものはどれですか？', '全てのテクニカル手法は詐欺であり、個人投資家には役立たないから', '特定の手法は市場環境の変化で通用しなくなるが、注文構造を読む力は環境に左右されない基盤になるから', '一つの完璧な手法を見つければそれを永遠に使い続けるべきだから', '手法の開発はプロに任せ、個人投資家はフォロートレードに徹するべきだから', 2, '特定のテクニカル手法は市場環境が変わると機能しなくなりますが、大口の注文痕跡という根本的な構造を読む力は、環境が変わっても通用する基盤です。「手法を探し回る旅を終え、構造を読む力に集中する」ことが核心思想です。', true, 8),
(13, '口座資金50万円のトレーダーが2%ルールを厳守する場合、1回のトレードで許容できる最大リスク額はいくらですか？', '5,000円', '25,000円', '50,000円', '10,000円', 4, '2%ルールでは「1回のトレードで口座の2%以上を賭けない」と定めています。50万円 × 2% = 10,000円が1回の最大リスク額です。口座資金が減ればリスク額も自動的に減るため、破産を防ぐブレーキとして機能します。', true, 9),
(13, '機関投資家が「分割して買い集め、一気に利益を取る」とき、チャートに典型的に現れるパターンはどれですか？', '常にV字型の急反発パターンが連続して現れる', '一定期間のレンジや緩やかな動きの後に、急激な方向性のある動きが現れる', '上昇と下降が等間隔で繰り返す規則的な波動パターン', '出来高が常に一定水準を保ち、ローソク足のサイズが均一になる', 2, '大口は大量買いを一度に出せないため、価格帯を分割して少しずつ買い集めます。この期間はレンジや緩やかな動きとして現れ、買い集め完了後に一気に利益を取りに行くため急激な方向性のある動きが生まれます。', true, 10),
(13, '「ステルス性能」が個人投資家の武器である理由を最も正確に説明しているものはどれですか？', '個人の取引は税務申告の対象になりにくく、利益を隠せるから', '個人の注文は市場規模に対して極めて小さく、価格を動かさずにエントリー・エグジットできるから', '個人は取引所に登録しなくても取引できるため、身分を隠してトレードできるから', '個人はダークプール（非公開取引所）を利用できるため、注文が市場に反映されないから', 2, '個人の注文規模は市場全体に対してごくわずかであり、価格にほぼ影響を与えずに静かにエントリー・エグジットできます。機関投資家は大量注文で価格を動かしてしまいますが、個人はこの「気づかれない」という利点を活かせます。', true, 11),
(13, 'STRADAの学習において、資金管理が最も重視される理由は何ですか？', '資金管理を徹底すれば勝率が自動的に70%を超えるため', '資金管理は税金対策上で最も重要な要素だから', '分析力があっても資金管理が崩壊すれば一発で退場するため', 'プロのトレーダーは全員資金管理ツールを使っているため', 3, '分析力やエントリーテクニックがどれほど優れていても、資金管理が疎かなら1回の大きな負けや連敗で退場に追い込まれます。「生き残る」ことが全ての前提であり、資金管理はその基盤です。', true, 12),
(13, 'STRADAが「感情に頼らない、構造ベースの判断」を重視する理由として最も適切なものはどれですか？', '人間の感情は常に間違っており、感情ベースの判断は絶対に勝てないから', '感情の介入余地を減らすことで結果の一貫性が生まれ、長期的に安定するから', '感情的なトレードは法律で禁止されているため', '構造ベースの判断の方が常に感情的な判断より高い利益率を出せるから', 2, '感情に頼った判断は一貫性がなく、その日の気分や直前の勝敗に左右されやすくなります。構造ベースで判断することで感情の介入余地を減らし、「構造を読む → リスクを管理する → 感情を排除する → 生き残る」というサイクルを安定して回すことができます。', true, 13),
(13, '「待つ権利」が個人投資家にとって強力な武器である理由として、最も的確な説明はどれですか？', '機関投資家と違い四半期報告などのパフォーマンス義務がなく、条件が揃った最良の場面だけを選んでエントリーできるアドバンテージがあるから', '資金が少ないため、チャンスが来るまで待つしか方法がないから', '個人は機関投資家より忍耐力が高いことが統計的に証明されているから', '取引手数料が安いので、何度でもエントリーし直せるから', 1, '機関投資家には四半期報告や運用方針による制約があり、常にポジションを持つ義務に近い状況があります。一方、個人には外部からの義務がないため、「条件が揃わないからやらない」という選択が自由にできます。これが「待つ権利」の本質です。', true, 14),
(13, 'STRADAが「大口に勝つのではなく、大口の流れに乗る」という立場をとる理由として最も適切なものはどれですか？', '個人の技術力では大口に勝てる可能性がゼロだから', '法律で個人が大口と対抗する取引を行うことが禁止されているから', '大口は常に正しい判断をしていることが統計的に証明されているから', '大口の資金量は個人の何万倍もあり、真っ向から対抗するのは構造的に不可能だから', 4, '大口の資金量は個人の何万倍もあり、真っ向から対抗するのは不可能です。しかし、大口の注文がチャートに残す痕跡を読み、その流れに乗ることは十分に可能です。「勝つ」のではなく「乗る」という発想の転換がSTRADAの出発点です。', true, 15),
(13, '「感覚ではなく設計で動く」とは、具体的にどういう実践を指していますか？', '常に複数の経済指標を確認してからエントリーすること', '全てのトレードを自動売買プログラムに任せること', 'エントリー根拠・損切り位置・ロット数を事前にルール化し、感情が介入する余地を構造的に減らすこと', '毎回同じ通貨ペア・同じ時間帯でしかトレードしないこと', 3, '「設計で動く」とは、エントリー根拠・損切り位置・ロット数などを事前に明確に決め、そのルールに従って機械的に実行することです。感覚でエントリーすると認知バイアスに支配されやすくなり、一貫性が失われます。', true, 16),
(13, '次のシナリオについて、資金管理の三原則に照らして最も適切な判断はどれですか？  「口座資金100万円。証拠金維持率は現在180%。エントリーチャンスを見つけ、逆指値（ストップロス）を設定すればリスクは口座の1.5%に収まる。」', '証拠金維持率が200%を下回っているため、まずポジションを縮小するか入金して維持率を改善させてからエントリーを検討する', 'リスク1.5%は十分に小さいので、逆指値なしでエントリーしても安全である', 'リスクは2%以内に収まっているので、すぐにエントリーして問題ない', '維持率が低いほど利益を出しやすい状態なので、この機会を逃さずエントリーする', 1, '資金管理の三原則の第3条「証拠金維持率200%以上」を下回っています。リスクが2%以内であっても、維持率が基準を満たしていない場合は先にポジション縮小や入金で改善させる必要があります。三原則は全て同時に満たす必要があります。', true, 17),
(13, 'STRADAの全体設計における4つのステップの正しい順序はどれですか？', '武器を知る → 生き残る技術 → チャートを読む → 構造を知る', 'チャートを読む → 武器を知る → 生き残る技術 → 構造を知る', '生き残る技術 → 武器を知る → チャートを読む → 構造を知る', '構造を知る → 武器を知る → 生き残る技術 → チャートを読む', 1, 'STRADAの12週間は「武器を知る（W1-4）→ 生き残る技術（W5-8）→ チャートを読む（W9-10）→ 構造を知る（W11-12）」の順で構成されています。まず自分の強みを知り、次に生き残る術を学び、そして相場の読み方を深めていきます。', true, 18),
(13, '大口投資家が抱える3つの制約として正しい組み合わせはどれですか？', '1銘柄あたりの保有上限／日次の損失報告／監督官庁の承認が必要', 'レバレッジ1倍制限／月次報告の義務／特定銘柄の取引禁止', '大量注文を分割しなければならない／四半期報告の義務／リスク管理規則の遵守', '個人投資家と同じ取引ルールの適用／税申告の義務／取引時間の制限', 3, '大口投資家の制約は「大量注文を分割して出さざるを得ない」「四半期ごとのパフォーマンス報告」「リスク管理規則（ドローダウン制限等）」の3つです。これらの制約がチャートに痕跡として残り、それを読むのがSTRADAのアプローチです。', true, 19),
(13, '口座資金30万円のトレーダーが2%ルールを守る場合、1回のトレードで許容できる最大リスク額はいくらですか？', '3,000円', '30,000円', '15,000円', '6,000円', 4, '2%ルールでは口座資金の2%が1回の最大リスク額です。30万円 × 2% = 6,000円となります。証拠金維持率が十分に高くても、リスク額のルールは変わりません。', true, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(14, 'あるトレーダーが1.1050という価格ぴったりに指値を入れたが、価格は1.1055で反転して届かなかった。一方、1.1040〜1.1060のゾーンで待っていたトレーダーは反発を捉えられた。この違いが起きる根本的な理由は何か？', '指値注文は証券会社のサーバー遅延により実際の価格とズレが生じるため', '大口の注文は1点に集中するのではなく帯状に分布しており、ピンポイントの価格で待つと届かないケースが多いため', '個人投資家の指値注文が集中している価格帯は逆に避けられるため', '1点の価格で待つと競争が激しくなり、約定率が下がるため', 2, '大口の注文はピンポイントの1価格に集中するのではなく、帯状に分布している。「線で待つ」と大口の注文帯の手前で反転するケースが多く、「面で待つ」ことで現実の反転を捉えられる確率が上がる。', false, 1),
(14, 'あるトレーダーがチャート分析中、ある価格帯に複数のLB（大口買い注文の痕跡）が集中していることに気づいた。この価格帯について最も正しい扱い方はどれか？', 'LBが複数あるのは誤検出の可能性が高いため無視する', '最も新しいLBだけを買いの根拠として使う', '複数のLBが集合してZB（買いゾーン）を形成しており、その価格帯全体を面として意識する', 'LBが集中しているほど売りの圧力も高まるため、逆に売りエントリーを検討する', 3, 'LB（Level Buy）は大口買い注文の痕跡を点として捉えたもの。複数のLBが集合することでZB（Zone Buy）という買いゾーン（面）が形成される。点が集まって面になるこの構造がゾーン分析の基本であり、価格帯全体を面として意識することが重要。', false, 2),
(14, 'あるトレーダーが「価格が急騰した価格帯には、大口の注文は全て消費されてしまったはずだ」と考えた。ゾーン分析の観点から、この考え方の誤りはどこにあるか？', '急騰した後は全ての注文が消費されるため、この考え方は正しい', '大口は注文を分割して出すため、急騰で全て消化されるわけではなく、未約定の残注文が価格帯に残り続ける', '急騰の原因は大口ではなく個人投資家の群集行動であるため、大口の注文とは無関係', '一度形成されたゾーンは価格に関係なく永久に機能し続ける', 2, '大口は桁違いの資金量のため、1回の相場変動で全注文を消化できない。分割された残注文がその価格帯に残り続けるためゾーン（痕跡）が形成される。これがゾーン分析の構造的な根拠であり、「フレッシュなゾーン」が強い理由でもある。', false, 3),
(14, 'ゾーン分析において「面で待つ」ことが推奨される理由として最も適切なものはどれですか？', '面で待つ方が損切り幅を広く設定でき、負けにくくなるため', '線（点）で待つと価格がちょうどその位置に届かないことが多く、実際の注文は帯状に分布しているため', 'テクニカル指標の精度が面の方が高いため', '上位足の分析では線での判定が技術的に不可能なため', 2, '「線」で待つと価格がその一点に届かずに反転することが多々あります。大口の注文は特定の価格に集中するのではなく帯状に分布しているため、幅を持ったゾーン（面）で待つ方が現実的なアプローチです。', false, 4),
(14, 'あるトレーダーが同じ通貨ペアで2つのZBを発見した。「ゾーンA」は日足のフレッシュなZBでフィボナッチ58%と重なっている。「ゾーンB」は同じく日足のフレッシュなZBだが、フィボナッチとの合流はない。どちらを優先すべきか？', 'ゾーンAを優先。フィボナッチとゾーンの合流は複数の根拠が重なることを意味し、反応確率が高まるため', 'ゾーンBを優先。フィボナッチとの合流は逆に多くの人が注目するため「だまし」になりやすいため', 'フィボナッチの合流よりゾーン自体の形成を優先するため、どちらでも差はない', 'ゾーンBを優先。フィボナッチとは無関係にゾーン単体で反応するため', 1, 'フィボナッチ50〜61.8%のリトレースメントとゾーンが重なるポイントは「ゴールデンゾーン」と呼ばれる最高信頼度のエリア。複数の分析ツールの根拠が一致するほど反応の確率が高まり、エントリーの優位性が上がる。', false, 5),
(14, 'チャートを見ると、ゾーンAはある価格帯から穏やかに上昇して離れた。ゾーンBはある価格帯から急騰して離れた。ゾーン分析の観点から、どちらがより信頼できるゾーンか？', 'ゾーンA。急騰のゾーンは「だまし」の可能性があり、穏やかな動きの方が信頼度が高いため', 'どちらも同じ。出発の動きとゾーンの信頼度は無関係のため', 'ゾーンB。急激な価格変動の背後には大口の大量注文が存在し、その痕跡（残注文）が濃く残っているため', 'ゾーンA。急騰は投機的な動きで注文痕跡が残りにくいため', 3, '急激な価格変動（急騰・急落）は背後に大口の大量注文があったことを示す。「出発の勢い」が強いほど大口の関与が濃厚で、残された未約定注文も多いため、ゾーンとしての信頼性が高まる。穏やかな動きのゾーンは大口の痕跡が薄い。', false, 6),
(14, '同じ通貨ペアのチャートに2つのZBがある。「ゾーンX」は4H足・フレッシュ・フィボ合流あり。「ゾーンY」は15分足・フレッシュ・フィボ合流あり。どちらを優先すべきか？', 'ゾーンX（4H足）を優先。上位足で確認されたゾーンは下位足のゾーンより強く、より多くの参加者に意識されるため', 'ゾーンY（15分足）を優先。短い時間足の方が直近の価格帯を反映しており、精度が高いため', 'どちらも同じ。同じ通貨ペアなら時間軸は関係ないため', '直近に形成された方を優先。形成からの時間が短い方がフレッシュさが高いため', 1, 'ゾーンの強さ5要素のひとつ「時間軸」は、上位足で確認されたゾーンほど強いことを意味する。4H足のゾーンは15分足のゾーンより多くのトレーダーに意識され、大口の注文痕跡も大きいため、反応する確率が高い。', false, 7),
(14, 'あるZBに過去3回価格が到達し、そのたびに反発してきた。4回目の到達が近づいている。このゾーンの「フレッシュさ」についての正しい判断はどれか？', '3回反発しているため、このゾーンは「実績あり」でさらに信頼できる', 'フレッシュさは到達回数に関係なく、形成からの経過時間だけで決まる', '到達回数が増えるにつれてフレッシュさが失われ、4回目は反発が弱まる可能性がある', '3回以上の反発は「超フレッシュ」の証明であり最優先で狙うべき', 3, 'フレッシュさとは「まだ一度も価格が戻っていない」ほど高い。到達のたびに残注文が消化されるため、回数が増えるほどフレッシュさが失われ、ゾーンの効力が低下する。3回以上の到達済みゾーンは「効きにくいゾーン」の典型であり、4回目は慎重な判断が必要。', false, 8),
(14, 'フレッシュな4H足のZBが2つある。「ゾーンP」はフィボナッチ50%の水準と重なっている。「ゾーンQ」は特定のフィボや他ツールとの合流がない。どちらを優先すべきか？', 'ゾーンQ。合流がない分、ダマシのシグナルが少なく純粋にゾーン分析だけで判断できるため', 'どちらも同じ。合流はあくまで補助的な要素で、ゾーン単体の方が重要なため', 'ゾーンQ。他のツールを使っている参加者が少ない分、競争相手が少なく有利なため', 'ゾーンP。複数の分析ツールが同じ価格帯を指すほど反応の根拠が強まり、信頼性が上がるため', 4, '「合流」はゾーンの強さ5要素のひとつ。フィボナッチや他の分析ツールがゾーンと重なることで、複数の根拠が一致する。多くの参加者が同じ価格帯に注目するほど、そこで反応が起きる確率が高まり、ゾーンの信頼性が増す。', false, 9),
(14, '週足で確認されたフレッシュなZBを発見した。フィボナッチ56%と重なっており、上位足の上昇トレンドとも一致している。このゾーンに価格が近づいてきた。最も適切な行動は？', 'このゾーンは条件が弱いため静観し、別のゾーンを探す', '条件が全て揃った最高グレードのゾーンのため、即座に成行買いを入れる', 'S級条件が揃った最高信頼度のゾーン。プライスアクション確認後の買いエントリー計画を立てる', '週足ゾーンは価格が到達するまで時間がかかるため、より下位足のゾーンに切り替える', 3, '週足（日足以上）・フレッシュ・フィボ50〜61.8%合流・トレンド一致の4条件を満たし、S級ゾーンの最高グレード。しかしゾーンはあくまで「準備エリア」。到達即エントリーではなく、プライスアクション（ピンバー・包み足等）の確認後に判断するのが正しい手順。', false, 10),
(14, '1H足のZBに価格が到達した。フィボナッチとの合流はなく、過去に一度この価格帯で反発している。このゾーンでのエントリーリスクとして正しいものは？', '下位足のみ・合流なし・すでに再到達済みという弱点が重なっており、信頼性が低く慎重な判断が必要', '1H足のゾーンはフレッシュなら常にS級の信頼度があるため、リスクは低い', '1回の反発実績があるため、2回目も同様に機能する可能性が高くリスクは低い', '合流がないのは逆に「だまし」が少ないことを意味し、純粋なゾーンとして信頼できる', 1, 'このゾーンは「下位足のみ」「合流なし」「再到達済み（フレッシュさ低下）」とB級以下の特徴が揃っている。グレードが低いほど反応する確率が下がり損失リスクが高まる。複数の弱点が重なるゾーンは見送りを検討すべき。', false, 11),
(14, '価格が買いゾーンに到達した際、推奨される正しい対応はどれですか？', 'ゾーン到達と同時に即座に成行買い注文を入れる', 'ゾーン到達後は損切り幅を広く設定してエントリーする', 'ゾーン到達を確認したら、すぐに指値注文を入れて待機する', 'ゾーン到達はあくまで準備エリアであり、ピンバー・包み足等のプライスアクション確認後に判断する', 4, 'ゾーンは「ここで反応する可能性がある」という準備エリアに過ぎません。到達即エントリーはギャンブルと同じであり、ピンバーや包み足などのプライスアクションによる反転確認を待ってから判断するのが正しい手順です。', false, 12),
(14, 'あるZBに過去4回価格が到達し、そのたびに反発してきた。5回目の到達が近づいており、「実績があるから信頼できる」と考えているトレーダーがいる。この判断のどこが問題か？', '4回の反発実績は「超フレッシュ」の証明のため、問題はない', '5回目の到達ではフィボナッチとの合流を改めて確認する必要があるだけで、判断の方向性は正しい', '問題は「ゾーンの時間軸」を確認していない点であり、上位足で確認すれば信頼できる', '到達回数が増えるほどゾーンの残注文が消化されて効力が落ちており、「実績がある＝信頼できる」は誤りである', 4, '「よく効くゾーン＝何度も反発したゾーン」という思い込みは危険。到達のたびに残注文が消化されてゾーンの効力は低下する。3回以上の到達済みゾーンは「効きにくいゾーン」の典型であり、実績への過信がギャンブルトレードの入り口になる。', false, 13),
(14, '次のシナリオを読んで、このゾーンのグレードとして最も適切なものを選んでください。  「日足で確認された買いゾーン。価格はまだ一度もこのゾーンに戻っていない。フィボナッチのリトレースメント58%付近と重なっており、上位足の上昇トレンド方向と一致している。」', 'A級', 'S級', 'B級', 'グレード外（条件不足）', 2, '日足以上で確認（S級条件）、フレッシュ（未到達）、フィボ50〜61.8%と合流、トレンド方向と一致。S級の4条件すべてを満たしています。', false, 14),
(14, '次のシナリオを読んで、このゾーンのグレードとして最も適切なものを選んでください。  「4時間足で確認された売りゾーン。価格はまだ一度も戻っていない。フィボナッチ38.2%付近とは離れているが、直近の高値と重なる。」', 'S級', 'B級', 'グレード判定不能', 'A級', 4, 'A級の条件は「4H足で確認」「フレッシュ」「合流あり」です。このゾーンは4時間足・フレッシュ・直近高値との合流があるためA級に該当します。フィボナッチとの合流がなくても、何らかの合流があればA級条件を満たします。', false, 15),
(14, 'S級・A級・B級、どのグレードのゾーンに価格が到達した場合でも変わらない鉄則として正しいものはどれか？', 'S級ゾーンへの到達は「絶好のエントリーシグナル」のため、即座に成行注文を入れる', 'グレードが高いほどエントリーのハードルを下げてよく、S級なら確認不要', 'B級以下のゾーンは到達しても無視し、次のS/A級ゾーンを待つ', 'どのグレードでも、ゾーン到達はあくまで「準備エリア」への到達であり、プライスアクション確認を省略しない', 4, 'S級でもA級でも、ゾーンは「反応するかもしれないエリア」への到達に過ぎない。到達と同時に飛び乗るのはギャンブルと同じ。ピンバー・包み足等のプライスアクションで反転を確認してからエントリーするのが、グレードに関わらず変わらない鉄則。', false, 16),
(14, '「出発の勢い」が強いゾーンほど信頼性が高い理由として最も適切な説明はどれですか？', '急騰や急落の背後には大口の大量注文が存在し、その痕跡が濃いほどゾーンとしての根拠が強いため', '急激な動きの後はテクニカル指標が全て買いシグナルを出すため', '勢いが強いほど損切り幅を小さくできるため', '急激な動きの後は必ず反転するという統計的傾向があるため', 1, '急激な価格変動（急騰や急落）は、その背後に大口の大量注文があったことを示唆します。この「出発の勢い」が強いほど大口の関与が濃厚で、残された注文痕跡も明確になるため、ゾーンとしての信頼性が高まります。', false, 17),
(14, '下降トレンドが続く通貨ペアで、フレッシュな4H足のZB（買いゾーン）を発見した。フィボ55%と合流しており、出発の勢いも強い。このZBでの買いエントリーをどう判断すべきか？', 'フレッシュかつフィボ合流があるため、信頼度が高く買いエントリーを検討すべき', '4H足・フレッシュ・フィボ合流の条件が揃っているため、A級ゾーンとして積極的にエントリーすべき', 'フレッシュでフィボ合流があっても、下降トレンドへの逆行であるため効きにくく見送りを検討すべき', 'トレンドに逆行するゾーンは自動的にグレードアップするため積極的に狙うべき', 3, 'ゾーンの強さ5要素のひとつ「トレンドとの一致」は非常に重要。フレッシュでフィボ合流があっても、トレンドに逆行するゾーンは効きにくくなる。形式上の条件が揃っていてもトレンド逆行の弱点がその価値を下げる。トレンド方向と一致するゾーンを優先するのが基本。', false, 18),
(14, '次のシナリオについて、最も適切な判断を選んでください。  「15分足で確認された買いゾーンに価格が到達した。このゾーンは過去に2回価格が到達して反発している。フィボナッチ等との合流はなく、直近のトレンドは下降トレンドである。」', '過去2回の反発実績があるため、信頼性は高く即エントリーすべき', '下位足のみ・合流なし・トレンド逆行・再到達済みと条件が弱く、エントリーを見送るべき', '15分足で2回の反発実績はA級以上の根拠になるため、慎重にエントリーを検討すべき', 'フレッシュではないが、反発実績があるため小ロットでエントリーすべき', 2, 'このゾーンは下位足のみ（15分足）・合流なし・トレンドに逆行・再到達2回済みと、効きにくいゾーンの特徴ばかり揃えています。個別の条件が弱いことに加え、複数の弱点が重なっているため見送りが適切です。', false, 19),
(14, 'フレッシュな4H足のZBを発見したが、フィボナッチ50〜61.8%との合流はなく、直近高値と重なっている。このゾーンの扱い方として正しいものはどれか？', '4H足・フレッシュ・直近高値との合流（何らかの合流あり）の条件を満たし、A級ゾーンとして機能しうる', 'フィボナッチとの合流がないためB級以下に分類され、エントリー根拠として使えない', '直近高値との合流だけでは「合流」とはみなされず、フィボナッチとの合流が必須のためB級相当', 'フィボ50〜61.8%との合流がないためゴールデンゾーンにはならず、このゾーンは使えない', 1, 'A級ゾーンの条件は「4H足で確認」「フレッシュ（未到達）」「何らかの合流あり」の3点。合流はフィボナッチに限らず、直近高値・安値・移動平均線なども含まれる。ゴールデンゾーン（フィボ50〜61.8%合流）でなくても、何らかの合流があれば十分A級となる。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(15, '推進波の特徴として正しいものはどれですか？', 'トレンドと逆方向に動き、出来高が減少する', 'トレンド方向に動き、ローソク足が大きく角度が急である', 'トレンド方向に動くが、出来高は減少傾向にある', 'トレンドと逆方向に動き、ローソク足が大きい', 2, '推進波はトレンド方向に力強く動き、出来高が増加し、ローソク足が大きく、角度が急になるのが特徴です。これに対し修正波はトレンドと逆方向に弱く動きます。', false, 1),
(15, '修正波の特徴として正しい組み合わせはどれですか？', '出来高増加・ローソク足大きい・角度急', 'トレンド方向・力強い・角度緩やか', '出来高減少・ローソク足小さい・角度緩やか', 'トレンド方向・出来高減少・ローソク足大きい', 3, '修正波はトレンドと逆方向に動き、力が弱く、出来高が減少し、ローソク足が小さく、角度が緩やかになります。これらは推進波と対照的な特徴です。', false, 2),
(15, 'エリオット波動の基本構造として正しいものはどれですか？', '上昇3波＋下降2波の計5波', '推進5波＋修正3波（A-B-C）の計8波', '推進3波＋修正5波（A-B-C）の計8波', '上昇5波＋下降5波の計10波', 2, 'エリオット波動はトレンド方向に進む推進5波（1〜5波）と、トレンドに逆行する修正3波（A・B・C波）の計8波で一つのサイクルを構成します。', false, 3),
(15, 'エリオット波動の第1波の特徴として最も適切なものはどれですか？', '最も値幅が大きく、多くのトレーダーが参入する波', '天井を示唆するダイバージェンスがよく出現する波', '始まりの波だが、ほとんどの人が気づかず後からわかることが多い', '直前のトレンドの反転を確認させる、最も恐怖の強い波', 3, '第1波は新しいトレンドの始まりの波ですが、当時はほとんどのトレーダーが気づかず、後から振り返って「これが1波だった」と判明することが多いのが特徴です。', false, 4),
(15, 'エリオット波動の第2波における「鉄則」とは何ですか？', '3波の起点を割り込んではならない', '5波の高値を超えなければならない', '1波の起点（出発点）を割り込んではならない', 'A波の安値を必ず更新しなければならない', 3, '第2波はふるい落としの波で恐怖がピークに達しますが、1波の起点（出発点）を割り込まないことが鉄則です。起点を割り込んだ場合、エリオット波動のカウント自体が見直しの対象になります。', false, 5),
(15, 'エリオット波動において「本流」と呼ばれ、最も狙うべきとされる波はどれですか？', '第1波 — 最初に動くため最も安全', '第5波 — 最後のひと押しで確実性が高い', '第3波 — 確認済みの流れで最大の値幅を持つ', 'B波 — 偽りの回復だが、順張りのチャンス', 3, '第3波は「本流」と呼ばれ、最も大きな値幅を持ち、出来高が急増します。1波が確認済みであることから参入の根拠が立ちやすく、5波のような天井掴みリスクもないため最も狙いやすい波です。', false, 6),
(15, '第5波の注意点として正しいものはどれですか？', '出来高が最も急増し、1波の起点を割り込むリスクがある', '3波よりも値幅が大きく、最も利益を狙いやすい波', '勢いが鈍り、ダイバージェンスが出現し、天井掴みのリスクが高い', '直前の4波と価格帯が重なるため、エントリーを避けるべき波', 3, '第5波はトレンドの最後のひと押しですが、勢いが鈍っており、オシレーターとのダイバージェンスが出現しやすくなります。天井を掴むリスクが高いため慎重な対応が求められます。', false, 7),
(15, 'エリオット波動の修正波A波・B波・C波について、正しい説明はどれですか？', 'A波は本格的転換、B波はふるい落とし、C波は偽りの回復', 'A波は転換の始まり、B波は偽りの回復で罠、C波は本格的転換でA波の安値を割り込む', 'A波は最も値幅が大きい、B波は押し目確認、C波は新たなトレンドの始まり', 'A波は利確の調整、B波は最後のひと押し、C波は1波の起点への回帰', 2, 'A波は転換の始まりで「ただの押し目」と楽観視されがち、B波は偽りの回復で最も多い失敗パターン、C波は本格的な転換でA波の安値を割り込むという性格を持っています。', false, 8),
(15, '200MA（200日移動平均線）の役割として正しいものはどれですか？', 'エントリーの直接的な根拠となる指標', '短期の売買タイミングを判定するオシレーター', '方向を示すコンパスであり、ゾーンの信頼度を上げる補助ツール', 'フィボナッチリトレースメントと組み合わせるための基準線', 3, '200MAは方向を示すコンパスであり、エントリーの直接的な根拠ではなく、ゾーン分析などと組み合わせて信頼度を高める補助ツールとして使われます。価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断します。', false, 9),
(15, 'フラクタル構造とはどのような概念ですか？', '同じ時間軸の中で波動が3回繰り返される構造', '上位足の1波の中に下位足の3波構造があるという考え方', '上位足の3波の中に下位足の5波構造があるという考え方', 'すべての時間軸で波動の形が完全に一致するという法則', 3, 'フラクタル構造とは、上位足の3波の中に下位足の5波構造が内包されているという概念です。これにより、上位足で方向を確認し、下位足で起点を見つけるという二段階のアプローチが可能になります。', false, 10),
(15, '推進波と修正波の違いを実践で活かす際、正しいスタンスはどれですか？', '推進波でも修正波でも、エントリーチャンスがあれば積極的に乗る', '推進波に乗り、修正波では待つ。修正波でエントリーすると逆行に巻き込まれる', '修正波は推進波よりリスクが低いため、修正波中心にエントリーする', '推進波は値幅が大きすぎるため、修正波の反発を狙う方が安全', 2, '推進波はトレンド方向に力強く動くため、そこに乗ることが推奨されます。修正波では待つのが正解であり、修正波でエントリーすると逆行に巻き込まれるリスクが高くなります。', false, 11),
(15, '第3波を狙うべき理由として最も適切でないものはどれですか？', '1波がすでに確認済みであり、トレンドの方向性が見えている', '推進波の中で最も値幅が大きく、リスクリワードが良い', '天井掴みのリスクがなく、エントリー後の逆行リスクが最も低い', '出来高が急増しており、多くの参加者が同じ方向に動いている証拠がある', 3, '「天井掴みリスクがない」のは5波と比較した場合の利点ですが、「逆行リスクが最も低い」は言い過ぎです。3波であってもトレードにリスクは伴います。3波を狙う主な理由は、1波が確認済みで流れが見えることと、最大の値幅でリスクリワードが良いことです。', false, 12),
(15, '第4波の特徴として正しいものはどれですか？', '1波の価格帯と重ならない範囲で調整する波', '直前のトレンドの起点を割り込む、恐怖のピーク', '最も値幅が大きく、出来高が急増する波', '偽りの回復で、最も多い失敗パターンを生む波', 1, '第4波は3波での利確による調整の波ですが、1波の価格帯と重ならないのが特徴です。このルールはエリオット波動のカウントを検証する際の重要な基準の一つになります。', false, 13),
(15, 'B波が「最も多い失敗パターン」を生む理由として最も適切な説明はどれですか？', 'B波は値幅が最も大きく、損失が拡大しやすいため', 'B波は新たな上昇トレンドの始まりと錯覚させる偽りの回復であるため', 'B波は1波の起点を割り込むため、カウントが崩壊するため', 'B波は出来高が急増し、多くのトレーダーが参入してしまうため', 2, 'B波は一時的に価格が回復する「偽りの回復」であり、多くのトレーダーが「トレンド再開だ」と錯覚して買い（売り）を入れてしまいます。その後C波で本格的に転換するため、罠にはまったトレーダーが大きな損失を被るのが最も多い失敗パターンです。', false, 14),
(15, '次のシナリオを読んで、現在どの波にいる可能性が最も高いかを選んでください。  「上昇トレンドの途中で、直近の安値が前回の安値を下回らず、押し目から反発し始めた。出来高が急増しており、これまでの波の中で最も勢いがある。」', '第1波', '第5波', '第3波', 'A波', 3, '前回の安値を下回らない押し目（2波の終わり）から反発し、出来高が急増して最も勢いがあるという特徴は、第3波の始まり〜進行中の典型的なパターンです。第3波は推進波の中で最も力強く、出来高が最も増加します。', false, 15),
(15, '200MAを使った相場環境の判断として正しいものはどれですか？', '価格が200MAにタッチしたら、必ず反発する', '価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断する', '200MAの傾きが上を向いていれば、下降トレンドでも買いでエントリーする', '200MAは短期売買のエントリー・エグジットのシグナルとして使う', 2, '200MAは方向を示すコンパスであり、価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断します。ただし、これはエントリーの直接的な根拠ではなく、トレンド方向を確認する補助的な役割です。', false, 16),
(15, 'フラクタル構造を活用した実践的なアプローチとして正しいものはどれですか？', '下位足で波を数え、その結果を上位足に当てはめて方向を決める', '上位足で方向を確認し、下位足でエントリーの起点を見つける', '上位足と下位足で完全に同じ波動カウントが一致した場合のみエントリーする', '下位足の波動をすべてカウントし終えてから上位足を確認する', 2, 'フラクタル構造の実践的な活用方法は、まず上位足でトレンド方向を確認し、その後に下位足に切り替えてエントリーの起点を見つけるという二段階アプローチです。上位足の大方向に沿って下位足でタイミングを測ります。', false, 17),
(15, '次のシナリオを読んで、最も適切な判断を選んでください。  「日足で価格が200MAの下にある。4時間足で上昇の5波カウントができ、現在5波付近に達している。オシレーターにダイバージェンスが出現している。」', '200MAが下にあるため下降トレンドであり、5波の上昇は修正波の可能性が高い。買いエントリーは避けるべき', '5波まで上昇している勢いに乗って、追加の買いエントリーをする', 'ダイバージェンスは無視し、200MAのブレイクアウトを待ってからエントリーする', '4時間足の5波は日足の3波の中にある可能性が高く、積極的に買いを入れる', 1, '日足で200MAの下にあれば下降トレンドの可能性が高く、4時間足の5波カウントは下降トレンド中の修正波（上昇）の一部に過ぎない可能性があります。5波付近でダイバージェンスが出ていれば天井掴みリスクも高く、大方向に逆行するエントリーは避けるべきです。', false, 18),
(15, '波動カウントに対する正しいスタンスはどれですか？', 'すべての波を完璧にカウントできないとエントリーしてはならない', '1波から5波まで完璧にカウントできた場合のみ3波を狙う', '完璧なカウントは不要であり、「だいたい3波目あたり」で十分実践に役立つ', '波動カウントは主観的すぎるため、一切参考にすべきではない', 3, '実践では完璧な波動カウントは不要です。「だいたい3波目あたり」という大まかな判断でも、トレンド方向に乗るという目的には十分に機能します。完璧を求めすぎるとエントリーの機会を失います。', false, 19),
(15, '次のシナリオを読んで、最も注意すべきリスクを選んでください。  「上昇トレンドが続いている銘柄で、直近高値をわずかに更新した後、押し目が来た。多くのトレーダーが「押し目買いのチャンス」と言っている。しかし、オシレーターは直近高値時の数値を下回っている。」', '第3波の始まりであり、押し目買いの絶好のチャンスである', 'ダイバージェンスが示唆する第5波の天井圏であり、B波の罠の可能性がある', '第2波のふるい落としが終わった直後であり、3波開始の合図である', 'A波の転換が始まっており、C波で大きく下落する可能性があるため空売りすべき', 2, '直近高値を更新したもののオシレーターがそれを下回っているのはダイバージェンスの発生です。これは第5波の特徴であり、その後の押し目はB波（偽りの回復）の可能性があります。「押し目だ」と楽観視して飛び込むと、C波での本格的転換に巻き込まれる典型的な罠のパターンです。  ---  ## 正解分布 | 選択肢 | 問題番号 | 件数 | |--------|----------|------| | A | Q1, Q4, Q10, Q13, Q18 | 5 | | B | Q3, Q6, Q8, Q11, Q15 | 5 | | C | Q2, Q5, Q9, Q17, Q19 | 5 | | D | Q7, Q12, Q14, Q16, Q20 | 5 |  ## 出題バランス | カテゴリ | 問題番号 | 件数 | |----------|----------|------| | 用語確認 | Q1, Q2, Q3, Q4, Q5 | 5 | | 概念理解 | Q6, Q7, Q8, Q9, Q10, Q13, Q14, Q16 | 8 | | 応用・判断 | Q11, Q12, Q15, Q17, Q18, Q19, Q20 | 7 |', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(16, 'あるトレーダーが買いポジションで含み益+3万円になった途端に利確した。その後、別のポジションで含み損-3万円になっても「戻るはず」と保有し続けた。なぜこのような行動パターンが生まれるのか？', '損失の痛みを利益の喜びの約2倍強く感じるため、利益は早く確定し損失は先延ばしにするから', '利益の喜びが損失の痛みより強く、もっと利益を得たいという欲求が行動を支配するから', '利益と損失の感じ方は同じで、単に取引経験の不足による判断ミスだから', '含み損になると脳が危機モードになり、何もできなくなるから', 1, '損失の痛みは利益の喜びの約2倍強く感じるため、利益が出ると「早く確定したい（利小）」、損失が出ると「なかったことにしたい（損大）」という行動パターンが生まれます。これが利小損大の根本原因です。', false, 1),
(16, '確証バイアスによる判断の歪みを防ぐ対策として、最も有効なものはどれか？', '自分のエントリー方向を支持するアナリストのレポートを複数集め、根拠を固める', 'エントリー前に「自分が間違っている場合のシナリオ」を書き出し、反対意見も意図的に探す', 'ポジションを持ったら情報収集を止め、チャートの動きだけを見て判断する', '確証バイアスは経験を積めば自然に消えるため、トレード数をこなして慣れる', 2, '確証バイアスは、都合のいい情報だけを集める心理です。対策は意図的に反対意見・反証を探すこと。「自分が間違っていたらどうなるか」を書き出すことで、バイアスを外した客観的な判断ができます。', false, 2),
(16, '「損切りラインの-2万円を超えたが、2週間も我慢してきたから今さら損切りできない」と考えてポジションを保有し続けた。このトレーダーの判断の何が問題か？', '2週間という保有期間が短すぎるため、もっと長期で様子を見るべきだったから', '損切りラインを-2万円と設定したこと自体が間違いで、もっと広く設定すべきだったから', '現在の損失額ではなく「過去に費やした時間・忍耐」を判断の根拠にしてしまっているから', '含み損の状況で感情的になることは当然で、感情に従って待つことも合理的な選択だから', 3, '過去に費やした時間や忍耐は、今後の損益には一切関係しません。「ここまで我慢したから」という理由で損切りを先延ばしするのは取り戻せないコストにとらわれた判断であり、損失をさらに拡大させます。', false, 3),
(16, '含み損のポジションについて「このペアは自分で調べて選んだものだから」「手放すのが惜しい」と感じて損切りできない。このトレーダーの根本的な問題は何か？', 'ポジションを持つ前の分析が不十分だったため、再度ファンダメンタルを確認すべきだから', 'ポジション保有中にネガティブな感情が生まれることは正常であり、感情への対処法を学ぶべきだから', '損切りラインを事前に明確に設定していなかったことが根本的な原因だから', 'ポジション自体に「自分が選んだ」という感情的な価値を付加してしまい、客観的な損切り判断ができなくなっているから', 4, '保有効果は、自分が持っているものに実際より高い価値を感じる心理です。「自分が選んだポジション」に思い入れを持つほど手放せなくなり、損切りのタイミングを逃して損失が拡大します。', false, 4),
(16, '含み損-5万円で損切りラインをすでに超えているのに、「今は動かない方がいい」「もう少し待てば…」と何もできない状態が続いている。このトレーダーが今すべき行動として正しいものはどれか？', '感情に関係なく、事前に設定した損切りラインを根拠に今すぐ損切りを実行する', '含み損が-8万円まで広がったら強制決済されるよう、逆指値を入れ直す', 'チャートを閉じて一晩置き、翌朝冷静になってから判断する', '「待てば回復する」という直感を信じ、ファンダメンタル分析で根拠を探す', 1, '「今は動かない方が安全」と感じて損切りを先延ばしするのは現状維持バイアスの典型です。すでに損切りラインを超えている以上、感情ではなく事前のルールに従って即座に実行することが損失の拡大を防ぐ唯一の方法です。', false, 5),
(16, '5つの認知バイアスが重なって生まれる負けパターンの流れとして正しいものはどれですか？', '利小損大 → 損切り遅延 → 塩漬け → 破滅', '確証バイアス → リベンジ心理 → 利小損大 → 破滅', '塩漬け → 利小損大 → リベンジ心理 → 確証バイアス', 'リベンジ心理 → 保有効果 → サンクコスト → 利小損大', 1, 'プロスペクト理論による利小損大から始まり、損失回避による損切り遅延、現状維持バイアスによる塩漬けへと連鎖し、最終的に破滅に至るのが典型的な負けパターンです。', false, 6),
(16, '「ここまで耐えたのだから」と損切りを先延ばしにした結果、-10万円の損切り後にロットを3倍にしてリベンジトレードに走った。この連鎖を最初の段階で断ち切るために必要だったことは何か？', '-10万円になった時点でチャートを閉じ、頭を冷やしてから再エントリーを検討すること', 'ロットを3倍にする前に、過去の連敗パターンをトレード日誌で振り返ること', '「ここまで耐えた」という感情が湧いた時点でそれをシグナルと捉え、事前の損切りルールに機械的に従うこと', 'コミュニティで他のトレーダーに現状を相談し、客観的な視点をもらうこと', 3, '「ここまで耐えた」という感情はサンクコストの典型的なシグナルです。この感情が湧いた瞬間に気づき事前のルールに機械的に従うことで、保有効果→リベンジ心理へと続く破滅の連鎖を最初の段階で止められます。', false, 7),
(16, '損切りを「保険料」と捉える理由として最も適切なものはどれですか？', '損切りをすることで税金上の優遇措置が受けられるから', '小さな損失を払うことで大きな損失（破産）を防げるから', '損切りの回数を重ねることで自動的に勝率が上がるから', '損切りした金額は後で必ず回収できる仕組みになっているから', 2, '損切りは失敗ではなく、大損を防ぐための保険です。火災保険と同じで、小さな費用（損失）を払うことで、破産級の損失を未然に防ぐことができます。', false, 8),
(16, 'メタ認知の最初のステップ「気づく」で最も重要なことは何か？', '感情に気づいたらすぐチャートを閉じて、感情が収まるまで休むこと', '過去の失敗トレードのパターンをノートで振り返り、同じ状況かどうか確認すること', '深呼吸や瞑想で心を落ち着かせ、感情を中立の状態に戻すこと', '「今、焦りを感じている」「今、恐怖を感じている」と、感情に具体的な名前をつけること', 4, '感情に名前をつける（ラベリング）だけで、感情と自分の間に距離が生まれます。「焦り」「恐怖」と認識した瞬間、それは「脳の反応」になり、衝動的なエントリーを防ぐことができます。', false, 9),
(16, '「今この波に乗らなければ置いていかれる！」という強い衝動でエントリーしようとした。この暴走感情の正体と、取るべき行動の正しい組み合わせはどれか？', '焦り（FOMO）が暴走している。5秒止まって「計画外のエントリーではないか？」を確認し、計画になければ見送る', '欲望（もっと欲しい）が暴走している。利確目標をあらかじめ設定し、その目標まで機械的に待つ', '恐怖（損を認められない）が暴走している。逆指値を入れて感情の介入余地をなくす', '後悔（過去に囚われる）が暴走している。過去のトレード日誌を振り返ってから判断する', 1, '「乗り遅れる恐怖（FOMO）」は焦りが暴走した状態です。5秒止まって「計画通りのエントリーか？」を確認することで感情による飛び乗りを防げます。5秒のチェックに通らない衝動は、そもそも計画外のエントリーです。', false, 10),
(16, '5秒ルール（5問チェック版）の5つの質問として含まれないものはどれですか？', '計画通りのエントリーか？', '損切り位置は決まっているか？', '過去10回の勝率は50%以上か？', '上位足と整合しているか？（逆張りではないか）', 3, '5秒ルールの5問は「計画通りか」「損切りは決まっているか」「RR1:2以上か」「上位足と整合しているか」「夜眠れるロット数か」です。過去の勝率の確認は含まれません。', false, 11),
(16, '保有効果を打破するための「最重要の問いかけ」として正しいものはどれですか？', '「今日の損益はプラスだろうか？」', '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」', '「過去に同じパターンで勝てたか？」', '「この通貨ペアは今上昇トレンドにあるか？」', 2, '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」——答えがNoなら、保有効果にとらわれずそのポジションを手放すべきです。', false, 12),
(16, '「5秒で逃すチャンスは、そもそもあなたのチャンスではなかった」という言葉が意味することとして最も適切なものはどれですか？', 'チャンスは頻繁に来るので、1つ見逃しても気にする必要はない', '5秒の冷静チェックに通らないエントリーは、計画外の感情的なものである', 'エントリーの判断は5秒以内に直感で行うべきである', 'どんなチャンスも5秒で判断しなければ次のチャンスに切り替えるべきである', 2, '5秒ルールのチェックで弾かれるエントリーは、元々計画になかった感情的な飛び乗りです。5秒止まることで防げる損失の方が、逃すチャンスよりはるかに大きいという意味です。', false, 13),
(16, '次のシナリオを読んで、作動している認知バイアスを答えてください。  「USD/JPYの買いポジションを持っている。含み損が-3万円まで膨らんだが、SNSで「ドル円は上昇トレンド」という投稿を3つ見つけて安心し、損切りを見送った。逆に「下落リスク」を指摘する記事は読まなかった。」', 'プロスペクト理論', '確証バイアス', '保有効果', 'サンクコスト', 2, '自分のポジションに都合のいい情報（上昇トレンドの投稿）だけを集め、不都合な情報（下落リスクの記事）を無視しているのが確証バイアスの典型的なパターンです。', false, 14),
(16, '次のシナリオを読んで、最も優先すべき行動を選んでください。  「連敗が続いてイライラしている。「今日中に取り返そう」とロットを2倍に上げてエントリーしようとしている。上位足は下降トレンド、エントリー方向は買い。」', '焦り（FOMO）に対処するため、上位足の下降トレンドに従って売りエントリーに切り替える', 'ロットを2倍にするのではなく、いつものロットで買いエントリーする', 'リベンジトレードの典型パターンなので、エントリーを見送りチャートを閉じる', '「今日中に取り返す」という目的を達成するため、損切り幅を広く設定してエントリーする', 3, '連敗後の「取り返したい」という衝動はリベンジ心理です。上位足に逆行し、ロットを上げ、感情で動いている状態はリベンジトレードの典型であり、エントリーを見送るべきです。', false, 15),
(16, '次のケースで、5秒ルールの5問チェックを適用した場合の判断として正しいものはどれですか？  「日足上昇トレンド中。4時間足のZBに到達し、ピンバーが出た。損切りは決まっている。RR比は1:1.8。ロットは夜眠れるサイズ。計画通りのエントリー。」', '全ての条件を満たしているのでエントリーする', 'RR比が1:2未満なのでNoが1つあり、見送りまたは条件が整うまで待つ', 'ロットが適正ならRR比は関係ないのでエントリーする', 'ピンバーが出ているならRR比の確認は不要なのでエントリーする', 2, '5秒ルールは5つすべてYesでなければエントリー不可です。RR比1:1.8は「RR1:2以上か？」という質問に対してNoとなり、1つでもNoがあれば見送りが正解です。', false, 16),
(16, '次のシナリオを読んで、作動しているバイアスの連鎖として最も適切なものを選んでください。  「含み損-2万円のポジション。「ここまで耐えたのだから」と損切りを見送った。含み損が-5万円に拡大。「自分のポジションを手放したくない」とさらに保有し続けた。ついに-10万円で損切り。「すぐに取り返さないと」とロットを3倍にして再エントリーした。」', 'プロスペクト理論 → 確証バイアス → 現状維持バイアス', '現状維持バイアス → 確証バイアス → プロスペクト理論', 'サンクコスト → 保有効果 → リベンジ心理', '保有効果 → サンクコスト → 確証バイアス', 3, '「ここまで耐えたから」がサンクコスト、「手放したくない」が保有効果、「すぐに取り返さないと」がリベンジ心理です。この3つの連鎖が損切りできない人の典型的な破滅パターンです。', false, 17),
(16, '恐怖（Fear）による暴走を防ぐ対策として最も有効なものはどれですか？', '勝率を上げるために分析をさらに細かくする', '小さいロットで何度も練習して恐怖に慣れる', '損失を認めない自信をつけるために勝率の高い手法を探す', 'エントリー前に逆指値注文を入れておき、感情の介入余地をなくす', 4, '恐怖は「損を認められない感情」です。エントリー前に逆指値（損切り注文）を設定しておけば、損切りラインに達した時点で自動的に決済され、感情の介入余地がなくなります。', false, 18),
(16, '次のシナリオを読んで、メタ認知の3ステップを適用した場合の正しい順番を選んでください。  「チャートを見ていて「乗り遅れる！」と焦ってエントリーしようとした瞬間に立ち止まった。」', '「今、焦り（FOMO）を感じている」と認識する → 「これは一時的な脳の反応だ」と切り離す → 5秒ルールのチェックリストに従う', '5秒ルールのチェックリストに従う → 「今、焦りを感じている」と認識する → 「これは一時的な脳の反応だ」と切り離す', '「これは一時的な脳の反応だ」と切り離す → 5秒ルールのチェックリストに従う → 「今、焦りを感じている」と認識する', 'エントリーしてから感情を分析する → 次回同じ失敗をしないようルールを見直す → 新しいルールを記録する', 1, 'メタ認知は「気づく（感情にラベルを貼る）→ 距離を置く（感情と自分を切り離す）→ ルールに戻る（事前のルールに従う）」の順です。感情に名前をつけるだけで行動の質が変わります。', false, 19),
(16, '次のシナリオを読んで、最も適切な判断を選んでください。  「EUR/USDの買いポジションを持っている。含み益+1.5万円。「まだ上がるかも」と思ったが、同時に「利益が消えたら嫌だ」という不安も感じた。利確目標の+3万円にはまだ届いていない。」', '「まだ上がるかも」という欲望に従い、そのまま保有し続ける', '利益が消える恐怖から、利確目標より早く利益を確定させる', 'プロスペクト理論による利小損大の兆候と気づき、事前に決めた利確目標まで機械的に待つ', '含み益が出ているうちにロットを追加して利益を最大化する', 3, '「利益が消えたら嫌だ」と早く利確したくなるのはプロスペクト理論による反応です。メタ認知で気づき、事前に決めたルール（利確目標+3万円）に戻って機械的に実行するのが正しい対処です。  ---  ## 正解分布 | 選択肢 | 問題番号 | 件数 | |--------|----------|------| | A | Q1, Q6, Q9, Q16, Q19 | 5 | | B | Q2, Q5, Q8, Q12, Q15 | 5 | | C | Q3, Q7, Q10, Q14, Q17 | 5 | | D | Q4, Q11, Q13, Q18, Q20 | 5 |  ## 出題バランス | カテゴリ | 問題番号 | 件数 | |----------|----------|------| | 用語確認 | Q1, Q2, Q3, Q4, Q5 | 5 | | 概念理解 | Q6, Q7, Q8, Q9, Q10, Q11, Q12, Q13 | 8 | | 応用・判断 | Q14, Q15, Q16, Q17, Q18, Q19, Q20 | 7 |', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(17, '取引を始めて間もないトレーダーがConservative段階の推奨上限を超え、実質レバレッジ1.5倍でポジションを保有し続けた。この状態で相場が逆行した場合、最も起きやすい問題はどれか？', '相場が逆行しても損切りルールで自動的に守られるため問題ない', '実質レバレッジが高い分、わずかな逆行で証拠金維持率が急落し、強制ロスカットのリスクが高まる', 'Conservative段階では損切りが自動発動されるため問題は限定的', '強制ロスカットは維持率100%以下にならない限り起きないため問題ない', 2, 'Conservative段階（推奨1.0倍以下）を超えた実質レバレッジは、相場の小さな逆行でも証拠金維持率を急速に低下させる。「仕組みを知るフェーズ」での過大なレバレッジは退場リスクを著しく高める。', false, 1),
(17, 'STRADA基礎を一通り習得し、数ヶ月の実績がある。「まだ初心者だから」とConservative段階（1.0倍以下）に留まり続けている。この判断について最も正しい見方はどれか？', '経験に関わらず、Conservative段階を卒業すべきではない', 'STRADA基礎習得済みで実績があれば、Standard段階（1.5倍以下）へ移行する根拠がある', 'Standard段階への移行には最低1年の実績が必要', 'レバレッジ段階はVIX値だけで決め、経験は関係ない', 2, 'Standard段階（1.5倍以下）はSTRADA基礎習得済み・経験ありのトレーダーへのJTA推奨ライン。成長に合わせて段階を移行することが設計通りの運用であり、過度に保守的な段階に留まり続けることは判断力の萎縮につながる。', false, 2),
(17, 'Advanced段階（1年以上の実績）のトレーダーが、相場の好機と感じて実質レバレッジ3.0倍でポジションを持った。この状況の何が問題か？', 'Advanced段階なら3.0倍は推奨上限内のため問題ない', 'Advanced段階の推奨上限は2.5倍以下であり、3.0倍は上限を超えているため強制ロスカットリスクが高まる', 'Advanced段階には上限がなく、問題はトレードの方向性だけ', '証拠金維持率が200%以上なら何倍でも問題ない', 2, 'Advanced段階でも推奨上限は2.5倍以下。「上級者だから高レバレッジを使える」は誤解で、3.0倍は上限を超えている。上限は「常にこの倍率まで張る」ではなく「超えてはいけない天井」であり、相場の一時的な逆行で致命傷を負うリスクがある。', false, 3),
(17, '複数ポジションを保有中に証拠金維持率が185%まで低下したトレーダーが「あと少しで200%に回復しそうだから待とう」と判断した。この選択の何が問題か？', '185%はデイトレードの安全水準に近いため、問題は方向性の判断だけ', '200%を下回った時点でポジション縮小のトリガーが発動しており、「回復待ち」は強制ロスカットへの距離をさらに縮める', '逆指値が設定されていれば維持率に関わらず自動で守られるため問題ない', '証拠金は追加入金で即時回復できるため、まず入金を検討すべき', 2, '維持率200%を下回ったら「即ポジション縮小」がルール。「回復を待つ」という判断が強制ロスカットへの距離を縮め続ける。縮小で余力を取り戻し冷静な状態を保つことが、次の判断の質を守る。', false, 4),
(17, 'エントリー直前に「①ポジションサイズ計算済み ②リスク2%以内 ③維持率200%以上 ④レバレッジ推奨範囲内」の4項目を確認してエントリーした。しかし連敗中だったこのトレーダーは感情的な判断でエントリーしていた。見落とした5つ目のチェック項目はどれか？', '今日の経済指標発表スケジュールを確認したか？', '損切りラインは明確に決まっているか？', '連敗中に「特別なこと」をしようとしていないか？', '上位足のトレンド方向と一致しているか？', 3, '5項目チェックの5つ目は「連敗中に特別なことをしようとしていないか？」。連敗の焦りから通常と異なるエントリーをする心理を止める最も見落とされやすいチェックで、これがなければ資金管理ルールを守っていても感情が介入するリスクが残る。', false, 5),
(17, '口座100万円のトレーダーが連敗で50万円にまで減らした。「あと50万円稼げば元通りだ」と考えたが、この認識の何が誤りか？', '50万円の口座で「元の100万円に戻す」には+100%の利回りが必要で、損失前の「-50%」と回復の「+50万円」では難易度が数学的に2倍異なる', '50万円は正確な金額で、認識に誤りはない', '損失を取り戻すより追加入金のほうが合理的なため、考え方がそもそも間違い', '過去の損失はサンクコストなので、切り離して考えるべき', 1, '100万→50万は-50%。元に戻すには+100%が必要。「金額は同じ50万円」でも現在の口座に対する利回りは2倍になる。この回復の非対称性が「大きく負けないこと」を最優先にする数学的根拠。', false, 6),
(17, '損失が大きくなるほど回復に必要な利回りが「非対称的に」増大することを理解したとき、導かれる最も重要な行動変容はどれか？', '損失が出たら、より大きなポジションで早期回復を狙う', '大きな損失を避けること自体が、将来の利益機会を守る最も効率的な方法だと理解する', '損失後はトレードを一時休止し、資金が自然回復するまで待つ', '回復のために、より高いレバレッジ段階に移行する', 2, '50%の損失には100%の回復が必要なように、損失が大きくなるほど回復の利回りは非対称的に膨らむ。だからこそ「大きく負けないこと」自体が最大の利益創出であり、2%ルールやレバレッジ管理の数学的根拠となっている。', false, 7),
(17, '勝率68%の手法を持つトレーダーが「勝率が高いから多少のリスクは取っても大丈夫」と毎回口座の15%をリスクにさらした。その後5連敗が続き口座が激減した。最も根本的な問題はどれか？', '勝率68%なら5連敗は確率的にありえないため、手法自体が壊れていた', '勝率は長期の期待値を保証するが、1回あたりの過大なリスクが「退場」を先に引き起こす', '勝率を90%以上に高めれば、このような問題は避けられた', '5連敗後は相場が反転するので、ポジションを維持すべきだった', 2, '勝率68%でも15%リスクの5連敗で口座は約44%まで減少する。どれだけ優れた手法も退場すれば使い続けられない。「まず生存すること」が優れた手法を活かし続ける唯一の前提条件。', false, 8),
(17, 'Standard段階（上限1.5倍）でトレードしていたところ、VIXが普段の13から33に急上昇した。「良いセットアップが出た。今日もいつも通りエントリーしよう」と判断した。何が問題か？', 'VIXはFX市場に直接影響しないため、この判断に問題はない', 'VIX上昇時はレバレッジを+0.5倍引き上げてボラティリティを活かすべき', 'VIX33は「恐怖指数」の通常範囲内であり、特別な調整は不要', 'VIX30超えはボラティリティ急拡大のサインで、同じ1.5倍でも損失の振れ幅が大きくなる。-0.5倍の動的調整（1.0倍以下）が必要', 4, 'VIX30超えではボラティリティが急拡大し、同じレバレッジでも実際のリスクが増大する。Standard段階なら-0.5倍の動的調整で1.0倍以下に抑える。「良いシグナル＝通常通り」という思考が落とし穴。', false, 9),
(17, '「なぜ1回のリスクを口座の2%以内に制限するのか」という問いに対して、最も本質的な理由はどれか？', 'ブローカーがそれ以上のリスクを禁止しているから', '10連敗しても約82%の資金が残り、冷静に立て直せる水準を数学的に確保できるから', '2%を超えると税率が高くなるから', '勝率が50%を超えないと2%には意味がないから', 2, '2%ルールは10連敗で約82%が残る水準。口座残高に連動してポジションサイズが自動縮小し、破産確率が極めて低くなる。これは我慢ではなく、数学的に最も合理的なリスク水準。', false, 10),
(17, '勝率65%のトレーダーが月を追うごとに口座を減らし続けている。平均利益3,000円、平均損失8,000円。この状態の根本的な原因はどれか？', '勝率65%は低すぎる。まず90%以上に上げる必要がある', '勝率が高くても損益比が悪ければ期待値がマイナスになり、続けるほど口座が減っていく', 'このくらいの勝率と損益比は普通で、口座が減り続けるのは運が悪いだけ', '損失を抑えるには、ポジションサイズをさらに大きくする必要がある', 2, '期待値＝(0.65×3,000)-(0.35×8,000)＝1,950-2,800＝-850円。勝率65%でもマイナス。長期生存には「勝率を高める」ではなく「損益比をRR1:2以上に保ち期待値をプラスにする」ことが本質。', false, 11),
(17, 'Advanced段階に到達したトレーダーが「上限2.5倍まで使えるようになった」と解釈し、毎回のエントリーで2.5倍を基準にポジションサイズを決めていた。この解釈の何が問題か？', 'Advanced段階では2.5倍を基準にすることが推奨されており、問題はない', '推奨上限は「常にこの倍率まで張る目標値」ではなく「超えてはいけない天井」であり、実際の運用はそれより低い水準で行う', 'Advanced段階に達していれば2.5倍程度なら連続使用しても問題ない', '上限が2.5倍なら、1回のリスクが2%以内であれば何倍でも使用してよい', 2, '推奨上限は「超えてはいけない天井」であり「毎回張るべき目標値」ではない。相場環境・ポジション状況・精神状態に応じて上限より低いレバレッジで臨むのが正しい使い方。上限まで常に張り続ければ逆行時に致命傷を負うリスクが残り続ける。', false, 12),
(17, '同じ手法を使う2人のトレーダーAとBがいる。Aは1%ルール、Bは5%ルールで運用していた。20連敗という同じ結果を経験した後、最も大きく異なるのはどれか？', '連敗数が同じなので、口座残高の差はほぼない', '5%ルールのBは早く損失を取り戻せるため、最終的には有利になる', 'Aの口座は約82%が残っているが、Bは約36%まで減少しており、次のトレードから「かけられるリスク額」が大きく違う', '1%ルールのAは20連敗後に強制的なトレード停止がかかるが、5%ルールのBにはかからない', 3, '20連敗で1%ルールなら約82%残存、5%ルールなら約36%まで減少。連敗は確率的に必ず起きる。残存資金の差が「立て直せる」か「退場に近づく」かを分ける。%ルールの選択は単なる保守性ではなく、生存設計そのもの。', false, 13),
(17, '「強制ロスカットは維持率が100%前後で発動するから、100%を超えていれば問題ない」と考えるトレーダーがいた。この認識の何が欠けているか？', '強制ロスカットの発動水準は100%ではなく130%のため、認識が正確ではない', '強制ロスカット水準に近い状態での運用は、市場のわずかな動きで一瞬にして発動するリスクがあり、維持率200%はそこから十分な距離を保つための最低ライン', '100%以上であれば損益はプラスなので、問題は方向性の判断だけ', '維持率は証券会社によって異なるため、100%という基準は一律に存在しない', 2, '強制ロスカット水準ギリギリでの運用は「崖っぷちを歩く」状態。維持率200%はその水準から十分な距離を保ち、急な逆行があっても冷静な判断を続けられる余力を確保するための最低ライン。', false, 14),
(17, '5連敗した直後、「損を取り返すためにいつもより大きなロットでエントリーしたい」と感じた。このとき推奨される行動と、その理由はどれか？', '大きなロットでエントリーする。連敗後は相場が反転しやすいから', 'ロットを半分に下げる。連敗中は判断力が低下しており、さらなる損失拡大を防ぐため', 'その日のトレードを終了する。5連敗は「悪い日」のサインだから', 'レバレッジを上限まで使う。連敗分を一気に取り戻す好機だから', 2, '5連敗時はロットを半分に下げる。連敗中の「取り返したい」感情こそが判断力を狂わせる。ロットを下げることで損失の拡大を防ぎながら冷静さを取り戻すための構造的な安全装置。3連敗→当日終了、5連敗→ロット半減という段階設計。', false, 15),
(17, '「大きく勝つ」ことより「退場しない」ことを優先すべき根拠として最も適切なものはどれですか？', '大きな利益には高い税率がかかるから', 'ブローカーが大きな利益の引き出しを制限するから', '損失と回復には非対称性があり、大きな損失を取り戻すには不相応な利回りが必要だから', '大きく勝つことができるトレーダーは稀だから', 3, '損失と回復の非対称性が「退場しない」ことを優先すべき数学的根拠です。50%の損失には100%、90%の損失には900%の利回りが必要になります。つまり、大きな損失を回避すること自体が、将来の利益の可能性を残すことに直結します。', false, 16),
(17, 'スイングトレード（数日〜数週間保有）を行うトレーダーが「証拠金維持率130%でも問題ない」と判断してポジションを保有している。この判断が危険な理由はどれか？', 'スイングトレードでは証拠金維持率は関係ない', '維持率130%はスキャルピング向けの水準であり、スイングトレードでは急激な逆行で強制ロスカットのリスクが高い', '維持率130%はどのスタイルでも十分な水準', '維持率はポジションを保有していないときだけ確認すればよい', 2, '維持率の安全水準はスタイルによって異なる。スキャルピング（約130%）は保有時間が極めて短いため成立するが、スイングは300〜500%が目安。保有時間が長いほど逆行リスクが大きく、低い維持率では強制ロスカットが近づく。', false, 17),
(17, '10連敗が続いているトレーダーが「そろそろ反転するはず」と考え、通常より大きなロットでエントリーした。この行動の根本的な問題は何か？', '10連敗は統計的に異常で、相場のルールが変わったサインだから大きなロットが適切', '連敗は確率的に起きて当然であり、連敗中ほどロットを下げて口座を守るべきなのに逆の行動をしているから', '10連敗後はトレードを完全に止めるのが唯一の正解', 'ロットを大きくすること自体は問題ないが、損切りラインの設定が問題', 2, '連敗は「異常」ではなく「正常」な確率現象。1%ルールなら10連敗でも約90%の資金が残るよう設計されている。連敗中ほど「取り返したい」心理でロットを上げたくなるが、ドローダウン時こそロットを下げて口座を守るのが正しい構造的な備え。', false, 18),
(17, 'VIXが通常レベル（12〜15）から30を超えた状態に変化した場合、Advanced段階（通常上限2.5倍）のトレーダーが取るべき対応として正しいものはどれですか？', 'レバレッジを変更せず、普段通りにトレードを続ける', 'レバレッジ上限を2.0倍に引き下げ、リスクを抑制する', '全てのポジションを保有したまま、指値で利確を待つ', 'レバレッジ上限を3.0倍に引き上げ、大きく動く相場で利益を狙う', 2, 'VIX30超え時の動的調整により、Advanced段階（2.5倍上限）は-0.5倍されて2.0倍以下に引き下げる。パニック相場では値動きが荒くなるため、通常より保守的なレバレッジで臨むことが生存確率を高める。', false, 19),
(17, '週の前半で口座の-6%に達したトレーダーが「あと2日ある、週後半で取り返せる」と考えてトレードを続けた。この判断の何が問題か？', '-6%程度は許容範囲内で、週後半に続けることは合理的', '週-6%は自動ブレーキのトリガーであり、続けることで損失が拡大し、回復に必要な利回りが非対称的に増える', '-6%の損失は取り返せる範囲で、感情がなければ続けていい', 'ブレーキをかけるべきは月-10%であり、週-6%では継続してよい', 2, '週-6%はその週のトレードを終了するトリガー。「取り返せる」という思考自体が損失拡大の原因で、連敗の負のスパイラルを防ぐのが段階的ブレーキの目的。3連敗→当日終了、5連敗→ロット半減、週-6%→週終了、10連敗→1週休止、月-10%→月終了の5段階設計。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(18, 'あるトレーダーが「今日は絶対に勝てる」と確信し、口座資金の20%を1回のトレードにリスクした。この行動がなぜ危険なのか、最も本質的な理由はどれですか？', '利益確定目標を設定せずにエントリーしているから', '数回の連敗で口座に致命的なダメージを受け、退場リスクが急上昇するから', '自信がある時ほど相場は逆に動きやすいから', '損切り注文を置いていないに違いないから', 2, '20%をリスクすると5連敗で口座は33%以下に激減します。2%ルールで同じ5連敗なら約90%が残る。1回のリスクを2%以内に制限することが、退場を防ぐ構造的な防壁になります。', false, 1),
(18, '口座資金100万円のとき2%ルールでの許容損失は2万円だった。連敗が続き口座が50万円に減った場合、次のトレードで許容できる損失額はいくらになりますか？', '変わらず2万円（ルールは金額で固定されている）', '1万円（口座残高の2%が自動的に新たな上限になる）', '0.5万円（口座が半分になったのでリスクも半分にする）', '2%ルールは口座が半分以下になったら停止する', 2, '2%ルールは「残高の2%」という比率固定のため、口座が減れば許容損失も連動して縮小します。これにより連敗時に損失ペースが自然に鈍化し、口座への致命傷を構造的に防ぎます。', false, 2),
(18, '正しいロット計算の手順として適切なものはどれですか？', '総資金の2%でエントリー金額を決めてから、損切り位置を探す', '自信の度合いに応じてロット数を調整し、損切り幅を後から決める', '損切り幅（pips）を先に決め、許容損失額からロット数を逆算する', '利益目標の値幅を先に決め、そこから逆算してロット数を計算する', 3, '正しい手順は「許容損失額（総資金×2%）を決める → 損切り幅（pips）を決める → 許容損失額と損切り幅からロット数を逆算する」という順序です。ロット数は感情や自信ではなく、数学的に導きます。', false, 3),
(18, '2%ルールを厳守して10連敗した場合、残存する資金はおよそ何%ですか？', '約50%', '約65%', '約82%', '約95%', 3, '2%ルールでの10連敗は 0.98^10 ≒ 0.817、つまり資金の約82%が残存します。口座が減るたびにリスク額も減るため、損失のペースが自然に鈍化するのが2%ルールの強みです。', false, 4),
(18, '2%ルールを守るトレーダーAと、毎回10%をリスクするトレーダーBが10連敗した。残存資金率の比較として正しいものはどれですか？', 'AもBも約80%が残り、差はほぼない', 'Aは約82%、Bは約35%しか残らない', 'どちらも約60%前後で、リスク設定より運の影響が大きい', 'Bの方がリスクを取っているため、最終的に口座は多く残る', 2, 'Aは0.98^10≒82%、Bは0.90^10≒35%。同じ10連敗でも1回あたりのリスク設定の違いだけで残存率が2倍以上変わります。「小さなリスクを維持すること」が長期的な生存確率を決定づけます。', false, 5),
(18, 'あるトレーダーが今日3回連続で負けた。「まだ取り返せる、もう1回だけ」と感じ、同じロットで続けようとしている。資金管理のルールに従った正しい行動はどれですか？', 'ロットを1.5倍に増やして3回分を一発で取り返す', 'ロットを半分に下げて今日の分を続ける', 'その日のトレードを終了し、翌日冷静な状態で再開する', 'エントリー前に5秒ルールを実行してから慎重に続ける', 3, '3連敗は「その日のトレード終了」の自動ブレーキポイントです。連敗中は感情が乱れリベンジトレードに向かいやすく、さらに損失が重なるリスクが高い。強制停止することで感情的な損失拡大を防ぎます。', false, 6),
(18, '今週に入り5連敗が続いているトレーダーが、翌日から同じロットで再開しようとしている。次にすべき行動として正しいものはどれですか？', 'その週のトレードをすべて終了する', '1週間の休止をとってから再開する', 'ロットを半分に下げて継続する', '損切り幅だけを狭めたうえで同じロットで再開する', 3, '5連敗は「ロット半減」の自動ブレーキポイントです。3連敗でその日を切り上げても翌日も負けが続く場合、ロットを縮小して追加ダメージを抑えながら、手法の分析・検証に集中できます。', false, 7),
(18, '月曜から金曜の間に口座資金の7%を失った。残り1日あるため「今週中に取り返したい」と思い、金曜のトレードを続けようとしている。資金管理のルールに従うと次にすべき行動は？', '残り1日で取り返せるようロットを2倍に増やす', '月間-10%に達するまでは続けてよい', 'その週のトレードを終了する', '5秒ルールを徹底してから1回だけエントリーする', 3, '週で-6%が「その週のトレード終了」の自動ブレーキです。7%はすでにこれを超えています。「取り返したい」という焦りが生まれている状態こそ、ルールが最も機能すべきタイミングです。', false, 8),
(18, 'あるトレーダーが10連敗を記録した。「これ以上ロットを下げると利益が出ない」と考え、現在のロットのまま続けようとしている。正しい行動は？', 'ロットを4分の1に下げて継続する', 'その月のトレードを終了する', '1週間の休止をとる', '手法を変えてすぐに再挑戦する', 3, '10連敗は「1週間の休止」の自動ブレーキポイントです。ここまで負けが続く場合、手法や分析に根本的な問題がある可能性が高い。感情的な継続より、冷静に振り返る時間を確保することが最優先です。', false, 9),
(18, '今月口座資金の11%を失ったトレーダーが「来月から気持ちを切り替えればいい」と思い、月末まで少額でトレードを続けようとしている。正しい行動は？', '少額なら続けても問題ない', '翌月の計画を立てながら様子見トレードを続ける', 'その月のトレードを終了する', '2%ルールを1%に変更して今月残りを継続する', 3, '月間-10%に達した時点で「その月のトレード終了」が自動ブレーキです。月間で5回分の2%損失は手法・メンタル両面に問題がある可能性を示しており、翌月に備えて今月中に徹底的に振り返ります。', false, 10),
(18, '「自信があるからロットを張る」のではなく、何に基づいてロット数を決めるべきですか？', 'チャートの形状が完璧に見える度合い', '損切りまでの距離が近いかどうか', '直近の勝率の高さ', '経済指標発表の重要度', 2, 'ロット数は「自信」ではなく「損切りまでの距離」で決めます。損切り幅が狭い（距離が近い）ほど、同じ許容損失額でも大きなロットを張れる仕組みです。感情ではなく構造的にロットを算出することが資金管理の核心です。', false, 11),
(18, '口座資金100万円で損切り幅が50pipsのトレードをする場合、2%ルールに従った正しいロット計算の考え方として適切なものはどれですか？（1pipsあたりの損失をロット単位とします）', '100万円の2%である2万円を損切り幅50pipsで割り、ロット数を求める', '100万円を50pipsで割り、その2%をロット数とする', '100万円を一括でエントリーし、2万円下がったら損切る', '50pips動くごとにロットを増やしていく', 1, 'ロット計算の基本は「許容損失額（総資金×2%）÷ 損切り幅（pips）」です。100万円×2%=2万円を損切り幅50pipsで割ることで、逆算された適正ロット数が求まります。', false, 12),
(18, '「夜、ぐっすり眠れるロット数が適正値」という言葉が意味する内容として最も適切なものはどれですか？', 'ポジションを持ったまま寝るべきではないため、デイトレードのみを行えという意味', '利益が出た日は安心して眠れるため、勝率を上げることに集中すべきという意味', '含み損を気にして眠れないような大きなロットは、適正なロット数を超えているという意味', '寝る前には必ず全ポジションを決済すべきという意味', 3, '適正なロット数であれば、ポジションを持っていても精神的な負担は小さく安眠できます。逆に含み損が気になって眠れないなら、それはロットが大きすぎるサインであり、資金管理の観点から縮小が必要です。', false, 13),
(18, '勝率40%のトレーダーが毎月安定して利益を上げている。「なぜ勝率が低いのに勝てるのか」という問いへの最も本質的な答えはどれですか？', '運が良い月が続いているだけで、長期的には必ず負ける', '1回の平均利益が1回の平均損失より十分に大きく、期待値がプラスになっているから', 'エントリー回数を増やすことで勝率の影響が薄まるから', '損切りを使わないポジション管理をしているから', 2, '期待値は「勝率×平均利益 + 敗率×平均損失」で決まります。勝率40%でも平均利益が平均損失の2倍以上あれば長期的に利益が出ます。勝率より損益比（リスクリワード）の設計が収益の鍵です。', false, 14),
(18, 'トレーダーの期待値がプラスであるために必要な条件はどれですか？', '勝率が50%を超えること', '平均利益が平均損失より大きいこと、または勝率が十分に高いこと', '毎回同じロット数でエントリーすること', '1日あたりのトレード回数を一定に保つこと', 2, '期待値がプラスになるには「勝率×平均利益 + 敗率×平均損失 > 0」である必要があります。勝率が低くても平均利益が平均損失より十分に大きければプラスになりますし、逆に勝率が高ければ利益目標が小さくても成立します。', false, 15),
(18, '「ロットを張らない勇気」が最も尊い勇気である理由として最も適切なものはどれですか？', 'ロットを張らない期間が長いほど税金の負担が減るため', '条件が揃っていない場面でエントリーを自制できることが、長期的な生存に直結するため', '少ないロットで利益を出す方が技術が高いと評価されるため', '大きなロットを張るよりも小さなロットを何度も張る方が統計的に有利なため', 2, '相場には常にチャンスがあるわけではなく、条件が揃わない場面でエントリーしないこともトレードの重要な判断です。「張らない勇気」を持てることは、感情に抗える自律性の証明であり、長期的な生存に直結します。', false, 16),
(18, 'あるトレーダーが1日に2%ルールを守りながら2回エントリーし、どちらも負けた。合計損失率は約4%になった。この状況への正しい対応はどれですか？', '1回あたり2%ルールを守っているので、この日はそのまま続けてよい', '合計損失が1日の上限（総資金の3%）を超えたため、その日のトレードを終了する', '次のトレードだけロットを半分に下げて続ける', '3%を超えた時点で自動的に1週間の休止が発動する', 2, '1日の損失上限は総資金の3%が目安です。1回2%のルールでも2回負けると4%になるため、「1日あたり3%」の上限を設けることで、1日のうちに口座に致命傷を与えることを防ぎます。', false, 17),
(18, '口座資金200万円のトレーダーが、損切り幅20pipsのトレードと損切り幅80pipsのトレードを比較します。2%ルールに従う場合、どちらがより大きなロット数でエントリーできますか？', '損切り幅20pipsの方が大きなロット数でエントリーできる', '損切り幅80pipsの方が大きなロット数でエントリーできる', 'どちらも同じロット数になる', '損切り幅に関係なく、総資金の2%分のロット数で固定される', 1, '許容損失額が同じ（200万円×2%=4万円）場合、損切り幅が狭いほど1pipsあたりの許容損失が大きくなるため、より大きなロット数でエントリーできます。損切り幅20pipsなら4万円÷20pips、80pipsなら4万円÷80pipsで計算されます。', false, 18),
(18, 'トレードの期待値がマイナスであるトレーダーが、トレード回数を増やした場合どうなりますか？', '大数の法則により、次第に期待値がプラスに近づく', '回数を増やすほど1回あたりの損失が減っていく', '期待値がマイナスのまま回数を増やすほど、長期的な累積損失は大きくなる', 'トレード回数と期待値には関係がない', 3, '期待値がマイナスの場合、トレードを繰り返すほど数学的には確実に累積損失が拡大します。回数を増やすことが解決策ではなく、まず期待値をプラスにする（分析方法やリスクリワードの改善）ことが前提です。', false, 19),
(18, 'あるトレーダーが今月を振り返ると、3連敗した日が2回あり、1週間で7%下落し、月間では12%下落していた。この月にどの自動ブレーキが正しく発動すべきでしたか？', '3連敗時：その日終了 ／ 週-6%超：その週終了 ／ 月-10%超：その月終了', '3連敗時：ロット半減 ／ 週-7%：その日終了 ／ 月-12%：1週間休止', 'すべて継続OK、月末にまとめて振り返れば十分', '3連敗時：1週間休止 ／ 週損失は問わない ／ 月-10%超：ロット半減', 1, '自動ブレーキの5段階は「3連敗→その日終了」「5連敗→ロット半減」「週-6%→その週終了」「10連敗→1週間休止」「月-10%→その月終了」。感情が動く前にルールが止める。それが自動ブレーキの存在意義です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(19, '口座残高が200万円から120万円に減ったトレーダーが「1トレードの損失を4万円以内に抑えれば安全」と考えた。2%ルールから見て、この判断の何が問題ですか？', '現残高120万円の2%は2.4万円が上限で、4万円のリスクはルール上限を大きく超えているから', '2%ルールは口座が増加している局面にしか適用しないから', '4万円以内に抑えていれば、口座残高の変動に関わらず安全だから', '損失額は固定するよりも相場の状況に応じて毎回変えるべきだから', 1, '2%ルールは「現在の残高×2%」で毎回計算します。残高120万円なら上限は2.4万円です。元の4万円（残高200万円時の2%）を使い続けると、実質3.3%のリスクになりドローダウンがさらに拡大します。口座が減るほどルールを厳守することが生存の条件です。', false, 1),
(19, '高値からの下落が続くチャートを見て、あるトレーダーは「そろそろ反発するはず」と感じた。しかし自分のルールではエントリー根拠が揃っていない。どう行動すべきですか？', '感覚的な予測を信じて、小さいロットで様子見エントリーする', '根拠が揃わなければエントリーしない。反発しても見送る', '極小ロットで入れば損失が限定されるため、根拠がなくても許容できる', '他のトレーダーのSNS投稿を参考に判断する', 2, '根拠のないエントリーは期待値がマイナスになります。「張らない勇気」とは条件が揃わないとき何もしない自制心のことです。見送ることで口座を守り、次のチャンスを待てる状態を維持します。', false, 2),
(19, 'ロット数を計算する前に、必ずチャート分析でエントリーポイントを確定させる必要がある。その理由として最も適切なものはどれですか？', 'ロット数を先に決めると証券会社の注文画面で入力できないから', 'エントリーポイントが決まらないと損切りラインが設定できず、ロット計算に必要な損切り幅が出ないから', 'エントリーと利確の両方が決まってからでなければ、損切りラインを設定できないから', 'ロット数の計算変数はすべてチャートから直接読み取れるから', 2, 'ロット数は「許容損失額 ÷ 損切り幅」で決まります。損切り幅はエントリーポイントと損切りラインの差であるため、まずエントリー根拠を確定させなければロット計算自体が成立しません。分析が先、計算は後です。', false, 3),
(19, 'トレードしない日チェックリストに含まれる項目として正しいものはどれですか？', 'その日の経済指標発表がすでに終わっている', '直近3トレードのうち2つが勝ちである', 'SNSの他人のトレードを見て焦っている', '1日の利益目標をまだ達成していない', 3, 'SNSで他人の結果を見て焦っている状態は、感情に基づくエントリーの危険信号です。チェックリストは「自分のルール以外の要因で動こうとしていないか」を確認するためのものであり、該当する項目があればその日はトレードを見送ります。', false, 4),
(19, 'セットアップが出ず1週間ノートレードが続いている。焦りを感じたあるトレーダーが「少し条件が甘くてもエントリーしてしまおう」と考えた。この判断の問題点として最も適切なものはどれですか？', '1週間空けると感覚が鈍るため、できるだけ毎日エントリーすべきだから', '条件が不十分な場面でのエントリーは期待値がマイナスになりやすく、焦りに負けた行動は長期成績を悪化させるから', 'ノートレード期間は精神的ストレスになるため、小ロットでポジションを持つ方がよいから', '1週間空けると過去の分析が無効になってしまうから', 2, '条件が揃わない場面でのエントリーは期待値がマイナスになる「ギャンブル」です。焦りやヒマからくる衝動的なエントリーは長期成績を確実に悪化させます。ルールに合うセットアップが来るまで待ち続ける忍耐力こそが、長期生存の核心です。', false, 5),
(19, '口座資金100万円のトレーダーが2%ルールに従う場合、1回のトレードで許容される最大損失額はいくらですか？', '5,000円', '10,000円', '50,000円', '20,000円', 4, '100万円 × 2% = 20,000円です。口座資金が増えれば許容損失額も増え、減れば自動的に縮小するため、2%ルールは口座残高に連動した安全装置として機能します。', false, 6),
(19, 'エントリー根拠が固まったあるトレーダーが、次に「損切りライン」より先に「利益確定ライン」を設定しようとした。この手順の問題点はどれですか？', '損切りラインと利確ラインを同時に設定しなければ証券会社のシステムが受け付けないから', '損切りラインが決まらないとリスク額が不明なままで、ロット数を計算できないから', '利確ラインを先に決めると感情が入り、損切りラインが甘くなるから', '損切りラインは利確ラインの2倍の距離に置く必要があるから', 2, 'ロット計算は「許容損失額 ÷ 損切り幅」で行うため、損切りラインが決まらないとロット数を算出できません。損切りは「根拠が崩れる価格」という客観的基準で決まるため、エントリー根拠の確定直後に設定するのが正しい順序です。', false, 7),
(19, 'トレードを始めたばかりで手法の検証データがほとんどないトレーダーが、どの取引スタイルから始めるべきか考えている。最も適切な考え方はどれですか？', '利益を早く増やすために高めのレバレッジで積極的に取引する', '経験が浅いうちは最も保守的なレバレッジ設定で始め、データを積んでからスタイルを上げる', '損失が出た場合はレバレッジを上げて早期回復を狙う', 'レバレッジよりもエントリー頻度を増やして早く経験を積む', 2, '経験が浅いほど資金管理の失敗リスクが高く、保守的なレバレッジ設定が生存の前提です。まず小さなリスクで検証データを積み、結果に応じて段階的にスタイルを引き上げることで、致命的なドローダウンを避けながら成長できます。', false, 8),
(19, '資金100万円、損切り幅40pipsのトレードにおいて、2%ルールに従ってロット数を計算する際の正しい考え方はどれですか？（1pipsあたりの損失をロット単位とします）', '100万円の2%である2万円を損切り幅40pipsで割ってロット数を求める', '100万円を40pipsで割り、その2%をロット数とする', '100万円の40%をリスク額とし、それを2pipsで割る', '40pipsの2%にあたる0.8pips分のロット数を計算する', 1, 'ロット計算の基本式は「許容損失額（総資金×2%）÷ 損切り幅（pips）」です。100万円×2%=20,000円を40pipsで割ることで、損切りに到達した時の損失がちょうど2万円に収まるロット数が逆算できます。', false, 9),
(19, 'エントリー直後、あるトレーダーが「相場の様子を見てから損切り注文を入れよう」と逆指値を保留にした。この判断の何が危険ですか？', '逆指値を後から入れると証券会社に手数料が2重にかかるから', '損切り注文がない状態では感情が介入しやすく、含み損が出ても「もう少し待てば」とルール通りに切れなくなるリスクがあるから', '相場を見ながら損切りを判断する方が柔軟で合理的だから', '逆指値は早めに入れると相場に読まれてハントされるから', 2, 'エントリー後に損切り注文がない状態は「感情で判断する余地」を残します。含み損が出た瞬間に「まだ戻るかも」という心理が働き、損切りが遅れて損失が拡大します。エントリーと同時に逆指値を入れることで、感情の介入を構造的に排除できます。', false, 10),
(19, '損切りが3回続いた直後、あるトレーダーが「今すぐ取り返さなければ」と感じて次のエントリーを検討している。この状況で最も適切な行動はどれですか？', '小ロットであれば連敗直後でもエントリーして問題ない', '感情的な状態でのトレードはリベンジトレードになりやすいため、まずチャートを閉じて冷静になる時間を取る', '損失を取り返すためにロットを上げてエントリーする', '連敗は確率的な偏りなので次は勝率が上がる。すぐにエントリーすべきだ', 2, '連敗後の「取り返したい」という感情は判断力を著しく低下させます。この状態でのエントリーはリベンジトレードになりやすく、ロットが大きくなるほど一発退場のリスクが高まります。感情が収まるまでチャートから離れることが最優先です。', false, 11),
(19, 'ドローダウンを小さく保つことが重要な理由として最も適切なものはどれですか？', '資金が減ると元の残高に戻るために必要な利益率が非線形的に増大するため', 'ドローダウンが大きいと税金の計算が複雑になるため', 'ドローダウンが大きいとレバレッジが自動的に上がってしまうため', '証券会社の規定でドローダウン率に制限があるため', 1, '資金が10%減ると元に戻すには約11%の利益が必要で、50%減ると100%の利益が必要になります。減少幅が大きくなるほど回復に必要な利益率が急増するため、ドローダウンを小さく抑えることが生存の鍵です。', false, 12),
(19, 'エントリー前に「損切り幅」と「リスク額」の両方を確定させてからロット計算をする理由として最も適切なものはどれですか？', '証券会社の注文画面で両方の入力が必須だから', '利益目標を先に決めるよりも手間が少ないから', '損切り幅だけでは損失額がわからず、リスク額だけではロット数が決まらないから', '損切り幅とリスク額が同じでなければならないから', 3, 'ロット数は「許容損失額 ÷ 損切り幅」で計算されるため、この2つの値が揃って初めて適正ロット数が算出されます。どちらか一方だけではロットを確定できず、適当にロットを決めてから損切りを探すのは本来の手順と逆です。', false, 13),
(19, '損切り確定直後、チャートを確認したあるトレーダーが「今度こそ良いセットアップが来た」と感じてすぐにエントリーしようとした。この段階で即エントリーすることの問題点は何ですか？', '損切り確定直後はチャートデータが更新されておらず、情報が不正確だから', '損失の痛みで感情が高ぶっており、パターン認識が歪んでリベンジトレードになるリスクが高いから', '連続エントリーは証拠金の追加が必要になる可能性があるから', '前のトレードの分析をまとめてから次のエントリーをするのが正しい手順だから', 2, '損切り直後は損失の痛みで感情が高ぶっており、「次こそ勝てる」という思い込みでセットアップを見誤りやすい状態です。感情が落ち着くまでチャートから離れ、冷静な判断ができる状態に戻ってから次のトレードを検討します。', false, 14),
(19, '資金管理の基本を習得し検証データも一定量積んだが、まだ上級者とは言えない段階のトレーダーが取引スタイルを選ぼうとしている。最も適切な考え方はどれですか？', '勝率が高い月が続けば、レバレッジを実績に応じて自由に引き上げてよい', '検証データが一定量あっても経験が浅い段階は最も保守的なスタイルを維持すべき', '実績が積み上がるにつれてスタイルを段階的にアップグレードし、より積極的な設定に移行する', 'スタイルは固定せず、毎回のトレードで状況判断して最適なレバレッジを選ぶ', 3, '検証データと実戦経験が積み上がるにつれて、資金管理スタイルも段階的にアップグレードすることが適切です。経験なしに積極的なスタイルを採用すると、たった数回の連敗で致命的なドローダウンを招くリスクがあります。', false, 15),
(19, '同じ資金100万円で、損切り幅20pipsのトレードと損切り幅80pipsのトレードを比較します。2%ルールに従う場合、どちらがより大きなロット数でエントリーできますか？', '損切り幅20pipsの方が大きなロット数でエントリーできる', '損切り幅80pipsの方が大きなロット数でエントリーできる', 'どちらも同じロット数になる', '許容損失額が同じなのでロット数に違いはない', 1, '許容損失額（20,000円）が同じ場合、損切り幅が狭いほど1pipsあたりに割り当てられる金額が大きくなり、結果としてより大きなロット数でエントリーできます。20pipsなら20,000÷20=1,000/lot-unit、80pipsなら20,000÷80=250/lot-unitとなり、前者が4倍のロット数になります。', false, 16),
(19, '十分な検証データと実戦経験を持つ上級者が、より積極的なレバレッジ設定でトレードしている。それでも「リスク率の上限」を設けなければならない理由として最も適切なものはどれですか？', '上級者でも証券会社のリスク規制に従う義務があるから', 'どれだけ経験があっても連敗は起こり、上限がなければ1回の連敗で口座が壊滅する可能性があるから', '上級者はスプレッドが広がる局面でリスク率を変動させるべきだから', 'リスク率の上限設定は初心者向けのルールであり、上級者には本来不要である', 2, 'リスク管理の基本は経験レベルに関わらず有効です。どれだけ実績があっても相場は予測不能な動きをすることがあり、上限なしでは一度の連敗で口座が壊滅するリスクを排除できません。スタイルが上がっても管理の本質は変わりません。', false, 17),
(19, 'トレードしない日チェックリストの項目として、「損切り直後（30分以内）」が含まれている理由は何ですか？', '損切り注文の約定確認に30分かかるため', '30分以内はスプレッドが広がっているため', '証券会社のシステム制限により再注文できないため', '損失直後は感情的になっており、冷静な判断ができないため', 4, '損切り直後は損失の痛みが感情的な判断を引き起こし、リベンジトレードや焦りによるミスエントリーにつながりやすい状態です。30分の待機時間は感情を落ち着かせ、冷静さを取り戻すための安全装置です。', false, 18),
(19, '資金100万円のトレーダーが、損切り幅25pipsのセットアップを見つけました。2%ルールに従った場合、許容損失額20,000円を損切り幅25pipsで割ると、適正ロット単位はいくつですか？', '400', '500', '800', '1,000', 3, '20,000円 ÷ 25pips = 800です。許容損失額を損切り幅で割ることで、損切りに到達した時の損失がちょうど20,000円に収まる適正ロット数が計算できます。計算結果が端数になる場合は、切り下げて安全側に寄せます。', false, 19),
(19, '次のシチュエーションのうち、「トレードしない日チェックリスト」に該当する理由が複数含まれているものはどれですか？シチュエーション：昨晩よく眠れず、朝の経済指標発表前にSNSで他人の大きな利益を見て焦りを感じている。', '該当項目は1個。体調不良のみが該当する', '該当項目は3個。「体調不良」「重要指標発表前」「SNSで焦っている」がすべて該当する', '該当項目は2個。「体調不良（寝不足）」と「SNSで焦っている」が該当する', '該当項目は0個。すべてチェックリスト外の理由である', 2, '「寝不足（体調不良）」「重要な経済指標の発表前」「SNSの他人のトレードを見て焦っている」の3項目がすべてチェックリストに該当します。1項目でも該当すればトレードを見送るべきであり、3項目同時に該当する状況は間違いなくエントリーを避けるべき場面です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(20, '「損切りは保険料」という考え方について、最も適切な説明はどれですか？', '損切り注文を出すと証券会社に手数料が発生するため、保険料と呼ばれる', '損切りを一度もしないトレーダーに対して、口座に保険料が課金される仕組み', '利益が出たトレードの一部を、将来の損切りに備えて積み立てる制度', '小さな損失を支払うことで、大きな損失から口座を守るという考え方', 4, '損切りは「火災保険」と同じ考え方です。家が火事になる前に小さな保険料を払っておけば、全焼という最悪の事態を防げます。同様に、小さな損失を確定させることで口座への致命傷を防ぎます。', false, 1),
(20, '損切りができない心理の変化として、正しい順番はどれですか？', '麻痺 → 否認 → 期待', '期待 → 麻痺 → 否認', '否認 → 期待 → 麻痺', '否認 → 麻痺 → 期待', 3, '含み損を抱えたトレーダーの心理は「否認（まだ大丈夫）」→「期待（きっと戻る）」→「麻痺（どうでもいい）」の3段階で進行します。この連鎖に気づくことが損切り実行の第一歩です。', false, 2),
(20, '「成り行き逆指値」とはどのような注文方法ですか？', '損切りラインに到達した時点で、現在の市場価格で約定させる注文', '損切りラインに到達した時点で、指定した価格で約定させる注文', '利益が一定額に達した時点で、自動的にポジションを閉じる注文', 'エントリーと同時に損切りと利確の両方を設定する注文', 1, '成り行き逆指値は、指定した価格に到達した瞬間に「成り行き」で発注されるため、価格が急変していても確実に約定します。スリッページは発生しますが、損切り未執行のリスクを構造的に排除できます。', false, 3),
(20, '損切りラインを一度決めた後、「まだ大丈夫だろう」と言い訳してラインを不利な方向に動かしてはいけない理由として最も適切なものはどれですか？', '損切りラインの変更には証券会社の承認が必要だから', '損切りラインは法律で一度決めたら変更禁止とされているから', 'ラインを動かすと自動的にロット数が増えてしまうから', '一度動かすと「もう少し待てば」と二度と止まらなくなるから', 4, '損切りラインの後出し変更は「否認→期待→麻痺」の心理連鎖そのものです。一度許容すると「今回だけ」という例外が常態化し、最終的に制御不能な含み損に直面します。', false, 4),
(20, '「30分ルール」とは何をするルールですか？', 'エントリー前に30分間チャートを観察し続けるルール', '1回のトレードで最大30分間しかポジションを保有してはいけないルール', '損切り後、最低30分間チャートを閉じて冷静になるルール', '利確後に30分間は新規エントリーをしてはいけないルール', 3, '損切り直後は感情が高ぶっており、リベンジトレードに走りやすい状態です。最低30分チャートから離れることで感情を落ち着かせ、冷静な判断力を取り戻すための安全装置です。', false, 5),
(20, 'トレードにおいて「逆指値（ストップロス）」をエントリー前に設定すべき理由として最も重要なものはどれですか？', '含み損が拡大してからでは感情的に損切りできなくなる可能性が高いから', 'エントリー前の方がスプレッドが狭いから', '証券会社のシステム上、エントリー後は逆指値を設定できないから', '逆指値を設定しないと税制上の優遇を受けられないから', 1, '含み損が拡大すると「否認→期待→麻痺」の心理が働き、冷静な損切りができなくなります。逆指値を事前に設定しておくことで、感情が介入する隙間を構造的に排除できます。', false, 6),
(20, '次のうち、「指値逆指値」の説明として正しいものはどれですか？', '現在の価格より有利なレートでエントリーする注文', 'ポジションの利益が減少し始めた時点で自動的に決済する注文', '損切りラインに到達した時点で、指定した価格で売買する注文', '毎日決まった時刻に自動的に損切りを執行する注文', 3, '指値逆指値は、トリガー価格に到達した際に「指定した価格」で指値注文を出す方式です。希望価格での約定を狙えますが、急変時には約定しないリスクがあり、確実性では成り行き逆指値に劣ります。', false, 7),
(20, 'ナンピンが危険とされる理由として最も適切なものはどれですか？', 'ナンピンすると証券会社の手数料が倍になるから', 'ナンピンは実質的に損切りラインを不利な方向に動かすことと同じだから', 'ナンピンは法律で禁止されている取引手法だから', 'ナンピンすると自動的にレバレッジが上がってしまうから', 2, 'ナンピンは「平均取得単価を下げる」行為ですが、本質的には損切りラインを後退させることと同じです。損切りラインを動かしてはいけないのと同様に、ポジションを増やすことで含み損のリスクを拡大させます。', false, 8),
(20, '「損切り＝保険料」という比喩において、「家が火事」に相当するものはどれですか？', 'テクニカル分析の失敗', '経済指標の予想外の結果', 'レバレッジの上限到達', '口座資金の大きな減少（ドローダウン）', 4, 'この比喩では、小さな損失（保険料）を支払うことで、口座資金の取り返しのつかない減少（家の全焼）を防ぐという構造を示しています。火災保険と同じく、損切りは「備え」です。', false, 9),
(20, 'トレーリングストップの基本的な考え方として正しいものはどれですか？', '価格が有利に動くにつれて損切りラインも有利な方向に追従させる', '損切りラインを常にエントリー価格の同じ距離に保ち続ける', '損切りラインをランダムに変更して相場の変動に対応する', '利益が出たら損切りラインを外して利益を伸ばし続ける', 1, 'トレーリングストップは、利益が拡大するにつれて損切りラインを利益側に移動させる手法です。利益を守りながらさらなる値幅を狙える一方で、損切りラインを不利方向には決して動かさないのが原則です。', false, 10),
(20, '含み損の拡大を防ぐために最も効果的な仕組みはどれですか？', 'エントリーと同時に逆指値注文を設定しておく', '含み損が一定額に達したらナンピンして平均単価を改善する', '損切りラインを広めに設定して、相場のノイズに耐えさせる', 'ポジションを持ったままチャートを見続け、手動で損切りを判断する', 1, 'エントリー直後に逆指値を設定することで、感情が介入する前に損切りラインを構造的に固定できます。手動での損切り判断は「否認→期待→麻痺」の心理的罠にかかるリスクがあります。', false, 11),
(20, '損切り直後にトレーダーが陥りやすい「リベンジトレード」とはどのような行動ですか？', '損切りしたのと同じ通貨ペアで、逆方向にエントリーすること', '過去の損切りを記録して分析し、次回のトレードに活かすこと', '損切りの精度を上げるために、すぐにデモトレードで検証すること', '損失を取り返そうと、感情の高ぶりの中で衝動的にエントリーすること', 4, 'リベンジトレードは損失の痛みから「取り返さなきゃ」という感情に駆られてエントリーする行動です。30分ルールはこのリベンジトレードを防ぐための安全装置として機能します。', false, 12),
(20, 'エントリーの正しい順番5ステップのうち、第2ステップは何ですか？', '許容損失額からロット数を計算する', '根拠が崩れる場所を特定して損切りラインを決定する', '即座に逆指値注文を入れる', '利益確定の目標価格を設定する', 2, '第1ステップでエントリーポイントが決まった後、第2ステップでは「そのエントリーの根拠が崩れる価格帯」を損切りラインとして決定します。根拠と損切りラインはセットで考えます。', false, 13),
(20, '次のシチュエーションで、最も適切な行動はどれですか？「USD/JPYの買いポジションを持ち、損切りラインを150.00に設定していた。価格が150.00に到達し、損切りが執行された直後である。」', '最低30分間はチャートを閉じ、感情を落ち着かせる', 'すぐにチャートを確認し、反転の兆しがあれば再エントリーする', '損切りの原因を分析するため、直ちに1分足チャートを開く', '損失を取り返すため、ロット数を増やしてすぐに再エントリーする', 1, '損切り直後は「30分ルール」を適用し、最低30分間チャートから離れることが正しい行動です。損失の直後は感情的になっており、冷静な判断ができない状態のため、リベンジトレードを防ぐ必要があります。', false, 14),
(20, '損切りの心理的障害について、「否認」の段階でトレーダーが典型的に考えることは何ですか？', '「もうどうでもいい、全部消えても構わない」', '「きっと明日には戻っているはずだ」', '「まだ損切りするような状況じゃない、一時的な下落にすぎない」', '「早く損切りして次のトレードに進もう」', 3, '否認の段階では、含み損の現実を認めず「まだ大丈夫」「一時的な動きだ」と自分に言い聞かせます。損切りの必要性を頭ごなしに否定するのがこの段階の特徴です。「きっと戻る」は次の「期待」の段階にあたります。', false, 15),
(20, '次のケースのうち、正しいエントリー手順に従っているものはどれですか？', 'まずロット数を決め、次にエントリーポイントを探し、最後に損切りラインを設定した', 'エントリーしてから損切りラインを検討し、利益が出たら逆指値を入れた', 'チャート分析でエントリーポイントを決め、損切りラインを決め、ロットを計算し、エントリー後すぐに逆指値を入れた', 'エントリーポイントと損切りラインを同時に決め、逆指値を入れずにエントリーした', 3, '正しい順番は「①チャート分析→エントリーポイント決定」「②損切りライン決定」「③ロット計算」「④エントリー」「⑤即座に逆指値注文」です。エントリー前にリスクを完全に設計し、エントリー直後に損切りを構造的に固定するのが鉄則です。', false, 16),
(20, '成り行き逆指値と指値逆指値の最大の違いは何ですか？', '成り行きは買い専用、指値は売り専用であること', '成り行きは確実に約定するが価格ズレが生じる、指値は希望価格を指定できるが約定しないリスクがあること', '成り行きは日中のみ有効、指値は翌日も有効であること', '成り行きは手数料無料、指値は手数料が発生すること', 2, '成り行き逆指値は価格ズレ（スリッページ）があっても確実に約定するため、損切りの確実性を重視する場合に適しています。指値逆指値は価格を指定できる分、急変時には約定しないリスクを伴います。', false, 17),
(20, '損切りラインを決定する際に考えるべき「根拠が崩れる場所」とは、具体的にどのような場所を指すのが適切ですか？', 'エントリー価格から一律50pips離れた場所', '直近の高値・安値やサポート・レジスタンスなど、エントリーの前提が否定される価格帯', '自分が許容できる金額の損失に相当する価格帯', 'テクニカル指標の売買シグナルが出る場所', 2, '損切りラインは「エントリーの根拠が崩れる場所」に設定するのが原則です。直近の安値を割る、サポートラインを割るなど、自分のシナリオが否定される価格帯に置くことで、損切りに意味を持たせられます。', false, 18),
(20, '損切りの心理で「麻痺」の段階に達したトレーダーの特徴として最も当てはまるものはどれですか？', 'チャートを頻繁に確認して、1pipsごとの値動きに一喜一憂する', '含み損の金額が大きすぎて感覚が麻痺し、損切りも放置もどちらでもよくなる', '損切りを決意し、冷静に逆指値の価格を再計算する', '過去の類似のチャートパターンを検索して根拠を探し始める', 2, '麻痺の段階では含み損が大きくなりすぎ、「どうせ戻らない」と諦めや「もう関係ない」という無関心に陥ります。ここまで進むと損切りの実行は極めて困難になり、口座に致命的なダメージを与えることが多いです。', false, 19),
(20, '次のシチュエーションで、このトレーダーの最大の問題点は何ですか？「EUR/USDの買いポジションを持っている。損切りラインを1.0800に設定していたが、価格が1.0790まで下落した。しかし『重要な経済指標の発表が控えているから、その後に戻るかもしれない』と考え、損切りラインを1.0750に変更した。」', '経済指標を考慮していない点 — 指標発表前は損切りラインを広げるべきである', '買いポジションを選択した点 — 経済指標前は売りポジションにすべきだった', 'ロット数が小さすぎる点 — 損切りラインを変更するならロットも増やすべきだった', '損切りラインを後出しで変更している点 — 一度動かすと二度と止まらなくなる', 4, '損切りラインを「まだ大丈夫」という理由で不利方向に変更するのは、否認→期待→麻痺の心理連鎖の典型的な兆候です。一度決めた損切りラインは理由を問わず動かさないことが、トレーダーの生存に直結する鉄則です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(21, '日足チャートで、直近の安値が前の安値より高い位置に形成された。買い手と売り手の力関係として何が読み取れるか？', '売り手が毎回前より高い水準でしか押せなくなっており、買い手が優位', '安値が更新できていないため上昇トレンドが終わったサイン', '安値が高くなっているのは売り手の資金量が増えている証拠', '安値の位置は上昇・下降の判断とは無関係', 1, '安値が切り上がる（HL）とは、売り手が前より高い水準でしか押せなくなっていること。買い手が優位を保っており、上昇トレンドを構成する2要素のひとつ。', false, 1),
(21, '上昇トレンド中に価格が再度高値を目指したが、前回の高値を超えられずに反転した。この状態が示す最も重要なことはどれか？', '買い手の勢いが衰え、売り手が前より低い位置で押し返し始めている', '高値を超えられなかっただけで、上昇トレンドにはまったく問題ない', '高値圏にいるのでポジションを半分利確するタイミング', '出来高が増えていれば問題なく上昇が続く', 1, '高値が切り下がる（LH）は、買い手が前より低い位置で売り手に押し返されている状態。下降トレンドの構成要素であり、トレンド転換の初期シグナルになりうる。', false, 2),
(21, 'チャート上でHHとHLが連続して形成されている場合、現在の相場環境はどれですか？', '下降トレンド', 'レンジ相場', '上昇トレンド', 'トレンド転換中', 3, 'HH（高値切り上げ）とHL（安値切り上げ）の連続は、上昇トレンドの定義です。山も谷も切り上がっていることが、買い手が主導権を握っている証拠です。', false, 3),
(21, '反発のたびに前回高値を超えられず、下落のたびに前回安値を更新し続けている相場を見ている。このような環境でトレーダーが取るべき基本的な姿勢はどれか？', '売り手優位の環境として売り目線を持ち、戻り売りのタイミングを探す', 'レンジ相場なのでどちらにも対応できるよう準備する', 'いつ底打ちするかわからないので買い目線でチャンスを待つ', '上昇と下降が混在しているためポジションを持たない', 1, 'LH（高値切り下げ）＋LL（安値切り下げ）の連続は下降トレンドの定義。山も谷も切り下がる環境では売り手が主導権を持っており、逆張りの買いは危険。', false, 4),
(21, 'ダウ理論でチャートを読む練習を始めたいトレーダーが、高値・安値の認識を鍛えようとしている。最初のステップとして最も効果的な方法はどれか？', '日足チャートを開き、明確に反転した山と谷だけを終値ベースでカウントする', '1分足チャートで細かい値動きをすべて捉える練習をする', 'インジケーターを複数設定して自動的に高値・安値を検出させる', '5分足で短期の値動きを観察し、素早く判断する練習をする', 1, '短い時間足はノイズが多く正しい波の把握が難しい。日足の明確な反転ポイントを終値ベースで拾う練習で目が養われ、その後に短い時間軸への応用が可能になる。', false, 5),
(21, 'レンジ相場をHH/HL/LH/LLの観点から説明したものとして最も適切なものはどれですか？', 'HHもLLも形成されず、高値と安値が同じ水準で推移する状態', 'HLとLHが交互に現れる状態', 'HHとLLが同時に連続して形成される状態', 'HLだけが連続し、HHが出現しない状態', 1, 'レンジ相場は「HHもLLも出ない」状態です。高値を更新できず、安値も更新できないため、価格が一定の範囲内で行ったり来たりします。', false, 6),
(21, 'ある株が数ヶ月にわたり大きく上昇した。最初は一部の機関投資家だけが静かに買い始め、やがて個人投資家が大量参加して急騰、その後高値圏で横ばいになり大口が売り始めた。このパターンをダウ理論では何と説明できるか？', '先行期（賢い資金が動く）→ 追随期（大衆が参加）→ 利食い期（賢い資金が抜ける）', '利食い期 → 先行期 → 追随期の順で進んだ', '追随期 → 先行期 → 利食い期の順で進んだ', '先行期 → 利食い期 → 追随期の順で進んだ', 1, 'ダウ理論第1原則「トレンドには3段階がある」。先行期に賢い資金が動き始め、追随期に大衆が乗り、利食い期に賢い資金が抜ける。この流れを知ると今がどの段階かを判断できる。', false, 7),
(21, '上昇トレンドが続いているが、最近の高値更新時に出来高が前回より大幅に減少している。このシグナルをどう解釈すべきか？', 'トレンドに乗る参加者が減っており、上昇の勢いが衰えているサイン', '出来高が少ないほど価格が動きやすく、上昇が加速する証拠', '出来高はトレンドの強さと無関係なため無視してよい', '出来高の減少はトレンド転換が確定したことを示す即時売りシグナル', 1, 'ダウ理論第2原則「出来高がトレンドを確認する」。出来高の減少は参加者がトレンドに同意しなくなってきたサイン。価格が上昇でも出来高が減ればトレンドの衰えを疑う。', false, 8),
(21, '上昇トレンド継続中に高値更新に失敗したが、押し安値はまだ割れていない。このとき取るべき行動として最も適切なものはどれか？', '転換シグナルが出るまでは上昇継続と仮定し、逆張りの売りは入れない', '高値更新に失敗した時点で転換と判断し、即座に売りエントリーする', '方向感がなくなったため全ポジションを手仕舞いして様子見に入る', '押し安値は割れていないが念のため半分だけ利確する', 1, 'ダウ理論第3原則「疑わしきはトレンド継続」。転換の2条件（高値更新失敗＋押し安値を割る）が揃うまでトレンド継続と仮定する。片方だけで逆張りすると損切りの繰り返しになる。', false, 9),
(21, '上昇トレンド中に高値更新が失敗したのを見て、あるトレーダーが「転換した」と判断して売りエントリーした。しかし価格はその後急反発し、損失が出た。このトレーダーが見落とした条件はどれか？', '押し安値をまだ割り込んでいなかった——転換には高値失敗＋押し安値割れの両方が必要', '出来高が減少していなかった', '200MAが上向きのままだった', '日足でも上昇トレンドを確認していなかった', 1, '転換の判断には「高値更新の失敗」と「押し安値を割り込む」の2条件が揃う必要がある。片方だけの判断は逆張りになりやすく、ダマシに遭う原因となる。', false, 10),
(21, '次のケースのうち、「調整」ではなく「転換」の兆候として最も適切なものはどれですか？', '出来高が減少し、押し安値は割っていない', '出来高が急増し、上位足が崩れ始め、押し安値を明確に割った', '上位足は上昇トレンドのままで、価格が直近の押し安値近くまで下落した', '出来高が減少し、上位足の方向は変わっていない', 2, '転換の兆候は「出来高急増」「上位足が崩れ始める」「押し安値を明確に割った」の3要素で判断します。出来高が減少している場合や押し安値が保たれている場合は調整の可能性が高いです。', false, 11),
(21, 'チャートを開くと、現在の価格は200MAを大きく下回り、200MA自体も右肩下がりになっている。このような環境での適切な行動はどれか？', '売り手優位の環境として売り目線を持ち、戻り売りのタイミングを探す', '200MAは長期すぎて短期トレードには無関係なため別の指標だけを使う', '200MAが右肩下がりでも価格が200MAに近づいたら買いチャンスと見る', '200MAより価格が低い状態はレンジなのでどちらにも対応できるよう準備する', 1, '200MAは相場全体のトレンド方向を示す「北極星」。価格が200MAを下回り200MA自体も下向きなら明確な下降トレンド環境。この環境での買いはトレンドに逆らう行為になる。', false, 12),
(21, '価格が200MAの上にあり、200MA自体も右肩上がりの場合、最も適切な目線はどれですか？', '売り目線で戻り売りを探す', 'レンジ目線で両方向のブレイクアウトを待つ', '買い目線で押し目買いを考える', '200MAの傾きに関係なく、常にニュートラル目線', 3, '価格が200MAの上にあり、200MA自体も上向きの場合は明確な上昇トレンドの環境です。買い目線で押し目買いを検討するのが、トレンドに逆らわない順張りの基本です。', false, 13),
(21, 'スイングトレードでエントリーを狙っているトレーダーが、週足で上昇トレンドを確認した。次のステップとして正しい順番はどれか？', '日足でエントリーシナリオを描き、4H足で具体的なタイミングを探す', 'すぐに4H足に切り替えて細かいエントリーポイントを探す', '週足と月足をさらに比較して長期トレンドを再確認する', '1H足に切り替えてスキャルピングでエントリーする', 1, 'スイングトレードは「週足で方向→日足でシナリオ→4H足でタイミング」が基本。上位足で確認した方向に沿って徐々に小さい時間軸でタイミングを絞り込むことで精度が上がる。', false, 14),
(21, '日足で上昇トレンド、1時間足で下降の波が見られる場合、最も適切な判断はどれですか？', '1時間足の下降を重視して売りエントリーする', '日足と1時間足が矛盾するため、両方無視して別の銘柄を探す', '1時間足の下降が終わるまで待ち、反転したら日足に関係なく売りで入る', '日足の上昇トレンドを信じて、1時間足の下降は押し目の可能性が高いと考える', 4, '上位足と下位足が矛盾する場合、上位足の調整（押し目）の可能性が高いです。迷ったら上位足を信じるのが鉄則であり、日足の上昇トレンドが続く前提で対応すべきです。', false, 15),
(21, '次のチャート状況のうち、「上昇トレンドが継続している」と最も自信を持って言えるものはどれですか？', '直近の高値を更新し、直近の安値も切り上がっている', '直近の高値を更新したが、直近の安値も下抜けた', '直近の高値更新に失敗したが、直近の安値は保っている', '直近の高値は更新していないが、直近の安値は切り上がっている', 1, '上昇トレンドの定義は「HH（高値切り上げ）＋ HL（安値切り上げ）の連続」です。高値も安値も切り上がっているAが、上昇トレンド継続を最も明確に示しています。', false, 16),
(21, '次のシチュエーションで、トレンド転換と判断できるものはどれですか？', '上昇トレンド中に高値を更新したが、その後少し下落した', '上昇トレンド中に直近の押し安値を下抜けたが、その後すぐに新高値を更新した', '上昇トレンド中に高値更新に失敗し、さらに直近の押し安値を下抜けた', '上昇トレンド中に高値更新に失敗し、その後も高値を更新し続けている', 3, '転換の2条件「高値更新の失敗」と「押し安値を割り込む」が両方揃った場合にのみ、トレンド転換と判断できます。Aは通常の波、Bはダマシの可能性、Dはトレンド継続です。', false, 17),
(21, 'ダウ理論に基づき押し安値を割れた瞬間に売りエントリーしたが、その後すぐに価格が反発して損失となった。この経験から学べるダウ理論の注意点として最も適切なのはどれか？', '転換シグナル確認後のエントリーは遅れる場合があり、ダマシも存在する', 'ダウ理論は出来高をまったく考慮しないため信頼性が低い', 'ダウ理論はどんな相場でも正確に転換点を教えてくれる', '安値を割った瞬間は必ず転換が確定しており、エントリーのミスが原因', 1, 'ダウ理論の限界は「転換シグナルが遅れること」と「ダマシが存在すること」。シグナル確認後に動いても既に遅く、偽シグナルもあるため、損切り設定と出来高の確認が欠かせない。', false, 18),
(21, 'デイトレードでエントリーを考えているトレーダーが、日足で上昇トレンドを確認した。次のステップとして正しい順番はどれか？', '4H足でエントリーシナリオを描き、1H足で具体的なタイミングを探す', 'すぐに5分足に切り替えてスキャルピングエントリーを探す', '週足と日足をさらに比較して長期トレンドを再確認する', '1H足だけで全ての判断をして効率的にエントリーする', 1, 'デイトレードは「日足で方向→4H足でシナリオ→1H足でタイミング」が基本。上位足で環境認識してから下位足でタイミングを取ることで、トレンドに逆らうエントリーを防げる。', false, 19),
(21, 'ダウ理論に基づくトレードで「最も重要な教訓」とされるものはどれですか？', 'レンジ相場では積極的にスキャルピングする', '出来高が減少したら必ずエントリーする', '200MAに触れたら必ず反転すると仮定する', 'トレンドに逆らう逆張りトレードをしない', 4, 'ダウ理論の最大の教訓は「逆張りをしない」ことです。トレンドが継続している限り、その方向に沿った順張りを心がけることが、ダウ理論を活かしたトレードの基本姿勢です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(22, '6ヶ月の下落後、2ヶ月間レンジが続いている。下限を一時的に割り込んで即反発する動きが2度あった。今のフェーズと取るべき行動はどれか？', 'ブレイクアウト確認まで待ち、ベアトラップに引っかからないよう注意する', '下落が長かったため今が底値と判断して即買いする', '下限を何度か割っているため、ショートを仕込む', 'レンジが続くため判断できず完全に観察から外す', 1, '長い下落後のレンジは蓄積期（春）の特徴。下限を一時割り込んで戻す動きはベアトラップで、損切りを誘発する大口の罠。ブレイクアウト確認まで待つことで罠を回避できる。', false, 1),
(22, '日足で高値・安値がともに6週間連続で切り上がり、出来高も徐々に増えている。次の行動として最も適切なものはどれか？', '天井に近いと判断して戻り売りを検討する', '出来高増加は売り圧力の可能性もあるため静観する', '上昇期（夏）のHH/HLパターンに乗り、押し目でのロングを検討する', '出来高が増えているので注意が必要で参戦を見送る', 3, 'HH/HL継続と出来高増加は上昇期（夏）の典型パターン。大口が保有を続けており、この環境では逆張りは禁物。押し目（安値切り上がりポイント）でのロングが最も合理的な行動。', false, 2),
(22, '2年間の上昇後、高値圏で3週間レンジが続いている。ニュースは「史上最高値更新」「強気相場継続」と楽観的ばかり。追加ロングを検討しているが、最も警戒すべきことは何か？', '出来高が増えていれば問題ないため、出来高だけ確認して追加する', '楽観的なニュースが続く間は相場は上昇するので追加は問題ない', '天井か否か判断できないため静観するのが唯一の正解', '高値圏レンジ＋ニュース最楽観は分配期（秋）のサインで、大口が売り抜けている可能性がある', 4, '長い上昇後の高値圏レンジ＋ニュース最楽観は分配期（秋）の典型サイン。大口が高値で個人に売り抜けるフェーズで、「ニュース最楽観＝最危険」という逆説がここに現れる。追い買いが最も危ないタイミング。', false, 3),
(22, '日足でLH/LLが4週間続いている相場で「今週こそ反転するはず」と買いポジションを保有している。この行動の何が危険か？', '4週間という保有期間が長すぎるから', 'LH/LLの継続というチャート構造が下落を示しており、「反転」の根拠がないまま保有しているから', 'レバレッジが高すぎることが唯一の問題だから', '週次チャートの確認が足りないから', 2, 'LH/LLの連続は下落期（冬）のダウ理論的な定義。チャートが下落継続を示す中での「反転期待」は根拠のない希望的観測。底打ちシグナル（出来高急増・下ヒゲ連発）が出るまで待つのが正解。', false, 4),
(22, '企業が「過去最高益」を発表した直後、株価がほとんど動かなかった。「良いニュースなのに動かない理由」として最も根本的な説明はどれか？', '大口がその情報を事前に織り込んでポジションを持ち、発表付近で売り抜けているため', '個人投資家が情報を受け取るのが遅れているため', 'その日の取引量が少なく注文が通りにくい状態だったため', 'ニュースは価格に影響せず、テクニカルだけが価格を動かすため', 1, '価格を動かすのはニュースではなく買い手と売り手の資金量の差。大口は発表前にポジションを持ち、楽観ニュースで個人が買い始めたところで売り抜ける。「良いニュース＝上昇」が成立しない構造が4サイクルで説明できる。', false, 5),
(22, '「毎日トレードしないと感覚が鈍る」と考え、明確なトレンドのないレンジ相場でも毎日エントリーを繰り返している。この行動の本質的な問題はどれか？', '取引コストが積み重なり利益を圧迫するから', 'レンジ相場はスキャルピング専用の環境で手法が合っていないから', '毎日参加することでリスク管理が崩れるから', '相場の約7割がレンジで、条件が揃わない環境での参加は期待値をマイナスにするから', 4, '相場の7割がレンジという事実は、トレード可能な環境が3割しかないことを意味する。「条件が揃わない局面ではやらない」が正解で、これ自体がトレードの実力。セットアップが揃う瞬間だけに絞ることが長期的な利益の源泉。', false, 6),
(22, '4時間足で買いパターンを発見し、週足と日足を確認せずにエントリーした。直後に大きく逆行して損失になった。根本原因として最も可能性が高いものはどれか？', '週足で下降トレンドが継続していた可能性があり、下位足の買いシグナルが逆行になった', '4時間足のパターン認識が間違っていた', 'エントリータイミングが早すぎた', 'ポジションサイズが大きすぎた', 1, '環境認識は「上位足で大方向→中位足でフェーズ→下位足でタイミング」の順が鉄則。上位足を確認せず下位足だけで判断すると、週足の下降トレンド中の修正波に乗るリスクがある。大枠の方向を先に固めてからが前提条件。', false, 7),
(22, 'VIXが42まで急騰し、ニュースは「市場がパニック状態」と報じている。周囲のトレーダーは全ポジションを手仕舞いしている。4サイクルの視点から最も合理的な解釈はどれか？', 'VIX40以上は暴落継続のシグナルで、全ポジションをすぐに閉じるべき', 'VIXは短期的な指標で、4サイクルの判断には使えない', 'VIX40以上は極端な恐怖で歴史的に底打ちが多く、蓄積期移行を疑い始めるサイン', 'パニック時は全判断を保留して相場から離れるべき', 3, 'VIX30以上はパニック、40以上は極端な恐怖。全員が恐れているときこそ大口が蓄積を始めるタイミングでもある。恐怖の絶頂と底打ちが重なりやすいことを知ることで、パニック時に冷静な判断を保つ根拠になる。', false, 8),
(22, 'Fear & Greed Indexが12（Extreme Fear）を示している。「これはさらに暴落するサインだ」という意見が多い。4サイクルの視点から最も正確な解釈はどれか？', 'Extreme Fearは追加下落の確認シグナルで全ポジションを閉じるべき', 'F&Gはトレードに使えない信頼性の低い指標', 'Extreme Fearでは方向感がなくトレードを避けるべき', '投資家の恐怖がピークに達しており、逆に底打ち・蓄積期に近い可能性がある', 4, 'Extreme Fear（0〜25）は蓄積期の「個人がまだ悲観的」な心理と一致。逆に買いチャンスが近い可能性のサインと読む。Extreme Greed（75〜100）は分配期の楽観ピークと重なる。感情指数をサイクルと重ねることで逆張りタイミングを計れる。', false, 9),
(22, '日足で高値の切り下がりと安値の切り下がりが3週間連続で確認されている。「そろそろ反転するはず」と買いを検討している。ダウ理論と4サイクルの観点から適切な判断はどれか？', '3週間のLH/LLは短期調整なので週足が上昇なら買いを進める', 'LH/LLの連続はダウ理論の下落トレンドの定義で、底打ちシグナルが出るまで買いを待つべき', '3週間続けばそろそろ反転のため押し目買いの絶好チャンス', 'LH/LLが続けば積極的にショートを仕込む局面', 2, 'LH/LLの連続はダウ理論の下落トレンド定義で4サイクルの下落期（冬）に対応。「そろそろ反転」に根拠はなく、底打ちシグナル（出来高急増・下ヒゲ連発）が出るまで待つのが正解。構造が転換するまでトレンドは継続するというのがダウ理論の前提。', false, 10),
(22, 'レンジ相場の下限付近で価格が一時的に支持線を割り込み、ショートの損切りを誘発した後に急反発した。この現象の名称と活用方法はどれか？', 'ブルトラップ。急反発後も売り圧力が強いためショートを維持する', 'ベアトラップだが大口の意図は読めないため静観する', 'ベアトラップ。損切り誘発後の急反発は大口の買い集め完了のサインで、ロング候補になる', 'ダブルボトム。次のブレイクアウトを待ってからエントリーする', 3, 'ベアトラップはサポートを一時割り込んで損切りを誘発し、その注文を燃料に急反発させる現象。蓄積期に多く見られる。「下抜けた！」と飛びつくショートが逆に燃料になるが、このシグナルを認識できれば反発シナリオを描ける。', false, 11),
(22, '重要な抵抗線を突破したように見えたためロングで参入したが、直後に急反落して損失を被った。分配期（秋）でこの現象が多い根本的な理由は何か？', '個人が同タイミングで買うため、流動性の問題で価格が弾かれるから', '大口が個人の買い注文を誘発するために一時的に上値を突破させ、その買いに売りをぶつけて急反落させるから', '抵抗線は一度突破したら二度と機能しなくなるから', '出来高が激減する分配期では少しの売りで急落するから', 2, 'ブルトラップは分配期（秋）の典型現象。大口はブレイクアウト買いを引き出すために一瞬抵抗線を超えさせ、その買いに売りをぶつけて急反落させる。「突破したから買い！」という条件反射が最も多い罠にはまるパターン。', false, 12),
(22, 'スイングトレーダーが「週足で大方向→日足で判断→4時間足でタイミング」を実践している。日足で確認すべき最も重要な情報はどれか？', '損切り価格の算出', '週足と同じ大方向の再確認', '蓄積・上昇・分配・下落のどのフェーズにいるかのサイクル判断', '4時間足と同じエントリータイミングの絞り込み', 3, '環境認識3ステップで日足の役割はフェーズ判断。週足で大方向は済んでいるため日足での重複は不要。「今のサイクルはどのフェーズか」を把握することで、下位足でのエントリーに正しい文脈を与えられる。', false, 13),
(22, '週足で上昇トレンドが継続。日足では高値圏のレンジが3週間続き、ニュースは「過去最高値更新」「強気相場継続」と報じている。このフェーズを最も正確に判断するとどれか？', '蓄積期（春）。レンジ終了後にブレイクアウトを狙う買いを準備する', '上昇期（夏）。まだ上昇中なので押し目買いを続ける', '分配期（秋）。大口が売り抜けている可能性があり、追い買いを避けブルトラップに注意する', '下落期（冬）。LH/LLが出るまで判断を保留する', 3, '長い上昇後の高値圏レンジ＋ニュース最楽観は分配期（秋）の典型サイン。大口がすでに売り抜けを始めており、個人の追い買いがブルトラップになるフェーズ。「ニュース最楽観＝天井圏に近い」をサイクルで説明できる。', false, 14),
(22, 'VIXが13.5で市場は穏やかな状態。「VIXが低いほど大暴落が近い。すぐポジションを整理すべきだ」と言う人がいる。正しい判断はどちらか？', 'VIX12〜15は通常の市場環境で、過度な警戒は不要。通常通りに分析してトレードできる', '正しく、VIX低下は暴落の前触れなのでポジションを整理すべき', 'VIXが低いほど絶好調なので、積極的にロットを増やすべき', 'VIX15以下は完全に安全なので損切り設定を外しても問題ない', 1, 'VIX12〜15は通常の相場環境。20〜25で「やや警戒」、30以上でパニック、40以上で極端な恐怖という基準を持つことで、VIX低下を過度に恐れる必要がなくなる。正常な環境では通常通りのトレードが機能する。', false, 15),
(22, 'HH/HLが明確に続く上昇期のチャートを見ながら「今回だけ逆張りショートで大きく取ろう」と考えている。この思考の最も根本的な問題点はどれか？', '逆張りの損切り価格が複雑で計算しにくいから', '上昇期は出来高が多いためショートの約定が難しいから', '利確目標が決まっていないまま感情でエントリーしようとしているから', 'トレンドへの逆行であり、「今回だけ」という例外的な思考自体が感情的判断のサイン', 4, '上昇期（夏）はHH/HLが続くトレンド環境。「今回だけ」という例外判断こそが感情的な思考のサイン。順張りを崩す根拠がない限り、トレンドに沿った押し目買いが原則。例外を作り始めると一貫したルールが崩れていく。', false, 16),
(22, '「今売ったら-8万円の確定損になる。2週間も保有してきたし、きっと戻るはず」と考え、LH/LLが続く下落相場でポジションを保有し続けている。最も危険な点は何か？', '2週間という保有期間が長すぎて税制上の問題が生じるから', '「2週間耐えた」という過去のコストが損切りを妨げており、チャート構造（LH/LL継続）が下落を示す中で根拠なく保有しているから', '他の銘柄への乗り換え機会が失われているから', '証拠金維持率の計算が複雑になるから', 2, '「ここまで耐えた」はサンクコストの典型で、過去に費やした時間は今後の損益に無関係。LH/LLが続く下落期では「戻る」に根拠がなく、保有継続は損失を拡大させるだけ。損切りの根拠はチャート構造であり、保有期間ではない。', false, 17),
(22, '市場が1ヶ月間レンジを続けている。「蓄積期（春）か分配期（秋）か」を判断するために最も重要な情報はどれか？', 'そのレンジの前に長い下落があったか、長い上昇があったかという「前後の文脈」', 'VIXの現在の数値', 'レンジの値幅の広さ', '1日あたりの出来高の絶対量', 1, '蓄積期も分配期もレンジを形成するが、区別の鍵は「文脈」。長い下落後のレンジ＝蓄積期（春）、長い上昇後のレンジ＝分配期（秋）。出口の方向（上か下か）も変わるため、前後の相場の状態の確認が最初のステップ。', false, 18),
(22, '週足チャートはHH/HLが続く上昇期。日足では直近1週間で下落中の押し目が形成されている。最も合理的な判断はどれか？', '日足の下落が続いているため週足の上昇は終わったと判断してショートに切り替える', '週足の上昇期における日足の押し目は買いのチャンスで、下位足でエントリータイミングを探す', '週足と日足の方向が異なるためどちらでもエントリーせず静観する', '日足の押し目は全て「下落期の始まり」で週足を無視して売る', 2, '4サイクルの環境認識は上位足優先。週足の上昇期（HH/HL継続）中の日足押し目は「押し目」であり、上昇継続シナリオが有効。一時的な下位足の逆行は上位足のトレンドに沿ったエントリーを絞り込む機会として読む。', false, 19),
(22, '「先週は1度もトレードしなかった。チャートは見ていたが、条件が揃う場面が一度もなかった」と話すトレーダーが「技術が伸びない。毎日参加すべき」と批判された。4サイクルの視点からどう評価するか？', '批判が正しく、毎日少なくとも1回はエントリーして経験を積むべき', '条件が厳しすぎるので、セットアップを少し緩めて参加頻度を増やすべき', '1週間トレードしないのは集中力の問題で改善が必要', 'セットアップが揃わない中でのトレードは期待値がマイナスで、「やらない」選択自体がトレードの実力', 4, '相場の7割がレンジという事実が示すとおり、条件が揃う場面は3割しかない。「やらない」と決めることは怠慢ではなく、期待値の低い局面を意図的に排除する規律。毎日参加より、揃った場面だけに絞ることが長期的な成果につながる。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(23, 'あるトレーダーが「出来高は急増しているのに価格がほとんど動かなかった」現象に気づいた。これはワイコフの3法則のうちどれで説明できますか？', '需要と供給の法則（大量注文が拮抗して価格が動かなかった）', '努力と結果の法則（出来高＝努力に対し値動き＝結果が伴っていない）', '原因と結果の法則（レンジが長いほどトレンドが大きくなる）', 'レンジ継続の法則（上昇トレンドの一時的な停滞を示している）', 2, '努力と結果の法則では、出来高（努力）に対して価格変動（結果）が伴わない乖離が「異変のサイン」です。この状態が続くとトレンド転換の前兆として警戒が必要になります。', false, 1),
(23, '銘柄Xが2週間のレンジを上抜けたケースと、6ヶ月のレンジを上抜けたケースを比べると、どちらのブレイク後の上昇幅が大きくなると考えられますか？', '2週間のレンジ（短期間で集中したエネルギーが爆発する）', 'どちらも同じ（レンジの長さは結果に影響しない）', '6ヶ月のレンジ（長期間の蓄積エネルギーがブレイク後に解放される）', 'ブレイクの方向のみが重要で、レンジの長さは無関係', 3, 'ワイコフの原因と結果の法則では、レンジ（原因）が長いほど蓄積エネルギーが大きく、ブレイク後のトレンド（結果）も大きくなります。長期レンジのブレイクほど大きな値幅を期待できます。', false, 2),
(23, '上昇トレンド中、直近5本のローソク足がすべて陽線で価格は上昇しているが、出来高はじりじりと減少している。このトレーダーが最も警戒すべきリスクはどれですか？', '出来高減少は調整局面の典型で、次の急騰の前兆である', '買い手の参加意欲が低下しており、上昇の勢いが続かなくなる可能性がある', '出来高の減少はスクイーズを示しており、大きなブレイクが近い', '市場参加者が少ない時間帯なだけで、需給に問題はない', 2, '価格上昇にもかかわらず出来高が減少する場合、買い手の参加意欲が低下しており上昇の勢いが衰えているサインです。このまま出来高が戻らなければ、失速・反落リスクが高まります。', false, 3),
(23, 'FXトレーダーが需給分析に出来高を使おうとしたが、「FXは取引所を介さないため実出来高が取得できない」という問題に直面した。この制約下で最も有効な代替手段はどれですか？', '出来高分析を諦め、移動平均線だけで判断する', 'ティックボリューム（価格変動の回数）を代替指標として使う', '複数ブローカーのデータを平均して推計する', '株式市場の出来高をFXの需給の代替として参照する', 2, 'FXでは実出来高が存在しないため、価格変動の回数を測るティックボリュームが代替として広く活用されます。完全ではないものの、需給の強弱を推測する実用的な手段です。', false, 4),
(23, 'あるトレーダーが先週の急騰局面を範囲指定してFRVPを表示すると、1.1050付近に突出した出来高の山が現れた。このデータをどう活用するのが最も有効ですか？', '1.1050付近が大口の主要取引水準であり、次の反発・抵抗として機能しやすい', '1.1050で大量に売られた価格帯なので、この水準を抜けると急騰する', 'FRVPは過去データなので将来の判断には使えない', '出来高が多い価格帯は避けてトレードするべき', 1, 'FRVPは特定期間で大口が集中的に売買した価格水準を可視化します。出来高が突出した価格帯は大口の関心が高い場所であり、次の反発・抵抗として機能しやすいです。', false, 5),
(23, 'ある銘柄が急落局面で大陰線・出来高は直近平均の2.5倍を記録した。翌日、価格はほぼ動かず出来高は激減した。この2日間の動きをワイコフの出来高×価格パターンから読み取れる最も適切な解釈はどれですか？', '1日目の急落で売り手の力が出し尽くされ（パニック売り）、2日目のエネルギー蓄積が底打ちの可能性を示している', '2日連続で弱い動きを示しており、さらに下落が続くサインである', '出来高が激減した2日目は大口の売りが完了したことを示しており、即売りのチャンスである', '急落後の静けさは需給均衡を意味し、方向感が出るまで最低2週間様子見すべきである', 1, '下落+出来高増加はパニック売りで売り手の力が出し尽くされたサイン。翌日の横ばい+出来高激減はエネルギー蓄積を示します。この組み合わせは底打ちの前兆として警戒が必要で、反発に備えたポジション管理の見直しタイミングです。', false, 6),
(23, 'あるトレーダーが深夜の東京時間に、USD/JPYのティックボリュームが平均の40%しかないのに80pips急騰したことに気づいた。このトレーダーが最も慎重になるべき理由はどれですか？', '少数の大口注文が薄い流動性を利用して価格を動かした可能性があり、その方向への追随は逆戻りリスクが高い', 'ティックボリュームが少ない時間帯の値動きは信頼性が高く、本物のトレンド発生のサインである', '深夜時間帯の動きはアジア市場の需要を反映しており、欧米時間に継続する', '出来高が少ない急騰は大口がポジション解消した結果であり、価格は翌日必ず戻る', 1, '出来高なし（努力なし）＋大きな値動き（結果あり）は「大口の足跡」パターンです。流動性の薄い時間帯に少量の注文で価格を動かした可能性があり、実需を伴わない動きへの追随は急反落リスクが高く危険です。', false, 7),
(23, 'レジスタンス超えに飛び乗ってロングエントリーしたが、翌日価格が戻ってきた。エントリー時の出来高は平均の60%で、ローソク足の実体も小さかった。何を見落としていましたか？', '出来高不足と小さな実体はフェイクブレイクのサインだった', '翌日の戻しは当然のリトレースで、エントリーは正しかった', '出来高が少ない方が大口参入を示す本物のサインだった', 'ローソク足の実体が小さいのはエネルギーが蓄積されているから', 1, '本物のブレイクは出来高平均1.5倍以上と大きな実体を伴います。出来高不足の小実体でのブレイクはフェイクの可能性が高く、勢いを確認してからエントリーすべき場面でした。', false, 8),
(23, '上昇トレンド中にロングを保有しているトレーダーが、直近3週間で3度新高値を更新したものの、そのたびに出来高が前回より少なくなっていることに気づいた。この状況でとるべき行動として最も適切なものはどれですか？', '上昇トレンドは継続しているので買い増しを続ける', '買い手の勢いが衰えているサインであり、利確や損切りラインの引き上げを検討する', '出来高が少ない方が安定した上昇を示しており、長期保有を継続する', '出来高の減少は一時的で、次の足で急増する前兆である', 2, '新高値更新に伴う出来高減少は、買い手の参加意欲が低下している警告サインです。価格は上昇していても勢いは衰えており、このまま続けば失速・反転リスクが高まるためポジション管理の見直しが必要です。', false, 9),
(23, '直近高値の少し上に損切りを置いてショートを持つトレーダーが多数いた。突然価格が急騰して直近高値を一瞬超えたが、その足の終値はすぐに直近高値の下に戻った。この動きをワイコフの視点で最も自然に説明するものはどれですか？', 'ストップ狩り — 直近高値外側の損切りを大口が意図的に刈り取り、売りを仕込んだ', '本物のブレイクアウトの失敗で、需給の均衡が崩れた', '突発的なニュースによる一時的な上昇で、需給とは無関係', '小口の個人投資家の集中買いが引き起こしたフラッシュ上昇', 1, '直近高値の外側には買いの損切り注文が集中しており、大口はそれを意図的に誘発させてから逆方向へ動かす「ストップ狩り」を行うことがあります。終値がすぐに戻れば罠の可能性が高いです。', false, 10),
(23, 'サポートラインを下回ったのを確認してショートエントリーしたトレーダーが、直後の急反発で大きな損失を被った。この「罠」はどのような順序で仕掛けられていたと考えられますか？', '急反発 → 大口が買い → サポート割れ → 損切り発動', 'サポート一瞬割れ → 損切り発動 → 大口が安値で買い → 急反発', '大口が買い → サポート割れ → 急反発 → 損切り発動', '損切り発動 → 急反発 → サポート割れ → 大口が買い', 2, 'ベアトラップはサポートを一瞬割り込むことでショートの損切りを誘発し、その注文を燃料に大口が安値で買い集めた後に急反発する仕組みです。終値がサポートに戻るかを必ず確認してください。', false, 11),
(23, 'レジスタンスを突破したのを確認してロングエントリーしたトレーダーが、直後の急落で大きな損失を被った。大口はなぜレジスタンス超えを演出したのですか？', '個人の買い注文を誘発し、その需要を利用して高値で売りを積み上げるため', '価格の発見プロセスを支援し、市場の効率化を促すため', 'ショートカバーを誘発してさらに上昇させるための仕込みだった', '取引量を増やして流動性を高めるための市場操作のため', 1, 'ブルトラップは分配期に多く見られます。大口はレジスタンス超えで個人の買いを誘発し、その需要を相手に高値で売りを積み上げます。この罠にはまると急落で損切りを余儀なくされます。', false, 12),
(23, 'あるレンジ相場で、下限に近づくたびに長い下ヒゲと出来高増加が見られる。一方、上限に近づくと上ヒゲが目立ち出来高は減少する。この状況をワイコフの視点でどう解釈すべきですか？', '下値で大口が買い支える蓄積期の可能性が高く、上放れのブレイクに備える', '上値で大口が売り抜ける分配期であり、下放れに警戒する', '高ボラティリティのレンジで、売買差益を狙うレンジ戦略が有効', '需給が拮抗しており、方向感が出るまで待つしかない', 1, '下限での下ヒゲ増加は大口が下値で買い支えている蓄積期のサインです。上限での上ヒゲ・出来高減少は売り圧力が弱い状態を示しており、蓄積完了後の上放れブレイクを狙う判断が合理的です。', false, 13),
(23, 'ロングを保有中のトレーダーが、今日のローソク足は大きな陽線（強い足）だったが、出来高は前日より30%減少していたことに気づいた。このトレーダーが取るべき行動として最も適切なものはどれですか？', '大きな陽線が出たので安心して買い増しを検討する', '足の力強さと出来高減少が矛盾しており、このトレンドの勢いが続くか要注意でポジションサイズや利確ラインを見直す', '出来高30%減少は正常な変動範囲であり、変更の必要はない', '出来高の減少は翌日の急騰前のエネルギー蓄積であり、さらなる上昇の前兆である', 2, '強い足（大きな値動き）に出来高が伴わない場合、上昇を支える参加者の本気度が不足しています。見た目は力強くても勢いの持続性に疑問があるため、ポジション管理を見直して失速・反転に備えることが重要です。', false, 14),
(23, '銘柄Bの日足チャートを見ると、4ヶ月のレンジが形成され、先週は下限を一瞬割れて即戻し、最近は出来高が増加傾向にある。大口の行動を確認するため、次に優先して確認すべきことはどれですか？', '移動平均線のゴールデンクロスが近づいていないか確認する', 'レンジ高安値外側への突破・即反転（ストップ狩り）が繰り返されていないか確認する', 'RSIが70以上の過熱水準にないか確認する', '直近の経済指標発表スケジュールを確認する', 2, '大口は蓄積・分配の前にストップ狩りで反対勢力を排除します。レンジ高安値外側への一時的な突破と即反転が繰り返されていれば、ポジション蓄積が終盤に差し掛かっているサインです。', false, 15),
(23, 'ある銘柄が3ヶ月間のレンジを上にブレイクした。出来高は平均の2倍、ローソク足は大きな陽線でヒゲは短い。日足・週足ともに上昇方向を示している。このブレイクはどう評価すべきですか？', 'フェイクブレイクの可能性が高いので戻り売りを検討する', '出来高が多すぎるため逆張りのチャンスである', '本物のブレイクの条件を満たしており、トレンドに沿った順張りを検討できる', '3ヶ月のレンジは短すぎるため、様子見が適切である', 3, '本物のブレイクの4条件（出来高平均1.5倍以上、大きな実体、方向の継続性、上位足との一致）を全て満たしています。3ヶ月のレンジという十分な「原因」の後のブレイクであり、信頼性が高いと評価できます。', false, 16),
(23, 'USD/JPYの4時間足で、150.00円のレジスタンスを一瞬超えて150.30円まで上昇したが、その足の終値は149.80円だった。出来高は平均以下だった。この状況をどう読み取るべきですか？', 'ブルトラップの可能性が高く、フェイクブレイクと判断すべき', '出来高が少ないため大口の足跡の可能性がある', '強い買い圧力による本物のブレイクアウト', '蓄積期の典型的なパターンで、上昇トレンドの始まり', 1, 'レジスタンスを一瞬超えたものの、長い上ヒゲを残して終値がレジスタンス下に戻っており、出来高も平均以下です。これはフェイクブレイクの典型的な特徴であり、ブルトラップの可能性が高いと判断すべきです。', false, 17),
(23, '日足チャートで直近高値を3回連続で更新しているが、その都度出来高が減少している。現在のトレンド方向は上昇だが、OBV（On Balance Volume）は天井を切り下げている。この状況から読み取れる最も適切な判断はどれですか？', '上昇トレンドが強まっており、買い増しを検討すべき', '大口が買い集めている蓄積期であり、ブレイクを待つべき', '出来高ダイバージェンスが発生しており、トレンドの衰えに警戒が必要', 'レンジ相場に入ったため、逆張り戦略に切り替えるべき', 3, '新高値更新に伴う出来高の減少とOBVの天井切り下げは、明らかな出来高ダイバージェンスです。価格は上昇しているものの、それを支える買い手の勢いが低下しており、トレンドの衰えに対する警戒が必要です。', false, 18),
(23, 'EUR/USDが1.0800〜1.0950のレンジを6週間形成後、1.0800を下ヒゲで一瞬割り込んで1.0785まで下落したが、即座に反発して1.0900まで戻った。この下ヒゲの出来高は直近平均の3倍だった。この状況は何を示唆していますか？', '下落トレンドへの本格的な転換', '方向感のないレンジの継続', 'ベアトラップの可能性が高く、大口が安値で買い集めた可能性がある', '大口の足跡によるフェイクブレイクで、さらに下落する', 3, '長いレンジの下限を下ヒゲで一瞬割り込み、高出来高を伴いながら即反発するパターンはベアトラップの典型です。出来高増加（努力あり）にもかかわらず価格が維持できず反発（結果なし→反転）しており、大口が損切り注文を燃料に安値で買い集めた可能性が高いです。', false, 19),
(23, '株式銘柄Aが長い上昇後、高値圏で2ヶ月のレンジを形成している。レンジ上限でのローソク足には上ヒゲが目立ち、出来高は高いが上値が重い。FRVPではレンジ上限付近に大量の売買が集中している。大口の行動チェックリストに照らし合わせた場合、最も適切な判断はどれですか？', '上昇トレンドの一時休止であり、買いを継続すべき', '分配期の特徴が揃っており、ブルトラップに警戒して上値での買いは避けるべき', '蓄積が完了しており、上放れのブレイクアウトを待つべき', '出来高が高いので本物のブレイクの前兆であり、買いエントリーの準備をする', 2, '長い上昇後の高値圏レンジ、上ヒゲの目立ち、高い出来高でも上値が重い、レンジ上限での大量売買集中は全て分配期の特徴です。大口はレンジ上限付近で売り抜けている可能性が高く、ブルトラップに警戒して上値での買い注文は避けるべき判断です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(24, '明確な上昇トレンドが続いているが、翌週に雇用統計の発表を控えており、インフレ懸念から金利上昇が見込まれている。テクニカルとファンダが示している情報として正しいものはどれか？', 'テクニカル（地図）とファンダ（天気予報）は上下関係がなく、両方揃って初めて完全な判断ができる', 'テクニカルが上昇を示しているので、ファンダは無視してよい', 'ファンダが不確かな時はテクニカルが上位の判断基準になる', '2つが異なる情報を示している場合、テクニカルの方が精度が高い', 1, 'テクニカルは「値動きの道筋（地図）」、ファンダは「市場環境が変わるか（天気予報）」を示します。上下関係はなく、両方揃って初めて完全な判断が可能になります。', false, 1),
(24, 'あるトレーダーが総合CPIの上昇を見て「FRBは必ず利上げするだろう」と予測したが、その後FRBは据え置いた。見落としていた可能性が最も高いものはどれか？', 'FRBは食品・エネルギーを除くコアCPIを重視しており、コアが安定していれば据え置く場合がある', 'FRBはCPIを参考指標として扱っておらず、GDPだけで判断する', '総合CPIが上昇しても前月比がマイナスなら利上げしない', 'FRBは議会の承認がなければ政策変更できない', 1, 'FRBが重視するのは食品・エネルギーを除いたコアCPIです。総合CPIが高くてもコアが安定していれば政策変更しないことがあります。FRBの動きを読むには重視する指標の把握が重要です。', false, 2),
(24, '景気はまだ悪化が続いているが、FRBが利下げを開始した。株式市場では成長株やテック株が先行して上昇し始めている。これは金融サイクルのどの局面か？', '業績相場（夏）: 企業業績が改善して安定上昇する局面', '逆業績相場（冬）: 景気後退で株価が本格下落する局面', '逆金融相場（秋）: FRBの利上げで株価が重くなる局面', '金融相場（春）: FRBの利下げで株が先行上昇し景気はまだ悪い局面', 4, '景気が悪い中でもFRBの利下げによって株が先行上昇し始めるのが「金融相場（春）」の特徴です。どの局面かを把握することで、強いセクターへの判断精度が上がります。', false, 3),
(24, 'NFPの雇用者数が予想を上回った。あるトレーダーは「良い数字だ」と即断したが、熟練トレーダーはさらに3つの追加データを確認してから判断を下した。その3つとして正しいものはどれか？', '失業率、平均時給、世帯調査との乖離', '貿易収支、消費者信頼感指数、失業率', 'PMI、平均時給、輸入物価指数', '失業率、GDP速報値、生産者物価指数', 1, 'NFPのヘッドライン数字だけでは労働市場の全体像が見えません。失業率（実態）・平均時給（インフレ圧力）・世帯調査との乖離（信頼性）を合わせて確認することで、本当の雇用環境を判断できます。', false, 4),
(24, 'FOMC会合後、声明文では利上げが発表された。しかし翌日の相場は強く上昇した。この逆行を理解するために確認すべき要素として最も適切なものはどれか？', '議長記者会見のニュアンスから「今後の利上げは限定的」という解釈が市場に広まった可能性', 'GDPの速報値が同日に発表され、景気の強さが確認されたため', '議事要旨（3週間後公開）が前倒しで発表されたため', '翌日にCPI発表と重なったため、FOMCの影響は相殺された', 1, 'FOMCは声明文・ドットプロット（年4回）・議長記者会見・議事要旨（3週間後）の4要素で構成されます。利上げ決定でも議長の記者会見次第で市場が逆方向に動くことがあります。4つを総合して読む力が重要です。', false, 5),
(24, 'CPIレポートで前年比は依然高かったが、前月比は2ヶ月連続で低下していた。「前年比が高いからインフレはまだ強い」という判断の問題点はどれか？', '前月比が低下していれば、インフレはすでに終わったと判断してよい', '前月比（足元の勢い）も合わせて見ると、ピークアウトの可能性を見落としている', '前年比だけで判断するのが正しく、前月比は参考程度でよい', '2つが矛盾しているため、どちらのデータも使えない', 2, '前月比はインフレの「勢い（足元の変化）」、前年比は「トレンド」を示します。前年比が高くても前月比が鈍化していればピークアウトを読み取れます。片方だけの判断は政策変更タイミングの見誤りにつながります。', false, 6),
(24, '市場がCPI発表後に動くきっかけとして正しいものはどれですか？', 'CPIの絶対値が高いか低いかのみで動く', '事前予想値からのズレ（サプライズ）で動く', 'コアCPIが総合CPIを上回った場合のみ動く', '前回のCPI値との差の大きさで動く', 2, '市場は「予想からのズレ」で動きます。絶対値そのものよりも、エコノミストの予想より高いか低いかによって反応が決まります。', false, 7),
(24, 'エントリー前にファンダを確認するため、①A社の決算発表、②FOMCの声明文、③政府の財政刺激策を調べた。これらはファンダメンタルズのどの分類にあたるか？', '①ミクロ ②マクロ ③政治・政策', '①マクロ ②ミクロ ③政治・政策', '①テクニカル ②センチメント ③マクロ', '①ミクロ ②政治・政策 ③マクロ', 1, '企業決算はミクロ（業績）、FOMCはマクロ（金利・インフレ政策）、財政刺激策は政治・政策（政府の動き）に分類されます。3分類を理解することで確認すべき情報を整理し、ファンダの確認漏れを防げます。', false, 8),
(24, 'FRBが急ピッチで利上げを続け株価全体が重くなっている局面で、成長株やテック株が特に大きく下落している。相対的に強さを保ちやすいセクターはどれか？（2022年がこの局面にあたる）', '成長株・テック（将来の高成長が期待されるため）', '幅広いセクター（企業業績が引き続き改善しているため）', 'ディフェンシブ（生活必需品・公益など景気に左右されにくいセクター）', '現金・債券（金利上昇の恩恵を直接受けるため）', 3, '利上げ局面では将来キャッシュフローの割引率が上がる成長株が特に下落します。景気に左右されにくいディフェンシブセクターは相対的に底堅くなります。どの局面で何が強いかを把握することで、環境に合ったトレードができます。', false, 9),
(24, '2年間の利上げサイクルを経てインフレが目標水準（2%）に近づき、FRBが利下げを開始した。この利下げが株式市場に与える影響として最も正確なものはどれか？', '景気後退対応の利下げと同じなので、株にマイナス', '緊急事態への対応なので、短期的に不安定になる', '正常な金利水準への回帰であり、株への追い風となりやすい', '利下げは必ず株価下落を引き起こす', 3, 'インフレが落ち着いた後の「正常化カット」は景気後退を意味しません。企業の資金調達コストが下がりバリュエーションも改善するため株への追い風となります。同じ利下げでもリセッションカットとは株への影響が逆であることが重要です。', false, 10),
(24, 'NFP発表で「良すぎる雇用データ」が株価にマイナスになる理由として正しいものはどれですか？', '雇用が良いと消費が冷え込むため', '雇用が良すぎると金利低下の可能性が遠のくため', '雇用改善は常に株価下落の前兆であるため', '企業が人件費を削減するため', 2, '雇用が良すぎるとFRBの利下げ必要性が薄れ、金利低下の期待が後退します。高い金利は企業業績やバリュエーションにとってマイナスとなるため、株価に悪影響を及ぼすことがあります。', false, 11),
(24, 'NFP発表直後、数字は予想を大きく上回りドル円が2秒で100pips急騰した。「明確に上昇だ」と即座に買いエントリーした場合、この行動の問題点はどれか？', 'NFPが強い数字の時はドル円は下落するため、方向の判断が誤っていた', '発表直後のスパイクはウィップソーのリスクが高く、方向感が定まる前に飛び乗るのは危険', 'エントリーサイズが小さすぎたため利益が出なかった', '発表前にポジションを持っていなかったため利益機会を逃していた', 2, '発表直後の急騰・急落は一時的なスパイクで、すぐに逆方向に動くウィップソーが起きやすい危険な瞬間です。この瞬間に飛び乗ることは禁止されており、1〜2時間後に方向感が定まってから再判断するのが原則です。', false, 12),
(24, '株式市場が数ヶ月間安定して上昇し、好業績報道が続き投資家の間に楽観ムードが広がっている。この局面でトレーダーが特に警戒すべきことは何か？', 'FRBがこの局面では必ず急利上げをするため、即売りに転じるべき', '楽観ムードのピークは相場転換点が近いサインであり、高値掴みのリスクを意識すべき', '好業績が続くと出来高が急減し、流動性が不足する', 'コアCPIが急上昇するため、即座に損切りすべき', 2, '業績相場（夏）は安定上昇の局面ですが「最大の楽観＝最大のリスク」という原則があります。全員が強気になった局面は転換点が近い可能性があります。楽観的なニュースが多い時こそ、冷静に転換点を意識することが重要です。', false, 13),
(24, 'テクニカル分析が上昇を示しているが、ファンダメンタルズが下落リスクを示している場合、適切な判断はどれですか？', 'テクニカルを優先して買いエントリーする', 'ファンダメンタルズを優先して売りエントリーする', 'どちらかのシグナルが強い方に従ってエントリーする', 'エントリーせず見送る', 4, 'テクニカルとファンダメンタルズが矛盾する場合は「何もしない」が正解です。両方が同じ方向を示している時だけエントリーするという統合判断の基本原則に従います。', false, 14),
(24, '企業業績の悪化が相次ぎ景気後退が確認されながら株価が本格的に下落している局面で、資産を守りつつ長期的な視点を持つトレーダーの判断として正しいものはどれか？', '下落局面でも成長株を割安と判断して全力買いする', 'ショートポジションだけが唯一の正解である', '現金・債券で資産を守りつつ、最悪期こそが長期的な買い場になる可能性に備える', 'レバレッジを最大限に使って最安値での一括購入を狙う', 3, '逆業績相場（冬）は本格的な下落局面で現金・債券が相対的に強いセクターです。同時に「最悪期が長期的な買い場になる可能性」も把握しておくことで、パニック売りだけでなく底付近での好機を見逃さない準備ができます。', false, 15),
(24, 'FOMC会合で金利据え置きが発表された直後、ドル円が大幅なドル高方向に動いた。据え置きにもかかわらずドル高になった理由として考えられるものはどれか？', 'ドットプロットで多数の委員が想定より高い金利水準を予測していることが明らかになった', '議事要旨が発表直後に公開され、利上げ派が多数だったことが分かった', 'ドットプロットはFOMC毎回公開されるため、今回は利上げシグナルが含まれていた', '据え置き決定は市場には利下げと同じ意味で解釈されるため', 1, 'ドットプロットは年4回公開されるFOMC委員ごとの金利見通しを点で示した図です。声明文が据え置きでもドットプロットで高い金利見通しが示されれば、市場はドル高方向に反応します。声明文と合わせた読み解きが重要です。', false, 16),
(24, 'FRBが利下げを発表した。直前まで景気は安定しておりインフレは目標水準に近づいていた。この利下げはどの分類にあたりますか？', '正常化カット', 'パニックカット', 'リセッションカット', '緊急利上げ', 1, '景気が安定しておりインフレが落ち着いている状況での利下げは「正常化カット」に分類されます。インフレ抑制のための高金利から正常な水準へ戻す動きで、株に追い風となります。', false, 17),
(24, '金融市場に大きな不安が広がる中、FRBが予定外の緊急利下げを実施した。発表直後にエントリーを検討しているトレーダーへのアドバイスとして正しいものはどれか？', '緊急利下げはV字回復のシグナルなので、即座に強く買いエントリーする', '市場が短期的に混乱して方向感が定まらないため、落ち着くまで様子を見る', '緊急利下げは株価にマイナスしかないため、即座に売りエントリーする', '債券市場だけが反応するため、株式市場はトレードしなくてよい', 2, 'パニックカット（緊急利下げ）は危機への対応であり、直後は市場が混乱して方向感が定まりません。急いでエントリーすると損失リスクが高く、1〜2時間待って方向感が固まってから判断するのが原則です。', false, 18);
(24, 'CPI発表を翌日に控えている状況で、テクニカル分析で明確な買いシグナルが点灯している。ファンダメンタルズの方向は不明確である。この場合の適切な対応はどれですか？', '買いシグナルが明確なので即座にエントリーする', 'ファンダメンタルズが不明確でもテクニカルシグナルが強いので小ロットでエントリーする', '重要指標発表前24時間は新規エントリーを控えるルールに従い見送る', '損切りを広めに設定すればエントリーしてもよい', 3, '重要指標の発表前24時間は新規エントリーを控えるというルールがあります。テクニカルシグナルが明確でも、指標発表による予測不能な変動リスクを避けるため見送りが適切です。', false, 19),
(24, 'FOMC声明文はハト派的で利下げを示唆していたが、テクニカル分析では上値が重く下降トレンドが継続している。この状況で「FRBが利下げするから買い」と判断してエントリーした場合、何を無視していることになりますか？', 'テクニカル×ファンダの統合判断において、両方の方向が一致している必要があるという原則', 'FOMC声明文は市場に影響を与えないという事実', '利下げは常に株価上昇につながるという前提', 'テクニカル分析はファンダメンタルズより重要であるという原則', 1, 'ファンダメンタルズは上昇を支持していても、テクニカルが下降を示している場合、両方が同じ方向を示していないためエントリーすべきではありません。片方だけの判断で飛びつくのは統合判断の原則に反します。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(25, '3連勝後に「今日は多少条件が足りなくても取れる」と感じた。最初に疑うべきリスクはどれか？', '連勝で基準が緩み、本来見送る場面をチャンスに見せている', '相場環境が急に良くなり、機会が増えている', '分析力が上がり、細かな条件が不要になっている', '損切り幅を広げれば優位性が保てる', 1, '連勝後の「いけるだろう」は過信のサインです。勝った事実がエントリー基準を甘くし、再現性の低い場面までチャンスに見せます。まずチェックリストを通常より厳格に戻すことが防衛策です。', false, 1),
(25, '5連勝した直後にロットを上げたくなった。最も適切な行動はどれか？', '連勝中だけロットを2倍にして利益を伸ばす', '通常ロットを維持し、必要なら1日休んで環境認識からやり直す', '損切り幅を広げて勝率を守る', '同じ銘柄だけに絞ればロットを上げてもよい', 2, '5連勝は実力だけでなく確率の偏りでも起きます。ここでロットを上げると、次の1回の負けで連勝分が消えます。連勝中こそサイズを変えず、冷却時間を入れる設計が大切です。', false, 2),
(25, '勝率60%の手法で5連勝した後、「手法が完成した」と判断して基準を広げた。この判断の誤りはどれか？', '勝率60%なら5連勝は絶対に起きないと考えている', '手法を固定せず毎回変えるべきなのに固定している', '少数の連勝を実力の証明と見なし、確率の偏りを軽視している', '連勝した手法はすぐ使えなくなると決めつけている', 3, '5連勝は珍しくても起こり得る事象です。問題は、その短期結果を「完成」と誤認してルールを緩めることです。連勝の質は、各トレードが事前条件を満たしていたかで検証します。', false, 3),
(25, '連勝中にチェックリストの一部を飛ばし始めた。まだ勝てている場合でも危険な理由はどれか？', 'チェックリストは負けた後だけ使えば十分だから', '勝てている間はチェック項目が相場に合わなくなる', '省略した方が判断が速くなりすぎる', '勝ちがルール違反を強化し、次第に低品質な判断が普通になる', 4, 'ルールを破って勝つと、脳はその省略を成功体験として記憶します。すると次回も基準が緩み、損失が出る頃には規律が崩れています。勝っている時の省略こそ早めに止めるべきです。', false, 4),
(25, '4連勝後の損切りを「今回は例外」と片づけ、すぐ同方向に入り直した。最も大きな問題はどれか？', '再エントリーはどんな場合も禁止されている', '失敗を例外扱いし、検証なしに過信を守っている', '同じ方向に入ると必ず損切りになる', '損切り後は別の通貨ペアへ移るべきだから', 2, '連勝バイアスは損切りを「自分の間違い」ではなく例外に見せます。検証せず再エントリーすると、同じ歪みを持ったままリスクを重ねます。まず何が条件と違ったかを記録する必要があります。', false, 5),
(25, '連勝後に「今日は休むのがもったいない」とレンジでも入った。この行動が危険なのはなぜか？', 'レンジ相場では利益が絶対に出ない', '休むと手法の感覚が消えてしまう', '調子の良さを根拠に、相場の条件不足を無視している', '連勝中は取引回数を増やすほど有利になる', 3, '休むのが惜しい感覚は、相場ではなく自分の高揚感を基準にしています。条件がない場面で入るほど期待値は下がります。ノートレードを「機会損失」ではなく「リスク回避」と定義することが必要です。', false, 6),
(25, '連勝中のトレードを振り返ると、後半ほど根拠が薄くなっていた。次に取るべき対応はどれか？', '勝っているので根拠の薄さは問題にしない', '後半の勝ちだけを新しい手法として採用する', '次回から薄い根拠でもロットを下げれば入る', '連勝分を実力とせず、後半の勝ちは再現性の低い勝ちとして扱う', 4, '根拠が薄い勝ちは、結果が良くても再現性の証明にはなりません。連勝の中身を分解し、ルール通りの勝ちと偶然の勝ちを分けることで、過信ではなく検証に戻れます。', false, 7),
(25, '「今月は負けなしだから、次だけ少し大きく張ろう」と考えた。最も適切な反論はどれか？', '今月の結果と次の1回の優位性は別であり、ロットは事前ルールで決める', '負けなしの月は統計的に次も勝ちやすい', '利益がある月だけは損切り幅を広げてよい', '大きく張るなら利確目標を近くすれば安全', 1, '直近の勝敗は、次のトレードの期待値を保証しません。ロットを損益状況で変えると、感情が資金管理を支配します。サイズは口座リスクと損切り幅から機械的に決めるべきです。', false, 8),
(25, '連勝後に分析ノートの記述が短くなっていた。これをどう扱うべきか？', '勝てている証拠なのでノートは簡略化する', '短いノートほど迷いがなく良い状態と判断する', '分析省略の初期サインとして、次回は記入項目を増やして確認する', '連勝中は記録より実戦を優先する', 3, '連勝で自信が強まると、環境認識や反証探しが省略されやすくなります。ノートが短くなる変化は客観性低下のサインです。次回は反対根拠欄まで書き、判断を外に出すことが有効です。', false, 9),
(25, '連勝バイアスを防ぐために、最も仕組みとして機能するルールはどれか？', '勝った日は同じ方向だけを狙う', '連勝中は利確を早めて利益を守る', '連勝が止まるまで取引回数を増やす', '3連勝で警戒項目を追加し、5連勝で1日休む', 4, 'バイアスは気づいた時には判断に入り込んでいます。連勝数に応じて自動的に警戒項目や休止ルールを発動させると、気分に左右されずブレーキがかかります。意志より仕組みが頼りです。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(26, '「買い」と決めてからチャートを見ると、買い根拠ばかり見つかった。最初にすべき確認はどれか？', '売りシナリオが成立する根拠を意図的に3つ探す', '買い根拠をさらに増やして確信を高める', '同じ意見のSNS投稿を確認する', '損切りを広げて買いで入る', 1, '方向を先に決めると、支持する情報だけが目に入りやすくなります。対策は反対根拠を意図的に探すことです。根拠の数ではなく、反証の重さも含めて判断する必要があります。', false, 1),
(26, '日足の高値更新失敗を見落とし、4時間足の買いサインだけで入った。何が起きていた可能性が高いか？', '日足より4時間足の方が常に正確だった', '都合の良い時間足だけを見て、反対情報を無意識に除外していた', '高値更新失敗は中級者には関係ない情報だった', '買いサインが出た時点で上位足確認は不要だった', 2, '確証バイアスは、見たい時間足や材料だけを強調します。日足の弱さを無視して下位足の買いだけを見ると、全体のリスク評価が歪みます。上位足から反対情報を確認する習慣が必要です。', false, 2),
(26, '含み損のポジションで「戻る根拠」を探し続けている。最も注意すべき心理はどれか？', '根拠を探すほど損切り精度が上がっている', '含み損中は分析力が最も高まっている', '自分の仮説の誤りを認めたくなくて、損切りを先延ばしにしている', '損切り位置は保有後に柔軟に決めるべき', 3, '含み損中の分析は、ポジションを守るための理由探しになりやすい状態です。「戻るはず」は仮説の否定を避ける心理かもしれません。損切りは事前ルールで実行し、保有後の分析で動かしません。', false, 3),
(26, 'エントリー前に「このシナリオが間違うなら何か」と聞かれて何も出ない。適切な扱いはどれか？', '完璧なシナリオなので通常より大きく入る', '反対根拠がないなら損切りは不要になる', 'すぐ入らないと好機を逃す', 'リスクがないのではなく、見えていない可能性が高いので一度止まる', 4, 'リスクが全く出ない時ほど、分析不足か確証バイアスを疑います。相場にリスクゼロはありません。上位足、出来高、ファンダ、損益比を見直し、反証が見えるまで判断を保留します。', false, 4),
(26, 'SNSで自分と同じ方向の投稿だけを読んで安心した。なぜ危険か？', 'SNSの投稿は全て間違っている', '安心感を得るための情報収集になり、反対意見を過小評価しやすい', '同じ方向の意見が多いほど相場は必ず逆に動く', '他人の意見を見ること自体が禁止だから', 2, '確証バイアス下の情報収集は、判断の検証ではなく安心材料探しになります。同じ方向の声だけを集めると、リスクが見えにくくなります。反対意見を先に読むルールを置くと偏りを抑えられます。', false, 5),
(26, 'メイン根拠3つ、反対根拠2つがある。反対根拠の1つは上位足の転換だった。どう判断すべきか？', '根拠は3対2なので予定通り入る', '反対根拠は探した時点で役目を終える', '数ではなく重さを評価し、見送りやロット縮小を検討する', '上位足よりメイン根拠の数を優先する', 3, '根拠は多数決ではありません。上位足の転換のような重い反証は、買い根拠が多くても期待値を大きく下げます。反対根拠が深刻なら、見送りかロット縮小で対応します。', false, 6),
(26, '1週間前の上昇シナリオに固執し、押し安値割れを「だまし」と決めつけた。問題はどれか？', '押し安値割れは必ず上昇継続のサインである', 'シナリオは最低1週間変えてはいけない', 'だましを疑うこと自体が間違いである', '新しい証拠を例外扱いし、古い仮説を守ろうとしている', 4, '一度立てたシナリオには愛着が生まれます。新しい弱気材料を例外として処理し続けると、判断が更新されません。シナリオは正しさを守るものではなく、相場情報に合わせて更新するものです。', false, 7),
(26, '反対根拠を探すと毎回エントリーできなくなりそうで避けている。正しい理解はどれか？', '反対根拠探しは否定ではなく、リスクを含めて判断するための工程', '反対根拠を探すほど勝率は必ず下がる', '強いシナリオなら反対根拠は不要', '迷いが増えるので中級者には向かない', 1, '悪魔の代弁者は、トレードを全否定する作業ではありません。反対材料も見たうえでメインが優勢か確認する工程です。これにより無自覚な偏りが減り、入る時の根拠も強くなります。', false, 8),
(26, '損切りラインを「少しだけ」広げたくなった。確証バイアスの観点で危険な理由はどれか？', 'ラインを広げるほど資金管理が安定する', '損切りは相場に合わせて毎回広げるべき', '仮説の否定を避けるため、ルール変更を合理化している可能性がある', '少しだけなら心理への影響はない', 3, '保有後に損切りを広げる行為は、相場分析ではなく「間違いを認めたくない」心理から来ることがあります。事前の無効化条件を動かすと、損失上限が消えます。ルール変更は次回以降に検証します。', false, 9),
(26, '確証バイアスを抑えるシナリオノートの使い方として最も有効なのはどれか？', '勝った理由だけを詳しく残す', 'SNSで見た同意見を貼り付ける', 'エントリー後に都合よく追記する', 'メイン根拠と同じ数だけ反対根拠を書き、深刻度を比較する', 4, 'ノートに反対根拠欄を作ると、偏りが紙面に出ます。大切なのは数だけでなく深刻度の比較です。書くことで、頭の中で都合よく処理していたリスクを客観視できます。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(27, '過去に大きく取れた形に似たチャートを見て、条件確認前に入りたくなった。最初にすべきことはどれか？', '形ではなく、現在の相場環境・流動性・根拠の合流を確認する', '過去に勝てた形なので素早く入る', '同じ形ならロットを上げて再現を狙う', '過去の勝ちを忘れるため別手法に切り替える', 1, '成功体験は「似た形」を特別に見せます。しかし相場は背景条件まで同じにはなりません。現在の環境、ゾーンの鮮度、出来高、上位足との整合を確認してから判断します。', false, 1),
(27, 'トレンド相場で成功したブレイク手法を、レンジ相場でも使い続けて連敗した。根本原因はどれか？', 'ブレイク手法はどの環境でも使えない', '相場環境の変化より過去の成功記憶を優先してしまった', 'レンジ相場では全ての手法が必ず負ける', '昨年の利益が全て偶然だった', 2, '過去に機能した手法でも、環境が変われば期待値は変わります。成功体験が強いほど「また通用する」と思い込み、切り替えが遅れます。手法は過去ではなく今の環境で評価します。', false, 2),
(27, '「3回連続で勝ったパターンだから今回も同じ」と考えた。危険な理由はどれか？', '3回勝ったパターンは次に必ず負ける', '同じパターンは一度しか機能しない', '少数の成功に特別な意味を持たせ、背景条件の違いを見落とす', '勝った回数を数えること自体が不要', 3, '3回の成功は強い記憶になりますが、統計的には十分ではありません。形が似ていても参加者、ボラティリティ、流動性は違います。毎回の成功はサンプルの1つとして扱う必要があります。', false, 3),
(27, '以前の押し目買い成功が忘れられず、安値更新後も「押し目」と見て買った。防ぐ認識はどれか？', '押し目買いは一度成功したら使い続ける', '安値更新後も買い目線を固定する', '過去の成功を完全に記録から消す', '押し目か転換かは過去の記憶ではなく現在の構造で判断する', 4, '成功記憶が強いと、転換の兆候まで押し目に見えます。判断基準は今の高安値、出来高、波動、上位足です。過去の記憶より現在の構造を優先することで執着を切れます。', false, 4),
(27, '勝てた手法の成績が2ヶ月悪化している。適切な対応はどれか？', '過去に勝てたので何も変えず耐える', '現環境で機能しにくい理由を検証し、必要なら修正や休止を選ぶ', '半年は無条件に同じ手法を続ける', '心理面だけが原因と決めつける', 2, '成績低下には、環境変化か運用ミスか原因があります。過去の成功実績があるほど見直しを遅らせがちです。現在のデータで検証し、修正や休止を選べる柔軟性が生存につながります。', false, 5),
(27, '「前にこのゾーンで反転したから今回も反転する」と考えた。何を見落としている可能性が高いか？', '過去に反転した場所は二度と機能しない事実', 'ゾーン分析は成功体験と無関係であること', '到達回数や注文の残り、上位足の環境が変わっている可能性', '反転した場所では必ず出来高が増えること', 3, '同じ価格帯でも、何度も試されると注文が減り、環境も変わります。前回の反転は参考情報であり、今回の根拠そのものではありません。鮮度や上位足の流れを改めて確認します。', false, 6),
(27, '成功した1回のトレードを「自分の型」として固定したくなった。なぜ危険か？', '成功した型は必ず次から使えなくなるから', '型を持つこと自体が中級者には不要だから', '固定すると記録が取りにくくなるから', '1回の結果に過剰な意味を持たせ、統計的な検証を飛ばすから', 4, '印象的な勝ちは、自分だけの発見に見えやすいものです。しかし1回の結果はサンプルにすぎません。100回規模の記録で評価する姿勢が、成功体験への執着を防ぎます。', false, 7),
(27, '月次の手法棚卸しで最も確認すべきことはどれか？', '先月の勝ちパターンが今月の環境でも同じ条件で機能しているか', '一番利益が出たトレードだけを再現できるか', '負けたトレードを記録から外せるか', '毎月必ず新しい手法を追加できるか', 1, '棚卸しの目的は手法探しではなく、環境との適合確認です。先月の勝ち筋が今月も同じ条件で機能しているかを見ることで、成功体験に縛られず微調整できます。', false, 8),
(27, '「初心者の目」でチャートを見る練習が役立つ理由はどれか？', '初心者の方が必ず正しい判断をするため', '難しい分析を全て捨てるため', '過去の成功記憶を一度脇に置き、今のチャートを先入観なく読むため', '過去の検証を使わないため', 3, '初心者の目とは、知識を捨てることではありません。過去の勝ち負けの記憶をいったん横に置き、今の価格、構造、出来高をそのまま見る姿勢です。これが執着のフィルターを弱めます。', false, 9),
(27, '成功体験への執着が学習停止につながる場面はどれか？', '勝ったトレードを記録に残す', '負けた手法を一度休止する', '環境に合わせて微調整する', '「自分はもう分かっている」と感じ、新しい相場変化を検証しなくなる', 4, '過去の成功は自信になりますが、過信になると学びを止めます。「もう分かっている」と感じた時ほど、現在の相場に合っているかを確認する必要があります。成長は成功後の検証で続きます。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(28, '損切りは守れるようになったが、含み益が出ると利確目標前に全決済してしまう。何が起きているか？', '中級者の利確問題で、利益を失いたくない心理が伸ばす判断を妨げている', '損切り技術が完全に身についた証拠', '利確目標を設定すること自体が間違い', '勝っている時は早い利確が常に正解', 1, '中級者は損切りの壁を越えた後、利益を伸ばせない壁にぶつかります。含み益を失う恐怖でシナリオより早く決済すると、損益比が崩れます。分割利確で心理を設計するのが有効です。', false, 1),
(28, 'RR1:3の計画なのにRR1:1.2で全利確した。その後目標に届いた。次回の改善策はどれか？', '次回から利確目標を持たない', '一部を先に利確し、残りを計画目標まで伸ばす分割利確を使う', '全ポジションを必ず最後まで握る', 'ロットを倍にして早利確を補う', 2, '全てを握るか全てを利確するかの二択にすると心理負荷が高くなります。33%など一部を先に確保すれば、残りを伸ばす余裕ができます。利確も意志ではなく構造で扱います。', false, 2),
(28, 'SNSで他人の大きな利益を見て、自分の利益が小さく感じた。最も危険な次の行動はどれか？', '自分のトレード日誌を見返す', '1ヶ月前の自分と比較する', '焦って普段より大きなロットや低品質な場面に入る', 'ルーティンを守れたか確認する', 3, 'SNSは勝った場面だけが見えやすく、全体像ではありません。他人のハイライトと自分の日常を比べると焦りが生まれ、ロット増大やルール違反につながります。比較対象は過去の自分です。', false, 3),
(28, '月前半で利益が出た後、「守りに入る」と決めて全てのチャンスを見送った。問題はどれか？', '利益が出た月は必ず追加で攻めるべき', '守りに入ることは常に悪い', '見送りは投資判断ではない', '損益状況で判断基準が歪み、条件が揃った場面まで避けている', 4, '守ること自体は悪くありません。問題は、基準が相場条件ではなく今月の利益に変わることです。条件が揃ったらルール通り、心理状態が悪ければロット縮小など、事前基準で判断します。', false, 4),
(28, '月前半の利益を「ボーナス」と考え、普段やらない高リスク取引に入った。何が危険か？', '利益がある月はリスクを増やすべき', '利益を余剰資金のように扱い、リスク管理の一貫性を失っている', '高リスク取引は必ず損になる', '月前半の利益は記録しない方がよい', 2, '利益が出た後でも、口座資金は守るべき資金です。ボーナス感覚になると、普段なら避けるリスクを正当化します。月間損益に関係なく、同じリスクルールを維持します。', false, 5),
(28, '前回負けた直後、「次は絶対に取り返す」と同じ方向を探している。正しい認識はどれか？', '負けた方向は次に勝ちやすい', '取り返す意識は集中力を高める', '前回の結果と次の相場は独立しており、今の環境認識だけで判断する', '同じ方向なら分析時間を短縮できる', 3, '前回の勝敗は次の値動きを変えません。取り返したい心理が入ると、見たい根拠だけを集めやすくなります。次のトレードは独立事象として、現在の条件だけで判断します。', false, 6),
(28, '前回勝った後、「今日も同じ通貨ペアなら勝てる」と感じた。注意すべきことはどれか？', '同じ通貨ペアは連続で取引してはいけない', '勝った後は必ず環境が悪化する', '勝った銘柄だけに絞るのが中級者の基本', '勝った記憶が今回の優位性を保証しているように錯覚させる', 4, '前回勝ったペアでも、今回の環境は別物です。勝った記憶は親近感を生み、根拠を甘く見せます。毎回、上位足、シナリオ、損益比をゼロから確認する必要があります。', false, 7),
(28, '他人と比較して落ち込んだ時、最も建設的な確認項目はどれか？', '1ヶ月前より環境認識・損切り・ルーティンが改善しているか', 'SNS上で自分より利益が少ない人を探す', '利益額だけをプロと比較する', '次の1回で差を埋められるか', 1, '比較の基準を他人に置くと焦りが増えます。見るべきは、1ヶ月前の自分より判断の質が上がったかです。成長指標を内部に戻すことで、無理なトレードを防げます。', false, 8),
(28, '「今日は利益を減らしたくない」と、条件が揃っているのに極端に小さく入った。何を疑うべきか？', 'ロットを小さくするほど常に期待値が上がる', '条件が揃った場面は避けるべき', '今月の利益を守りたい心理が、通常の判断基準を歪めている', '利益がある日は取引禁止にすべき', 3, '守りたい心理が強すぎると、良い場面でも行動できなくなります。ロット縮小は心理チェックの結果として行うなら有効ですが、損益への執着で毎回変えると判断が不安定になります。', false, 9),
(28, '勝ち始めた後の心理的罠をまとめて避ける姿勢として最も適切なのはどれか？', '利益が出たら取引回数を増やす', '負けた後だけ心理チェックを行う', '勝っている月はルールを柔軟にする', '前回結果・他人比較・月間利益を判断基準にせず、事前ルールで淡々と処理する', 4, '中級者の罠は、勝った後や利益が出た後に判断基準が変わることです。前回結果、SNS、月間損益を相場判断から切り離し、事前ルールで同じように処理することが安定につながります。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(29, '「次から気をつける」と決めたのに同じミスを繰り返す。仕組み化が必要な理由はどれか？', 'バイアス発動中は自分が歪んでいることに気づきにくい', '意志力が強い人ほど必ず勝てる', '反省すればチェックリストは不要になる', '経験が増えればバイアスは消える', 1, 'バイアスの怖さは、発動中に自覚しにくいことです。だから気合いではなく、事前のチェックリストや休止ルールで行動前に止めます。気づく前に止まる設計が必要です。', false, 1),
(29, '心理チェックで「直近3連勝」「ロットを上げたい」がYESだった。適切な対応はどれか？', '調子が良いのでロットを上げる', '注意レベルとしてロットを70%程度に落とし、条件確認を厳格化する', 'YESが2つなら無視してよい', 'すぐ全ての手法を変更する', 2, '1〜2つのYESは警戒サインです。完全停止までは不要でも、通常よりバイアスが入りやすい状態です。ロットを縮小し、チェック項目を厳しくすることで損失時の影響を抑えます。', false, 2),
(29, '心理チェックでYESが3つ以上になった。最も適切な判断はどれか？', 'ロットを半分にして必ず1回だけ入る', 'YES項目を見ないことにして通常運用する', '今日はトレードを休み、翌日に環境認識からリセットする', '勝てそうな場面だけ例外的に入る', 3, 'YESが3つ以上なら複数のバイアスが同時に出ています。この状態で精度を期待するのは危険です。休むことをルールにしておけば、迷いや例外判断を入れずに口座を守れます。', false, 3),
(29, '「今日は絶対にトレードしたい」がYESだった。なぜ単独でも強い警告になるのか？', '毎日トレードすること自体が禁止だから', 'トレードしたい日は必ず相場が悪いから', '欲求があるほど分析精度が高いから', '条件ではなく行動したい欲求が先に立ち、基準を緩めやすいから', 4, '「絶対にやりたい」は、相場条件より自分の欲求が前に出ている状態です。この感情があると、足りない根拠を補って見せやすくなります。単独でも一時停止の十分な理由になります。', false, 4),
(29, 'チェックリストをエントリー直前ではなく、朝のルーティンに入れる利点はどれか？', '朝に見れば日中の相場確認が不要になる', 'ポジションを持つ前の冷静な状態で心理リスクを把握できる', 'チェック項目が全て自動で消える', '朝の判断なら損切りが不要になる', 2, 'エントリー直前は欲や焦りが入りやすい時間です。朝の冷静な状態で心理状態を見ておけば、日中のロットや見送り基準を先に決められます。先に決めるほど感情の余地が減ります。', false, 5),
(29, '月次メンタル振り返りで「勝った月ほど問題が多い」と分かった。次に設計すべき対策はどれか？', '勝った翌月は無条件で取引を増やす', '負けた月だけ日誌を詳しく書く', '勝った月ほどチェック省略やロット増大がないか確認する項目を追加する', '勝った月の反省は不要とする', 3, '勝った月は油断が見えにくくなります。チェックリスト省略、ロット増大、根拠の薄い勝ちを振り返る項目を月次に入れることで、翌月の大きな負けの前兆を見つけやすくなります。', false, 6),
(29, '反対根拠欄をノートに作ったが、空欄のままエントリーしたくなった。仕組みとしての判断はどれか？', '反対根拠がない証拠なので即エントリーする', '空欄でも損切りを広げれば問題ない', '勝率が高い手法なら反対根拠欄は不要', '空欄なら確証バイアス警戒として、反対根拠を探すまでエントリーしない', 4, '反対根拠欄が空欄なのは、リスクがないのではなく探していない可能性があります。欄を埋めるまで入らないルールにすると、確証バイアスが行動に移る前に止まれます。', false, 7),
(29, 'ロットを通常より大きくしたい衝動をチェックリストに入れる目的はどれか？', '連勝や高揚で資金管理を変えようとする瞬間を可視化する', '利益を最大化するタイミングを知らせる', 'ロット計算を省略するため', '大きく張る日を増やすため', 1, 'ロットを上げたい衝動は、連勝バイアスや焦りの分かりやすい出口です。チェック項目にしておくと、感情によるサイズ変更を早期に発見できます。資金管理は衝動ではなく計算で決めます。', false, 8),
(29, '月次振り返りで改善課題を1つだけ選ぶ理由として適切なのはどれか？', '複数の課題は存在しないから', '1つ選べば記録を取らなくてよい', '課題を絞るほど翌月の行動ルールに落とし込みやすい', '最も簡単な課題だけ直せば十分だから', 3, '課題を多く並べると、結局どれも実行に移りません。翌月は「連勝後のロットを固定する」など1つに絞ると、具体的なチェック項目や禁止ルールへ変換しやすくなります。', false, 9),
(29, '心理的な罠を仕組みで回避する最終目的として最も近いものはどれか？', '感情を完全になくして機械になること', '全てのトレードを自動化すること', 'チェックリストを作れば必ず勝てること', '感情を消すのではなく、感情があってもルール外の行動に移さないこと', 4, '目標は感情をゼロにすることではありません。連勝の高揚や焦りが出ても、行動がルール外へ流れないようにすることです。仕組みは、感情と注文ボタンの間に置く安全装置です。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(30, '5連勝後にロットを2倍にした結果、1回の負けで5連勝分の利益の大半を失った。この事例から読み取れる最も重要な教訓はどれですか？', '5連勝した後は必ず負ける運命にある', '5連勝した銘柄と同じ銘柄ではトレードすべきでないこと', '2倍より3倍に増やしていればリカバリーできた可能性があること', 'ロットを変えていなければ、1回の負けは他の1回の負けと同じ程度の損失で済んだこと', 4, 'ロットを一定に保っていれば、1回の負けは単なる1回の損失で済みます。連勝中のロット変更が、統計的なリスク管理を破壊する最大の要因です。', false, 1),
(30, '「買い」と決めた後に買いの根拠だけを5つ集め、出来高の減少とVIX上昇を見落とした結果、トレンド転換で損切りされた。この失敗を防ぐために有効な対策はどれですか？', '買いの根拠を10個に増やすこと', '出来高とVIXを全く見ないようにすること', '他人の買い意見だけを参考にすること', 'エントリー前にメインの根拠と同数の反対根拠を探す「悪魔の代弁者」を実践すること', 4, '買いの根拠を増やすだけでは確証バイアスを強めます。「悪魔の代弁者」で反対の根拠を意図的に探すことで、出来高減少やVIX上昇などの危険信号を見落とさなくなります。', false, 2),
(30, '過去にS級ゾーンでピンバーが出て大きく取れた経験があるトレーダーが、鮮度3回目のゾーンで合流1層しかないにもかかわらずエントリーして損切りされた。この失敗の根本原因は何ですか？', 'パターンの「形」の類似性だけで判断し、鮮度や合流といった「条件」を確認しなかったこと', 'ピンバーというパターン自体が信頼性に欠けること', 'S級ゾーンでは必ず損切りされる運命にあること', 'エントリータイミングが遅すぎたこと', 1, '成功体験への執着により「形が似ている」だけで飛びつきました。鮮度3回目は注文枯渇、合流1層は根拠不足であり、条件を確認していれば見送りでした。', false, 3),
(30, 'RR1:3の利確目標があるのにRR1:1.5の時点で全ポジションを利確してしまい、その後利確目標に到達した。この問題を構造的に解決する方法として最も適切なものはどれですか？', '利確目標をRR1:1.5に下げる', 'ロットを減らして心理的負担を軽くする', '利確しないで必ずRR1:3まで待つ', '分割利確で33%を先に確保し、残りで目標まで伸ばす', 4, '分割利確で一部の利益を先に確保することで、「利益を失いたくない」心理を満たしつつ、残りのポジションで利確目標まで伸ばす心の余裕が生まれます。', false, 4),
(30, '3日間ノートレードが続き、「何もしていない＝サボっている」と感じて条件が完全には揃っていないのにエントリーした。この「焦りのバイアス」に対する正しい認識はどれですか？', '見送りは立派な投資判断であり、「条件が揃わなかったから正しく見送った」と捉えるべき', '3日間トレードしないのは怠惰であり、即座に改善すべき', 'ノートレードが続く時は条件を緩めてでもエントリーすべき', '3日以上トレードしない場合は強制的にエントリーするルールを作るべき', 1, '「トレードしない＝無駄」という認知の歪みが焦りを生みます。条件が揃わない場面で見送ることも立派な投資判断であり、「何もしなかった」のではなく「正しく見送った」と認識することが重要です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(31, '経済指標を相場への影響度で3段階に分類したとき、Tier 1（最重要）に該当する指標の組み合わせとして正しいものはどれですか？', '政策金利決定、消費者物価指数、雇用統計', 'PMI、中央銀行総裁の講演、貿易収支', '鉱工業生産指数、住宅着工件数、小売売上高', 'GDP速報値、PMI、中央銀行総裁の講演', 1, 'Tier 1は政策金利決定（FOMC等）、CPI、雇用統計（NFP）の3つで、相場の方向を変える可能性がある最重要指標です。最初はこの3つだけ意識すれば十分です。', false, 1),
(31, '経済指標で相場が大きく動く直接の要因は何ですか？', '指標の結果そのものの絶対値が高いこと', '前回の指標値との差の大きさ', '市場の事前予想と実際の結果との差（サプライズ）', '指標が発表された時間帯の出来高の多さ', 3, '相場が動くのは「結果の良し悪し」ではなく「市場予想との差」です。良い結果でも織り込み済みなら反応は限定的で、予想を裏切る結果が出たときに大きく動きます。', false, 2),
(31, '指標の結果が市場予想を上回った場合（ポジティブサプライズ）、基本となる相場の反応として正しいものはどれですか？', '必ず通貨安方向に動く', '通貨高方向に動きやすいが、織り込み済みの場合は逆に動くこともある', '常況に関わらず必ず上昇する', '出来高が減少するまで反応を待つ必要がある', 2, 'ポジティブサプライズは基本的に通貨高方向の動きを生みますが、すでに市場がその結果を織り込んでいる場合は「噂で買って事実で売る」の逆行現象が起きます。', false, 3),
(31, '経済指標の結果が市場予想とほぼ同じだった場合、相場はどう反応しやすいですか？', '予想以上に大きく動くことが多い', '大きな反応はなく、すでに織り込まれていた証拠となる', '必ず翌日にかけて急激なトレンドが発生する', '出来高だけが急増して価格は動かない', 2, '結果が予想通りの場合、市場はすでにその数値を前提にポジションを組んでいるため大きな反応は起きません。これが「織り込み済み」の典型的な状態です。', false, 4),
(31, 'Tier 2（重要）の経済指標に該当するものはどれですか？', '消費者物価指数（CPI）', 'PMI（購買担当者景気指数）', '鉱工業生産指数', '非農業部門雇用者数（NFP）', 2, 'Tier 2はPMIや中央銀行総裁の講演などで、大きな値動きを生むことがあるもののTier 1ほどの方向転換は起こしにくい指標です。CPIとNFPはTier 1に分類されます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(32, 'Tier 1指標の発表を控えている場合、含み益のポジションに対して取るべき対応として最も適切なものはどれですか？', '発表直前にロットを増やして利益を最大化する', '一部利確、トレーリングストップの設定、または建値ストップへの移動を検討する', '指標結果を予測してポジションを維持する', '損切りラインを広げて指標発表の波を乗り切る', 2, '含み益のポジションは、発表前に利益を一部確保するか、トレーリングストップや建値ストップで保護することが基本です。指標次第で利益が消えるリスクを事前に管理します。', false, 1),
(32, '「CPIが良ければ上がるから、発表前に買っておこう」という考え方はなぜ危険ですか？', 'CPIの結果は公開されないことがあるため', '指標の結果は誰にもわからず、結果に賭けるのはトレードではなくギャンブルであるため', 'CPI発表日は取引所が閉まっているため', 'CPIはTier 2指標であり、そもそも相場に影響しないため', 2, '発表前にポジションを取るのは結果への賭けであり、トレードではありません。結果が出た後に対応するのが原則で、事前のポジション整理が重要です。', false, 2),
(32, '経済指標発表前にノーポジションの場合、事前に準備すべき最も重要なことは何ですか？', '発表直後に飛び乗るための指値注文を入れておくこと', '結果がどちらに出ても対応できるIf-Thenシナリオを3パターン準備すること', 'SNSで他のトレーダーの予想を確認すること', '発表日まで全くチャートを見ないこと', 2, 'ノーポジションの場合は、「結果＞予想」「結果＝予想」「結果＜予想」の3パターンのシナリオを事前に準備し、いずれの場合も発表直後のスパイクには飛び乗らないことを決めておきます。', false, 3),
(32, '指標発表前に含み損のポジションがある場合、取るべき対応として正しいものはどれですか？', '損切りラインを広げて様子を見る', '指標結果次第でさらに悪化するリスクを想定し、発表前に損切りを検討する', 'ナンピンして平均取得価格を下げる', '指標発表後に必ず反転すると信じて保有し続ける', 2, '含み損のポジションは指標結果によってさらに悪化するリスクがあります。発表前に損切りを検討するか、少なくとも損切りラインを確認・再設定することが重要です。', false, 4),
(32, '指標前のシナリオ準備テンプレートで、「結果＝予想」の場合の対応として正しいものはどれですか？', '結果にかかわらず直ちにエントリーする', '通貨高方向への強いエントリーを検討する', '大きな動きはないため、通常のテクニカル分析に戻る', '全ポジションを決済して翌日まで待つ', 3, '結果が予想通りの場合は大きな反応がなく、材料はすでに織り込み済みです。テクニカル主体の通常の分析・判断に戻って対応します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(33, 'Tier 1指標の発表直後（0〜5秒）の相場状態と対応として正しいものはどれですか？', '方向が確定しているため即座にエントリーする', '初動スパイクによりスプレッドが急拡大し、この瞬間のエントリーは極めて危険である', '出来高が減少するため安全にエントリーできる', '必ずトレンドの方向に沿った直線的な動きになる', 2, '発表直後の0〜5秒は結果に反応して急激に動き、スプレッドが急拡大します。この瞬間にエントリーするのはリスクが極めて高く、避けるべきです。', false, 1),
(33, '指標発表後の「ウィップソー（往復ビンタ）」が起きやすい時間帯はいつですか？', '発表から0〜5秒', '発表から5秒〜5分', '発表から30分〜2時間', '発表から翌日', 2, '5秒〜5分の間は初動と逆方向に急反転するウィップソーが起きやすく、「上がった→戻った→やっぱり上がった」という乱高下が発生します。', false, 2),
(33, '経済指標発表中のルールとして、発表後どの程度の時間は新規エントリーを禁止すべきとされていますか？', '発表後5分間', '発表後30分間（Tier 1の場合は1〜2時間まで延長推奨）', '発表後10分間', '発表後12時間', 2, '基本ルールは発表前30分〜発表後30分の新規エントリー禁止で、Tier 1指標の場合は発表後1〜2時間まで延長が推奨されます。混乱が落ち着くまで待つことが重要です。', false, 3),
(33, '指標発表直後にチャートを見ることについて正しい態度はどれですか？', 'チャートを見ると感情が揺さぶられるため見ない方がよい', 'チャートを見てもよいが、「見る」と「動く（注文する）」を明確に分離する', 'チャートを見たら必ず何らかのアクションを取るべきである', 'チャートを見る代わりにSNSの反応を確認すべきである', 2, '「見る」と「動く」を分離することが重要です。観察自体は学習になりますが、感情に支配された状態でのエントリーは避けるべきです。', false, 4),
(33, '指標発表中に既存ポジションの損切りが発動した場合、どう対応すべきですか？', 'すぐに損切りを取り消す', '発表前に設定した損切りが発動したのは計画通りであり、手動で変更しない', '損切り価格をさらに広げてポジションを維持する', '同じ方向にすぐさま再エントリーする', 2, '発表前に設定した損切りが発動したら計画通りです。手動で損切りラインを変更したり、損切りを取り消したりするのは感情に支配された判断になり危険です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(34, '指標発表後の再エントリーを検討する5条件に含まれないものはどれですか？', '値動きで上昇/下降の方向が明確になっていること', '指標の結果とテクニカル分析の方向が一致していること', '発表直後のスパイクに乗る形でエントリーできていること', 'スプレッドが通常の水準に戻っていること', 3, '再エントリーの5条件は「方向が明確」「テクニカルとの整合」「出来高の正常化」「スプレッドの正常化」「ゾーン/トリガーの確認」です。スパイクへの飛び乗りは明確に避けるべき行動です。', false, 1),
(34, '指標発表後の再エントリーにおいて、「出来高が落ち着いた」ことを確認する理由は何ですか？', '出来高が多いと約定しにくいため', '異常な出来高の間はノイズが多く、方向が定まっていない可能性が高いため', '出来高が多いとトレンドが終わる兆しであるため', '出来高は価格変動と無関係であるため', 2, '発表直後の異常な出来高の間は市場が結果を消化している最中であり、ノイズも多いです。出来高が通常水準に戻りつつあるタイミングで方向が明確になります。', false, 2),
(34, '「織り込み済み」の典型的なサインとして正しいものはどれですか？', '発表前に大きく動いていなかったのに、発表直後に急激に動いた', '発表前にすでに大きく動いており、結果通りに動いた直後に急反転した', '発表後に出来高が急増して方向が定まった', '指標結果が予想と大きく乖離した', 2, '織り込み済みの典型は、発表前にすでに動いていた（噂で買った）状態で、結果通りの動きをした直後に「事実で売る」反転が起きるパターンです。初動は反射反応、反転が市場の本音です。', false, 3),
(34, '指標発表後の環境認識アップデートの正しい手順として並べたものはどれですか？', 'ステップ1:テクニカル確認→ステップ2:指標結果確認→ステップ3:市場解釈確認→ステップ4:見通し更新', 'ステップ1:指標結果確認→ステップ2:市場解釈確認→ステップ3:テクニカルとの整合確認→ステップ4:見通し更新', 'ステップ1:市場解釈確認→ステップ2:指標結果確認→ステップ3:ポジション構築→ステップ4:見通し更新', 'ステップ1:見通し更新→ステップ2:テクニカル確認→ステップ3:市場解釈確認→ステップ4:指標結果確認', 2, 'まず指標の結果を確認し、次に市場がその結果をどう解釈しているかを確認、テクニカルとの整合を取り、最後に今後の見通しを更新する、という順序が正しい手順です。', false, 4),
(34, 'テクニカルが上昇を示し、ファンダメンタルズも上昇方向の場合、トレードの確度はどう評価されるべきですか？', '低確度 — ファンダメンタルズは無視してよい', '中確度 — ロットを50〜70%に縮小する', '高確度 — 積極的にエントリーを検討できる', '不可能 — テクニカルとファンダが一致することはない', 3, 'テクニカルとファンダメンタルズが同方向を向いている場合は高確度と評価でき、通常のポジションサイズで積極的にエントリーを検討できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(35, 'FOMC（連邦公開市場委員会）の発表において、金利据え置きが決定された場合でも相場が大きく動く理由として最も適切なものはどれですか？', '金利据え置きは常に相場に悪影響を与えるため', '声明文の文言や記者会見のニュアンスで「将来の金利の方向」が変わるため', '金利据え置きは予想外の出来事であるため', '市場は金利決定そのものには反応しないため', 2, 'FOMCでは金利の変更の有無だけでなく、声明文の文言や議長の記者会見で将来の金利政策のニュアンス（タカ派かハト派か）が変わることで相場が大きく動きます。', false, 1),
(35, 'NFP（非農業部門雇用者数）の特徴として正しいものはどれですか？', '毎月第一月曜日に発表される', '発表直後のボラティリティが非常に大きく、上下に100pips以上振れることもある', 'Tier 2指標であり、特別な対応は不要', '発表前のADP雇用統計と常に同じ方向の結果が出る', 2, 'NFPは毎月第一金曜日に発表され、発表直後のボラティリティが極めて大きいのが特徴です。最もウィップソーが激しい指標で、上下に100pips以上振れることもあります。', false, 2),
(35, 'NFPの発表前に確認しておくと役立つ先行指標は何ですか？', 'CPIの前月比', 'ADP雇用統計（民間版の先行指標）', 'FOMCの議事要旨', 'ドルインデックス（DXY）の週足チャート', 2, 'NFPの週前半に発表されるADP雇用統計は民間版の先行指標として機能し、おおまかな雇用の方向感を把握する参考になります。', false, 3),
(35, 'CPI発表後の対応として正しいものはどれですか？', '初動スパイクに乗って素早くエントリーする', '「結果＞予想＝通貨高」が基本だが、織り込み済みの場合は逆に動くことを前提に見送り、方向が定まってから検討する', 'CPIはTier 2指標なので通常通りのトレードを継続する', '結果に関わらず必ずショートポジションを取る', 2, 'CPIはインフレ動向を示し金利政策に直結しますが、基本の「結果＞予想＝通貨高」が必ずしも当てはまるわけではありません。織り込み済みの場合は逆行するため、初動を見送って方向が定まってから判断します。', false, 4),
(35, 'FOMCの翌日以降にやるべき対応として正しいものはどれですか？', 'FOMCの影響は発表日だけなので翌日からは通常通りでよい', '中長期的な金利の方向性を踏まえて、バイアス（買い目線/売り目線）を修正する', 'FOMC翌日は必ず全ポジションを決済する', 'FOMCの結果を忘れて新しい環境認識をゼロから始める', 2, 'FOMCの影響は発表日だけではありません。翌日以降は声明文や記者会見の内容を踏まえて中長期的な金利の方向性を再評価し、自身の相場バイアスを修正します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(36, 'CPI結果が予想を下回り（インフレ鈍化）、テクニカルも下降トレンド継続中だった場合の評価として正しいものはどれですか？', 'ファンダとテクニカルが逆方向のため見送る', 'テクニカルとファンダが一致しており、高確度のエントリーチャンスになり得る', 'インフレ鈍化は必ず通貨高につながるため買いを検討する', '指標結果が悪い場合はエントリーを禁止するルールがある', 2, 'テクニカルの下降トレンドと、CPI結果による利上げペース鈍化期待の通貨安方向が一致していれば、高確度のエントリーチャンスになります。発表後の値動きが落ち着いたタイミングで検討します。', false, 1),
(36, '雇用統計が予想を大幅に上回る好結果だったにもかかわらず、初動の急上昇後に大幅下落した場合、その原因として最も考えられるものはどれですか？', '雇用統計のデータに誤りがあったため', '発表前の1週間で市場がすでに好結果を織り込んで上昇していた「噂で買って事実で売る」パターンのため', '好結果の雇用統計は常に下落を引き起こすため', '出来高が少なすぎて価格が維持できなかったため', 2, '発表前に市場が好結果を織り込んで上昇していた場合、結果が出た瞬間に「もう上がる材料は出尽くした」と解釈され、利益確定の売りに転じます。初動の上昇は反射反応、反転が市場の本音です。', false, 2),
(36, 'FOMCで金利据え置きが決まったが、声明文が想定よりタカ派だった場合、翌日以降の対応として正しいものはどれですか？', '金利は変わっていないので無視してよい', '金利自体は変わらなくても「将来の金利の方向」が変わったと判断し、環境認識をタカ派寄りにアップデートする', 'タカ派の声明文は必ず株価上昇につながるため即座に買いを入れる', '声明文はテクニカル分析に影響しないため無視する', 2, '金利が据え置かれても、声明文のタカ派的なニュアンスは将来の利上げ確率を高めます。環境認識のマクロ背景をタカ派寄りにアップデートし、通貨高方向のバイアスに修正します。', false, 3),
(36, 'CPI発表前に含み益のスイングロングポジションがある場合の対応として最も適切なものはどれですか？', '全ポジションを一度決済して、発表後に買い直す', '分割利確の第一利確分（33%）をCPI発表前に利確し、残りはトレーリングストップで保護する', '含み益があるならそのまま保有し続けるのが最善', 'ロットを増やして利益を最大化する', 2, '分割利確の考え方を活用し、33%分を事前に利確して利益を一部確保します。残りはトレーリングストップで保護し、発表結果がポジション方向と一致すれば継続、逆方向なら自動的に利確されます。', false, 4),
(36, 'テクニカル的に完璧な押し目買いのセットアップが揃っているが、翌日にTier 1指標の発表を控えている場合、どうすべきですか？', 'セットアップが完璧なら指標前でもエントリーすべきである', '発表前のエントリーは見送り、発表後もセットアップが崩れていなければその時点でエントリーする', '半分だけエントリーして残りは発表後に判断する', '指標発表後にセットアップが消えることはないため、すぐエントリーする', 2, 'どんなに完璧なセットアップでも、Tier 1指標次第で方向が急変するリスクがあります。「逃したチャンス」は「回避したリスク」と捉え、発表後に再評価するのが安全な判断です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(37, '毎週日曜夜に確認すべき週次の指標カレンダーチェックの目的は何ですか？', '週前半にエントリーを集中させるため', 'その週のTier 1・Tier 2指標の日程を把握し、対応メモを作成するため', '経済指標がある週は一切トレードしないため', '指標の結果を予想するため', 2, '週次ルーティンでその週の指標スケジュールを確認し、Tier 1・Tier 2の日程と対応メモを作成することで、指標当日に慌てずに計画的な対応ができます。', false, 1),
(37, '指標発表日の朝のルーティンで確認すべき項目に含まれないものはどれですか？', '指標名と発表時刻の確認', '市場予想の確認', '既存ポジションの整理（利確/損切り/建値移動）', '指標の具体的な数値結果の確認', 4, '発表前の朝のルーティンでは指標名・発表時刻・市場予想・既存ポジションの整理・If-Thenシナリオの準備を行います。指標の具体的な数値結果はまだ発表されていないため確認できません。', false, 2),
(37, '指標発表後1〜2時間のチェック項目として正しいものはどれですか？', '方向が明確になったか、テクニカルとの整合、出来高・スプレッドの正常化、ゾーン/トリガーの確認', 'SNSで他のトレーダーのエントリー状況を確認すること', '発表直後のスパイクに乗り遅れていないかを確認すること', '翌日の指標を調べること', 1, '発表後1〜2時間は再エントリーの5条件（方向の明確化、テクニカルとの整合、出来高の正常化、スプレッドの正常化、ゾーン/トリガーの確認）をチェックし、条件が揃えばエントリーを検討します。', false, 3),
(37, '指標発表当日の終わりにやるべき環境認識のアップデートとして正しいものはどれですか？', 'マクロ背景の更新、今後の金利方向に変化があるか確認、週次ファンダチェックリストの更新', 'その日の損益のみを確認して終わる', '翌日のエントリーポイントをテクニカルだけで決める', '指標結果をメモするだけで分析は不要', 1, '発表当日の終わりには、指標結果を踏まえて環境認識のマクロ背景をアップデートし、金利の方向性に変化がないか確認、週次ファンダチェックリストを更新することで今後の判断精度を高めます。', false, 4),
(37, '経済指標に対する中級者の理想的なスタンスとして正しいものはどれですか？', '指標発表日は一切チャートを見ない', '「前」で整理し、「中」で見送り、「後」で活かすという3段階の立ち回りを身につける', '指標発表前に必ずエントリーして利益を狙う', 'Tier 1指標以外は気にしなくてよい', 2, '中級者にとって経済指標は単に避けるだけの存在ではありません。「前」でポジションを整理し、「中」で混乱を見送り、「後」で値動きが落ち着いてからテクニカルとファンダの一致を確認してエントリーする、この3段階の立ち回りが理想です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(38, '環境認識を5つのレイヤーに分解したとき、「トレンドは加速中か減速中か」を判断するのはどのレイヤーですか？', 'レイヤー1：サイクル位置', 'レイヤー3：トレンド強度', 'レイヤー2：トレンド方向', 'レイヤー4：波動位置', 2, 'レイヤー3「トレンド強度」はMA乖離率やADX、出来高を用いて、トレンドの加速・減速を判定します。同じ上昇トレンドでも加速中と減速中で意味が異なります。', false, 1),
(38, '環境認識の3つの問いのうち、「この相場は誰が動かしているか」を推測するために最も有用な判断材料は何ですか？', '移動平均線のクロス', 'フィボナッチリトレースメント', 'RSIのダイバージェンス', '出来高と価格の関係', 4, '出来高と価格の関係から、大口の仕込みフェーズか、個人の追随フェーズか、利確の撤退フェーズかを推測できます。出来高は「誰が動かしているか」の手がかりです。', false, 2),
(38, '環境認識の5レイヤーのうち、レイヤー4「波動位置」で確認する判断材料として正しいものはどれですか？', '波動カウントとフィボナッチ', 'MA乖離率とADX', 'ダウ理論によるHH/HLの判定', '金利、VIX、経済指標', 1, 'レイヤー4「波動位置」では、波動カウントとフィボナッチを使用して、推進波の途中か修正波の途中かを判定します。', false, 3),
(38, '環境認識の5レイヤーのうち、レイヤー1「サイクル位置」で確認する判断材料として正しいものはどれですか？', '週足構造、出来高推移', 'MA乖離率、ADX、出来高', 'ダウ理論（HH/HL判定）、200MA', '金利、VIX、経済指標', 1, 'レイヤー1「サイクル位置」では、週足構造と出来高推移を確認して、蓄積・上昇・分配・下落のどのフェーズかを推定します。', false, 4),
(38, '「今の波は、上位足のどの部分にあたるか」という問いの重要性を最もよく表している状況はどれですか？', '1時間足のピンバーのヒゲの長さを測るとき', '4時間足の上昇が日足の修正波の中の反発なのか、日足の推進波の本流なのかを判断するとき', '週足で上昇トレンドか下降トレンドかを判定するとき', '出来高が20日平均を上回っているかを確認するとき', 2, '同じ4時間足の上昇でも、それが日足の修正波の中の反発であれば期待値は低く、推進波の本流であれば期待値は高くなります。上位足のどの位置にあるかで判断が変わります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(39, 'MTF分析において「3層構造」が実戦で最も機能する理由として正しいものはどれですか？', '3つの時間足を使えば勝率が必ず上がるから', 'プロのトレーダーが全員3層を使っているから', '3層なら全ての通貨ペアで同じ分析ができるから', '2層だと情報が不足し、4層以上だと判断が遅くなるから', 4, '2層構造では情報が不足し、4層以上では判断が遅くなるため、3層（戦略足・戦術足・執行足）が実戦的なバランスとして最適です。', false, 1),
(39, 'MTF分析の3層構造において、戦略足（Strategic）の役割として正しいものはどれですか？', '具体的なエントリーとエグジットのタイミングを取る', '今のトレンド・レンジの状態と波動位置を判定する', '大きなトレンドの方向とサイクル位置を確認する', '出来高の急変をリアルタイムで検知する', 3, '戦略足（週足）の役割は、大きなトレンドの方向とサイクル位置を確認することです。確認頻度は週に1回で十分です。', false, 2),
(39, '3層構造のサーフィン比喩において、「波のセットを待つ」ことに相当するのはどの層ですか？', '戦略足', '執行足', '全ての層が同時', '戦術足', 4, 'サーフィン比喩では、戦略足が「風向きを見る」、戦術足が「波のセットを待つ」、執行足が「ブレイクが来たらパドルする」に相当します。戦術足（日足〜4時間足）はトレンド・レンジの状態と波動位置の判定を担います。', false, 3),
(39, '日足上昇＋4時間足高値圏の組み合わせは、どのような評価・対応が適切ですか？', '順張りの高確度エントリーとして積極的に買う', '新規エントリーは見送り（追いかけ買いのリスク）', '戻り売りを検討する', 'レンジの上限まで限定的に買う', 2, '日足が上昇でも4時間足がすでに高値圏にある場合、新規エントリーは追いかけ買いのリスクが高いため見送りが適切です。', false, 4),
(39, '執行足（Execution）で使用するトリガーのうち、信頼度「強」とされる条件の組み合わせはどれですか？', 'ピンバー出現、包み足完成、ブレイク＋リテスト', '移動平均線のゴールデンクロス＋出来高平均的', '出来高減少＋コマ足の出現', 'レンジ内での小陽線の連続＋出来高増加', 1, '執行足の信頼度「強」のトリガーは、ゾーンでのピンバー出現、前足を実体で包む包み足の完成、水平線ブレイク後のリテスト確認の3つです。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(40, '時間軸の衝突パターンのうち「最頻出」とされるのはどれですか？', '上位足レンジ中の下位足トレンド', '上位足トレンド中の下位足調整', '上位足トレンド転換の初動', '全時間足がレンジ', 2, '上位足トレンド中に下位足が逆行する現象は、トレンドの中に必ず修正波が含まれるため日常的に発生し、最も頻出する衝突パターンです。フィボ38.2〜61.8%＋MA反発で押し目買いを狙います。', false, 1),
(40, '週足レンジ中に日足が上昇している場合、適切な対応として正しいものはどれですか？', '週足を無視して日足のトレンドに乗る', 'レンジ上限でのブレイクアウトを狙ってフルロットで買う', '利確目標をレンジ上限の手前に設定し、ポジションサイズを50%に縮小する', '日足の上昇が週足に反映されるまで待つ', 3, '上位足がレンジの場合、下位足のトレンドはレンジ上限で止まる可能性が高いため、利確目標を手前に設定し、ポジションサイズを縮小するのが適切です。この局面は「罠が多い」パターンです。', false, 2),
(40, '「どの時間足でも方向感がないのに、スキャルピングならいけるかも」という思考が危険な理由として最も適切なものはどれですか？', 'スキャルピングは上級者しかできない手法だから', '手数料コストが高くなるから', 'スキャルピングはMTF分析と相性が悪いから', '方向感のない相場は、短い時間足でも方向感がないから', 4, '方向感のない相場では、時間足を短くしても方向感は現れません。「短い時間足なら答えが見つかる」という幻想を捨てることが重要です。', false, 3),
(40, '上位足トレンド転換の初動を判断する際、「迷ったら」取るべき行動として正しいものはどれですか？', '小さなロットで逆方向にエントリーする', '日足の200MAが下を向くまで待つ', 'フィボ戻し率、出来高、週足安値の3つの手がかりで判断し、それでも迷えば見送る', '4時間足のトリガーが出たら即座にエントリーする', 3, 'トレンド転換の初動は判断が最も難しい局面です。フィボ戻し率・出来高・週足安値の3手がかりで総合判断し、迷った場合は見送るのが正解です。', false, 4),
(40, '全時間足（週足・日足・4時間足）がレンジの状態になった場合、適切な対応はどれですか？', 'トレードしない（「何もしない」が正解）', 'レンジの上下限でデイトレードを繰り返す', 'レンジ幅が狭くなるのを待ってからエントリーする', '4時間足以下で方向感を探す', 1, '全時間足がレンジの状態は方向感が全くなく、トレードすべきでない局面です。「何もしない」ことが正しい判断です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(41, '環境認識に組み込むべきファンダメンタルズ4要素として正しい組み合わせはどれですか？', '金利の方向、GDP成長率、貿易収支、住宅着工件数', '為替介入、財政収支、消費者信頼感、小売売上高', '金利の方向、インフレ動向、雇用統計、リスクオン/オフ', '政策金利、鉱工業生産指数、PMI、失業保険申請件数', 3, '環境認識に組み込むべきファンダ4要素は、金利の方向、インフレ動向（CPI）、雇用統計（NFP）、リスクオン/オフ（VIX・株式市場）です。これらはテクニカル分析の確度を測る基準になります。', false, 1),
(41, 'テクニカルは明確だがファンダメンタルズが中立・不明の場合、適切なアクションはどれですか？', 'エントリーせず、ファンダが明確になるまで待つ', '通常のポジションサイズで積極的にエントリーする', 'ファンダメンタルズ分析をやめてテクニカルのみで判断する', 'エントリー可だが、ポジションサイズを50〜70%に縮小する', 4, 'テクニカルが明確でもファンダが中立の場合は「中確度」と判定し、エントリーは可能ですがポジションサイズを50〜70%に縮小してリスクを抑えます。', false, 2),
(41, 'テクニカルとファンダメンタルズが逆方向のときの対応として正しいものはどれですか？', 'テクニカルを優先して通常サイズでエントリーする', 'ファンダメンタルズを優先して逆方向にエントリーする', 'ポジションサイズを30%に縮小すればエントリーしてよい', '原則エントリーせず、方向が一致するまで待つ', 4, 'テクニカルとファンダが逆方向の場合は「低確度」と判定し、原則としてエントリーしません。両方が一致するまで待つのが適切です。', false, 3),
(41, '週次ファンダチェックリストに含まれる項目として含まれないものはどれですか？', 'VIXの現在の水準確認', 'ドルインデックス（DXY）の方向確認', '主要中央銀行の直近のスタンス確認', '200週移動平均線の傾き確認', 4, '週次ファンダチェックリストは経済指標の日程、主要中央銀行のスタンス、VIX水準、主要株価指数の方向、DXYの方向、リスクオン/オフの記述の6項目です。200週MAの確認はテクニカル分析の環境認識チェックに含まれます。', false, 4),
(41, 'VIXが「15以下」の水準である場合、一般的な市場の状態として正しいものはどれですか？', '市場がパニック状態にあり、リスクオフが強まっている', 'トレンド転換の直前であり警戒が必要', 'ボラティリティが低く、リスクオンの穏やかな相場環境', '出来高が急増しており、ブレイクが近い', 3, 'VIXが15以下の場合は市場の恐怖感が低く、リスクオンの穏やかな環境を示しています。VIXは30以上でリスクオフの警戒レベル、20〜25で注意レベルとされます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(42, '実戦シナリオ分析のケーススタディで「週足上昇×日足押し目×4H反転」の教科書通りの押し目買いにおいて、損切りの適切な位置はどこですか？', '直近高値のすぐ上', '週足の200MAの下', 'フィボ61.8%の下', '4時間足の直近安値', 3, '5レイヤー全てが買いを支持する高確度の場面では、損切りはフィボ61.8%の下に設定します。この位置は修正波の限界ラインとして機能しやすいためです。', false, 1),
(42, '価格は上昇しているのに出来高が直近3週間で明らかに減少している状況は、何を示唆していますか？', '上昇トレンドがさらに加速する前兆', 'トレンドの「息切れ」のサインで、新規買いは見送りすべき', '大口が新たにポジションを構築している', 'レンジ入りする前に一旦調整が入る合図', 2, '価格上昇に出来高が伴わないのは、上昇への参加者が減っている証拠です。トレンドの「息切れ」サインとして、新規買いは見送り、既存ロングはトレーリングストップで保護するのが適切です。', false, 2),
(42, 'テクニカル的には完璧な押し目買いのセットアップが揃っているが、翌日にCPI発表を控えている場合、適切な対応はどれですか？', '発表前のエントリーは見送り、発表後にセットアップが崩れていなければエントリーする', 'CPI発表前にエントリーし、損切りを広めに設定する', 'セットアップが完璧ならCPI前にエントリーすべき', 'ポジションサイズを50%に縮小してエントリーする', 1, 'Tier 1指標の発表前は、結果次第で方向が急変するリスクがあります。「待つ勇気」を持ち、発表後にセットアップが維持されていればその時点でエントリーするのが適切です。', false, 3),
(42, '日足で直近の押し安値を割り込んだが、週足の200MAはまだ上向きの局面で取るべき対応として最も適切なものはどれですか？', '日足の押し安値割れは売り転換の確定信号なので即ショート', '「わからない」と認めて、週足の直近安値まで待って反発を見るか、別のペアを探す', '週足の200MAが上向きだから買いで問題ない', 'フィボナッチ78.6%までの deeper な調整を待って買い', 2, 'この局面は「最も判断が割れる」トレンド転換の見極め場面です。無理に答えを出さず、「わからない」と認めて、より明確な状況を待つか、別の通貨ペアを探すのが適切です。', false, 4),
(42, '週足レンジ×日足上昇のケースで、日足と4時間足だけを見て「買い継続」と判断した場合の落とし穴は何ですか？', '日足の上昇トレンドがフェイクである可能性が高い', '週足のレンジ上限までの残り距離が近く、上値が限定的であることを見落とす', '4時間足のトリガーが信頼できない', '出来高が常にレンジ相場では機能しない', 2, '下位足だけで判断すると、週足レンジの上限が目前に迫っていることを見落とします。上位足のレンジ上限に到達するまでの距離を考慮せずにエントリーすると、上値が限定的で不利なトレードになります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(43, '環境認識チェックシートの「週次チェック」で確認する5項目に含まれないものはどれですか？', '週足のトレンド方向', '週足のサイクル位置', 'ファンダメンタルズ概況', 'エントリーのトリガー判定', 4, '週次チェックは週足のトレンド方向、サイクル位置、主要水平線、ファンダメンタルズ概況、今週の戦略メモの5項目です。トリガー判定はエントリー前チェック（3分）で行う項目です。', false, 1),
(43, '環境認識チェックシートの「日次チェック」における5番目の項目は何ですか？', 'トレード判断（「本日は〇〇を狙う/やらない」の記述）', '日足のトレンド方向', '4時間足の状態', '本日の経済指標', 1, '日次チェックの5番目は「トレード判断」で、「本日は〇〇を狙う/やらない」を1行で記述します。これによりその日の方向性を事前に明確にします。', false, 2),
(43, 'エントリー前チェック（トリガー出現時）で確認する6項目のうち、リスクリワード比の最低基準はいくつ以上ですか？', '1:1以上', '1:2以上', '1:1.5以上', '1:3以上', 3, 'エントリー前チェックの5番目の項目は「リスクリワード比は最低1:1.5以上あるか」です。この基準を満たさないエントリーは見送ります。', false, 3),
(43, 'エントリー前チェックの6項目で、「1つでもNOがあるなら」取るべき行動はどれですか？', '見送り（エントリーしない）', 'ポジションサイズを50%に縮小してエントリーする', 'NOの項目が重要でなければエントリーしてよい', 'トリガーが強いパターンなら例外としてエントリーする', 1, '6つのチェックすべてに「YES」と答えられるときだけエントリーします。1つでも「NO」がある場合は見送りです。基準を一部緩めることはしません。', false, 4),
(43, '環境認識チェックシートにおいて、エントリー条件の事前設計として記述すべき内容として正しいものはどれですか？', '「今日の損益目標は〇〇円」', '「今週は買い中心でいく」', '「〇〇の水準で〇〇のトリガーが出たらエントリー」', '「ロットを〇〇枚にする」', 3, 'エントリー条件の事前設計では、「〇〇の水準で〇〇のトリガーが出たらエントリー」という具体的な条件を記述します。これにより、トリガー出現時に冷静に判断できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(44, 'プライスアクションのパターン（ピンバー・包み足など）を単体で判断した場合の勝率は、およそどの程度に留まるか？', '約65%', '約50%', '約30%', '約80%', 2, 'パターンは「結果」であり「原因」ではないため、ピンバーが出たから反転するという判断はコイン投げとほぼ同じ勝率になります。場所と出来高を加えることで65〜70%まで引き上げられます。', false, 1),
(44, '「場所×足×出来高」の三位一体フレームワークにおいて、3要素の優先順位として正しいものはどれか？', '足の形 ＞ 出来高 ＞ 場所', '出来高 ＞ 場所 ＞ 足の形', '場所 ＞ 出来高 ＞ 足の形', '場所 ＞ 足の形 ＞ 出来高', 3, 'どんなにきれいなピンバーでも意味のない場所に出ていれば無視すべきであり、場所が正しくても出来高が伴っていなければ信頼度が半減します。優先順位は場所が最も高く、次いで出来高、最後に足の形です。', false, 2),
(44, '三位一体フレームワークで「WHERE」に分類される判断材料として正しいものはどれか？', 'ヒゲの長さと実体の大きさ', '20日平均との出来高比較', '直前の足との出来高の変化', '重要なサポート/レジスタンスゾーン内とフィボナッチ合流', 4, '「WHERE（場所）」の判断材料は、重要なサポート/レジスタンスゾーン内、フィボナッチ合流ポイント、200MA付近、週足の水平線上など、パターンが「意味のある場所」に出ているかを確認するものです。', false, 3),
(44, '三位一体の判断基準を導入した結果として、多くのトレーダーに共通して起こる変化はどれか？', 'エントリー回数が増え、勝率も上がる', 'エントリー回数が減り、勝率も下がる', 'エントリー回数が増え、勝率は変わらない', 'エントリー回数が減り、勝率が上がる', 4, '3要素すべてが揃ったときだけエントリーする基準を守ることで、エントリー回数は減りますが、1回あたりの期待値は大幅に上がります。回数を減らして質を上げるのが三位一体の効果です。', false, 4),
(44, '三位一体フレームワークの「HOW MUCH（出来高）」で確認すべきこととして正しいものはどれか？', '20日平均との比較と直前の足との出来高の変化', '直近1時間のティック数', '前日の終値との乖離率', 'ボリンジャーバンドの幅', 1, '「HOW MUCH」の判断では、パターンに出来高が伴っているかを確認します。具体的には20日平均との比較と、直前の足との出来高の変化を見ることで、その動きに参加者が集まっているかを判断します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(45, 'プライスアクションが「効く」場所として含まれないものはどれか？', '重要なサポート/レジスタンスゾーンの端', 'フィボナッチ50%〜61.8%とゾーンが重なるゴールデンゾーン', '日足または週足の200MA付近', '直近5日間の移動平均線のクロスポイント', 4, 'プライスアクションが効く場所は、ゾーンの端、フィボナッチ合流ポイント、200MA付近、週足・日足の明確な水平線、フェイクブレイク後のゾーン内です。移動平均線のクロスポイントは場所の判定には含まれません。', false, 1),
(45, '重要水準をヒゲで一瞬割った後にゾーン内へ戻る動きが高確度とされる理由は何か？', 'トレンドが長く続いた後に反転するから', '出来高が必ず減少するから', 'レンジが必ずブレイクアウトするから', '大口がストップ狩りを完了し、本来の方向に動き出すタイミングだから', 4, '重要ラインを一瞬割った後にゾーン内に戻るフェイクブレイクは、大口がストップ狩りで個人の損切りを刈り取った後の動きです。大口がポジションを構築した直後であるため、高確度のエントリーポイントになります。', false, 2),
(45, 'プライスアクションが「効かない」場所に該当するものはどれか？', '週足の明確な水平線上', '日足の200MA付近', 'どのゾーンにも属していないチャートの「途中」', 'フィボナッチ61.8%合流ポイント', 3, 'ゾーンにもフィボナッチ水準にも属していない「何もない場所」に出たパターンは、ただのノイズです。意味のある場所でなければ、どんなにきれいな足の形でも機能しにくくなります。', false, 3),
(45, '上位足が下降トレンドの最中に、4時間足のサポートで買いのピンバーが出た場合の適切な判断は何か？', '上位足より下位足のシグナルを優先して買いエントリーする', '上位足のトレンドに逆行しているため見送る', 'ピンバーの形だけで即座にエントリーする', 'ロットを2倍にしてエントリーする', 2, '上位足のトレンドに逆行する場所で出たパターンは機能しにくいです。たとえ4時間足で反転しても、日足の戻り売りに飲まれるリスクが大きいため、基本的には見送ります。', false, 4),
(45, 'すでに3回到達済みのゾーン内でパターンが出た場合に見送るべき理由は何か？', '複数回到達したゾーンは注文が枯渇しており反転力が不足している可能性が高いから', 'ゾーンに到達するたびにパターンが小さくなるから', '3回目は必ずブレイクアウトするから', '出来高が必ず急増するから', 1, '同じゾーンに複数回到達している場合、その水準にあった注文はすでに消化されています。注文が枯渇しているゾーンでパターンが出ても、反転に必要な売買圧力が不足している可能性が高くなります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(46, '高品質なピンバーの特徴として正しいものはどれか？', 'ヒゲが実体の3倍以上で、反対側のヒゲがほぼない', '実体と同じ長さのヒゲがあり、反対側にもヒゲがある', '実体が足の中央付近に位置し、終値と始値がほぼ同じ', '前の足のレンジ内に完全に収まっている', 1, '高品質なピンバーは、ヒゲが実体の3倍以上あり、反対側のヒゲがほぼないか極めて短いことが条件です。また、前の足の安値（買いの場合）を一旦割ってから戻していると信頼度がさらに上がります。', false, 1),
(46, '高品質な包み足の特徴として正しいものはどれか？', '前の足とほぼ同じ大きさの実体で、ヒゲが長い', '前の足の2倍以上の実体を持ち、前の足が小さいコマ足か十字線である', '1時間足以下で確定し、前の足も大きな実体である', '前の足のレンジ内に収まる小さな実体である', 2, '高品質な包み足は、前の足の2倍以上の実体を持ち、前の足が小さなコマ足や十字線であることが理想です。「迷いの後の決着」という文脈があり、日足または4時間足で確定したものが信頼性が高いです。', false, 2),
(46, 'はらみ足のブレイク方向を判断するために使用すべき情報は何か？', 'はらみ足自身の実体の色（陽線か陰線か）', '上位足のトレンド方向と出来高', 'はらみ足の連続する本数だけ', 'はらみ足のヒゲの長さ', 2, 'はらみ足自体は方向を教えてくれないパターンです。ブレイク方向は上位足のトレンドと出来高で判断します。上位足が下降トレンドなら下方向のブレイクを待つというように、文脈から方向を予測します。', false, 3),
(46, '高品質なはらみ足の特徴として、「エネルギー蓄積」を示すのはどれか？', '大きな実体の母足が1本だけ出現する', '2〜3本連続してはらみ足が出現する', '小さな実体の母足が1本だけ出現する', '母足の後にすぐ大きな実体の足が出現する', 2, 'はらみ足が2〜3本連続して出現することは、売りと買いが激しくぶつかり合いながらエネルギーが蓄積されている状態を示します。1本だけでは一時的な停滞の可能性がありますが、連続するほど信頼度が上がります。', false, 4),
(46, 'ピンバーの「質」を判定する際、前の足との関係で高品質とされる条件は何か？', '前の足のレンジ内に完全に収まっていること', '前の足の安値（買いの場合）を一旦割ってから戻していること', '前の足と同じ方向に実体が伸びていること', '前の足より実体が大きいこと', 2, '前の足の安値（買いの場合）を一旦割ってから戻しているピンバーは、その水準で売り圧力を吸収した証拠です。レンジ内に収まっているだけのピンバーは、売り圧力をテストしていないため信頼度が下がります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(47, '強い反転足が出たのに出来高が減少している場合、最も適切な対応はどれか？', '見た目が強いので直ちにエントリーする', '出来高が減るのは反転の前兆なので逆方向にエントリーする', '出来高は関係ないので無視してエントリーする', 'エントリーは保留し、次の足を確認してから判断する', 4, '強い反転足に出来高が伴っていない場合、見た目は強くても参加者が少ない「見せかけの反転」の可能性があります。次の足で出来高を伴った続伸・続落を確認してから判断することで、フェイクを回避できます。', false, 1),
(47, 'ゾーン到達時に出来高が急増（20日平均の2倍以上）した場合、何を示唆しているか？', '大口がそのゾーンで注文を執行しており、反転の可能性が高い', '個人投資家がパニック売りしている', 'レンジが継続する可能性が高い', 'トレンドが加速してゾーンを突破する', 1, 'ゾーン到達時の出来高急増は、大口機関投資家がその水準で大量の注文を執行した証拠です。彼らの注文が価格を反転させる原動力になるため、反転の可能性が高まります。', false, 2),
(47, 'ブレイク時に出来高が急増しているかどうかを確認する重要性は何か？', '出来高が多いほど利益が大きくなるから', '出来高を伴わないブレイクはフェイクブレイクの可能性が高いから', '出来高が多いほど損切り幅が小さくなるから', '出来高はスプレッドに影響するから', 2, '本物のブレイクは出来高の急増を伴います。出来高が伴わないブレイクはフェイクブレイクの可能性が高く、すぐに元のレンジ内に戻ることが多いため、出来高で本物か見せかけかを見極めることが重要です。', false, 3),
(47, 'トレンド中に出来高が急増した直後に反転足が出た場合、何が起きている可能性が高いか？', 'トレンドの再加速', '新たなレンジの形成', '大口の利確または新規ポジション構築によるクライマックス（転換点）', '個人投資家の参入によるトレンド継続', 3, 'トレンド中の出来高急増＋反転足は、クライマックス（転換点）の可能性を示唆しています。大口が利確のためにポジションを解消しているか、逆方向に新規ポジションを構築しているサインです。', false, 4),
(47, '弱い足（コマ足）に出来高が増加している場合、どのような判断をすべきか？', '方向感がないため直ちにトレードしない', '出来高が増えているのでエントリーする', 'コマ足は無意味なので完全に無視する', '必ず上方向にブレイクする', 1, '弱い足に出来高が増加している場合は、売りと買いが激しくぶつかり合っている状態です。次の動きは大きい可能性がありますが、方向がまだ確定していないため、上位足のトレンドからブレイク方向を予測して待機します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(48, '複数の根拠が重なる重要なサポートゾーン内でフィボ61.8%と合流し、長い下ヒゲのピンバー（実体の4倍のヒゲ）が出現し、出来高が20日平均の2.3倍だった場合の適切な判断は何か？', '三位一体のうち2つ揃っているので、ロットを半分にしてエントリーする', '出来高が多すぎるため見送る', 'さらに1週間待ってから判断する', '三位一体すべて高評価なので、迷わずエントリーする', 4, '場所（重要なサポートゾーン＋フィボ合流）、足（実体の4倍のヒゲ・反対側ヒゲなし）、出来高（20日平均の2.3倍）の3要素すべてが最高評価の場合、三位一体の全条件が充足されており高確度のエントリーポイントです。', false, 1),
(48, '4時間足のサポートゾーンで教科書通りのピンバーが出たが、出来高が平均以下だった場合の適切な対応はどれか？', '場所と足は合格だが出来高が欠けているため、次の足で出来高を伴った続伸を確認してからエントリーする', 'ピンバーがきれいなので通常通りエントリーする', '出来高は無視してピンバーだけで判断する', '出来高が低いので逆方向にエントリーする', 1, '三位一体のうち場所と足は合格でも、出来高が欠けていると「見せかけの反転」のリスクがあります。次の足で出来高を伴った続伸を確認することで、フェイクを回避しつつエントリーの精度を上げられます。', false, 2),
(48, 'どのゾーンにも属していない「チャートの途中」にきれいなピンバーが出た場合の判断として正しいものはどれか？', 'ピンバーの形が完璧ならエントリーしてよい', '出来高が平均以上ならエントリーしてよい', '場所が不合格なので見送る', 'より下位の時間足で確認してからエントリーする', 3, '「何もない場所のきれいなパターン」は最も多いノイズです。三位一体の優先順位で最も高い「場所」が不合格の場合、足の形や出来高にかかわらず見送るのが正解です。', false, 3),
(48, 'デュクシ発生後の反転足で、ヒゲ突破時は出来高が低く、戻り時に出来高が急増していた場合、何を示しているか？', '本物のブレイクが起きた', '個人投資家が追随している', '大口のストップ狩り後の反転であり、高確度のエントリーポイント', 'レンジが継続する', 3, '出来高の「低→高」の変化は、突破時には大口以外の参加が少なく（フェイク）、戻り時に大口が本気で反転方向に注文を入れた証拠です。デュクシの裏付けとして信頼性の高いパターンです。', false, 4),
(48, '日足のレジスタンスゾーン上限付近で大きな陰線の後にはらみ足が3本連続し、出来高が徐々に減少している場合、どのような戦略が適切か？', '直ちに買いエントリーする', 'はらみ足の方向性が不明なため見送る', '上位足が下降トレンドなら下方向のブレイクを待ち、ブレイク足の出来高急増でエントリーする', 'レンジ取引として上限と下限で往復トレードする', 3, 'はらみ足3本連続＋出来高減少はエネルギー蓄積中のサインです。はらみ足自体は方向を示しませんが、上位足が下降トレンドであれば下方向のブレイクが想定され、ブレイク時に出来高が急増したらエントリーします。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(49, 'エントリー前の確認項目が全てクリアされた場合の適切なアクションはどれか？', '通常のポジションサイズでエントリーする', 'ロットを2倍にしてエントリーする', 'さらに2時間待ってから判断する', '見送って次のチャンスを待つ', 1, '全ての確認項目がクリアされた状態は最高確度のシグナルです。三位一体の全条件が揃っているため、通常のポジションサイズで積極的にエントリーします。ロットを増やすのは連勝バイアスのサインなので避けます。', false, 1),
(49, 'エントリー前チェックで確認項目の多くが満たされなかった場合の適切な判断は何か？', 'ロットを50%に縮小してエントリーする', '確度不足として見送り、次のチャンスを待つ', '確認項目の半分以上が揃っているのでエントリーする', '満たされた項目だけを条件にエントリーする', 2, '確認項目が多く揃わない場合は確度不足と判定します。無理にエントリーするより見送って次の高確度のチャンスを待つ方が、長期的な損益を改善します。条件が高確度で揃う場面だけを狙うのが基準です。', false, 2),
(49, '三位一体チェックシートの項目に「上位足のトレンド方向と一致しているか」が含まれる理由は何か？', '上位足の分析だけで勝てるから', '上位足のトレンドは常に正しいから', '下位足のパターンは意味がないから', '上位足のトレンドに逆らうパターンは機能しにくいから', 4, '日足が下降トレンド中に4時間足のサポートで買いのピンバーが出ても、上位足の戻り売りに飲まれるリスクが大きいです。上位足と同方向のパターンだけを拾うことで、順張りの確度を高められます。', false, 3),
(49, '三位一体チェックシートを使い始めた結果として報告されている変化はどれか？', '月間トレード回数が増加し、勝率も上昇した', '月間トレード回数が減少し、勝率が大幅に低下した', '月間トレード回数が減少したが、勝率と月間損益が改善した', 'トレード回数と勝率は変わらず、損益だけが改善した', 3, 'チェックシートの基準を満たす場面だけに絞ることで、月間のトレード回数は大幅に減少しますが、エントリーの質が上がるため勝率と月間損益が改善します。「たくさんトレードすること」と「たくさん稼ぐこと」は別物です。', false, 4),
(49, '三位一体チェックシートにおいて「重要経済指標の発表30分前ではないか？」という項目が含まれている理由は何か？', '指標結果で全てがリセットされる可能性があり、パターンの信頼度が極端に下がるから', '指標発表前はスプレッドが広がりエントリーに不利だから', '指標発表前は必ずトレンドが発生するから', '指標発表前は出来高が必ず減少するから', 1, '経済指標の発表結果によって相場環境が一変する可能性があります。どんなに三位一体が揃っていても、指標発表直前は結果次第でパターンが無効になるリスクが高いため、エントリーを避けるべきです。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(50, '大口投資家がダマシを仕掛ける構造的理由として最も適切なものはどれか？', '個人投資家の注目を集めて取引量を増やすため', '大きな注文を一度に執行すると価格が動いてしまうため、損切り注文を「燃料」として流動性を確保するため', 'テクニカル指標を意図的に歪めてチャートパターンを崩すため', '中央銀行の政策判断に影響を与えるため', 2, '大口は何十億円もの注文を一度に執行すると自分の注文で価格が動いてしまうため、個人投資家の損切り注文を「天然の流動性プール」として利用します。', false, 1),
(50, 'ダマシのパターンが過去も現在も未来も繰り返される理由として正しい組み合わせはどれか？', '大口の構造的制約、個人投資家の心理的癖、教科書通りのトレードを逆手に取れること', 'アルゴリズム取引の普及、高頻度取引の増加、投資信託の拡大', 'テクニカル分析の進化、SNSの普及、グローバル化の進展', '中央銀行の政策変更、通貨制度の変更、取引所の規制変更', 1, '大口の大きな注文は分散執行の必要があり、個人は直近の高値・安値のすぐ外側に損切りを置く傾向があり、「サポート割れで売り」等の定石を逆手に取れるため、この構造は永遠に変わりません。', false, 2),
(50, 'ストップ狩り（Stop Hunt）の際に大口が狙う場所として、最も標準的な水準はどれか？', '移動平均線の交差ポイント', 'ボリンジャーバンドの中央線', '直近の明確な高値または安値のすぐ外側', 'フィボナッチ23.6%リトレースメント', 3, '直近の明確な高値・安値のすぐ外側には多くの投資家の損切り注文が集中しており、大口にとって最も「狩りやすい」流動性プールになります。', false, 3),
(50, 'ベアトラップ（Bear Trap）の説明として正しいものはどれか？', 'サポートを一瞬割り込んで売りを誘ってから急反転し、その売り注文で買い集める動き', '上位足のトレンドに逆行して下落を加速させる動き', '出来高を伴わないまま支持線を徐々に下抜けていく動き', 'レジスタンスを一瞬超えてから急反落し、買いを誘ってから売り抜ける動き', 1, 'ベアトラップはサポート割れで個人に「下落開始」と思わせて売らせ、その売り注文を燃料に買いポジションを構築する大口の仕掛けです。名前に「ベア（弱気）」とありますが、実際は大口が買いを入れる局面です。', false, 4),
(50, 'ストップ狩りか本物のブレイクかを見極める際、最も信頼度が高いシグナルの組み合わせはどれか？', 'ボリンジャーバンドの拡大＋RSIの乖離', '実体での突破＋直近3本のローソク足が同方向', 'ヒゲでの突破＋突破時の出来高が少ない', '出来高の急増＋上位足のトレンドとの一致', 3, 'ヒゲだけで高値・安値を超え、実体は元のレンジ内にあり、突破時の出来高が少ない場合、ストップ狩りの可能性が高いです。本物のブレイクは出来高の急増（20日平均の1.5倍以上）を伴います。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(51, 'リアルタイムでストップ狩りを検知する5つの特徴のうち、「即座の反転」が意味するものはどれか？', '突破後、1〜3本の足以内に元の方向に戻る', '突破後、新しいレンジを形成してから戻る', '突破後、損切りラインに向かって一気に進む', '突破後、10本以上のローソク足をかけてゆっくり戻る', 1, 'ストップ狩りでは、損切りを刈り取った直後に本来の方向に戻るため、1〜3本の足以内に反転が起きます。本物のブレイクは突破後も方向を維持する点が決定的に異なります。', false, 1),
(51, 'ストップ狩りが起きやすい時間帯として挙げられるのは、日本時間でどの時間帯か？', '12:00〜13:00（昼休み）', '3:00〜5:00（欧米市場クローズ直後）', '16:00前後と22:00前後（ロンドンオープン・NYオープン）', '6:00〜9:00（東京オープン直後）', 3, 'ロンドンオープン（16:00 JST前後）とNYオープン（22:00 JST前後）は流動性が急激に変化する時間帯で、大口のストップ狩りが起きやすくなります。', false, 2),
(51, 'ストップ狩りの判定基準で「5つのうち3つ以上該当＝ストップ狩りの可能性大」とされるが、これはなぜ全て該当を求めないのか？', '実戦では全ての条件が同時に揃うことは稀であり、3つ以上で十分に高い確度が得られるため', '条件が多すぎると判断が遅くなりエントリーチャンスを逃すため', '大口は常に3つの条件だけを満たすように仕掛けるため', '5つ全て該当することは統計的にあり得ないため', 1, 'リアルタイムの相場で5つの条件が全て同時に揃うことは稀ですが、3つ以上揃えば「ストップ狩りの可能性が高い」と実用的に判断できます。特にヒゲ突破＋出来高不足の組み合わせが信頼度を高めます。', false, 3),
(51, '毎朝の環境認識でストップ狩りが起きそうな場所を事前にマークする意味として最も適切なものはどれか？', 'マークした場所で必ずストップ狩りが起きることを確認するため', '大口の注文の正確な規模を推定するため', 'その場所でのみエントリーを許可するため', '構えていれば狩りに引っかかるのではなく、狩りの後の反転を狙えるため', 4, '事前に「狩り場」をマークしておけば、価格が接近したときに「狩りが来るかも」と構えられます。準備があることで、狩りの犠牲になるのではなく、狩りの後の反転を利益に変えられます。', false, 4),
(51, 'ストップ狩りが起きやすい場所として「キリ番のすぐ外側」が挙げられる理由は何か？', 'キリ番は中央銀行が介入する水準だから', 'キリ番では自動売買システムが停止するため', 'キリ番は過去の高値・安値と必ず一致するため', '多くのトレーダーがキリ番の数pips外側に損切りを置く傾向があるため', 4, '100円、145円などのキリ番は多くのトレーダーが意識する水準であり、その数pips外側に損切りを集める傾向があります。大口はその集まった損切り注文を狙ってヒゲで一瞬だけ突き抜けます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(52, '重要な水準をヒゲで一瞬割った後、反転の足が確定した瞬間にエントリーする手法の最も重要な特徴はどれか？', '重要な水準を実体で割り込んだ後に、新しい安値を更新してからエントリーする', 'ストップ狩り後の反転タイミングに乗るため、ヒゲで一瞬割った後の反転足確定を待つ', 'レンジの中央付近で価格が反転した瞬間にエントリーする', '出来高が急増した瞬間に順張りでエントリーする', 2, 'ストップ狩り後の逆張りエントリーは、大口がポジション構築を完了した直後のタイミングに乗る手法。重要水準をヒゲで一瞬割った後の反転足の確定を待つことで、フェイクと本物の反転を区別できます。', false, 1),
(52, 'ヒゲで重要水準を割った後に反転の足が確定する前にエントリーしてはならない理由は何か？', 'ヒゲで戻しただけでは本物の反転かさらなるフェイクか判別できず、二重ダマシのリスクがあるから', '約定価格がスリップする可能性が高いから', 'スプレッドが広がってコストが高くなるから', '大口の注文がまだ完了していない可能性があるから', 1, 'ヒゲで戻しただけでは一時的な反動なのか本物の反転なのか判断できません。反転方向のローソク足（ピンバーや包み足）が「確定」して初めて、反転の意思が確認できます。', false, 2),
(52, 'ストップ狩り後に逆張りエントリーする手法の最大のメリットとして正しいものはどれか？', '常に大きなポジションサイズでエントリーできる', 'ストップ狩りのヒゲの先端が損切り位置の目安となるため、損切り幅を小さく抑えてRR比を有利にできる', 'エントリー後の損切りがほぼ不要になる', 'どの時間軸でも同じ精度で機能する', 2, 'ストップ狩りのヒゲの先端が「これ以上は行かなかった」ことを証明しているため、その少し外側に損切りを置けばよく、損切り幅が非常に小さくなります。結果としてRR比が2:1、3:1と有利になりやすいです。', false, 3),
(52, 'ストップ狩り後の逆張りエントリーで損切りを「ヒゲの先端の外側」に設定する合理的な理由は何か？', 'その幅が一般的なスプレッドの幅だから', 'ヒゲの先端が「大口が到達させた最大値」であり、そこを超えたら本物のブレイクの可能性が高いから', '大口は常に一定幅刻みで注文を出すから', '統計的に最も損切りされにくい幅だから', 2, 'ヒゲの先端は大口が到達させた最大値を示しており、そこを超えた場合はストップ狩りではなく本物のブレイクである可能性が高くなります。そのため、ヒゲ先端の少し外側が合理的な損切り位置です。', false, 4),
(52, 'ストップ狩りの後の反転を狙う際、価格が重要水準に接近したことを確実に検知するための方法として最も有効なものはどれか？', 'その水準への指値注文を事前に入れる', '出来高の監視だけに集中する', '事前にマークした水準の手前にアラートを設定し、接近時に落ち着いて観察する体制を整える', '移動平均線のクロスアラートを使う', 3, '事前にアラートを設定しておくことで、価格が狩り場に接近したことを逃さず検知できます。リアルタイムで常に監視しなくてもよく、アラートが鳴ってから落ち着いて突破→反転の動きを確認できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(53, 'ベアトラップを逆利用して買いエントリーする際の条件として正しいものはどれか？', '割り込み時の出来高が多く、戻り時の出来高が少ない', '上位足のトレンドが下降方向で、逆張りで入る', 'サポートをヒゲで割り込んだ後、終値でサポートゾーン内に戻り、戻り時の出来高が割り込み時より大きい', 'サポートを実体で明確に下抜けてから反転を待つ', 3, 'ベアトラップ逆利用の条件は、ヒゲで割り込み後に終値でサポートゾーン内に戻っていること、割り込み時の出来高が少なく（フェイクの証拠）、戻り時の出来高が多い（反転の本気度）ことなどが揃うことで高確度になります。', false, 1),
(53, 'ブルトラップ（Bull Trap）において、大口が仕掛ける狙いは何か？', 'レジスタンスを超えて個人に「ブレイクした」と思わせて買わせ、その買い注文で売り抜けること', 'サポートを割って売りを誘い、その売り注文で買い集めること', '安値を更新してパニック売りを誘発すること', '出来高を急増させてトレンドを加速させること', 1, 'ブルトラップはレジスタンスを一瞬超えて「ブレイク」と錯覚させ、個人に買わせた後に急反落します。大口はその買い注文を燃料に売りポジションを構築・利確します。', false, 2),
(53, '二重ダマシ（ストップ狩り→反転→もう一度割り込み）に対する対策として正しいものはどれか？', '1回目の反転時に大きなロットで一気に利益を取る', '2回目の割り込み後にエントリーすればより確実', '損切りは1回目のヒゲの先端の外側に置き、1回のリスクを資金の1%以内に抑える', '二重ダマシは予測可能なので事前に回避できる', 3, '二重ダマシは完全に避けることはできませんが、損切りを1回目のヒゲ先端の外側に置き、1回のリスクを資金の1%以内に抑えることで、損失を管理可能な範囲に収められます。', false, 3),
(53, 'トラップの逆利用エントリーで「5つの条件のうち4つ以上該当」を基準とする理由として最も適切なものはどれか？', '3つ以下では大口の仕掛けではないことが確定するから', '条件を満たす数が多いほど、その動きが大口の仕掛けである確度が高まり、エントリーの根拠が強くなるから', '条件が多いほどエントリー回数を増やせるから', '全ての条件が揃うまで待つとチャンスを逃すから', 2, 'ヒゲでの突破、出来高の不一致、即座の反転、上位足との一致などの条件が多く揃うほど、ストップ狩りである確度が高まります。4つ以上で高確度のエントリーとして扱います。', false, 4),
(53, 'ベアトラップ逆利用とブルトラップ逆利用の共通点として正しいものはどれか？', 'どちらも出来高の「低→高」の変化と上位足のトレンドとの一致を確認する点が共通している', 'どちらも逆張りで入る点が同じである', 'どちらも日足レベルでしか機能しない', 'どちらも分割利確が必須である', 1, '両トラップとも、フェイク時の出来高が少なく反転時の出来高が大きいこと、上位足のトレンド方向と反転方向が一致していることが条件に入っており、この「出来高の質的変化」と「上位足との整合」が共通の判断基準です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(54, 'ロンドンオープン直後にレンジ下限を一瞬割り込み、直後に急反転して上昇したケースの分析として最も適切なものはどれか？', 'ロンドンの traders が意図的にレンジを拡大しようとした', '東京時間のレンジ下限にアジア勢の損切りが集中しており、ロンドン勢がそれを刈ってから本来の方向に動いた', '経済指標の発表がたまたま重なっただけの偶然', 'アジア市場の流動性が低すぎてスリップしただけ', 2, '東京時間に形成されたレンジの下限にはアジア勢の損切り注文が集中しています。ロンドンオープン時に大口がそれを刈り取ってから上昇に転じるのは、典型的なロンドンフェイクアウトのパターンです。', false, 1),
(54, '3週間のレンジ上限を日足のヒゲで一瞬超えた翌日に大陰線で急落したケースで、大口が狙ったものは何か？', 'レンジ中央での流動性確保', 'レンジ上限の外側に蓄積した「ブレイクアウトの買い注文」と「ショートの損切り注文」の一掃', '下位足のテクニカルパターンの破壊', '中央銀行の政策への影響', 2, '3週間のレンジが続くと、上限のすぐ外側にブレイクアウトを狙う買い注文と、ショートの損切り注文が大量に蓄積します。大口はこれを一瞬のヒゲで一掃し、その買い注文を燃料に売りに転じます。', false, 2),
(54, 'FOMC発表直後に上下に大きく振れた後、発表前のレンジ内に戻ったケースの正しい対応はどれか？', '初動の方向にすぐ乗る', '反対方向にすぐエントリーする', '発表後1〜2時間は一切手を出さず、値動きが落ち着いてから方向を確認する', '出来高が多い方の方向に乗る', 3, 'FOMC直後は流動性が一時的に薄くなり、大口のストップ狩りが起きやすく、上にも下にもヒゲを出してから方向が決まるパターンが多いため、1〜2時間は手を出さずに落ち着きを待つのが正解です。', false, 3),
(54, 'フェイクブレイク逆張りエントリーが10回中7回成功し3回損切りになっても、トータルでプラスになる条件は何か？', '勝率が70%以上あれば RR比に関係なくプラスになる', 'RR比が1:2以上確保できていれば、損失額より利益額が上回るため', '1回の損失額を利益額の半分以下に抑えること', '全ての勝ちトレードで利確目標を2倍に引き上げること', 2, 'RR比1:2の場合、1回の勝ちでリスクの2倍の利益を得られます。7回勝てば14単位の利益、3回負けても3単位の損失で、トータルで+11単位になります。ストップ狩り後の逆張りエントリーは損切り幅が小さいためRR比1:2以上を確保しやすいです。', false, 4),
(54, '二重ダマシで損切りになった後、「2回目にもう一度エントリーしたくなる」衝動を抑えるために有効な方法はどれか？', '直ちに相反する方向にエントリーする', '一時停止して自分の感情に気づくことでリベンジを防止する', 'ロットを倍にして損失を取り返す', 'チャートを閉じて翌週まで見ない', 2, '二重ダマシで損切り後の再エントリー衝動は典型的なリベンジ心理です。一時的にチャートから離れて感情に気づき、1回の損失が資金の1%以内に抑えられていればダメージは限定的だと認識することで冷静さを取り戻せます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(55, '朝のルーティンで「ストップ狩りポイントのマーキング」を行う際、マークすべき場所として含まれないものはどれか？', '直近のスイングハイ/ローのすぐ外側', 'レンジの上限/下限のすぐ外側', 'キリ番のすぐ外側', '移動平均線の現在の値位置', 4, 'ストップ狩りが起きやすい場所は、直近のスイングハイ/ロー、レンジの上限/下限、キリ番、フィボナッチ水準のすぐ外側など、損切り注文が集中しやすい場所です。移動平均線の現在値はストップ狩りのターゲットではありません。', false, 1),
(55, 'リアルタイムのストップ狩り検知チェックで「5つ中2つ以下YES」の場合の判定として正しいものはどれか？', 'ロットを50%に縮小してエントリー検討', '高確度のフェイクブレイク逆張りエントリーとして実行する', '損切り幅を広げて様子を見る', 'ストップ狩りではなく本物のブレイクの可能性があるため見送る', 4, '5つのチェック項目で2つ以下しか該当しない場合、その動きはストップ狩りではなく本物のブレイクである可能性が高いです。この場合はフェイクブレイク逆張りエントリーではなく見送りが正しい判断です。', false, 2),
(55, 'ストップ狩り検知時に確認する「ヒゲだけで突破し、終値は元のレンジ内か」というチェック項目が意味するものはどれか？', '実体での突破は本物のブレイクである可能性が高い', 'ヒゲでの突破はフェイクであり、終値が戻っているなら実体としての支持・抵抗ラインは維持されている', 'ヒゲと実体の両方で突破していれば信頼度が高まる', '終値の位置は関係なく、ヒゲの長さだけで判断すべき', 2, '終値が元のレンジ内にあるということは、実体としてのラインは維持されており、ヒゲだけが一瞬突き抜けたに過ぎません。これは損切りを刈るためのフェイク突破の典型的な特徴です。', false, 3),
(55, '大口の仕掛けに対する認識を「恐れる対象」から「利益の源泉」に変えるために最も重要な考え方はどれか？', '大口の仕掛けを逆利用するのではなく、大口と同じ方向に乗ること', '全てのダマシを正確に見抜こうとすること', '常に大口より早くエントリーすること', '大口が使用するアルゴリズムを解読すること', 1, '大口のダマシは「大口に勝つ」のではなく「大口と同じ方向に乗る」ためのシグナルです。ストップ狩りが起きた直後は大口がポジションを構築したばかりのタイミングであり、その方向に付くことが利益に繋がります。', false, 4),
(55, '朝のルーティンで「どちら方向の狩りが起きそうか」を予測する際に最も重視すべき情報は何か？', 'SNSでのセンチメントの強さ', '出来高の直近3日間の推移', '前日のエントリーの損益結果', '上位足のトレンド方向と逆の方向に狩りが起きやすい傾向', 4, 'ストップ狩りは上位足のトレンド方向と逆の方向に起きやすい傾向があります。上昇トレンド中なら下方向への狩り（ベアトラップ）が起きやすく、その後に上昇する流れに乗れるため、上位足の方向性が予測の重要な手がかりになります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(56, 'トレードにおいて、単一のシナリオだけで相場に臨むことの最も大きな欠点は何か。', '相場がシナリオ通りに動かなかった場合、感情的な判断に陥りやすくなる', 'エントリーのタイミングが遅くなり、利益を取り逃がしやすくなる', '分析に使える時間が短くなり、環境認識が不正確になる', 'ポジションサイズの計算が複雑になり、リスク管理が崩れやすくなる', 1, '単一シナリオは想定通りの展開でのみ機能し、外れた場合は焦りから感情的な判断を引き起こす。複数シナリオを用意しておけば、「想定内の別ケース」として冷静に対応できる。', false, 1),
(56, 'プロトレーダーが常に複数のシナリオを用意する理由として最も適切なものはどれか。', 'エントリー回数を増やして利益の機会を最大化するため', 'テクニカル指標の信頼性を補うため', '一つのシナリオの損切り幅を小さくするため', '相場には常に「AかBか」の分岐点が存在するため', 4, '相場には常に複数の展開が可能であり、事前にどちらになるかは分からない。だからこそ両方の分岐に対する「if-then」を準備するのが複数シナリオの本質である。', false, 2),
(56, 'シナリオの中に「はず」という言葉が入ったとき、それは何を意味するか。', '分析ではなく願望に変わっているサイン', '過去の類似パターンからの統計的推論', '環境認識のレイヤーが十分に統合されている状態', '分析が確率的に十分に裏付けられている状態', 1, 'シナリオに「はず」が入った瞬間、それは客観的分析から主観的な願望へと変質している。メタ認知で「分析しているのか、願望を持っているのか」を常に確認する必要がある。', false, 3),
(56, '複数シナリオ（メイン＋サブ）を用意した場合と単一シナリオの場合を比較したとき、準備時間はどう変わるか。', '約30分追加で必要になる', '約5分程度追加で必要になる', '準備時間は変わらない', '環境認識が不要になる分、むしろ短くなる', 2, 'メイン＋サブの設計は単一シナリオに比べて+5分程度の追加で済むが、その5分が日中の迷いを排除し、感情的な判断を防ぐ効果は非常に大きい。', false, 4),
(56, '「相場はあなたのシナリオ通りに動く義務がない」という認識がもたらす最も重要な実践的意味は何か。', 'どのような値動きが来ても対応できる準備をしておくべきということ', 'シナリオ構築そのものに意味がないということ', 'エントリー後に損切りラインを広げてもよいということ', '直感や経験に基づく判断の方がシナリオより信頼できるということ', 1, '相場は予言通りに動かない前提に立つからこそ、すべての分岐に対する準備（メイン＋サブ＋無効化条件）が意味を持つ。シナリオは「予言」ではなく「準備」である。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(57, 'メインシナリオとはどのようなものか。', '過去に最も利益を出したトレードパターンに基づくシナリオ', 'テクニカル分析のみに基づき、ファンダメンタルズを排除したシナリオ', '現在の環境認識から「最も確度が高い」と判断したシナリオ', 'リスクリワード比が最も有利になる方向のシナリオ', 3, 'メインシナリオは、上位足のトレンド方向と一致し、ゾーンの合流もあり、ファンダメンタルズとも整合している「最も確度が高い」シナリオとして定義される。', false, 1),
(57, 'サブシナリオを設計する上で最も重要な原則は何か。', 'メインシナリオと同じゾーンで逆方向のエントリーを狙うこと', 'メインシナリオが崩れてから慌てて考えること', 'メインシナリオと同時に設計しておくこと', '常に売り方向に設定しておくこと', 3, 'サブシナリオは「メインが崩れてから考える」のではなく「メインと同時に設計しておく」ことが原則。事前に設計しておかないと、リアルタイムの感情が判断を歪める。', false, 2),
(57, 'メイン＋サブの設計テンプレートにおいて、「無効化条件」とは何を定義するものか。', 'エントリー後に損切りラインを変更する条件', 'ポジションサイズを半分にする条件', '利確目標を早める条件', 'メインもサブも成立しない状況を定義し、完全にノートレードにする条件', 4, '無効化条件は「メインもサブも成立しない状況」を事前に定義するもの。この条件に達したら全シナリオを破棄し、その通貨ペアから離れることが求められる。', false, 3),
(57, '日足上昇トレンド中に4時間足のサポートゾーンに向けて調整が進んでいる場面で、メインシナリオが「買い」のとき、サブシナリオとして適切な設計はどれか。', '4H足の終値でサポートゾーンの下限を下抜けた場合、より深い位置の新しいサポートゾーンで改めて買いを検討する', '日足のトレンドが上昇なのでサブシナリオは不要', 'レンジ上限まで戻ったら利確する', '同じサポートゾーンで売りエントリーを狙う', 1, 'サブシナリオは「メインのサポートゾーンが機能しなかった場合」の代替を定義する。より深い位置に別のサポートゾーンを設定し、そこでトリガーを待つか、ノートレードにするのが適切な設計。', false, 4),
(57, 'サブシナリオの発動条件として、最も客観的で感情が介入しにくい書き方はどれか。', '「チャートの雰囲気が変わったら発動」', '「下落の勢いが強くなったと感じたら発動」', '「出来高がなんとなく増えたら発動」', '「〇〇の水準を4H足の終値で割り込んだ場合に発動」', 4, '切り替え条件は「〇〇の水準を〇〇足の終値で割ったら」といった客観的・定量的な表現で定義する必要がある。主観的な表現は感情による判断の余地を残してしまう。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(58, 'シナリオの切り替え条件を「リアルタイムで判断」するときに最も起こりやすい問題は何か。', 'エントリーのタイミングが遅れること', 'スプレッドが広がってエントリーしにくくなること', '感情が介入し、「もう少し待てばメインが復活するかも」と損失を拡大すること', '出来高が減少して判断材料が不足すること', 3, 'リアルタイムでの判断には必ず感情が介入し、「かも」という希望が損失を拡大させる。だからこそ切り替え条件は事前に定義し、機械的に実行する必要がある。', false, 1),
(58, 'シナリオの切り替えトリガーのうち、VIXが30を超えて急上昇した場合の対応として正しいものはどれか。', '通常通りメインシナリオを実行する', 'サブシナリオに切り替えて逆方向にエントリーする', '全シナリオを一時停止し、VIXが落ち着くまで待機する', 'ロットを半分にしてエントリーする', 3, 'VIXが30超で急上昇した場合、市場環境が急変しており通常のテクニカルが効きにくくなる。全シナリオを一時停止し、落ち着くまで待機するのが正しい対応。', false, 2),
(58, '切り替えトリガーのうち、「価格がサポートゾーンを終値で下抜けた」場合のアクションとして正しいものはどれか。', '損切りラインを広げてポジションを維持する', '即座に逆方向にエントリーする', 'エントリー条件を見直してロットを増やす', 'サブシナリオのサポートゾーン（より深い位置）に移行する', 4, 'メインのサポートゾーンが終値で下抜けた＝ゾーンが機能しなかったことを意味する。ここではメインを破棄し、サブシナリオで設定したより深い位置のサポートゾーンに移行する。', false, 3),
(58, '「計画的な切り替え」と「リベンジトレード」の最も本質的な違いは何か。', 'エントリーする方向が同じか逆かの違い', '事前に定義した条件に基づいているか、損切り後の感情に基づいているかの違い', 'ポジションサイズの大小の違い', '使用する時間足の違い', 2, '切り替えは事前に定義した条件に基づく計画的な方向転換であり、リベンジは損切り後の感情的な方向転換。見た目は似ていても本質は全く異なる。書き出していない条件で方向を変えたらリベンジの可能性が高い。', false, 4),
(58, 'ゾーンに到達したがトリガーが出ないまま価格が反対方向に動いた場合、適切な対応はどれか。', 'ゾーンに到達した事実だけでエントリーする', '即座に逆方向にエントリーする', 'トリガーなしの見送りに切り替え、次のゾーンまで待機する', '損切りラインを広げて待機を続ける', 3, 'ゾーン到達だけでトリガーが出ない場合は「待つ→見送り」に切り替える。トリガーなしにエントリーすれば確度の低いトレードになる。次の機会を待つのが正しい判断。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(59, 'If-Then-Elseの条件分岐構造をトレードに応用する最大のメリットは何か。', '「想定外」がなくなり、どんな値動きにも冷静に対応できること', 'エントリー回数を最大化できること', 'テクニカル指標の種類を減らせること', '利確目標を自動的に計算できること', 1, 'If-Then-Elseで全ての分岐を事前に定義しておけば、どんな値動きが来ても「これはIf-Aのケースだな」「これはElseのケースだな」と冷静に対応でき、「想定外」がなくなる。', false, 1),
(59, '3段階のIf-Then-Elseにおいて、「If D：サブシナリオのサポートゾーンも下抜けた」に該当した場合の正しいアクションはどれか。', '新しいゾーンを探して第3のシナリオを作る', 'ロットを縮小してもう一度エントリーを試みる', '損切りラインを大幅に広げて待機する', '全シナリオを無効化し、その通貨ペアは当日トレードしない', 4, 'メインもサブも機能しなかった場合、全シナリオを無効化する。無理に新しいシナリオを作ろうとすると焦りからバイアスのかかった分析になる。その日は休むのが最も賢い判断。', false, 2),
(59, '「Else：上記のいずれにも該当しない状態」に該当した場合、どのようなアクションが適切か。', 'チャートを閉じてトレードを完全にやめる', 'アラートを設定して待つ——まだ何も起きていない状態', '直感でエントリーする', 'ロットを増やしてエントリーの機会を逃さない', 2, 'どのIf条件にも該当しない＝まだ何も起きていない状態。アラートを設定して待機するのが適切。分岐図のElseは「待つ」という立派な判断を明示的に定義している。', false, 3),
(59, 'If-Then-Elseの分岐図をノートに書くべき理由として最も重要なものはどれか。', '日中の判断を全て「計画の実行」に変え、地図なしで歩く状態を避けるため', 'SNSで共有して他者の意見を聞くため', '過去のトレード記録として保存するため', 'エントリーのタイミングを秒単位で指定するため', 1, '分岐図をノートに書くことで、日中のすべての判断が「計画の実行」になる。分岐図がない状態は「地図なしで知らない街を歩く」のと同じであり、感情に流されやすくなる。', false, 4),
(59, '「If B：価格がサポートゾーンに到達したが、トリガーが出ない」の場合、見送りに切り替える具体的な目安はどれか。', '10本のローソク足が経過してもトリガーが出ない場合', '2本のローソク足以内にトリガーが出ない場合', '1時間経ってもトリガーが出ない場合', '出来高が減少し始めた場合', 2, 'ゾーン到達後に2本のローソク足以内にトリガーが出なければ見送りに切り替える。いつまでも待ち続けると「待つ」ことが「執着」に変わるため、明確な期限を設定する。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(60, 'ケーススタディで、メインシナリオ通りの展開（If A）になった場合の対応として正しいものはどれか。', '利確目標を延ばしてさらに利益を狙う', 'メインシナリオの利確目標を手前に変更して確実に利益を確保する', 'メインシナリオ通りにエントリーし、計画通りの損切り・利確を実行する', 'サブシナリオも同時にエントリーする', 3, 'If A（価格がZBに到達＋トリガーが出た）は最も理想的な展開。メインシナリオを計画通りに実行し、損切り・利確も事前に設計した通りに処理する。', false, 1),
(60, 'ケーススタディで、サポートゾーンに到達したがトリガーが出ずに価格が反対方向に動いた（If B）場合、やってはいけないことはどれか。', 'トリガーなしにゾーン到達だけでエントリーすること', '次のゾーンまで待機すること', 'アラートを再設定すること', '見送り判断を下すこと', 1, 'If Bの場合、「トリガーなしにゾーン到達だけでエントリー」してはならない。三位一体の確認（場所×足×出来高）を満たさないエントリーは確度が低く、損失の原因になる。', false, 2),
(60, 'メインのサポートゾーンを下抜け→サブに移行（If C）したケーススタディにおいて、サブシナリオでトリガーが出なかった場合の正しい対応はどれか。', 'サブシナリオの損切りラインを広げる', 'ノートレードにする', '別の時間足でトリガーを探す', '逆方向にエントリーする', 2, 'サブに移行した後もトリガーが出なければノートレードにする。無理にエントリーを探すと感情が介入し、判断の質が下がる。「やらない」という選択も立派なトレード判断。', false, 3),
(60, '全シナリオが無効化（If D）された場合のケーススタディで、「撤退」が賢い判断とされる理由は何か。', '損失が確定するので税金対策になるから', '全シナリオが無効化されることは通常1年に1回しか起こらないから', '無理に新しいシナリオを作ると焦りからバイアスのかかった分析になるから', '撤退すれば必ず翌日に大きな利益のチャンスが来るから', 3, '全シナリオが無効化されたときに無理に新しいシナリオを作ろうとすると、焦りから確証バイアス等が働き、質の低い分析になりやすい。その日は休んで翌日に冷静に再スタートするのが最善。', false, 4),
(60, 'FOMCの結果が想定と大きく異なり、市場が急変したケーススタディでの対応として正しいものはどれか。', '直後にメインシナリオを修正して即座にエントリーする', '値動きが落ち着く（1〜2時間後）まで待ち、環境認識を再構築してから判断する', 'FOMCの結果に関わらず、もとのシナリオをそのまま実行する', '損切りラインを外してポジションを維持する', 2, '重要指標でファンダメンタルズの前提が変わった場合、全シナリオを一時停止し、値動きが落ち着いてから環境認識を再構築する。慌てて飛び乗るのは最も危険な対応である。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(61, 'シナリオ管理シートにおいて、メインシナリオとサブシナリオはどのタイミングで設計すべきか。', 'メインシナリオが崩れてからサブを設計する', 'エントリー後にサブを設計する', '週に1回、週次レビューのときに設計する', '朝のルーティンで同時に設計する', 4, 'ルール1として、メインとサブは必ず「同時に」設計する。メインだけ先に作ってサブを後回しにすると、結局リアルタイムでサブを考えることになり感情が介入する。', false, 1),
(61, 'シナリオ管理のルールのうち、「エントリー後にシナリオを変更しない」理由は何か。', '変更すると税金の計算が複雑になるから', '変更するとスプレッドが広がるから', 'エントリー後の変更は100%感情によるものだから', '変更するとブローカーのシステムエラーが起きるから', 3, 'エントリー後に条件が変わったように見えても、それはポジションを持った心理状態による認知の歪みの可能性が高い。エントリー後のシナリオ変更は100%感情に由来すると考えてよい。', false, 2),
(61, 'シナリオ管理シートで1日に管理すべきシナリオの上限はいくつか。', '10通貨ペアまで', '5通貨ペアまで', '制限はない', '最大2通貨ペアまで', 4, '1日に管理するシナリオは最大2通貨ペアまで。3つ以上になると管理が行き届かなくなり、判断の質が下がる。少ないペアに集中することで精度の高いトレードが可能になる。', false, 3),
(61, 'シナリオ管理シートの朝のルーティンに必要な追加時間はどの程度か。', '約5分', '約1時間', '約30分', '追加時間は不要', 1, '朝のルーティンに5分追加するだけで、メイン＋サブの「2本立て」シナリオが完成する。この5分が日中の迷いを全て消し、判断を「計画の実行」に変えてくれる。', false, 4),
(61, 'シナリオ管理シートを1週間続けるとどのような変化が起きると期待されるか。', 'エントリー回数が3倍に増える', 'チャートを開いた瞬間に「今日のIf-Aはここ、If-Cはここ」と頭に浮かぶようになる', 'すべてのトレードで勝てるようになる', '環境認識が不要になる', 2, '1週間続けると、シナリオの分岐構造が身体に染み込み、チャートを開いた瞬間に条件分岐が自然と思い浮かぶようになる。これは準備が習慣化された証拠である。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(44, 'あるトレーダーが毎回エントリー前に「今回は場所が合ってるから足だけで判断する」と考えている。この判断の問題点として最も適切なものはどれか？', '場所が合っていれば足の形は関係ない', '出来高を確認しないと、参加者の少ない動きに乗るリスクがある', '場所の評価を最後に回す方が合理的だから', '足の形だけで勝率は上がるから', 2, '場所が合っていても出来高が伴わない反転は「見せかけ」の可能性がある。三位一体の3要素を省略すると、1つが欠けるだけで信頼度が大幅に下がる。3要素すべてを確認してから判断することが基本。', false, 6),
(44, '「場所×足×出来高」の三位一体を使い始めたトレーダーが「エントリー機会が少なすぎる」と感じている。この感覚が示すことはどれか？', 'フレームワーク自体が実戦向きでない', '機会の少なさではなく質の高い機会を選んでいる正常な状態', '下位足を追加すれば機会が増える', '別のフレームワークに切り替えるべき', 2, '三位一体を適切に適用するとエントリー機会は減少する。しかし1回あたりの期待値は上がる。「機会が少ない＝悪いこと」という認識が間違いで、少ない高確度のトレードが長期利益を生む。', false, 7),
(44, '週足のトレンドが上昇中で日足のサポートゾーンに到達し、大きな下ヒゲのピンバーが確定し、出来高が20日平均の1.8倍だった。三位一体でこのシナリオの評価として最も適切なものはどれか？', '三位一体の3要素がすべて揃っており、高確度のエントリー候補として扱う', '出来高が2倍以上でないと不合格', '週足の確認は不要、日足だけでよい', 'ピンバーより包み足の方が信頼度が高い', 1, '場所（日足サポートゾーン＋上位足と整合）、足（ピンバー確定）、出来高（20日平均の1.8倍で急増確認）の3要素が揃っている。三位一体が機能する高確度のセットアップ。', false, 8),
(44, '三位一体フレームワークで「WHAT（足の形）」を最後に確認する理由として最も適切なものはどれか？', '良い場所と出来高があって初めて足の評価が意味を持つから', '足の形を先に見ると他の2要素を見落とすから', '出来高の計算に時間がかかるから', '足の形はどの場所でも同じ信頼度を持つから', 1, 'ピンバーは「場所が正しく、出来高が伴っているとき」に初めて意味を持つ。どこにでも出るパターンを最初に見ると、良い場所かどうかを見落とすリスクがある。判断順序が精度に直結する。', false, 9),
(44, 'ある通貨ペアで教科書通りのピンバーが出た。しかし場所は200MAから遠く、出来高は20日平均以下だった。適切な行動はどれか？', 'ピンバーの形が完璧なのでエントリーする', '出来高だけ追加確認してエントリーを検討する', '三位一体の3要素のうち2つが不合格なので見送る', '下位足に切り替えてピンバーが維持されているか確認する', 3, '場所（不合格）と出来高（不合格）の2要素が欠けているため、三位一体の評価は低い。完璧な足の形があっても2要素が揃わなければ見送るのが正しい基準。3要素すべてが揃う場面を待つ。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(45, 'フィボナッチ61.8%のリトレースメントと日足の水平サポートが重なる水準に価格が近づいている。この「合流ポイント」が単独の水準より信頼度が高い理由は何か？', '計算が複雑なほど信頼度が上がるから', '複数の独立した根拠が同じ水準を指しているため、その水準での反転を支持するトレーダーが多い', 'フィボナッチは水平線より必ず優先される', '合流ポイントでは必ず出来高が急増するから', 2, 'フィボナッチと水平線は独立した分析手法であり、両方が同じ水準を指すことは偶然ではない。複数の根拠が重なる水準には多くのトレーダーの注文が集まるため、反転力が強くなる。', false, 6),
(45, '日足では上昇トレンド中だが、週足では長期レジスタンス水準に近づいている。4時間足でサポートのピンバーが出た場合、適切な判断はどれか？', '日足が上昇トレンドなので素直に買いエントリーする', '上値が週足レジスタンスで限定されるため、RR比が悪化する可能性を考慮し見送るか利確目標を近く設定する', '週足は無視して4時間足のシグナルだけで判断する', 'レジスタンス到達まで引き付けて売りを狙う', 2, '上位足のレジスタンスが近いとRR比が悪化する。日足の上昇が正しくても、週足のレジスタンスに上値を抑えられれば利益が限定される。場所の判定には「上値余地の残り距離」も含まれる。', false, 7),
(45, '200日移動平均線上でサポートされた後、価格がゾーン内に戻りピンバーが確定した。このシナリオが一般的に信頼度が高い理由はどれか？', '移動平均線は自動的に反転を引き起こすから', '200MAは多くのファンドや機関投資家が意識する水準であり、その水準での反発を狙うプレーヤーが集まるから', '200MAは過去の高値・安値より常に優先される', '移動平均線は出来高と連動しているから', 2, '200MAは世界中の機関投資家が参照する長期的なサポート/レジスタンスの目安。多くのプレーヤーが同じ水準を意識するため、そこでの反転が自己実現的に起きやすい。', false, 8),
(45, 'あるトレーダーが「この場所は以前反転した」という理由だけで同じ水準にエントリーしようとしている。この判断の落とし穴はどれか？', '同じ水準は2回以上機能しない', '前回反転した水準でも、その後の到達回数や現在の相場環境によって信頼度が変わるため', '過去の反転水準は常に再び機能する', '以前反転した場所は必ず同じ方向にしか動かない', 2, '同じ水準でも到達回数が増えるほど注文が枯渇し信頼度が下がる。また上位足のトレンドが変化していれば、以前のサポートがレジスタンスに転換することもある。過去の実績だけで判断するのは危険。', false, 9),
(45, '価格が重要なサポートゾーンに到達したが、上位足が強い下降トレンド中だった。この場面でのエントリーを見送る主な理由は何か？', 'サポートゾーンは下降トレンド中に機能しない', '上位足の流れが下方向なら、一時的なサポートの反発も上位足の売り圧力に飲まれるリスクが大きいから', '出来高が必ず不足するから', 'ピンバーが出ない場所だから', 2, '下降トレンド中のサポートでの反発は「一時的な戻り」に終わることが多い。上位足の大きな流れに逆らう場所では、エントリーしても大局の方向に押し流されるリスクが高い。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(46, '日足でピンバーが確定した後、次の足が同方向に大きな実体で確定した。このことは何を示しているか？', '1本目のピンバーの信頼度が下がる', '反転方向に勢いが継続しており、ピンバーの信頼度を「後から」裏付けている', '2本目が大きな実体なら1本目は無関係', '利確タイミングが到来した', 2, 'ピンバー確定後に同方向の大きな実体が続くことは「反転が本物だった」ことを示す追加証拠。2本目の動きを確認してからエントリーする確認エントリーは、若干のリターンを犠牲にしてフェイクを回避できる。', false, 6),
(46, '包み足が出現したが、包む前の足がすでに大きな実体だった。この包み足の信頼度についての適切な評価はどれか？', '大きな足を包んでいるのでより強力なシグナル', '理想的な包み足は前の足が小さなコマ足・十字線であるため、大きな実体を包む場合は信頼度が下がる', '包み足は前の足のサイズに関係なく同じ信頼度を持つ', '大きな実体を包む包み足は常に見送るべきではない', 2, '高品質な包み足の条件は「前の足が迷い（コマ足・十字線）を示し、そこに大きな実体で決着をつける」という文脈。前の足がすでに強い方向性を持っていると「迷いの後の決着」という文脈が成立しない。', false, 7),
(46, 'サポートゾーンにはらみ足が1本出現した。上位足の上昇トレンドと合致している。次の適切な行動はどれか？', 'はらみ足1本でエントリーする', 'はらみ足の上限をブレイクし出来高が増加した足で買いエントリーを検討する', 'はらみ足は方向がないので無視する', '上昇側のブレイクより下落側のブレイクを待つ', 2, 'はらみ足自体は方向を示さないが、上位足が上昇トレンドならブレイク方向は上が有力。はらみ足の上限をブレイクし出来高が増加したことを確認してからエントリーすることで、ダマシを避けられる。', false, 8),
(46, 'ピンバーのヒゲが実体の2倍程度で、反対側にも同程度のヒゲがある場合、このパターンの評価はどれか？', 'ヒゲが2倍あるので高品質なピンバーとして扱う', '反対側のヒゲが長いことは「売りと買いが拮抗している」ことを示し、高品質なピンバーの条件を満たさない', 'ヒゲの比率より出来高だけで判断する', '時間足を下げて確認すれば高品質かどうかが分かる', 2, '高品質なピンバーは「ヒゲが実体の3倍以上かつ反対側のヒゲがほぼない」ことが条件。両側にヒゲがある場合は方向感が曖昧で、「一方的に売り圧力を吸収した」という状態とは言えない。', false, 9),
(46, '長期下降トレンド中に大きなサポートゾーンで日足の包み足が出現した。上位足が下降トレンドである事実を考慮した適切な判断はどれか？', '包み足の出現だけで上昇転換を確信してエントリーする', '週足や月足レベルで反転の証拠を確認するか、見送りを選択する', '包み足が大きいほどトレンド転換が確実', '下降トレンド中の包み足は常に偽シグナル', 2, '長期トレンドの転換には、上位足レベルでの確証が必要。日足の包み足は一時的な反発のシグナルであることも多く、長期下降トレンド中ではより上位の時間足で反転の証拠を確認してから判断するか見送る方が安全。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(47, '価格が重要なサポートに近づくにつれて出来高が減少し続けている。この状態が示すのはどれか？', '下落圧力が弱まり反転が近い', '売り手が力を失いつつあるが買い手の参入確認が必要で、反転確証には不十分', '出来高減少は常に反転のサイン', '直ちにサポートで買いエントリーする', 2, '出来高減少は「参加者が減っている」ことを示すが、それだけでは反転の確証にならない。サポートで出来高が急増した足（大口の参入証拠）が確認されて初めて、反転エントリーの根拠が揃う。', false, 6),
(47, '出来高が20日平均の1.5倍の足が確認されたが、その足はコマ足（小さな実体）だった。この組み合わせが示す意味として最も適切なものはどれか？', '出来高が多いので買いエントリーする', '売りと買いが激しくぶつかりエネルギーが蓄積されており、次の動き（ブレイク方向）を待つべき状態', 'コマ足は出来高に関係なく無意味', 'すぐに上昇するサイン', 2, '大きな出来高を伴うコマ足は「拮抗状態の激化」を示す。大量の注文が入っているにも関わらず方向が決まっていない状態で、次の足でどちらかに解放されることが多い。上位足のトレンド方向のブレイクを待つ。', false, 7),
(47, 'トレンド中に出来高が徐々に減少しながら価格が伸び続けている。この状態から予測されるリスクはどれか？', 'トレンドが加速する前の充電期間', 'トレンドを支持する参加者が減少しており、勢いが失われつつある可能性', '出来高の減少はトレンド継続のサイン', '重要な経済指標発表を控えているサイン', 2, '健全なトレンドは出来高を伴って伸びる。出来高が徐々に減少しながら価格だけが伸び続ける「ダイバージェンス」は、参加者が減って息切れが近いサイン。利確や新規エントリーの見送りを検討するタイミング。', false, 8),
(47, 'レジスタンス水準を出来高の急増を伴って実体で上抜け、翌日も同方向に継続した。この動きを「本物のブレイク」と判断する根拠として最も適切なものはどれか？', '出来高の急増は大口の積極的な参入を示し、実体での突破は方向性の確信を示しているから', '2日連続で同方向だから', 'レジスタンスを抜けたから', '出来高が多いほど利益が大きくなるから', 1, '本物のブレイクの条件は「実体での突破＋出来高の急増」の組み合わせ。大口が本気でポジションを構築した証拠が出来高であり、ヒゲではなく実体で終値が定着していることが「本物のブレイク」の確証。', false, 9),
(47, '急落直後の出来高急増（20日平均の3倍）＋長い下ヒゲのある反転足の組み合わせを見た。この状態を「クライマックスセリング（パニック売り後の底打ち）」と判断する根拠はどれか？', '急落後は必ず反転するから', '大量の売りが一気に消化され、売り方が枯渇した可能性を示すから', '出来高が多いほど反転が確実だから', '下ヒゲが長いから', 2, '急落時の出来高急増は大量の売り注文の消化を示す。売り方が一気に消化されると、それ以上売る人が減り底打ちにつながりやすい。ただし「可能性」であり、上位足のサポートゾーンとの合流確認も必要。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(48, '日足の上昇トレンド中に押し目として有力な水準に近づいたが、場所・足・出来高の3要素のうち場所だけが合格で残り2つが未確認だった。この段階での適切な行動はどれか？', '場所が合格なので早めにエントリーして有利な価格を取る', 'アラートを設定して、残り2要素が揃った段階でエントリーを検討する', '場所は3要素の中で最重要なので1要素だけでエントリーできる', '下位足に切り替えて判断する', 2, '三位一体は3要素すべてが揃ったときにエントリーを検討する。場所が合格でも残り2要素（反転足の確定と出来高急増）が揃っていなければ待つ。アラートを設定し、条件が揃ってから動くのが正しい順序。', false, 6),
(48, 'フィボナッチ61.8%と水平サポートが重なる水準で大きな包み足が確定し、その足の出来高が20日平均の2.5倍だった。しかし上位足（週足）が下降トレンド中だった場合の判断はどれか？', '3要素が揃っているので問題なくエントリーする', '場所・足・出来高は揃っているが、上位足のトレンドに逆行するため慎重になるか見送る', '出来高が2.5倍あれば週足トレンドより優先される', 'フィボ61.8%は週足トレンドを無効化する', 2, '三位一体の3要素が揃っていても、上位足が逆方向なら信頼度が落ちる。週足下降トレンド中の買いは「逆張り」になる。高い出来高があっても上位足の流れに飲まれるリスクがあり、見送りかロット縮小が妥当。', false, 7),
(48, '重要なサポートゾーンに価格が到達したが、ヒゲが実体の1.5倍程度のやや弱いピンバーしか出なかった。その後すぐ次の足がサポートを割り込んだ場合、何が起きたと考えられるか？', '反転パターンが確認されたので買いエントリーのチャンス', '弱い足の形が示す通り反転の意思が弱く、サポートが機能しなかった', '次の足でサポートを割ったので三位一体の評価は変わらない', '出来高を確認すれば判断できる', 2, '足の質が低いピンバー（ヒゲが実体の1.5倍程度・両側ヒゲあり）は反転の確信が薄い。低品質な足が出た時点で信頼度は低く、続落したことはその評価が正しかったことを示す。足の質の重要性がわかる。', false, 8),
(48, '三位一体の3要素の判定結果が「場所: 高評価、足: 中評価、出来高: 平均以下」だった場合の最も適切な対応はどれか？', '場所が高評価なのでエントリーする', '出来高が不合格なため、次の足で出来高を伴った続伸を確認するか見送る', '足の評価が中程度なのでロットを半分にしてエントリーする', '出来高の評価が最も重要なので直ちに見送る', 2, '出来高が平均以下は参加者が少ない動きであり、フェイクの可能性が高い。次の足で出来高が急増して続伸するかを確認してからエントリーするのが安全な対応。', false, 9),
(48, '3要素すべてが高評価の完璧なセットアップが揃った。翌日に重要な経済指標の発表が予定されている。最も適切な対応はどれか？', '三位一体が完璧なので迷わずエントリーする', '指標発表前はエントリーせず、発表後にセットアップが維持されていればエントリーする', 'ロットを通常の半分にしてエントリーする', '指標発表の30分前に利確する前提でエントリーする', 2, '三位一体の3要素が揃っていても、重要経済指標の発表前はリスクが残る。指標の結果次第で相場が急変し、セットアップが無効になる可能性がある。発表後に条件が維持されていれば同じセットアップでエントリーできる。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(49, 'エントリー前に確認項目をチェックリスト化して使う習慣の最大のメリットはどれか？', '分析の速度が上がる', '感情が高ぶっている状態でも客観的な基準でエントリー可否を判断できる', '相場の動きを予測できる', '損切り幅を自動的に計算できる', 2, 'チェックリストの最大の価値は「感情状態に関わらず同じ基準を適用できること」。興奮しているときや焦っているときでも、チェック項目を確認することで冷静な判断基準を維持できる。', false, 6),
(49, 'チェックリストを使い始めたトレーダーが「チェックしている間にエントリー機会を逃した」と感じる場面が増えた。この状況の最も正確な解釈はどれか？', 'チェックリストが実戦に向いていない証拠', '「逃した」のではなく「確認が完了する前に条件が崩れた低品質な機会だった」と考えるべき', 'チェック項目を減らして対応すべき', 'より下位足で判断することで改善できる', 2, '本当に高品質なセットアップは確認中に崩れない。チェック完了前に条件が崩れるのは「最初から質が低かった」機会である。「逃した」と感じるのは焦りであり、チェックリストはそれを防ぐためのシステム。', false, 7),
(49, 'チェックリストの判定で「合格項目の多さ」によってエントリーサイズを変える設計がある。この設計の狙いとして最も適切なものはどれか？', '常に最大ロットでエントリーするため', '確度が高い場面ほど大きく張り、確度が低い場面ほど小さく張ることでリスクを最適化するため', 'エントリー回数を増やして利益を最大化するため', '損切り幅を自動的に調整するため', 2, '全条件が揃う高確度の場面と一部しか揃わない低確度の場面を同じロットで扱うのは非効率。確度に応じてサイズを変えることで、期待値の高い場面に適切なリソースを配分できる。', false, 8),
(49, 'チェックリストで「上位足の200MAとの位置関係」を確認する項目がある。この確認が重要な理由はどれか？', '200MAは必ず反転ポイントになるから', '200MAはサポート/レジスタンスとして多くの参加者が参照する水準であり、それに対して有利な方向のエントリーかを確認するため', '200MAの上では常に買い、下では常に売りが正しいから', '200MAは出来高と連動しているから', 2, '200MAは機関投資家を含む多くの市場参加者が意識する長期的な方向性の目安。自分のエントリー方向が200MAと整合しているか（順張りか逆張りか）を把握することで、リスクと期待値を正しく評価できる。', false, 9),
(49, 'チェックリストを3ヶ月間続けたトレーダーが記録を見ると、「合格項目が多かった場面ほど勝率と損益が高い」という傾向を確認した。この記録が果たす最も重要な役割はどれか？', 'チェックリストの有効性を数値で証明し、改善への動機を維持する根拠となる', '税務申告の証拠資料になる', '証券会社への報告資料になる', '将来の相場予測に使える', 1, '記録によって「チェックリストが機能している」という客観的なフィードバックが得られる。感覚だけに頼らず数値で確認できると、基準を守り続ける動機が強化される。記録は改善の燃料。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(50, '大口機関投資家が個人のストップ注文を「流動性の源泉」として利用する行為は、なぜ市場の構造的な問題として繰り返されるのか？', '規制当局が監視していないから', '大きな注文を市場で執行する際に既存の注文を利用することは合法的な取引であり、大口の構造的制約が変わらない限り続くから', '大口は中央銀行の支援を受けているから', '個人は常に感情的に動くから', 2, '大口が個人の損切り注文を利用してポジションを構築するのは需給の論理に従った正当な市場行動。この構造は違法ではなく、大口が大量注文を分散執行しなければならない制約が変わらない限り永遠に繰り返される。', false, 6),
(50, '大口がサポートゾーンで買いポジションを構築したいとき、なぜわざわざサポートを一時的に割り込む動きを作るのか？', '相場を操縦して下落を加速させるため', 'サポート割れで売りを仕掛けた個人の売り注文を引き受けることで、大量の売りを安値で吸収できるから', 'テクニカル指標をリセットするため', '中央銀行の政策に対抗するため', 2, '大口が大量の買いを入れるには、それだけの売りが必要。サポートを割り込んで個人に売らせることで「天然の売り注文」が市場に溢れ、そこで大量の買いを集中執行できる。個人の損切りが大口の仕入れ値になる構造。', false, 7),
(50, '経験豊富なトレーダーが「直近高値の上にストップロスを置く」習慣のリスクとして適切なものはどれか？', '高値の上はストップロスの最良の位置である', '高値の上には多くのトレーダーの損切りが集中しており、大口のストップ狩りのターゲットになりやすい', '直近高値を超えたら常にトレンド転換が起きる', 'ストップロスを置く場所は相場の動きに影響しない', 2, '「直近高値の少し上にストップを置く」という一般的な推奨は、大口にとって最も分かりやすいストップの集中場所でもある。この構造を理解することで、ストップ位置をより工夫するか、戻りを確認してからエントリーするかを選択できる。', false, 8),
(50, '大口の仕掛けが「繰り返される」理由として、個人投資家の側の要因として最も正確なものはどれか？', '個人は常に感情的に動くから', '個人投資家は教科書通りのポイント（直近高値・安値のすぐ外側）にストップを置く傾向が変わらないから', '個人は大口より常に遅いから', '個人は情報が少ないから', 2, '同じ教科書を読み、同じテクニカルを使う個人トレーダーは同じポイントにストップを置く傾向がある。この「予測可能な行動パターン」が変わらない限り、大口はその集中した注文を利用し続ける。', false, 9),
(50, 'ベアトラップとブルトラップを「罠」として認識できるトレーダーとそうでないトレーダーの最大の違いは何か？', '使用するテクニカル指標の違い', '「なぜサポートが割れたか」「なぜレジスタンスを超えたか」というメカニズムを考えるかどうかの違い', '取引する通貨ペアの違い', 'エントリーのタイミングの速さの違い', 2, '同じチャートを見ても、「サポートが割れた＝下落開始」と見る人と「誰かが売りを誘い込んだかも」と見る人では判断が分かれる。メカニズムを意識することで、フェイクを利益に変える視点が持てる。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(51, '重要な高値を超えた瞬間に買いエントリーしたが、2本後に急反落してストップに当たった。この体験から学べる最も重要な教訓はどれか？', '高値ブレイクでは必ずエントリーしてはいけない', 'ヒゲ突破か実体突破か、そして出来高の変化を確認してから判断する重要性', 'ブレイクアウトは機能しない手法', '常に反対方向でエントリーすべき', 2, 'ヒゲで高値を一瞬超えた後に戻るのはストップ狩りの典型。実体で確定したか、出来高が伴っていたかを確認することで「本物のブレイク」と「ストップ狩り」を区別できる。確認を怠るとストップ狩りの犠牲になる。', false, 6),
(51, 'ロンドンオープン直後に価格が急激に動いてストップに当たった後、もとの方向に戻ったケースで適切な事後分析はどれか？', 'ロンドン時間はトレードすべきでない', 'ロンドンオープンは損切りが集中する時間帯であり、事前に「狩り場」を特定してオープン直後の動きを観察する準備が重要', 'ストップを2倍に広げれば次回は対応できる', '経済指標の影響だった', 2, 'ロンドンオープン（16:00 JST前後）は流動性が急変し、東京時間のレンジ上下限に溜まったストップを一掃してから本来の方向に動くパターンが多い。事前にストップが集中しやすい場所をマークし、オープン直後の動きを観察することで対策できる。', false, 7),
(51, '「ヒゲで突破したが終値は元のゾーン内に戻った」という状態を確認したとき、最初に判断すべきことはどれか？', '即座に逆方向にエントリーする', '突破時の出来高が少ないかどうかを確認し、他のストップ狩りの特徴と照合する', '次の足でもう一度同じことが起きるか待つ', '損切りをゾーンの外に移動する', 2, '終値がゾーン内に戻っただけではストップ狩りと断定できない。出来高の確認（突破時に少ないか）と他の特徴（即座の反転か、上位足との整合か）を照合して確度を高めてからエントリーを検討する。', false, 8),
(51, '流動性の薄い時間帯（欧米市場クローズ前後）に価格が急激に動いた後すぐに戻ることがある。この時間帯のシグナルに特に警戒すべき理由はどれか？', '流動性が低いため値動きが不安定で、大口が少量の注文でも価格を大きく動かしてストップ狩りをしやすいから', '経済指標の発表が集中するから', 'アジア市場が開くタイミングだから', 'アルゴリズム取引が停止するから', 1, '流動性が薄い時間帯は少量の注文でも価格が動きやすく、大口がより少ないコストでストップ狩りを仕掛けられる。このような時間帯に出るシグナルは精度が低いため、値動きの確認に時間をかける必要がある。', false, 9),
(51, 'ストップ狩りかブレイクかを判断する際、「出来高」の変化が重要な根拠となる理由はどれか？', '出来高は相場の方向を教えてくれるから', '本物のブレイクには新規参加者が必要であり、その参入は出来高の急増に現れるが、ストップ狩りは既存注文の消化で起きるため突破時の出来高が少ないから', '出来高は価格より先に動くから', 'ストップ狩りは必ず出来高が増加するから', 2, '本物のブレイクは多くの新規参加者が「ブレイクを確認して参入」することで起きる。その参入は出来高急増に現れる。ストップ狩りは「既存の損切り注文を刈るだけ」のため、突破時に大きな出来高を伴わない場合が多い。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(52, '重要サポートをヒゲで一瞬割った後に反転足が確定した。この場面でエントリーを焦らずに「反転足の確定」を待つことで回避できるリスクは何か？', '利益が少なくなる', '二重ダマシ（ヒゲで戻した後にさらに割り込む動き）のリスクを回避できる', 'スプレッドが広がるリスクを回避できる', '指値注文が約定されないリスクを回避できる', 2, 'ヒゲで一時的に戻した後、さらに大きく割り込む「二重ダマシ」が起きることがある。反転足の確定（ピンバーや包み足が1本閉じること）を確認してからエントリーすることで、この二重ダマシのリスクを大幅に減らせる。', false, 6),
(52, 'フェイクブレイク後の逆張りエントリーでRR比が有利になりやすい構造的な理由はどれか？', '利確目標が自動的に決まるから', 'ストップ狩りのヒゲ先端が「これ以上は行かなかった」事実を示すため、その少し外側という明確な損切り位置が決まり損切り幅が小さくなるから', '大口と同じポジションを持つから', 'エントリー価格が常に有利だから', 2, '損切り位置がヒゲ先端の外側という「論理的な根拠のある位置」に決まるため、損切り幅が小さくなりやすい。損切り幅が小さいと利確目標が同じでもRR比が改善する。', false, 7),
(52, 'フェイクブレイクを利用したエントリーで、エントリー後に価格がヒゲの先端を超えてさらに進んだ場合、どう対応すべきか？', '損切りをさらに遠ざけて待つ', '損切りを発動させる。ヒゲ先端超えは「本物のブレイク」の可能性を示すから', 'ポジションを追加する', 'ロットを半分に減らす', 2, 'ヒゲ先端の外側に設定した損切りを超えた場合、それはストップ狩りではなく本物のブレイクである可能性が高い。損切りを発動させ、損失を限定する。損切りラインを後から動かすことはしない。', false, 8),
(52, 'フェイクブレイク逆張りエントリーの精度を上げるために最も重要な「事前準備」はどれか？', '指値注文を大量に並べておく', '朝の環境認識でストップが集中しやすい水準を事前にマークしておき、その水準への接近をアラートで検知する準備', 'リアルタイムで全ての通貨ペアを監視する', '大口の注文量を追跡するツールを使う', 2, 'フェイクブレイクは事前に「どの水準でストップ狩りが起きやすいか」を予測していれば、起きた瞬間に冷静に対応できる。準備なしにリアルタイムで判断しようとすると感情が介入しやすくなる。', false, 9),
(52, 'ストップ狩り後に逆張りエントリーした後、利確目標として適切な位置はどこか？', 'ヒゲの先端', 'エントリー直前の高値/安値（ストップ狩りが起きた水準）', 'ストップ狩りが起きた水準より離れた次のサポート/レジスタンス', 'エントリー価格から固定pips', 3, '利確目標は「次の抵抗水準」が基本。ストップ狩りが起きた直後の反転で、エントリー水準のすぐ手前が利確目標だとRR比が1:1以下になりやすい。より遠い次のサポート/レジスタンスを目標にすることでRR比を改善できる。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(53, 'サポートゾーンをヒゲで割り込んだが終値がゾーン内に戻った。出来高は割り込み時が少なく、戻り時が急増していた。この状況でエントリーする際の損切り位置として最も合理的なのはどれか？', 'サポートゾーンの中央', '直近の高値', 'ヒゲの先端（サポートゾーンを割り込んだ最安値）の外側', 'エントリー価格から固定pips', 3, 'ヒゲの先端が「大口がストップを刈り取った最安値」を示す。その水準を超えた場合はベアトラップではなく本物の下落の可能性が高い。論理的な損切り位置はヒゲ先端の外側。', false, 6),
(53, 'ベアトラップが出現したが、上位足（日足・週足）が下降トレンド中だった。逆張りエントリーすべきかの判断として正しいものはどれか？', 'ベアトラップが出現した事実だけでエントリーする', '上位足が下降トレンドなら「本物の下落」の可能性もあり慎重になるか見送る', '出来高が多ければ上位足は無視できる', 'ベアトラップは上位足に関係なく機能する', 2, 'ベアトラップ逆利用は上位足が上昇トレンドまたは中立のときに高確度になる。下降トレンド中のサポート割れは「一時的なフェイク」ではなく「本物の下落」の可能性も高い。上位足との整合確認が必須。', false, 7),
(53, 'レジスタンスをわずかに超えて翌日に急落した（ブルトラップ）場面で、売りエントリーを検討する条件として最も重要なものはどれか？', 'レジスタンスを超えた事実だけで売りを狙う', 'ヒゲ突破かつ終値が元のレンジ内に戻っており、出来高が突破時より戻り時に増加している', '日足の実体がレジスタンスを超えてから売りを狙う', '翌日の開値の位置だけで判断する', 2, 'ブルトラップの条件は「ヒゲ突破（実体では抜けていない）」「終値がレンジ内に戻っている」「戻り時の出来高が突破時より多い」という組み合わせ。これらが揃うほどブルトラップの確度が上がる。', false, 8),
(53, 'フェイクブレイクの条件を確認せず「サポート/レジスタンスを抜けたら逆張り」という機械的なルールを適用した場合のリスクは何か？', 'エントリー回数が増えすぎること', '本物のブレイクアウトに対しても逆張りしてしまい、大きな損失を受けるリスク', '損切り位置が広くなること', '出来高の確認が不要になること', 2, '全てのブレイクがフェイクではない。「出来高の変化」「ヒゲか実体か」「即座の反転か継続か」を確認せず機械的に逆張りすると、本物のブレイクアウトに逆らって大きな損失を被る。条件確認が前提。', false, 9),
(53, '二重ダマシ（サポート割れ→反転→再度割れ）が完全に防げない理由として最も適切なものはどれか？', '大口が二重ダマシを計画的に仕掛けるから', '相場は確率的であり、確認条件が揃っていても想定外の展開は常に起きうるから', 'テクニカル分析は不完全だから', '個人投資家には情報が届かないから', 2, '二重ダマシの可能性は完全には排除できない。だからこそ「1回の損失を資金の1〜2%以内に限定する」ポジションサイジングが重要。確度を高めながらも、想定外への備えとして損失を限定する設計が必要。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(54, '重要な心理的節目付近でヒゲで一瞬突き抜けた後すぐに戻った場面で「ブレイクアウト失敗」と判断してエントリーする場合の根拠として必要な確認は何か？', 'チャートの見た目だけ', 'ヒゲの突破で終値が元のレンジ内に戻っているか、出来高が突破時に増加していないか', '前日の値動きの方向性', '他のアナリストの意見', 2, '「ブレイク失敗」と判断するには「ヒゲ突破＋終値の戻り＋出来高不足」の確認が必要。感覚だけで判断するのではなく、フェイクブレイクの特徴を具体的に確認してからエントリーすることで精度が上がる。', false, 6),
(54, 'フェイクブレイク逆張りエントリーが10回で7勝3敗（1回の損失が1単位、1回の利益が2単位）だった場合の総損益はどうなるか？', '±0（10回でイーブン）', '+7単位（7勝×1単位 - 3敗×1単位）', '+11単位（7勝×2単位 - 3敗×1単位）', '+14単位（7勝×2単位）', 3, '7勝×2単位＝14単位の利益、3敗×1単位＝3単位の損失。トータルは+11単位。勝率70%でRR比1:2なら高い期待値が得られる。損切り幅の小さいエントリー手法でRR比を確保することの重要性を数字で確認できる。', false, 7),
(54, '損切り後に「リベンジトレード」をしてさらに損失が拡大した。この連鎖を断ち切るための最も有効な方法はどれか？', '次のトレードで取り返す', '損切り後は一定時間（30分〜1時間）チャートから離れて感情を落ち着かせる', 'ロットを小さくしてすぐに再エントリーする', '逆方向にエントリーして損失をヘッジする', 2, '損切り後の再エントリー衝動（リベンジ心理）は感情的判断の典型。物理的にチャートから離れることで感情的な行動を防ぐ。「次のトレードは別のトレード」として切り分ける思考が大切。', false, 8),
(54, 'FOMC発表後に相場が大きく動き、その後1時間で当初の水準に戻ってきた。このケースで適切な対応はどれか？', '初動の方向についていく', '値動きが落ち着くまで待ち、通常の分析で方向を確認してから判断する', '戻りで逆張りする', '全シナリオを破棄して翌日まで待機する', 2, '指標発表直後は流動性が不安定で上下に大きく振れやすい。発表の影響を一時的に消化中の可能性がある。値動きが落ち着いてから方向を確認し、通常の分析に戻るのが安全。', false, 9),
(54, 'ストップ狩り後の逆張りエントリーを4回試みて3回成功、1回は二重ダマシで損切りになった。この結果をどう評価するか？', '成功率75%は低いので手法を変えるべき', '損切り1回分のリスクに対して3回分の利益が得られており、手法は機能している', '二重ダマシが1回でも出たので使ってはいけない', '4回のうち1回損切りは多すぎる', 2, 'RR比1:2の場合、4回で3勝1敗は+5単位（3×2-1×1）となる。重要なのは「1回の損失に対してどれだけの利益が得られたか（期待値）」。全ての手法で損切りは起きるが、損益の総計で評価することが正しい。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(55, '朝のルーティンでストップが集中しやすい水準をマークする作業を省略した場合のリスクは何か？', 'エントリー回数が減る', 'ストップ狩りが起きた際にリアルタイムで慌てて判断することになり、感情的な誤りを犯しやすくなる', '出来高の確認ができなくなる', '損切り位置が決まらなくなる', 2, '事前に「狩り場」をマークしておかないと、ストップ狩りが起きた瞬間に「これはフェイクか本物か」を初めて考えることになる。感情が入りやすいリアルタイム判断を避けるため、事前の準備が重要。', false, 6),
(55, 'ストップ狩りの特徴確認チェックで「該当項目が少ない（2つ以下）」と分かった場合の適切な対応はどれか？', '少ない項目でもリスクを取ってエントリーする', 'その動きをストップ狩りではなく「本物のブレイクの可能性が高い」と判断して見送るか、ブレイク方向に乗ることを検討する', '確認項目をさらに減らして対応する', '逆張りで半分のロットでエントリーする', 2, '特徴が2つ以下しか揃わない場合、ストップ狩りの確度が低く、本物のブレイクの可能性がある。この状況でフェイクブレイク逆張りをすると、本物のトレンドに逆らう危険なトレードになる。', false, 7),
(55, '大口の仕掛けを「利益の源泉」と見なす思考転換に必要な最も根本的な認識変化はどれか？', '大口より強くなる', 'ストップ狩り後は大口が方向を示しているシグナルとして、同じ方向に乗る', '全てのダマシを正確に予測する', '大口のアルゴリズムを解読する', 2, 'ストップ狩りの直後は大口がポジションを構築し終えた状態。大口が動き出す方向に乗ることが目的。「大口に勝つ」のではなく「大口と一緒に動く」というシフトが重要な認識変換。', false, 8),
(55, '朝の環境認識→アラート設定→価格接近時に確認→条件が揃ったらエントリー→損切りをヒゲ先端外側に設定、という一連の流れを習慣化する意義はどれか？', 'エントリー回数を最大化するため', 'リアルタイムの判断を「計画の実行」に変え、感情的な判断を排除するため', '出来高の確認を自動化するため', '損切りを最小化するため', 2, 'このルーティンにより、全ての判断が「事前に決めたルールの実行」になる。感情で動くのではなく、条件が揃ったら機械的に動く習慣が、長期的な成績の安定に直結する。', false, 9),
(55, 'フェイクブレイク後の逆張りエントリーに必要な複数の確認条件のうち、どれか1つでも欠けている場合の判断として正しいものはどれか？', '2つ揃えばエントリーしてよい', '全条件が揃わない場合は見送り、または条件が揃うまで待つ', '最も重要な1条件だけで判断できる', 'ロットを小さくしてエントリーする', 2, '複数条件が揃うほど確度が高まる。一部しか揃わない場合は確度が下がり、RR比の優位性が薄れる。「条件が揃わないときは見送る」規律がこの手法の精度を維持する。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(56, 'あるトレーダーが「強い根拠があるから1つのシナリオだけでいい」と考えて毎日トレードしている。この考え方の最大のリスクはどれか？', '根拠が強いほど正確に予測できるから問題ない', '想定外の展開になったとき感情的に判断し、損失を拡大させやすくなる', 'シナリオが1つの方が分析が正確になる', 'エントリーのタイミングが早くなりすぎる', 2, '根拠が強くても相場が想定通りに動く保証はない。1つのシナリオしかないと、外れた場合に混乱し感情的な判断に陥る。複数のシナリオが「想定内の別展開」を提供し、冷静さを維持できる。', false, 6),
(56, '「分岐点（If A、If B）」として複数のシナリオを描くことが有効な理由として最も本質的なものはどれか？', '分岐を増やすほど予測精度が上がるから', '相場は確率的であり「AかBか」は事前に分からないため、両方への準備が合理的だから', '複数の通貨ペアを同時に扱えるようになるから', '損切りラインを自動的に決められるから', 2, '相場は未来に何が起きるか分からない確率的な世界。「Aなら〇〇する、Bなら〇〇する」という事前設計により、どちらが来ても冷静に対応できる。', false, 7),
(56, 'トレード日誌を見ると、シナリオ通りでない日に損失が集中していた。この記録から導かれる最も重要な改善策はどれか？', 'シナリオを作る回数を増やす', '「シナリオ外」の展開になったときに感情的に判断しているため、代替シナリオを事前に設計する習慣をつける', 'より多くの指標を分析に取り入れる', 'エントリー頻度を下げる', 2, 'シナリオ通りでない展開になったときに損失が集中するのは「想定外に対応できていない」証拠。事前に代替シナリオを用意しておくと「想定外」がなくなり、全ての展開が「計画の実行」になる。', false, 8),
(56, 'シナリオを立てる際に「〜するはず」という表現が入りやすい状況はどれか？', '根拠が複数揃っているとき', '既存のポジションを持ち、評価損が出ているとき', '朝の環境認識を完了したとき', '利益が出ているとき', 2, '含み損のポジションを持っているとき「戻るはず」という願望がシナリオに混入しやすい。ポジションを持ってからの分析は感情に汚染されやすく、「はず」はその客観性が失われているサイン。', false, 9),
(56, 'メインシナリオとサブシナリオを設計することで「朝の準備に少し追加時間」をかけることで得られる最大のメリットはどれか？', 'エントリー機会が2倍に増える', '日中の全ての値動きが「どのシナリオのケースか」として判断でき、感情的な迷いが排除される', '損切りを不要にできる', '相場の方向を高確度で予測できる', 2, '分岐シナリオがあると、どんな値動きが来ても「これはAのケース」「これはBのケース」と判断できる。「想定外」がなくなることで、日中の感情的な迷いが大幅に減る。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(57, 'メインシナリオが「日足サポートゾーンからの買い」の場合、サブシナリオとして最も論理的な設計はどれか？', '同じサポートゾーンで売りを狙う', 'サポートゾーンを実体で下抜けた場合のより深い位置（次のサポートゾーン）で再度買いを検討するか、ノートレードにする', '即座に逆方向のシナリオを実行する', '利確目標を半分に変更する', 2, 'サブシナリオはメインが崩れた場合の「次の行動」を定義する。メインのサポートが機能しなかった場合、より深い位置の次のサポートに移行するか、条件が揃わなければノートレードとするのが論理的な設計。', false, 6),
(57, 'メインシナリオとサブシナリオを「同時に設計する」ことがなぜ重要なのか？', '2つのシナリオに同時にエントリーするため', 'リアルタイムでサブを考えると感情が介入するが、事前設計なら客観的な条件で設計できるから', '朝の時間を有効活用するため', 'チャートを見る時間を減らすため', 2, 'メインが崩れた後にサブを考えようとすると、感情（損切りの痛み、リベンジ心理）が判断に混入する。朝の冷静な状態で同時に設計しておくことで、サブの発動条件を客観的に定義できる。', false, 7),
(57, 'サブシナリオの「発動条件」を「〇〇の水準を4H足の終値で下抜けた場合」のように具体的に書く理由はどれか？', '書くと自動的に注文が入るから', '主観的な表現は感情の余地を残すが、客観的な表現は機械的に実行できるから', '規制当局への報告に使えるから', 'ブローカーに伝えるため', 2, '「勢いが強くなった」「雰囲気が変わった」は人によって異なり、感情が入りやすい。「〇〇水準を〇〇足の終値で割った場合」という客観的な条件なら、誰が見ても同じ判断ができ、感情による歪みを排除できる。', false, 8),
(57, 'メインシナリオが崩れてサブシナリオも機能しなかった場合に「それ以上シナリオを探さない」という条件を事前に決めておく意義はどれか？', 'メインもサブも成立しない状況でシナリオを際限なく作り続けることへのブレーキとなるから', 'より多くのエントリーを見つけるため', '損切りを不要にするため', '利確目標を自動計算するため', 1, 'この条件がないと「メインがダメでもサブがある」「サブがダメでも次のシナリオを作れる」という無限の合理化が起きる。「ここまで来たら今日は休む」を事前定義することで、根拠のないトレードを防ぐ。', false, 9),
(57, '週足上昇トレンド中に日足の調整が進んでいる場面で、メインが「4H足サポートで買い」のとき、無効化条件として適切なのはどれか？', '4H足が陰線で確定したとき', '日足の直近安値を4H足の終値で明確に下抜けた場合', '出来高が減少したとき', 'RSIが50を下回ったとき', 2, '無効化条件は「上位足の構造が崩れた」水準で設定するのが合理的。日足の直近安値を終値で明確に下抜けた場合、短期調整の域を超えて日足レベルのトレンドが変化した可能性がある。この水準以下ではシナリオ全体が無効。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(58, 'シナリオの切り替えを「リアルタイムで感覚的に」判断している場合に起きやすい問題はどれか？', '判断が速くなる', '「もう少し待てばメインが復活するかも」という希望的観測が損失を膨らませる', 'エントリー回数が増える', 'チャートの見方が改善される', 2, 'リアルタイムでポジションを持っている状態での判断には感情が介入する。特に含み損があると「まだいける」という希望が切り替えを遅らせ損失を拡大させる。事前設計した条件への機械的な従いが重要。', false, 6),
(58, '市場のボラティリティが急上昇したとき、全シナリオを一時停止する理由はどれか？', '価格変動が大きくなって利益が出づらくなるから', '高ボラティリティ環境では通常のテクニカルパターンの機能が低下し、予測の前提が崩れるから', 'スプレッドが広がるから', '大口が休憩に入るから', 2, '通常のテクニカル分析は「一定の秩序がある相場」を前提にしている。ボラティリティが急騰すると、サポート/レジスタンスの意味が薄れ、予測の信頼性が大きく低下する。環境が戻るまで待機が賢明。', false, 7),
(58, 'サポートゾーンを終値で下抜けたとき、損切りラインを広げてポジションを維持してはいけない理由はどれか？', 'ゾーンを下抜けると自動的に損失が確定するから', '事前に設定したシナリオの条件が発動しており、そこから先は根拠のないポジション保有になるから', 'ブローカーに追証を請求されるから', '出来高が必ず急増するから', 2, '損切りラインを後から動かすことは「根拠なき希望」でポジションを維持すること。シナリオが無効化された水準を下抜けた時点で、そのポジションの根拠は失われている。根拠のないポジションは持ち続けるべきでない。', false, 8),
(58, '「計画的な切り替え（サブシナリオへの移行）」と「リベンジトレード（損切り後の感情的な再エントリー）」が本質的に異なる理由はどれか？', 'エントリー価格が違うから', '事前に書いた条件が発動したかどうか——それだけが「計画」と「感情」を分ける唯一の基準だから', 'ポジションサイズが違うから', '使用する時間足が違うから', 2, '「損切り後に反対方向にエントリー」が事前の計画であれば計画実行、事前の計画なく損切りの感情で動けばリベンジトレード。両者は外見が同じで内実が全く異なる。だから事前に「書く」ことが重要。', false, 9),
(58, 'ゾーンに到達したがトリガーが出ず、価格が反対方向に動いた場合に「見送り」を選ぶことの長期的な意義はどれか？', 'トレード機会を逃すため不利になる', '根拠なきエントリーを排除することで、長期的な損益の質が維持される', '次の機会が必ず来るから', 'ゾーンに戻ってくる可能性があるから', 2, '「ゾーン到達だけでトリガーなし」はエントリーの3要素（場所×足×出来高）が揃っていない状態。こういった低確度の機会を見送ることが、長期的に損益を改善する。「やらない勇気」が勝ちトレーダーとの差を作る。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(59, 'If-Then-Elseの構造をトレードに導入する前と後で「精神的なプレッシャー」がどう変化するか？', '分析が増えてプレッシャーが増す', '全ての分岐に対して「次の行動」が決まっているため、「想定外」がなくなりプレッシャーが大幅に減少する', '変化はない', 'エントリー回数が増えてプレッシャーが増す', 2, '「想定外」が起きると人は慌てる。If-Then-Elseで全ての分岐を事前に設計しておけば、どんな値動きが来ても「このケース」として機械的に対応できる。不確実性への恐れが減り、冷静さを保てる。', false, 6),
(59, 'If条件（サポートゾーン到達＋トリガー確認）に該当した場合、エントリー後の損切り・利確の変更はなぜ禁止か？', 'ブローカーに罰則があるから', 'エントリー後の変更は感情に基づくものである可能性が高く、事前設計の客観性を破壊するから', '計算が複雑になるから', '税金の計算が変わるから', 2, 'エントリー後は「ポジションを持った心理」が判断を歪める。「利確を延ばせばもっと取れる」「損切りを遠ざければ回復するかも」という感情が入りやすい。事前設計を守ることが、感情的な判断を排除する唯一の方法。', false, 7),
(59, '分岐条件のElse（どの条件にも該当しない）状態でアラートを設定して待機することの意義はどれか？', '必ずチャンスが来るため', '「まだ何も起きていない」という状態を「待つ」という積極的な判断として定義することで、焦りによるランダムエントリーを防ぐから', 'アラートが鳴れば利益が確定するから', 'チャートを見る時間を節約するため', 2, '「待つ」ことを曖昧にしておくと、チャートを見続けて「何かエントリーしなければ」という焦りが生まれやすい。Elseの状態で「待つ」を明示的に定義することで、焦りによる低品質なエントリーを防ぐ。', false, 8),
(59, 'If-Then-Elseの分岐図を毎朝ノートに書くことで発生する最も実践的な効果はどれか？', 'チャートの見方が上達する', '全ての日中判断が「計画の実行」になり、リアルタイムで考える必要がなくなる', 'エントリー回数が増える', '環境認識が不要になる', 2, '分岐図が書いてあれば、価格が動いたとき「どのIfに該当するか」を確認するだけでよい。ゼロから考える必要がなくなり、感情的な判断の余地が排除される。「計画の実行者」になることが目標。', false, 9),
(59, '上位足のサポートゾーンに向けて調整が始まったシナリオで、ゾーンに到達したがトリガーが出なかった場合の適切な行動はどれか？', 'ゾーン到達の事実だけでエントリーする', 'ゾーン到達後に一定の足数以内にトリガーが出なければ見送りに切り替え、次のゾーンまたは次のチャンスを待つ', '損切りを広げてポジションを追加する', '逆方向にエントリーする', 2, 'ゾーン到達だけでエントリーすると、ローソク足パターンと出来高という確認要素が省略される。明確な見送り基準を設けることで「いつまでも待つ」という執着を防ぎ、見送りの判断を客観化できる。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(60, 'ケーススタディで「メインシナリオのサポートゾーンで完璧なピンバーが確定し出来高も急増した」場合（If A）の対応として、やってはいけないことはどれか？', '計画通りの損切り・利確を実行する', '「もっと利益を取れる」と利確目標を途中で延ばす', 'エントリーを実行する', '計画した損切りラインを維持する', 2, 'If Aが発動した最良の場面でも、「もっと行けるはず」と利確目標を途中で変えることは「エントリー後のシナリオ変更」にあたる。感情的な判断が紛れ込む典型的なパターン。計画通りに実行することが規律。', false, 6),
(60, 'ケーススタディで「メインのゾーンに到達したがトリガーが出ず見送った」（If B）場合の正しい心構えはどれか？', 'ゾーン到達時に早めにエントリーしておけばよかった', '「トリガーなしの見送り」は正しい判断であり、規律が機能している証拠', 'より下位足でトリガーを探せばよかった', 'シナリオが間違っていた', 2, 'If Bで見送ることができた事実は「基準を守れた」ことを意味する。結果論で「早く入ればよかった」と思うのは間違い。基準を守ることが長期的な成功の根拠になる。', false, 7),
(60, '「メインのサポートゾーンを下抜け→サブシナリオの深い位置のゾーンに移行」した後、そのサブゾーンでもトリガーが出なかった場合の正しい対応はどれか？', 'さらに深い第3のゾーンを探してエントリーを試みる', 'ノートレード（全シナリオを一時停止）にして翌日に改めて環境認識をする', '逆方向にエントリーする', '損切りラインを大幅に広げてエントリーを維持する', 2, 'メインもサブも機能しなかった場合は「相場が自分のシナリオと合っていない日」。無理に第3のシナリオを作ろうとすると焦りからバイアスのかかった分析になりやすい。当日は休んで翌日に冷静な目で再スタートする。', false, 8),
(60, 'ケーススタディで全シナリオが無効化された後、「今日は休む」と決めることが難しい心理的な理由は何か？', 'チャートを見る習慣があるため', '「せっかくチャートを開いたのだから何かしたい」「今日中に取り返したい」という心理が無理なトレードを促すから', '休むと技術が低下するから', '他のトレーダーが稼いでいる焦りから', 2, '「チャートを開いた後に何もしない」は心理的に難しい。しかし根拠のないトレードは期待値がマイナスになりやすい。「トレードしない」も立派な判断で、口座を守ることが最優先。', false, 9),
(60, '重要な経済指標発表でファンダメンタルズの前提が変わった場合、全シナリオを一時停止する判断が正しい理由はどれか？', '指標後は必ず相場が急変するから', 'テクニカルシナリオはファンダメンタルズの前提の上に立っており、その前提が変わると全シナリオの根拠が失われるから', '指標発表後は流動性がなくなるから', '大口が一時的に相場から退場するから', 2, 'テクニカル分析は現在の相場環境を前提にしている。重要指標で方向感が大きく変わると、その前提が崩れる。新しいファンダメンタルズの前提で環境認識を再構築してからシナリオを立て直すのが合理的。', false, 10);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(61, 'シナリオを立てる通貨ペア数を絞ること（毎日2〜3ペア程度）で得られる最も本質的なメリットはどれか？', '分析にかかる時間が短くなるから', 'ペアを絞ると各シナリオへの集中力が高まり、判断の質が向上するから', '少ないペアほど相場予測の精度が上がるから', 'ブローカーの推奨に合わせるため', 2, '複数のシナリオを高い品質で管理するには集中力が必要。管理対象が増えるほど各シナリオへの注意が分散して判断が雑になる。「少なく深く」に絞ることで、1つひとつのエントリーの精度を維持できる。', false, 6),
(61, 'シナリオ管理シートの習慣を1週間続けた後の変化として最も自然に期待できるものはどれか？', '全てのトレードが勝ちに変わる', 'シナリオの分岐構造が頭に染み込み、チャートを開いた瞬間に「どのIfに当たるか」が自然に浮かぶようになる', '環境認識に必要な時間が大幅に短縮される', '損切りが一切なくなる', 2, '繰り返しによって分岐構造が思考習慣になる。意識的に考えなくても「今はElseの状態だな」と自然に判断できるようになる。この「自動化」が精神的な余裕を生み、より冷静なトレードを可能にする。', false, 7),
(61, '「エントリー後にシナリオを変更しない」ルールの実行が難しい理由はどれか？', '市場の動きを予測できないから', 'ポジションを持った状態では「ポジションを有利に見たい」という無意識の欲求が判断を歪めるから', 'チャートが見づらくなるから', 'ブローカーが制限するから', 2, 'ポジションを持つと「願望的解釈」が始まる。「この動きはシナリオ通りでは？」「まだいけるかも」という歪んだ解釈が、エントリー後のシナリオ変更を合理化する。エントリー後の変更は感情由来と考えて基準を守る。', false, 8),
(61, 'シナリオ管理シートの「朝のルーティン（わずか数分の追加）」が日中の精神的な安定に直結する理由はどれか？', '運動後のリラックス効果と同じ原理だから', '朝に全ての分岐と対応を書き出しておくことで、日中の全ての出来事が「計画の実行」に変わり迷いがなくなるから', '朝の分析は夜の分析より精度が高いから', '習慣化すると相場予測が上達するから', 2, '「何が起きても計画通り」という状態は精神的な安定をもたらす。朝に分岐図を書いておくと、日中は「計画の実行者」として動けるため、不確実な相場でも焦りを感じにくくなる。', false, 9),
(61, '複数週にわたってシナリオ管理シートを継続したトレーダーが「損益の質が改善した」と感じる最も大きな要因はどれか？', 'シナリオが当たる頻度が増えたから', '計画なきエントリー（感情的・衝動的）が減り、根拠のある場面だけでトレードするようになったから', '勝率が統計的に上がるから', '相場の予測力が向上したから', 2, 'シナリオ管理により「計画にないトレード」が自然と減少する。衝動的なトレードは期待値が低いため、それが減るだけで損益の質が改善する。予測の精度が上がるのではなく、低品質なトレードが減ることが改善の正体。', false, 10);
